CREATE OR REPLACE PACKAGE BODY PKG_ESTOQUE
IS
  /***********************************************************************************************************************/
  /* Variaveis globais */
  /***********************************************************************************************************************/
  vsROTINA                   PCMOV.ROTINACAD%TYPE := SUBSTR(SYS_CONTEXT('USERENV', 'MODULE'),0, 33);
  vsSQL                      VARCHAR2(32000);
  -- Tabela de parâmetros para reserva de estoque
  TYPE TYPE_RESERVA IS RECORD
   (OPERACAO       VARCHAR2(1)
   ,PROCESSO       VARCHAR2(30)
   ,NUMPED         PCPEDC.NUMPED%TYPE
   ,ROTINA         NUMBER
   ,CODPROD        PCPEDI.CODPROD%TYPE
   ,CODFILIAL      PCPEDC.CODFILIAL%TYPE
   ,NUMSEQ         PCPEDI.NUMSEQ%TYPE
   ,NUMLOTE        PCPEDI.NUMLOTE%TYPE
   ,MSG_RETORNO    VARCHAR2(2000));
  -- Tabela de parâmetros para inventário
  TYPE T_INVENTARIO IS RECORD
   (NUMINVENT            PCINVENTROT.NUMINVENT%TYPE
   ,USAPRIMEIRACONTAGEM  VARCHAR2(1));
  -- Tabela de parâmetros para movimentações de estoque
  TYPE TYPE_FATURAR IS RECORD
   (OPERACAO       VARCHAR2(1)
   ,PROCESSO       VARCHAR2(30)
   ,ROTINA         NUMBER
   ,NUMPED         PCMOV.NUMPED%TYPE
   ,NUMTRANSVENDA  PCMOV.NUMTRANSVENDA%TYPE
   ,NUMTRANSENT    PCMOV.NUMTRANSENT%TYPE
   ,CODPROD        PCMOV.CODPROD%TYPE
   ,CODFILIAL      PCMOV.CODFILIAL%TYPE
   ,NUMSEQ         PCMOV.NUMSEQ%TYPE
   ,NUMLOTE        PCMOV.NUMLOTE%TYPE
   ,MSG_RETORNO    VARCHAR2(2000));
  -- Tabela de parâmetros para industria
  TYPE T_INDUSTRIA IS RECORD
   (ROTINA     NUMBER
   ,NUMOP      PCOPILOTE.NUMOP%TYPE
   ,CODPROD    PCOPILOTE.CODPROD%TYPE
   ,NUMLOTE    PCOPILOTE.NUMLOTE%TYPE
   ,NUMSEQ     PCOPILOTE.NUMSEQ%TYPE
   ,NUMREMESSA PCREMESSAPRODUCAO.NUMREMESSA%TYPE);
  -- Tabela de parâmetros para calcular estoque do depósito
  TYPE T_ESTOQUE_DEPOSITO IS RECORD
   (CODFILIAL       PCESTOQUEDEPOSITOPROD.CODFILIAL%TYPE
   ,CODDEPOSITO     PCESTOQUEDEPOSITOPROD.CODDEPOSITO%TYPE
   ,CODPROD         PCESTOQUEDEPOSITOPROD.CODPROD%TYPE
   ,QTESTOQUE       PCESTOQUEDEPOSITOPROD.QTESTOQUE%TYPE
   ,QTRESERVADA     PCESTOQUEDEPOSITOPROD.QTRESERVADA%TYPE
   ,QTPENDENTE      PCESTOQUEDEPOSITOPROD.QTPENDENTE%TYPE
   ,QTBLOQUEADA     PCESTOQUEDEPOSITOPROD.QTBLOQUEADA%TYPE
   ,QTINDENIZADA    PCESTOQUEDEPOSITOPROD.QTINDENIZADA%TYPE
   ,TIPO_OPERACAO   PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE);
  -- Tabela de parâmetros para movimentar o estoque entre os depósitos
  TYPE T_MOVIMENTACAO_DEPOSITO IS RECORD
   (IDENTIFICADOR       PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
   ,NOME_TABELA         PCREQUISICAODEPOSITO.NOME_TABELA%TYPE
   ,CODFILIAL           PCMOVESTOQUEDEPOSITO.CODFILIAL%TYPE
   ,CODPROD             PCMOVESTOQUEDEPOSITO.CODPROD%TYPE
   ,CODOPER             PCMOVESTOQUEDEPOSITO.CODOPER%TYPE
   ,CODDEPOSITOORIG     PCMOVESTOQUEDEPOSITO.CODDEPOSITOORIG%TYPE
   ,CODDEPOSITODEST     PCMOVESTOQUEDEPOSITO.CODDEPOSITODEST%TYPE
   ,QTREQUISITADA       PCREQUISICAODEPOSITO.QT%TYPE
   ,QTDE_A_TRANSFERIR   PCMOVESTOQUEDEPOSITO.QT%TYPE
   ,QTDE_A_BLOQUEAR     PCREQUISICAODEPOSITO.QT%TYPE
   ,QTDE_A_AVARIAR      PCREQUISICAODEPOSITO.QT%TYPE);
  -- Tabela de parâmetros internos
  TYPE T_INTERNO IS RECORD
    -- Datas
   (DTGERACAO                 PCHISTEST.DTGERACAO%TYPE,

    -- Códigos
    CONTADOR                  NUMBER,
    CODDEVOL                  PCMOV.CODDEVOL%TYPE,
    CODPROD                   PCMOV.CODPROD%TYPE,
    CODDEPOSITO               PCPEDI.CODDEPOSITO%TYPE,
    CODDEPOSITORESERVA        PCPEDI.CODDEPOSITO%TYPE,
    CODDEPOSITOORIG           PCMOVESTOQUEDEPOSITO.CODDEPOSITOORIG%TYPE,
    CODDEPOSITODEST           PCMOVESTOQUEDEPOSITO.CODDEPOSITODEST%TYPE,
    CONDVENDA                 PCNFSAID.CONDVENDA%TYPE,
    CODFUNCLANC               PCMOV.CODFUNCLANC%TYPE,
    CODCLI                    PCMOV.CODCLI%TYPE,
    CODAUXILIAR               PCMOV.CODAUXILIAR%TYPE,

    -- Numeradores
    PROGRAMA                  NUMBER(6),
    ROTINAENTRADA             NUMBER(6),
    NUMSEQ                    PCMOV.NUMSEQ%TYPE,
    SEQUENCIA_INSERCAO        PCLOGPKG_ESTOQUE.SEQUENCIA_INSERCAO%TYPE,
    NUMTRANSACAOORIGEM        PCMOV.NUMTRANSVENDA%TYPE,
    NUMTRANSENT               PCMOV.NUMTRANSENT%TYPE,
    NUMTRANSVENDA             PCMOV.NUMTRANSVENDA%TYPE,
    NUMNOTACONSIG             PCMOV.NUMNOTA%TYPE,

    -- Literais
    IDENTIFICADOR             PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE,
    CODFILIAL                 PCMOV.CODFILIAL%TYPE,
    CODFILIALRESERVA          PCMOV.CODFILIAL%TYPE,
    BROKER                    PCNFSAID.BROKER%TYPE,
    TIPODESCARGA              PCNFENT.TIPODESCARGA%TYPE,
    MOV_ESTOQUE               PCMOVCOMPLE.MOVEST%TYPE,
    STATUS                    PCMOV.STATUS%TYPE,
    DEVOLUCAOSIMBOLICA        PCNFSAID.DEVSIMBOLICA%TYPE,
    SERIENOTAORIGEM           PCNFSAID.SERIE%TYPE,
    CODOPER                   PCMOV.CODOPER%TYPE,
    TIPO_ENTREGA              PCPEDI.TIPOENTREGA%TYPE DEFAULT 'RI',
    TIPO_OPERACAO             PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE,
    CANCELAMENTO              PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE,
    NUMLOTE                   PCMOV.NUMLOTE%TYPE,
    TIPO_MOVIMENTACAO         PCLOGPKG_ESTOQUE.TIPO_MOVIMENTACAO%TYPE,
    MOVESTOQUEGERENCIAL       PCMOV.MOVESTOQUEGERENCIAL%TYPE,
    MOVESTOQUECONTABIL        PCMOV.MOVESTOQUECONTABIL%TYPE,
    POSICAO_ANTERIOR          PCPEDC.POSICAO%TYPE,
    SITUACAONFE               PCNFSAID.SITUACAONFE%TYPE,
    NOME_TABELA               PCLOGPKG_ESTOQUE.PROGRAMA%TYPE,
    INFORMACOES_LOG           PCLOGPKG_ESTOQUE.INFORMACOES%TYPE,
    MSG_RETORNO               PCLOGPKG_ESTOQUE.MSG_RETORNO%TYPE DEFAULT 'OK',
    OPERACAO_ENTRADA          VARCHAR2(100),
    PROCESSO                  VARCHAR2(50),
    CALCULA_ESTOQUE           VARCHAR2(1) DEFAULT 'S',
    USAPRIMEIRACONTAGEM       VARCHAR2(1) DEFAULT 'N',
    TRANSACAO_ANTERIOR        VARCHAR2(2000),
    TRANSACAO_ATUAL           VARCHAR2(2000),
    OBSERVACAO                VARCHAR2(2000),
    NOME_FUNCAO               VARCHAR2(2000),
    RETORNO_FUNCAO            VARCHAR2(2),
    LISTA_VALIDA              VARCHAR2(1),
    ORIGTRANSFORIGEM          VARCHAR2(30),
    ROWID_REGISTRO            VARCHAR2(2000),
    IMPRESSORA                PCREQUISICAODEPOSITO.IMPRESSORAREQ%TYPE,

    -- Types
    vtCONS_ESTOQUE_DEPOSITO   PCESTOQUEDEPOSITOPROD%ROWTYPE,
    vtESTOQUE_DEPOSITO        PCESTOQUEDEPOSITOPROD%ROWTYPE,
    vtCONS_ESTOQUE            PCEST%ROWTYPE,
    vtESTOQUE                 PCEST%ROWTYPE,
    vtHISTORICO               PCHISTEST%ROWTYPE,
    vtCABECALHO_ANTERIOR      PCPEDC%ROWTYPE,
    vtITEM_ANTERIOR           PCPEDI%ROWTYPE,
    vtLOTE                    PCLOTE%ROWTYPE,
    vtAVARIA                  PCMOVAVARIA%ROWTYPE,

    -- Qtde referente ao estoque
    -- Qtde Disponível
    QTDE_DISPONIVEL           PCEST.QTESTGER%TYPE,
    -- Qtde Genericas
    QUANTIDADE_1_ANTERIOR     PCEST.QTESTGER%TYPE,
    QUANTIDADE_1              PCEST.QTESTGER%TYPE,
    QUANTIDADE_2_ANTERIOR     PCEST.QTESTGER%TYPE,
    QUANTIDADE_2              PCEST.QTESTGER%TYPE,
    -- Qdte gerencial
    QTESTGERANT               PCEST.QTESTGER%TYPE,
    QTESTGER                  PCEST.QTESTGER%TYPE,
    -- Qdte contábil
    QTESTANT                  PCEST.QTEST%TYPE,
    QTEST                     PCEST.QTEST%TYPE,
    -- Qdte reservada
    QTRESERVANT               PCEST.QTRESERV%TYPE,
    QTRESERV                  PCEST.QTRESERV%TYPE,
    -- Qdte bloqueada
    QTBLOQUEADAANT            PCEST.QTBLOQUEADA%TYPE,
    QTBLOQUEADA               PCEST.QTBLOQUEADA%TYPE,
    QTDESBLOQUEADA            PCEST.QTBLOQUEADA%TYPE,
    -- Qdte indenizada/avariada
    QTINDENIZANT              PCEST.QTINDENIZ%TYPE,
    QTINDENIZ                 PCEST.QTINDENIZ%TYPE,
    -- Qdte pendente
    QTPENDENTEANT             PCEST.QTPENDENTE%TYPE,
    QTPENDENTE                PCEST.QTPENDENTE%TYPE,
    -- Qdte industria/quarentena
    QTINDUSTRIA               PCEST.QTINDUSTRIA%TYPE,
    -- Qdte estoque na gondula
    QTFRENTELOJAANT           PCEST.QTFRENTELOJA%TYPE,
    QTFRENTELOJA              PCEST.QTFRENTELOJA%TYPE,
    -- Qdte transito/importação
    QTTRANSITO                PCEST.QTTRANSITO%TYPE,
    QTTRANSITOANT             PCEST.QTTRANSITO%TYPE,
    -- Qdte em manifesto/transito
    QTTRANSITOTV13            PCEST.QTTRANSITOTV13%TYPE,
    QTTRANSITOTV13ANT         PCEST.QTTRANSITOTV13%TYPE,
    -- Qdte informada função
    QTPARAMETROENTRADA        PCEST.QTINDENIZ%TYPE,
    QTPARAMETROENTRADA_AVARIA PCEST.QTINDENIZ%TYPE,
    TESTEPROCEDURE            VARCHAR2(1) DEFAULT 'N');

  -- Type para armazenamento interno
  P_INTERNO T_INTERNO;
  vLOG      T_INTERNO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  17/10/2019     Fernandes Brito   0                   Criar a função para retornar a versão da rotina que atualiza o objeto
                                                       no banco de dados (Rotina 1100)
  ************************************************************************************************************************/
  FUNCTION VERSAO
  RETURN VARCHAR2
  IS
  BEGIN
    RETURN '30.4.1.15';
  END;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Criada a procedure para inserir os logs de ultilização da PKG_ESTOQUE
  29/11/2017    Fernandes Brito    0                   Alterada para incluir os campos QTPARAMETROENTRADA_AVARIA, QTPARAMETROENTRADA
                                                       e SEQUENCIA_INSERCAO para melhorar o intendimento dos dados.
  Observação:
  Não esquecer de sempre alterar em conjuto com esta procedure a LIMPARLOG
  ************************************************************************************************************************/
  PROCEDURE PRIV_GERARLOG
  IS-- Declaração das variáveis internas
    PRAGMA AUTONOMOUS_TRANSACTION;
  BEGIN
    -- Atribuindo valor para a sequencia de inserção de registros
    P_INTERNO.SEQUENCIA_INSERCAO := (NVL(P_INTERNO.SEQUENCIA_INSERCAO,0) + 1);
    -- Inserindo os valores na tabela de log
    INSERT
      INTO PCLOGPKG_ESTOQUE
          (DTGERACAO                             -- 1
          ,IDENTIFICADOR                         -- 2
          ,INFORMACOES                           -- 3
          ,CODFILIAL                             -- 4
          ,CODPROD                               -- 5
          ,TIPO_MOVIMENTACAO                     -- 6
          ,MOVESTGERENCIAL                       -- 7
          ,MOVESTCONTABIL                        -- 8
          ,POSICAO_ANTERIOR                      -- 9
          ,SEQUENCIA_INSERCAO                    -- 10
          ,PROGRAMA                              -- 11
          ,NUMSEQ                                -- 12
          ,TIPO_OPERACAO                         -- 13
          ,CANCELAMENTO                          -- 14
          ,MSG_RETORNO                           -- 15
          ,QTPARAMETROENTRADA                    -- 16
          ,QTPARAMETROENTRADA_AVARIA             -- 17
          ,NUMLOTE                               -- 18
          ,CODDEPOSITO                           -- 19
          ,QTESTGERANT                           -- 20
          ,QTESTGER                              -- 21
          ,QTESTANT                              -- 22
          ,QTEST                                 -- 23
          ,QTRESERVANT                           -- 24
          ,QTRESERV                              -- 25
          ,QTBLOQUEADAANT                        -- 26
          ,QTBLOQUEADA                           -- 27
          ,QTINDENIZANT                          -- 28
          ,QTINDENIZ                             -- 29
          ,QTPENDENTEANT                         -- 30
          ,QTPENDENTE                            -- 31
          ,QTFRENTELOJAANT                       -- 32
          ,QTFRENTELOJA                          -- 33
          ,QTTRANSITO                            -- 34
          ,QTTRANSITOANT                         -- 35
          ,QTTRANSITOTV13                        -- 36
          ,QTTRANSITOTV13ANT                     -- 37
           )
    VALUES (SYSDATE                                                                 -- 1
           ,NVL(vLOG.IDENTIFICADOR,NVL(P_INTERNO.IDENTIFICADOR,'Nulo'))             -- 2
           ,NVL(P_INTERNO.INFORMACOES_LOG,'Nulo')                                   -- 3
           ,NVL(vLOG.CODFILIAL,NVL(P_INTERNO.CODFILIAL,'NN'))                       -- 4
           ,NVL(vLOG.CODPROD,NVL(P_INTERNO.CODPROD,0))                              -- 5
           ,NVL(vLOG.TIPO_MOVIMENTACAO,NVL(P_INTERNO.TIPO_MOVIMENTACAO,'Nulo'))     -- 6
           ,NVL(vLOG.MOVESTOQUEGERENCIAL,NVL(P_INTERNO.MOVESTOQUEGERENCIAL,'N'))    -- 7
           ,NVL(vLOG.MOVESTOQUECONTABIL,NVL(P_INTERNO.MOVESTOQUECONTABIL,'N'))      -- 8
           ,NVL(vLOG.POSICAO_ANTERIOR,NVL(P_INTERNO.POSICAO_ANTERIOR,'NN'))         -- 9
           ,NVL(vLOG.SEQUENCIA_INSERCAO,P_INTERNO.SEQUENCIA_INSERCAO)               -- 10
           ,NVL(vsROTINA,'Nulo')                                                    -- 11
           ,NVL(vLOG.NUMSEQ,NVL(P_INTERNO.NUMSEQ,0))                                -- 12
           ,NVL(vLOG.TIPO_OPERACAO,NVL(P_INTERNO.TIPO_OPERACAO,'Nulo'))             -- 13
           ,NVL(vLOG.CANCELAMENTO,NVL(P_INTERNO.CANCELAMENTO,'N'))                  -- 14
           ,DECODE(NVL(P_INTERNO.MSG_RETORNO,'ERRO'),'ERRO',vLOG.MSG_RETORNO,P_INTERNO.MSG_RETORNO)-- 15
           ,NVL(vLOG.QTPARAMETROENTRADA,P_INTERNO.QTPARAMETROENTRADA)               -- 16
           ,NVL(vLOG.QTPARAMETROENTRADA_AVARIA,P_INTERNO.QTPARAMETROENTRADA_AVARIA) -- 17
           ,NVL(vLOG.NUMLOTE,NVL(P_INTERNO.NUMLOTE,'Nulo'))                         -- 18
           ,NVL(vLOG.CODDEPOSITO,P_INTERNO.CODDEPOSITO)                             -- 19
           ,NVL(vLOG.QTESTGERANT,P_INTERNO.QTESTGERANT)                             -- 20
           ,NVL(vLOG.QTESTGER,P_INTERNO.QTESTGER)                                   -- 21
           ,NVL(vLOG.QTESTANT,P_INTERNO.QTESTANT)                                   -- 22
           ,NVL(vLOG.QTEST,P_INTERNO.QTEST)                                         -- 23
           ,NVL(vLOG.QTRESERVANT,P_INTERNO.QTRESERVANT)                             -- 24
           ,NVL(vLOG.QTRESERV,P_INTERNO.QTRESERV)                                   -- 25
           ,NVL(vLOG.QTBLOQUEADAANT,P_INTERNO.QTBLOQUEADAANT)                       -- 26
           ,NVL(vLOG.QTBLOQUEADA,P_INTERNO.QTBLOQUEADA)                             -- 27
           ,NVL(vLOG.QTINDENIZANT,P_INTERNO.QTINDENIZANT)                           -- 28
           ,NVL(vLOG.QTINDENIZ,P_INTERNO.QTINDENIZ)                                 -- 29
           ,NVL(vLOG.QTPENDENTEANT,P_INTERNO.QTPENDENTEANT)                         -- 30
           ,NVL(vLOG.QTPENDENTE,P_INTERNO.QTPENDENTE)                               -- 31
           ,NVL(vLOG.QTFRENTELOJAANT,P_INTERNO.QTFRENTELOJAANT)                     -- 32
           ,NVL(vLOG.QTFRENTELOJA,P_INTERNO.QTFRENTELOJA)                           -- 33
           ,NVL(vLOG.QTTRANSITO,P_INTERNO.QTTRANSITO)                               -- 34
           ,NVL(vLOG.QTTRANSITOANT,P_INTERNO.QTTRANSITOANT)                         -- 35
           ,NVL(vLOG.QTTRANSITOTV13,P_INTERNO.QTTRANSITOTV13)                       -- 36
           ,NVL(vLOG.QTTRANSITOTV13ANT,P_INTERNO.QTTRANSITOTV13ANT)                 -- 37
           );
    COMMIT;
  -- Procedure
  END PRIV_GERARLOG;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/11/2015     Rodrigo Santos    0.119485.2015       Migrados os métodos "PRIV_DEFINIR_MOVESTOQUE" e "PROCESSA_MOVESTOQUE"
                                                       para a package PKG_ESTOQUE.
  24/01/2020     Anderson Silva    DDMEDICA-1965       Vendas de Crossdocking somente movimentar estoque contábil
  ************************************************************************************************************************/
  PROCEDURE PRIV_PROCESSA_MOVESTOQUE
  IS-- Declaração das variáveis internas
    vnCOUNTNF             NUMBER;
    vbEXISTECUPOM         BOOLEAN;
    vbEHNFCOMPLEMENTAR    BOOLEAN;
    vnNFDEVENTFUTURA      NUMBER;
    vnNUMTRANSENTCROSSDOCK PCPEDC.NUMTRANSENTCROSSDOCK%TYPE;
  BEGIN
    -- Verificar se é nf proveniente de cupom
    BEGIN
      SELECT COUNT(1)
        INTO vnCOUNTNF
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR
         AND TIPOVENDA = 'V4'
         AND NUMCUPOM > 0;
      vbEXISTECUPOM := (vnCOUNTNF > 0);
    EXCEPTION
      WHEN OTHERS THEN
        vbEXISTECUPOM := FALSE;
    END;
    -- Verificar se é nf complementar
    BEGIN
      SELECT COUNT(1)
        INTO vnCOUNTNF
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR
         AND FINALIDADENFE IN ('A', 'C');
      vbEHNFCOMPLEMENTAR := (vnCOUNTNF > 0);
    EXCEPTION
      WHEN OTHERS THEN
        vbEHNFCOMPLEMENTAR := FALSE;
    END;
    -- Zerando variável
    vnNFDEVENTFUTURA := 0;
    -- Verificando se é NF de devolução de entrega futura
    BEGIN
      SELECT COUNT(1)
        INTO vnNFDEVENTFUTURA
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR
         AND NFDEVENTFUTURA = 'S'
         AND TIPODEVOL = 2;
    EXCEPTION
      WHEN OTHERS THEN
        vnNFDEVENTFUTURA := 0;
    END;
    -- Verificando se a NF refere-se a um Pedido de CrossDocking - DDMEDICA-1965
    vnNUMTRANSENTCROSSDOCK := 0;
    IF (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_UTILIZACONTROLEMEDICAMENTOS', '99'), 'N') = 'S') AND (NVL(P_INTERNO.NUMTRANSENT, 0) = 0) THEN
      BEGIN
        SELECT NUMTRANSENTCROSSDOCK
          INTO vnNUMTRANSENTCROSSDOCK
          FROM PCPEDC
         WHERE NUMTRANSVENDA = NVL(P_INTERNO.IDENTIFICADOR, 0)
           AND ROWNUM        = 1;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnNUMTRANSENTCROSSDOCK := 0;
      END;
    END IF;
    -- Não movimentar estoque na remessa de brinde da rotina 1306
    BEGIN
      SELECT NVL(PCMOVCOMPLE.MOVEST, 'S')
        INTO P_INTERNO.MOV_ESTOQUE
        FROM PCMOV, PCMOVCOMPLE
       WHERE PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM
         AND PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MOV_ESTOQUE := 'S';
    END;
    -- Definindo movimentação padrão para status A
    IF INSTR(P_INTERNO.STATUS, 'A') > 0 THEN
      P_INTERNO.MOVESTOQUECONTABIL := 'S';
    ELSE
      P_INTERNO.MOVESTOQUECONTABIL := 'N';
    END IF;
    -- Definindo movimentação padrão para status B
    IF INSTR(P_INTERNO.STATUS, 'B') > 0 THEN
      P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
    ELSE
      P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
    END IF;
    -- Validando as movimentações de venda
    IF (SUBSTR(P_INTERNO.CODOPER,1,1) = 'S' AND P_INTERNO.IDENTIFICADOR IS NOT NULL AND P_INTERNO.CODOPER NOT IN ('SD', 'ST', 'SP')) THEN
      CASE P_INTERNO.CONDVENDA
        WHEN 1 THEN
          --> Tipo de Venda 1
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
          --TV1 proveniente de consignação(T20)
          IF P_INTERNO.NUMNOTACONSIG > 0 THEN
            P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
            P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END IF;
        WHEN 4 THEN
          --> Tipo de Venda 4
          IF vbEXISTECUPOM THEN
            P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
            P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          ELSIF vbEHNFCOMPLEMENTAR THEN
            P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
            P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          ELSE
            P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
            P_INTERNO.MOVESTOQUECONTABIL  := 'S';
          END IF;
        WHEN 5 THEN
          --> Tipo de Venda 5
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 7 THEN
          --> Tipo de Venda 7
          P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          P_INTERNO.MOVESTOQUECONTABIL  := 'N';
        WHEN 8 THEN
          --> Tipo de Venda 8
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 9 THEN
          --> Tipo de Venda 9
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 10 THEN
          --> Tipo de Venda 10
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 11 THEN
          --> Tipo de Venda 11
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 13 THEN
          --> Tipo de Venda 13
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        WHEN 14 THEN
          --> Tipo de Venda 14
          P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          P_INTERNO.MOVESTOQUECONTABIL  := 'N';
        WHEN 20 THEN
          --> Tipo de Venda 20
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        ELSE
          NULL;
      END CASE;
    -- Movimentações de venda
    END IF;
    -- Validando se é cupom fiscal
    IF P_INTERNO.SERIENOTAORIGEM = 'CF' THEN
      -- Verifica se é filial retira
      IF P_INTERNO.ORIGTRANSFORIGEM = 'RETIRA' THEN
        P_INTERNO.MOVESTOQUECONTABIL  := 'S';
        P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
      END IF;
    END IF;
    -- Validando se é uma devolução de cliente
    IF P_INTERNO.CODOPER = 'ED' THEN
      -- Zerando variavel
      P_INTERNO.NUMTRANSVENDA := 0;
      -- Validando se houve estorno da venda
      BEGIN
        SELECT NVL(PCESTCOM.NUMTRANSVENDA, 0)
          INTO P_INTERNO.NUMTRANSVENDA
          FROM PCESTCOM
         WHERE PCESTCOM.NUMTRANSENT = P_INTERNO.NUMTRANSENT;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          P_INTERNO.NUMTRANSVENDA := 0;
      END;
      -- Zerando variavel
      P_INTERNO.CONDVENDA := 0;
      -- Verificando o tipo da venda que originou da devolução
      BEGIN
        SELECT NVL(PCNFSAID.CONDVENDA, 0)
          INTO P_INTERNO.CONDVENDA
          FROM PCNFSAID
         WHERE PCNFSAID.NUMTRANSVENDA = P_INTERNO.NUMTRANSVENDA;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          P_INTERNO.CONDVENDA := 0;
      END;
      -- Se existir realmente a venda
      IF P_INTERNO.NUMTRANSVENDA > 0 THEN
        IF P_INTERNO.CONDVENDA = 7 THEN
          P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          P_INTERNO.MOVESTOQUECONTABIL  := 'N';
        END IF;
        IF P_INTERNO.CONDVENDA = 8 THEN
          CASE P_INTERNO.STATUS
            WHEN 'A' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'AB' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'S';
            WHEN 'B' THEN
              P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
            ELSE
              P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
              P_INTERNO.MOVESTOQUECONTABIL  := 'N';
          END CASE;
        END IF;
        IF ((P_INTERNO.BROKER = 'S') AND (P_INTERNO.CONDVENDA = 4)) THEN
          P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          P_INTERNO.MOVESTOQUECONTABIL  := 'S';
        END IF;
      ELSE
        P_INTERNO.TIPODESCARGA := 'X';
        BEGIN
          SELECT PCNFENT.TIPODESCARGA
            INTO P_INTERNO.TIPODESCARGA
            FROM PCNFENT
           WHERE PCNFENT.NUMTRANSENT = P_INTERNO.NUMTRANSENT;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            P_INTERNO.TIPODESCARGA := 'X';
        END;
        IF P_INTERNO.TIPODESCARGA = '7' THEN
          P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
          P_INTERNO.MOVESTOQUECONTABIL  := 'N';
        END IF;
        IF P_INTERNO.TIPODESCARGA = '8' THEN
          P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          P_INTERNO.MOVESTOQUECONTABIL  := 'S';
        END IF;
        IF P_INTERNO.TIPODESCARGA = 'X' THEN
          IF INSTR(P_INTERNO.STATUS, 'A') > 0 THEN
            P_INTERNO.MOVESTOQUECONTABIL := 'S';
          ELSE
            P_INTERNO.MOVESTOQUECONTABIL := 'N';
          END IF;
          IF INSTR(P_INTERNO.STATUS, 'B') > 0 THEN
            P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
          ELSE
            P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
          END IF;
        END IF;
      -- Venda que originou a devolução
      END IF;
    -- Validação da devolução
    END IF;
    -- Verificando se é entrada de devolução simbolica para consignação
    IF P_INTERNO.CODOPER = 'EN' THEN
      IF P_INTERNO.DEVOLUCAOSIMBOLICA = 'S' THEN
        P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
        P_INTERNO.MOVESTOQUECONTABIL  := 'N';
      ELSE
        P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
        P_INTERNO.MOVESTOQUECONTABIL  := 'S';
      END IF;
    --
    ELSIF P_INTERNO.CODOPER = 'SV' THEN
      P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
      P_INTERNO.MOVESTOQUECONTABIL  := 'N';
    ELSIF (P_INTERNO.CODOPER = 'SA' AND vsROTINA LIKE '%1181%') THEN
      P_INTERNO.MOVESTOQUEGERENCIAL := 'S';
      P_INTERNO.MOVESTOQUECONTABIL  := 'S';
    --
    END IF;
    -- Caso não seja devolução de entrega futura
    IF (vnNFDEVENTFUTURA <> 0) OR (P_INTERNO.MOV_ESTOQUE = 'N') THEN
      P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
      P_INTERNO.MOVESTOQUECONTABIL  := 'N';
    END IF;
    -- Caso seja Crossdocking somente movimentar estoque contábil - DDMEDICA-1965
    IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
      P_INTERNO.MOVESTOQUEGERENCIAL := 'N';
      P_INTERNO.MOVESTOQUECONTABIL  := 'S';
    END IF;
    -- Definindo movimentação contábil e gerencial na pcmovn
    UPDATE PCMOV
       SET PCMOV.MOVESTOQUECONTABIL  = P_INTERNO.MOVESTOQUECONTABIL,
           PCMOV.MOVESTOQUEGERENCIAL = P_INTERNO.MOVESTOQUEGERENCIAL
     WHERE ROWID = P_INTERNO.ROWID_REGISTRO;
  -- Procedure
  END PRIV_PROCESSA_MOVESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  28/01/2014   Rodrigo Santos      HIS.01198.2013      Implementação desta função para ajudar a definir o tipo de transferência a ser realizada para o item.
  18/11/2015   Rodrigo Santos      0.119485.2015       Migrados os métodos "ORIGEM_TRANSFERENCIA" e "TIPO_TRANSFERENCIA" para a package PKG_ESTOQUE.
  ************************************************************************************************************************/
  FUNCTION PRIV_TIPO_TRANSFERENCIA (psFILIALVENDA   IN PCMOV.CODFILIAL%TYPE
                                   ,psFILIALRETIRA  IN PCMOV.CODFILIALRETIRA%TYPE
                                   ,psFILIALNF      IN PCMOV.CODFILIALNF%TYPE)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
  BEGIN
    CASE--Todas as filiais iguais => NENHUMA TRANSFERÊNCIA
      WHEN psFILIALVENDA = NVL(psFILIALNF, psFILIALVENDA) AND
           psFILIALVENDA = NVL(psFILIALRETIRA, psFILIALVENDA) THEN
        RETURN 'N';
        --Somente a filial retira é diferente => TRANSFERÊNCIA DE FILIAL RETIRA
      WHEN NVL(psFILIALRETIRA, psFILIALVENDA) <> psFILIALVENDA AND
           NVL(psFILIALRETIRA, psFILIALVENDA) <> NVL(psFILIALNF, psFILIALVENDA) AND
           psFILIALVENDA = NVL(psFILIALNF, psFILIALVENDA) THEN
        RETURN 'R';
        --Somente a filial contábil é diferente => TRANSFERÊNCIA DE FILIAL VIRTUAL
      WHEN NVL(psFILIALNF, psFILIALVENDA) <> psFILIALVENDA AND
           NVL(psFILIALNF, psFILIALVENDA) <> NVL(psFILIALRETIRA, psFILIALVENDA) AND
           psFILIALVENDA = NVL(psFILIALRETIRA, psFILIALVENDA) THEN
        RETURN 'V';
        --Somente a filial de venda é diferente => NENHUMA TRANSFERÊNCIA
      WHEN psFILIALVENDA <> NVL(psFILIALNF, psFILIALVENDA) AND
           psFILIALVENDA <> NVL(psFILIALRETIRA, psFILIALVENDA) AND
           NVL(psFILIALNF, psFILIALVENDA) = NVL(psFILIALRETIRA, psFILIALVENDA) THEN
        RETURN 'N';
        --Todas as filiais são diferentes entre si => TRANSFERÊNCIA DE FILIAL VIRTUAL E RETIRA
      WHEN psFILIALVENDA <> NVL(psFILIALNF, psFILIALVENDA) AND
           psFILIALVENDA <> NVL(psFILIALRETIRA, psFILIALVENDA) AND
           NVL(psFILIALNF, psFILIALVENDA) <> NVL(psFILIALRETIRA, psFILIALVENDA) THEN
        RETURN 'VR';
        --Casos não identificados
      ELSE
        RETURN 'N';
    END CASE;
  -- Função
  END PRIV_TIPO_TRANSFERENCIA;
  
  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  22/08/2018     Fernandes Brito   0                   Criada a procedure para atualizar os custo do estoque na movimentação
  ************************************************************************************************************************/
  PROCEDURE PRIV_ATUALIZAR_CUSTO (pnNUMTRANSACAO IN PCMOV.NUMTRANSVENDA%TYPE
                                 ,psOPERACAO     IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE)
  IS-- Declaração das variáveis internas
    vnCUSTOREP                PCEST.CUSTOREP%TYPE;
    vnCUSTOFIN                PCEST.CUSTOFIN%TYPE;
    vnCUSTOCONT               PCEST.CUSTOCONT%TYPE;
    vnCUSTOREALSEMST          PCEST.CUSTOREALSEMST%TYPE;
    vnCUSTOFINSEMST           PCEST.CUSTOFINSEMST%TYPE;
    vnCUSTOREALLIQ            PCEST.CUSTOREALLIQ%TYPE;
    vnCUSTOREAL               PCEST.CUSTOREAL%TYPE;
    vnCUSTOFISCAL             PCEST.CUSTOFISCAL%TYPE;
    vnCUSTOULTENTFISCAL       PCEST.CUSTOULTENTFISCAL%TYPE;
    vsORIGEMCUSTOFILIALRETIRA VARCHAR2(2);
    vsCODFILIAL               PCEST.CODFILIAL%TYPE;
    vsESTBONIFIC              PCEST.ESTBONIFIC%TYPE;
  BEGIN
    -- Lista de produtos
    FOR DADOS IN (SELECT P.CODPROD,
                         ESTOQUECONTABIL.CODFILIAL  CODFILIALCONTABIL,
                         ESTOQUEGERENCIAL.CODFILIAL CODFILIALGERENCIAL,
                         P.CODFILIAL            CODFILIALVENDA,
                         P.NUMTRANSITEM,
                         P.ROWID ID
                    FROM PCMOV P,
                         PCEST ESTOQUEGERENCIAL,
                         PCEST ESTOQUECONTABIL
                   WHERE ((P.NUMTRANSVENDA = pnNUMTRANSACAO AND psOPERACAO = 'S')
                      OR (P.NUMTRANSENT = pnNUMTRANSACAO AND psOPERACAO = 'E'))
                     AND P.CODPROD = ESTOQUEGERENCIAL.CODPROD
                     AND P.CODPROD = ESTOQUECONTABIL.CODPROD
                     AND NVL(P.CODFILIALNF, P.CODFILIAL) = ESTOQUECONTABIL.CODFILIAL
                     AND NVL(P.CODFILIALRETIRA, P.CODFILIAL) = ESTOQUEGERENCIAL.CODFILIAL)
    LOOP
      -- Buscar parâmetro
      vsORIGEMCUSTOFILIALRETIRA := PRIV_TIPO_TRANSFERENCIA(DADOS.CODFILIALVENDA,
                                                           DADOS.CODFILIALGERENCIAL,
                                                           DADOS.CODFILIALCONTABIL);
      -- Usa custo filial retira?
      IF vsORIGEMCUSTOFILIALRETIRA = 'R' THEN
        vsCODFILIAL := DADOS.CODFILIALGERENCIAL;
      ELSE
        vsCODFILIAL := DADOS.CODFILIALCONTABIL;
      END IF;
      -- Buscar os custos atuais
      BEGIN
        SELECT PCEST.CUSTOREP,
               PCEST.CUSTOFIN,
               PCEST.CUSTOCONT,
               PCEST.CUSTOREALSEMST,
               PCEST.CUSTOFINSEMST,
               PCEST.CUSTOREALLIQ,
               PCEST.CUSTOREAL,
               PCEST.ESTBONIFIC,
               NVL(PCEST.CUSTOFISCAL, 0),
               NVL(CUSTOULTENTFISCAL, 0)
          INTO vnCUSTOREP,
               vnCUSTOFIN,
               vnCUSTOCONT,
               vnCUSTOREALSEMST,
               vnCUSTOFINSEMST,
               vnCUSTOREALLIQ,
               vnCUSTOREAL,
               vsESTBONIFIC,
               vnCUSTOFISCAL,
               vnCUSTOULTENTFISCAL
          FROM PCEST
         WHERE CODPROD = DADOS.CODPROD
           AND CODFILIAL = vsCODFILIAL;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCUSTOREP      := 0;
          vnCUSTOFIN      := 0;
          vnCUSTOCONT     := 0;
          vnCUSTOREALSEMST:= 0;
          vnCUSTOFINSEMST := 0;
          vnCUSTOREALLIQ  := 0;
          vnCUSTOREAL     := 0;
          vsESTBONIFIC    := 0;
          vnCUSTOFISCAL   := 0;
          vnCUSTOULTENTFISCAL := 0;
      END;
      -- Atualiza custos na PCMOV
      UPDATE PCMOV
         SET CUSTOREP       = vnCUSTOREP,
             CUSTOFINEST    = NVL(CUSTOFINEST, vnCUSTOFIN),
             CUSTOCONT      = vnCUSTOCONT,
             CUSTOREALSEMST = vnCUSTOREALSEMST
       WHERE ROWID = DADOS.ID;
      -- Atualiza custos na PCMOVCOMPLE
      UPDATE PCMOVCOMPLE
         SET CUSTOFINSEMST = vnCUSTOFINSEMST,
             CUSTOREALLIQ = vnCUSTOREALLIQ,
             CUSTOREALEST = vnCUSTOREAL,
             ESTBONIFIC   = vsESTBONIFIC,
             CUSTOFISCAL  = vnCUSTOFISCAL,
             CUSTOULTENTFISCAL = vnCUSTOULTENTFISCAL
       WHERE NUMTRANSITEM = DADOS.NUMTRANSITEM;
    -- Lista de produtos
    END LOOP;
  -- Procedure
  END PRIV_ATUALIZAR_CUSTO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  03/12/2017     Fernandes Brito   0                   Criada procedure unica para atualização de dados na tabela PCLOTE
  /***********************************************************************************************************************/
  PROCEDURE PRIV_ATUALIZAR_DEPOSITO
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar dados
    vLOG.QTESTGERANT      := NULL;
    vLOG.QTESTGER         := NULL;
    vLOG.QTRESERVANT      := NULL;
    vLOG.QTRESERV         := NULL;
    vLOG.QTBLOQUEADAANT   := NULL;
    vLOG.QTBLOQUEADA      := NULL;
    vLOG.QTINDENIZANT     := NULL;
    vLOG.QTINDENIZ        := NULL;
    vLOG.QTPENDENTEANT    := NULL;
    vLOG.QTPENDENTE       := NULL;
    -- Consultar estoque
    SELECT QTESTOQUE
          ,QTESTOQUE
          ,QTRESERVADA
          ,QTRESERVADA
          ,QTBLOQUEADA
          ,QTBLOQUEADA
          ,QTINDENIZADA
          ,QTINDENIZADA
          ,QTPENDENTE
          ,QTPENDENTE
      INTO vLOG.QTESTGERANT
          ,vLOG.QTESTGER
          ,vLOG.QTRESERVANT
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADAANT
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZANT
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTEANT
          ,vLOG.QTPENDENTE
      FROM PCESTOQUEDEPOSITOPROD
     WHERE CODFILIAL = P_INTERNO.vtESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = P_INTERNO.vtESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = P_INTERNO.vtESTOQUE_DEPOSITO.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PRIV_ATUALIZAR_DEPOSITO';
    PRIV_GERARLOG;
    -- Atualizar estoque do deposito
    UPDATE PCESTOQUEDEPOSITOPROD
       SET QTESTOQUE = NVL(P_INTERNO.vtESTOQUE_DEPOSITO.QTESTOQUE, 0)
          ,QTRESERVADA = NVL(P_INTERNO.vtESTOQUE_DEPOSITO.QTRESERVADA, 0)
          ,QTPENDENTE = NVL(P_INTERNO.vtESTOQUE_DEPOSITO.QTPENDENTE, 0)
          ,QTBLOQUEADA = NVL(P_INTERNO.vtESTOQUE_DEPOSITO.QTBLOQUEADA, 0)
          ,QTINDENIZADA = NVL(P_INTERNO.vtESTOQUE_DEPOSITO.QTINDENIZADA, 0)
     WHERE CODFILIAL = P_INTERNO.vtESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = P_INTERNO.vtESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = P_INTERNO.vtESTOQUE_DEPOSITO.CODPROD;
    -- Consultar estoque
    SELECT QTESTOQUE
          ,QTRESERVADA
          ,QTBLOQUEADA
          ,QTINDENIZADA
          ,QTPENDENTE
      INTO vLOG.QTESTGER
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTE
      FROM PCESTOQUEDEPOSITOPROD
     WHERE CODFILIAL = P_INTERNO.vtESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = P_INTERNO.vtESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = P_INTERNO.vtESTOQUE_DEPOSITO.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PRIV_ATUALIZAR_DEPOSITO';
    PRIV_GERARLOG;
    -- Limpar dados
    vLOG.QTESTGERANT      := NULL;
    vLOG.QTESTGER         := NULL;
    vLOG.QTRESERVANT      := NULL;
    vLOG.QTRESERV         := NULL;
    vLOG.QTBLOQUEADAANT   := NULL;
    vLOG.QTBLOQUEADA      := NULL;
    vLOG.QTINDENIZANT     := NULL;
    vLOG.QTINDENIZ        := NULL;
    vLOG.QTPENDENTEANT    := NULL;
    vLOG.QTPENDENTE       := NULL;
  -- Caso apresente erro ao atualizar
  EXCEPTION
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 - Atualizar Depósito: Não foi possível atualizar a quantidade do estoque do depósito (PCESTOQUEDEPOSITOPROD).'||CHR(13)||
                               'Cód. Filial..: '||TO_CHAR(P_INTERNO.vtESTOQUE_DEPOSITO.CODFILIAL)||CHR(13)||
                               'Produto......: '||TO_CHAR(P_INTERNO.vtESTOQUE_DEPOSITO.CODPROD)||CHR(13)||
                               'Depósito.....: '||TO_CHAR(P_INTERNO.vtESTOQUE_DEPOSITO.CODDEPOSITO)||CHR(13)||
                               'MSG Original.: '||SQLERRM;
  -- Procedure
  END PRIV_ATUALIZAR_DEPOSITO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  03/12/2017     Fernandes Brito   0                   Criada procedure unica para atualização de dados na tabela PCLOTE
  21/05/2020     Fernandes Brito   0                   Retirada as variáveis globais para uso em processos ficando apenas as variáveis globais
                                                       para a gravação do log. Desta forma visamos a diminuir o risto de erros e melhorar o entendimento da PKG_ESTOQUE.
  /***********************************************************************************************************************/
  PROCEDURE PRIV_CALCULAR_DEPOSITO (ptESTOQUE_DEPOSITO  IN T_ESTOQUE_DEPOSITO
                                   ,psMSG_RETORNO       OUT PCLOGPKG_ESTOQUE.MSG_RETORNO%TYPE)
  IS-- Declaração das variáveis internas
  BEGIN
    psMSG_RETORNO := 'OK';
    -- Limpar dados
    vLOG.QTESTGERANT      := NULL;
    vLOG.QTESTGER         := NULL;
    vLOG.QTRESERVANT      := NULL;
    vLOG.QTRESERV         := NULL;
    vLOG.QTBLOQUEADAANT   := NULL;
    vLOG.QTBLOQUEADA      := NULL;
    vLOG.QTINDENIZANT     := NULL;
    vLOG.QTINDENIZ        := NULL;
    vLOG.QTPENDENTEANT    := NULL;
    vLOG.QTPENDENTE       := NULL;
    -- Consultar estoque
    SELECT QTESTOQUE
          ,QTESTOQUE
          ,QTRESERVADA
          ,QTRESERVADA
          ,QTBLOQUEADA
          ,QTBLOQUEADA
          ,QTINDENIZADA
          ,QTINDENIZADA
          ,QTPENDENTE
          ,QTPENDENTE
      INTO vLOG.QTESTGERANT
          ,vLOG.QTESTGER
          ,vLOG.QTRESERVANT
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADAANT
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZANT
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTEANT
          ,vLOG.QTPENDENTE
      FROM PCESTOQUEDEPOSITOPROD
     WHERE CODFILIAL = ptESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = ptESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = ptESTOQUE_DEPOSITO.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PRIV_CALCULAR_DEPOSITO';
    PRIV_GERARLOG;
    -- Atualizar estoque do deposito
    UPDATE PCESTOQUEDEPOSITOPROD
       SET QTESTOQUE = (NVL(QTESTOQUE, 0) + (CASE
                                               WHEN SUBSTR(ptESTOQUE_DEPOSITO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                 (NVL(ptESTOQUE_DEPOSITO.QTESTOQUE, 0) * (-1))
                                             ELSE
                                               NVL(ptESTOQUE_DEPOSITO.QTESTOQUE, 0)
                                             END))
          ,QTRESERVADA = GREATEST((NVL(QTRESERVADA, 0) + (CASE
                                                            WHEN SUBSTR(ptESTOQUE_DEPOSITO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                              (NVL(ptESTOQUE_DEPOSITO.QTRESERVADA, 0) * (-1))
                                                          ELSE
                                                            NVL(ptESTOQUE_DEPOSITO.QTRESERVADA, 0)
                                                          END)),0)
          ,QTPENDENTE = GREATEST((NVL(QTPENDENTE, 0) + (CASE
                                                          WHEN SUBSTR(ptESTOQUE_DEPOSITO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                            (NVL(ptESTOQUE_DEPOSITO.QTPENDENTE, 0) * (-1))
                                                        ELSE
                                                          NVL(ptESTOQUE_DEPOSITO.QTPENDENTE, 0)
                                                        END)),0)
          ,QTBLOQUEADA = GREATEST((NVL(QTBLOQUEADA, 0) + (CASE
                                                            WHEN SUBSTR(ptESTOQUE_DEPOSITO.TIPO_OPERACAO,1,1) = 'B'  THEN
                                                              (NVL(ptESTOQUE_DEPOSITO.QTBLOQUEADA, 0) * (-1))
                                                          ELSE
                                                            NVL(ptESTOQUE_DEPOSITO.QTBLOQUEADA, 0)
                                                          END)),0)
          ,QTINDENIZADA = GREATEST((NVL(QTINDENIZADA, 0) + (CASE
                                                              WHEN SUBSTR(ptESTOQUE_DEPOSITO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                (NVL(ptESTOQUE_DEPOSITO.QTINDENIZADA, 0) * (-1))
                                                            ELSE
                                                              NVL(ptESTOQUE_DEPOSITO.QTINDENIZADA, 0)
                                                            END)),0)
     WHERE CODFILIAL = ptESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = ptESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = ptESTOQUE_DEPOSITO.CODPROD;
    -- Consultar estoque
    SELECT QTESTOQUE
          ,QTRESERVADA
          ,QTBLOQUEADA
          ,QTINDENIZADA
          ,QTPENDENTE
      INTO vLOG.QTESTGER
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTE
      FROM PCESTOQUEDEPOSITOPROD
     WHERE CODFILIAL = ptESTOQUE_DEPOSITO.CODFILIAL
       AND CODDEPOSITO = ptESTOQUE_DEPOSITO.CODDEPOSITO
       AND CODPROD = ptESTOQUE_DEPOSITO.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PRIV_CALCULAR_DEPOSITO';
    PRIV_GERARLOG;
    -- Limpar dados
    vLOG.QTESTGERANT      := NULL;
    vLOG.QTESTGER         := NULL;
    vLOG.QTRESERVANT      := NULL;
    vLOG.QTRESERV         := NULL;
    vLOG.QTBLOQUEADAANT   := NULL;
    vLOG.QTBLOQUEADA      := NULL;
    vLOG.QTINDENIZANT     := NULL;
    vLOG.QTINDENIZ        := NULL;
    vLOG.QTPENDENTEANT    := NULL;
    vLOG.QTPENDENTE       := NULL;
  -- Caso apresente erro ao atualizar
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 1 - Atualizar Depósito: Não foi possível atualizar a quantidade do estoque do depósito (PCESTOQUEDEPOSITOPROD).'||CHR(13)||
                       'Cód. Filial..: '||TO_CHAR(ptESTOQUE_DEPOSITO.CODFILIAL)||CHR(13)||
                       'Produto......: '||TO_CHAR(ptESTOQUE_DEPOSITO.CODPROD)||CHR(13)||
                       'Depósito.....: '||TO_CHAR(ptESTOQUE_DEPOSITO.CODDEPOSITO)||CHR(13)||
                       'MSG Original.: '||SQLERRM;
  -- Procedure
  END PRIV_CALCULAR_DEPOSITO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  03/12/2017     Fernandes Brito   0                   Criada procedure unica para atualização de dados na tabela PCEST
  /***********************************************************************************************************************/
  PROCEDURE PRIV_ATUALIZAR_ESTOQUE
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar dados
    vLOG.QTESTGERANT        := NULL;
    vLOG.QTESTGER           := NULL;
    vLOG.QTESTANT           := NULL;
    vLOG.QTEST              := NULL;
    vLOG.QTRESERVANT        := NULL;
    vLOG.QTRESERV           := NULL;
    vLOG.QTBLOQUEADAANT     := NULL;
    vLOG.QTBLOQUEADA        := NULL;
    vLOG.QTINDENIZANT       := NULL;
    vLOG.QTINDENIZ          := NULL;
    vLOG.QTPENDENTEANT      := NULL;
    vLOG.QTPENDENTE         := NULL;
    vLOG.QTFRENTELOJAANT    := NULL;
    vLOG.QTFRENTELOJA       := NULL;
    vLOG.QTTRANSITOANT      := NULL;
    vLOG.QTTRANSITO         := NULL;
    vLOG.QTTRANSITOTV13ANT  := NULL;
    vLOG.QTTRANSITOTV13     := NULL;
    -- Consultar estoque
    SELECT QTESTGER
          ,QTESTGER
          ,QTEST
          ,QTEST
          ,QTRESERV
          ,QTRESERV
          ,QTBLOQUEADA
          ,QTBLOQUEADA
          ,QTINDENIZ
          ,QTINDENIZ
          ,QTPENDENTE
          ,QTPENDENTE
          ,QTFRENTELOJA
          ,QTFRENTELOJA
          ,QTTRANSITO
          ,QTTRANSITO
          ,QTTRANSITOTV13
          ,QTTRANSITOTV13
      INTO vLOG.QTESTGERANT
          ,vLOG.QTESTGER
          ,vLOG.QTESTANT
          ,vLOG.QTEST
          ,vLOG.QTRESERVANT
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADAANT
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZANT
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTEANT
          ,vLOG.QTPENDENTE
          ,vLOG.QTFRENTELOJAANT
          ,vLOG.QTFRENTELOJA
          ,vLOG.QTTRANSITOANT
          ,vLOG.QTTRANSITO
          ,vLOG.QTTRANSITOTV13ANT
          ,vLOG.QTTRANSITOTV13
      FROM PCEST
     WHERE CODFILIAL = P_INTERNO.vtESTOQUE.CODFILIAL
       AND CODPROD = P_INTERNO.vtESTOQUE.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função atualizar estoque';
    PRIV_GERARLOG;
    -- Atualizando o estoque
    UPDATE PCEST
       SET PCEST.IDENTIFICADOR = P_INTERNO.vtESTOQUE.IDENTIFICADOR
          ,PCEST.MOTIVOBLOQESTOQUE = CASE-- Descrição motivo
                                       WHEN P_INTERNO.vtESTOQUE.MOTIVOBLOQESTOQUE IS NOT NULL THEN
                                         P_INTERNO.vtESTOQUE.MOTIVOBLOQESTOQUE
                                     ELSE
                                       PCEST.MOTIVOBLOQESTOQUE
                                     END
          ,PCEST.CODDEVOL = CASE-- Código motivo
                              WHEN P_INTERNO.vtESTOQUE.CODDEVOL IS NOT NULL THEN
                                P_INTERNO.vtESTOQUE.CODDEVOL
                            ELSE
                              PCEST.CODDEVOL
                            END
          ,PCEST.QTEST = CASE-- Contabil
                           WHEN P_INTERNO.vtESTOQUE.QTEST IS NOT NULL THEN
                             CASE-- Substituir Quantidade
                               WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                 NVL(P_INTERNO.vtESTOQUE.QTEST,0)
                             ELSE
                               (NVL(PCEST.QTEST, 0) + (CASE
                                                         WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                           (NVL(P_INTERNO.vtESTOQUE.QTEST, 0) * (-1))
                                                       ELSE
                                                         NVL(P_INTERNO.vtESTOQUE.QTEST, 0)
                                                       END))
                             END
                         ELSE
                           PCEST.QTEST
                         END
          ,PCEST.QTESTGER = CASE-- Gerencial
                              WHEN P_INTERNO.vtESTOQUE.QTESTGER IS NOT NULL THEN
                                CASE-- Substituir Quantidade
                                  WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                    (NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0))
                                ELSE
                                  NVL(PCEST.QTESTGER, 0) + (CASE
                                                              WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                (NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) * (-1))
                                                            ELSE
                                                              NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0)
                                                            END)
                                END
                            ELSE
                              PCEST.QTESTGER
                            END
          ,PCEST.QTRESERV = CASE-- Reservado
                              WHEN P_INTERNO.vtESTOQUE.QTRESERV IS NOT NULL THEN
                                CASE-- Substituir Quantidade
                                  WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                    (NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0))
                                ELSE
                                  GREATEST(NVL(PCEST.QTRESERV, 0) + (CASE
                                                                       WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                         (NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) * (-1))
                                                                     ELSE
                                                                       NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0)
                                                                     END), 0)
                                END
                            ELSE
                              PCEST.QTRESERV
                            END
          ,PCEST.QTPENDENTE = CASE-- Pendente
                                WHEN P_INTERNO.vtESTOQUE.QTPENDENTE IS NOT NULL THEN
                                  CASE-- Substituir Quantidade
                                    WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                      (NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0))
                                  ELSE
                                    GREATEST(NVL(PCEST.QTPENDENTE, 0) + (CASE
                                                                           WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                             (NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0) * (-1))
                                                                         ELSE
                                                                           NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0)
                                                                         END), 0)
                                END
                              ELSE
                                PCEST.QTPENDENTE
                              END
          ,PCEST.QTBLOQUEADA = CASE-- Bloqueado
                                 WHEN P_INTERNO.vtESTOQUE.QTBLOQUEADA IS NOT NULL THEN
                                   CASE-- Substituir Quantidade
                                     WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                       (NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0))
                                   ELSE
                                     GREATEST(NVL(PCEST.QTBLOQUEADA, 0) + (CASE
                                                                             WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                               (NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) * (-1))
                                                                           ELSE
                                                                             NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0)
                                                                           END), 0)
                                   END
                               ELSE
                                 PCEST.QTBLOQUEADA
                               END
          ,PCEST.QTINDENIZ = CASE-- Avaria
                               WHEN P_INTERNO.vtESTOQUE.QTINDENIZ IS NOT NULL THEN
                                 CASE-- Substituir Quantidade
                                   WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                     (NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0))
                                 ELSE
                                   GREATEST(NVL(PCEST.QTINDENIZ, 0) + (CASE
                                                                         WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                           (NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0) * (-1))
                                                                       ELSE
                                                                         NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0)
                                                                       END), 0)
                                 END
                             ELSE
                               PCEST.QTINDENIZ
                             END
          ,PCEST.QTTRANSITO = CASE-- Transito
                                WHEN P_INTERNO.vtESTOQUE.QTTRANSITO IS NOT NULL THEN
                                  CASE-- Substituir Quantidade
                                    WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                      (NVL(P_INTERNO.vtESTOQUE.QTTRANSITO, 0))
                                  ELSE
                                    GREATEST(NVL(PCEST.QTTRANSITO, 0) + (CASE
                                                                           WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                             (NVL(P_INTERNO.vtESTOQUE.QTTRANSITO, 0) * (-1))
                                                                         ELSE
                                                                           NVL(P_INTERNO.vtESTOQUE.QTTRANSITO, 0)
                                                                         END), 0)
                                  END
                              ELSE
                                PCEST.QTTRANSITO
                              END
          ,PCEST.QTTRANSITOTV13 = CASE-- Transito TV13
                                    WHEN P_INTERNO.vtESTOQUE.QTTRANSITOTV13 IS NOT NULL THEN
                                      CASE-- Substituir Quantidade
                                        WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                          (NVL(P_INTERNO.vtESTOQUE.QTTRANSITOTV13, 0))
                                      ELSE
                                        GREATEST(NVL(PCEST.QTTRANSITOTV13, 0) + (CASE
                                                                                   WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                                     (NVL(P_INTERNO.vtESTOQUE.QTTRANSITOTV13, 0) * (-1))
                                                                                 ELSE
                                                                                   NVL(P_INTERNO.vtESTOQUE.QTTRANSITOTV13, 0)
                                                                                 END), 0)
                                      END
                                  ELSE
                                    PCEST.QTTRANSITOTV13
                                  END
          ,PCEST.QTFRENTELOJA = CASE-- Transito TV13
                                  WHEN P_INTERNO.vtESTOQUE.QTFRENTELOJA IS NOT NULL THEN
                                    CASE-- Substituir Quantidade
                                      WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                        (NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                    ELSE
                                      NVL(PCEST.QTFRENTELOJA, 0) + (CASE
                                                                               WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                                 (NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0) * (-1))
                                                                             ELSE
                                                                               NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0)
                                                                             END)
                                    END
                                ELSE
                                  PCEST.QTFRENTELOJA
                                END
          ,PCEST.QTINDUSTRIA = CASE-- Idunstria
                                 WHEN P_INTERNO.vtESTOQUE.QTINDUSTRIA IS NOT NULL THEN
                                   CASE-- Substituir Quantidade
                                     WHEN P_INTERNO.CALCULA_ESTOQUE = 'N' THEN
                                       (NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0))
                                   ELSE
                                     GREATEST(NVL(PCEST.QTINDUSTRIA, 0) + (CASE
                                                                             WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                               (NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) * (-1))
                                                                           ELSE
                                                                             NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0)
                                                                           END), 0)
                                   END
                               ELSE
                                 PCEST.QTINDUSTRIA
                               END
          ,PCEST.DTHORAULTALTDISP = CASE
                                      WHEN (NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTTRANSITO, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) > 0) OR
                                           (NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0) > 0)
                                       THEN
                                         SYSDATE
                                       ELSE
                                         PCEST.DTHORAULTALTDISP
                                     END
     WHERE PCEST.CODFILIAL = P_INTERNO.vtESTOQUE.CODFILIAL
       AND PCEST.CODPROD = P_INTERNO.vtESTOQUE.CODPROD;
    -- Consultar estoque
    SELECT QTESTGER
          ,QTEST
          ,QTRESERV
          ,QTBLOQUEADA
          ,QTINDENIZ
          ,QTPENDENTE
          ,QTFRENTELOJA
          ,QTTRANSITO
          ,QTTRANSITOTV13
      INTO vLOG.QTESTGER
          ,vLOG.QTEST
          ,vLOG.QTRESERV
          ,vLOG.QTBLOQUEADA
          ,vLOG.QTINDENIZ
          ,vLOG.QTPENDENTE
          ,vLOG.QTFRENTELOJA
          ,vLOG.QTTRANSITO
          ,vLOG.QTTRANSITOTV13
      FROM PCEST
     WHERE CODFILIAL = P_INTERNO.vtESTOQUE.CODFILIAL
       AND CODPROD = P_INTERNO.vtESTOQUE.CODPROD;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função atualizar estoque';
    PRIV_GERARLOG;
    -- Limpar dados
    vLOG.QTESTGERANT        := NULL;
    vLOG.QTESTGER           := NULL;
    vLOG.QTESTANT           := NULL;
    vLOG.QTEST              := NULL;
    vLOG.QTRESERVANT        := NULL;
    vLOG.QTRESERV           := NULL;
    vLOG.QTBLOQUEADAANT     := NULL;
    vLOG.QTBLOQUEADA        := NULL;
    vLOG.QTINDENIZANT       := NULL;
    vLOG.QTINDENIZ          := NULL;
    vLOG.QTPENDENTEANT      := NULL;
    vLOG.QTPENDENTE         := NULL;
    vLOG.QTFRENTELOJAANT    := NULL;
    vLOG.QTFRENTELOJA       := NULL;
    vLOG.QTTRANSITOANT      := NULL;
    vLOG.QTTRANSITO         := NULL;
    vLOG.QTTRANSITOTV13ANT  := NULL;
    vLOG.QTTRANSITOTV13     := NULL;
  -- Caso apresente erro ao atualizar
  EXCEPTION
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 - Atualizar Estoque: Não foi possível atualizar a quantidade pendente do estoque(PCEST).'||CHR(13)||
                               'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                               'Cód. Filial..: '||P_INTERNO.vtESTOQUE.CODFILIAL||CHR(13)||
                               'Produto......: '||TO_CHAR(P_INTERNO.vtESTOQUE.CODPROD)||CHR(13)||
                               'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                               'MSG Original.: '||SQLERRM;
      vLOG.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
  -- Procedure
  END PRIV_ATUALIZAR_ESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  03/12/2017     Fernandes Brito   0                   Criada procedure unica para atualização de dados na tabela PCLOTE
  /***********************************************************************************************************************/
  PROCEDURE PRIV_ATUALIZAR_LOTE
  IS-- Declaração das variáveis internas
  BEGIN
    -- Atualizando o estoque
    UPDATE PCLOTE
       SET PCLOTE.IDENTIFICADOR = P_INTERNO.vtLOTE.IDENTIFICADOR
          -- Contabil
          ,PCLOTE.QTEST = CASE
                            WHEN P_INTERNO.vtLOTE.QTEST IS NOT NULL THEN
                              NVL(PCLOTE.QTEST, 0) + (CASE
                                                        WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                          (NVL(P_INTERNO.vtLOTE.QTEST, 0) * (-1))
                                                      ELSE
                                                        NVL(P_INTERNO.vtLOTE.QTEST, 0)
                                                      END)
                          ELSE
                            PCLOTE.QTEST
                          END
          -- Gerencial
          ,PCLOTE.QT = CASE
                         WHEN P_INTERNO.vtLOTE.QT IS NOT NULL THEN
                           NVL(PCLOTE.QT, 0) + (CASE
                                                  WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                    (NVL(P_INTERNO.vtLOTE.QT, 0) * (-1))
                                                ELSE
                                                  NVL(P_INTERNO.vtLOTE.QT, 0)
                                                END)
                       ELSE
                         PCLOTE.QT
                       END
          -- Reservado
          ,PCLOTE.QTRESERV = CASE
                               WHEN P_INTERNO.vtLOTE.QTRESERV IS NOT NULL THEN
                                 GREATEST((NVL(PCLOTE.QTRESERV, 0) + (CASE
                                                                        WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                          (NVL(P_INTERNO.vtLOTE.QTRESERV, 0) * (-1))
                                                                      ELSE
                                                                        NVL(P_INTERNO.vtLOTE.QTRESERV, 0)
                                                                      END)),0)
                             ELSE
                               PCLOTE.QTRESERV
                             END
          -- Bloqueado
          ,PCLOTE.QTBLOQUEADA = CASE
                                  WHEN P_INTERNO.vtLOTE.QTBLOQUEADA IS NOT NULL THEN
                                    GREATEST((NVL(PCLOTE.QTBLOQUEADA, 0) + (CASE
                                                                              WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                                (NVL(P_INTERNO.vtLOTE.QTBLOQUEADA, 0) * (-1))
                                                                            ELSE
                                                                              NVL(P_INTERNO.vtLOTE.QTBLOQUEADA, 0)
                                                                            END)),0)
                                ELSE
                                  PCLOTE.QTBLOQUEADA
                                END
          -- Avaria
          ,PCLOTE.QTINDENIZ = CASE
                                WHEN P_INTERNO.vtLOTE.QTINDENIZ IS NOT NULL THEN
                                  GREATEST((NVL(PCLOTE.QTINDENIZ, 0) + (CASE
                                                                          WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                            (NVL(P_INTERNO.vtLOTE.QTINDENIZ, 0) * (-1))
                                                                        ELSE
                                                                          NVL(P_INTERNO.vtLOTE.QTINDENIZ, 0)
                                                                        END)),0)
                              ELSE
                                PCLOTE.QTINDENIZ
                              END
          -- Avaria
          ,PCLOTE.QTINDUSTRIA = CASE
                                  WHEN P_INTERNO.vtLOTE.QTINDUSTRIA IS NOT NULL THEN
                                    GREATEST((NVL(PCLOTE.QTINDUSTRIA, 0) + (CASE
                                                                              WHEN SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) = 'B' THEN
                                                                                (NVL(P_INTERNO.vtLOTE.QTINDUSTRIA, 0) * (-1))
                                                                            ELSE
                                                                              NVL(P_INTERNO.vtLOTE.QTINDUSTRIA, 0)
                                                                            END)),0)
                                ELSE
                                  PCLOTE.QTINDUSTRIA
                                END
     WHERE PCLOTE.CODFILIAL = P_INTERNO.vtLOTE.CODFILIAL
       AND PCLOTE.CODPROD = P_INTERNO.vtLOTE.CODPROD
       AND PCLOTE.NUMLOTE = P_INTERNO.vtLOTE.NUMLOTE;
  -- Erros
  EXCEPTION
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 - Atualizar Lote: Não foi possível atualizar a quantidade pendente do estoque(PCEST).'||CHR(13)||
                               'Identificador.: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                               'Cód. Filial...: '||TO_CHAR(P_INTERNO.vtLOTE.CODFILIAL)||CHR(13)||
                               'Produto.......: '||TO_CHAR(P_INTERNO.vtLOTE.CODPROD)||CHR(13)||
                               'Num. Lote.....: '||P_INTERNO.vtLOTE.NUMLOTE||CHR(13)||
                               'MSG Original..: '||SQLERRM;
  -- Procedure
  END PRIV_ATUALIZAR_LOTE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/12/2017     Fernandes Brito   0                   Criada procedure unica para atualização da movimentação de avaria
  /***********************************************************************************************************************/
  PROCEDURE PRIV_ATUALIZAR_PCMOVAVARIA (ptAVARIA       IN OUT PCMOVAVARIA%ROWTYPE
                                       ,psOPERACAO     IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE)

  IS-- Declaração das variáveis internas
    vnNUMTRANSACAO PCMOV.NUMTRANSVENDA%TYPE;
  BEGIN
    -- Entrada de avaria
    IF psOPERACAO = 'E' THEN
      -- Inserindo dados de entrada
      BEGIN
        -- Buscar transação de entrada
        IF (ptAVARIA.NUMTRANSENT > 0) AND (NVL(ptAVARIA.CODROTINALANC,0) <> 2641) THEN
          vnNUMTRANSACAO := ptAVARIA.NUMTRANSENT;
        ELSE
          vnNUMTRANSACAO := FERRAMENTAS.F_PROX_NUMTRANSENT;
        END IF;
        -- Inserindo dados na PCMOVAVARIA
        INSERT INTO PCMOVAVARIA
          (DATA,CODPROD,CODCLI,QT,CODOPER,CODFUNCLANC,NUMTRANSENT,OBS,DTMOVLOG,CODFILIAL,NUMLOTE,CODROTINALANC,CODDEVOL,NUMTRANSWMS,CODDEPOSITO)
        VALUES
          (ptAVARIA.DATA,ptAVARIA.CODPROD,ptAVARIA.CODCLI,ptAVARIA.QT,ptAVARIA.CODOPER,ptAVARIA.CODFUNCLANC,vnNUMTRANSACAO,ptAVARIA.OBS,SYSDATE,ptAVARIA.CODFILIAL,ptAVARIA.NUMLOTE,ptAVARIA.CODROTINALANC,ptAVARIA.CODDEVOL,ptAVARIA.NUMTRANSWMS,ptAVARIA.CODDEPOSITO);
      EXCEPTION
        WHEN OTHERS THEN
          P_INTERNO.MSG_RETORNO := 'Erro 1 - Atualizar Mov. Avaria: Não foi possível atualizar a tabela de movimentação de avaria (PCMOVAVARIA).'||CHR(13)||
                                   'Num. Trans. Entrada: '||TO_CHAR(ptAVARIA.NUMTRANSENT)||CHR(13)||
                                   'Filial.............: '||ptAVARIA.CODFILIAL||CHR(13)||
                                   'Produto............: '||TO_CHAR(ptAVARIA.CODPROD)||CHR(13)||
                                   'Num. Lote..........: '||ptAVARIA.NUMLOTE||CHR(13)||
                                   'Operação...........: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                   'MSG Original.......: '||SQLERRM;
      END;
    -- Saída de avaria
    ELSIF psOPERACAO = 'S' THEN
      -- Inserindo dados de saída
      BEGIN
        -- Buscar transação de saída
        IF (ptAVARIA.NUMTRANSVENDA > 0) AND (NVL(ptAVARIA.CODROTINALANC,0) <> 2641) THEN
          vnNUMTRANSACAO := ptAVARIA.NUMTRANSVENDA;
        ELSE
          vnNUMTRANSACAO := FERRAMENTAS.F_PROX_NUMTRANSVENDA;
        END IF;
        -- Inserindo dados na PCMOVAVARIA
        INSERT INTO PCMOVAVARIA
          (CODROTINALANC,NUMLOTE,DATA,CODPROD,CODCLI,QT,CODOPER,CODFUNCLANC,NUMTRANSVENDA,OBS,CODFILIAL,CODDEVOL,DTMOVLOG,NUMTRANSWMS,CODDEPOSITO)
        VALUES
          (ptAVARIA.CODROTINALANC,ptAVARIA.NUMLOTE,TRUNC(SYSDATE),ptAVARIA.CODPROD,ptAVARIA.CODCLI,ptAVARIA.QT,ptAVARIA.CODOPER,ptAVARIA.CODFUNCLANC,vnNUMTRANSACAO,ptAVARIA.OBS,ptAVARIA.CODFILIAL,ptAVARIA.CODDEVOL,SYSDATE,ptAVARIA.NUMTRANSWMS,ptAVARIA.CODDEPOSITO);
      EXCEPTION
        WHEN OTHERS THEN
          P_INTERNO.MSG_RETORNO := 'Erro 2 - Atualizar Mov. Avaria: Não foi possível atualizar a tabela de movimentação de avaria (PCMOVAVARIA).'||CHR(13)||
                                   'Num. Trans. Saída: '||TO_CHAR(ptAVARIA.NUMTRANSVENDA)||CHR(13)||
                                   'Filial...........: '||ptAVARIA.CODFILIAL||CHR(13)||
                                   'Produto..........: '||TO_CHAR(ptAVARIA.CODPROD)||CHR(13)||
                                   'Num. Lote........: '||ptAVARIA.NUMLOTE||CHR(13)||
                                   'Operação.........: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                   'MSG Original.....: '||SQLERRM;
      END;
    -- Operação errada
    ELSE
      P_INTERNO.MSG_RETORNO := 'Erro 3 - Atualizar Mov. Avaria: A operação informada não é valida'||CHR(13)||
                               'Operação: '||P_INTERNO.TIPO_OPERACAO;
    END IF;
  -- Procedure
  END PRIV_ATUALIZAR_PCMOVAVARIA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Função criada para baixar o estoque pendente de um pedido
  ************************************************************************************************************************/
  PROCEDURE PRIV_BLOQUEIO_BAIXAR_LOTE (psCODFILIAL           IN PCEST.CODFILIAL%TYPE
                                      ,pnCODPROD             IN PCEST.CODPROD%TYPE
                                      ,psNUMLOTE             IN PCMOV.NUMLOTE%TYPE
                                      ,pnQTBLOQUEADA         IN PCEST.QTBLOQUEADA%TYPE
                                      ,psMOTIVOBLOQESTOQUE   IN PCEST.MOTIVOBLOQESTOQUE%TYPE)
  IS-- Declaração das variáveis internas
    vnQTBLOQUEADA  PCEST.QTBLOQUEADA%TYPE := pnQTBLOQUEADA;
  BEGIN
    --Bloquear pclote
    UPDATE PCLOTE
       SET PCLOTE.QTBLOQUEADA = NVL(PCLOTE.QTINDENIZ, 0)
     WHERE PCLOTE.CODFILIAL = psCODFILIAL
       AND PCLOTE.DTBLOQUEIO1 IS NULL
       AND PCLOTE.CODPROD = pnCODPROD
       AND NVL(PCLOTE.QTINDENIZ, 0) > NVL(PCLOTE.QTBLOQUEADA, 0);
    -- Lista de lotes
    FOR LOTE IN (SELECT PCLOTE.ROWID ID
                      , NVL(PCLOTE.QTINDENIZ, 0) BLOQUEAR
                      , GREATEST((NVL(PCLOTE.QTBLOQUEADA, 0) - NVL(PCLOTE.QTINDENIZ, 0)), 0) DESBLOQUEAR
                   FROM PCLOTE
                  WHERE PCLOTE.CODFILIAL = psCODFILIAL
                    AND PCLOTE.DTBLOQUEIO1 IS NULL
                    AND PCLOTE.CODPROD = pnCODPROD
                    AND (psNUMLOTE IS NULL OR PCLOTE.NUMLOTE = PSNUMLOTE)
                    AND PCLOTE.QTBLOQUEADA > 0
               ORDER BY NVL(PCLOTE.DTVALIDADE, TRUNC(SYSDATE) + 365))
    LOOP
      -- Gravar log item a item da pclote
      IF (vnQTBLOQUEADA > 0) THEN
        UPDATE PCLOTE
           SET PCLOTE.MOTIVOBLOQESTOQUE = psMOTIVOBLOQESTOQUE
             , PCLOTE.QTBLOQUEADA = GREATEST((CASE
                                                WHEN(vnQTBLOQUEADA > LOTE.DESBLOQUEAR) THEN
                                                 (PCLOTE.QTBLOQUEADA - LOTE.DESBLOQUEAR)
                                              ELSE
                                                (PCLOTE.QTBLOQUEADA - vnQTBLOQUEADA)
                                              END), LOTE.BLOQUEAR)
         WHERE PCLOTE.ROWID = LOTE.ID;
        -- Atualizar quantidade
        vnQTBLOQUEADA := vnQTBLOQUEADA - LOTE.DESBLOQUEAR;
      -- Atualizar bloqueado
      END IF;
    -- Lista de lotes
    END LOOP;
  -- Procedure
  END PRIV_BLOQUEIO_BAIXAR_LOTE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  19/08/2017     Fernandes Brito   0                   Bloquear o estoque pendente do item na PCEST
  26/03/2019     Fernandes Brito   WT500-395           Incluido o bloqueio da PCEST único e excluido os demais
  /***********************************************************************************************************************/
  PROCEDURE PRIV_BLOQUEAR_ESTOQUE (psCODFILIAL     IN PCEST.CODFILIAL%TYPE
                                  ,pnCODPROD       IN PCEST.CODPROD%TYPE
                                  ,psMSG_RETORNO   OUT VARCHAR2)
  IS-- Declaração das variáveis internas
    vnCONTADOR  NUMBER := 0;
    vnTENTATIVA NUMBER := 0;
  BEGIN
    -- Tentar bloquear o estoque
    WHILE (vnTENTATIVA < 5 AND NVL(psMSG_RETORNO,' ') <> 'OK') LOOP
      -- Locar tabela para fazer a bloqueio e avaria
      BEGIN
        SELECT PCEST.CODPROD
          INTO vnCONTADOR
          FROM PCEST
         WHERE PCEST.CODPROD = pnCODPROD
           AND PCEST.CODFILIAL = psCODFILIAL
           FOR UPDATE;
        -- Tudo certo ao bloquear
        psMSG_RETORNO := 'OK';
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 1 - Bloquear Estoque: Verifique os dados informados!'||CHR(13)||
                           '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                           '2 - Os dados informados podem não ser validos!'||CHR(13)||
                           'Filial: '||psCODFILIAL||CHR(13)||
                           'Produto: '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Erro original: '||SQLCODE||' - '||SQLERRM;
      END;
      -- Se confeguiu bloquear
      IF psMSG_RETORNO = 'OK' THEN
        EXIT;
      END IF;
      -- Atualizar número de tentativas
      vnTENTATIVA := vnTENTATIVA + 1;
    -- Tentativas
    END LOOP;
  -- Procedure
  END PRIV_BLOQUEAR_ESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/05/2020     Fernandes Brito   DDESTOQUE-4758      Bloquear o estoque do depósito para atualização
  /***********************************************************************************************************************/
  PROCEDURE PRIV_BLOQUEAR_DEPOSITO (psCODFILIAL     IN PCEST.CODFILIAL%TYPE
                                   ,pnCODDEPOSITO   IN PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE
                                   ,pnCODPROD       IN PCEST.CODPROD%TYPE
                                   ,psMSG_RETORNO   OUT VARCHAR2)
  IS-- Declaração das variáveis internas
    vnCONTADOR NUMBER;
  BEGIN
    -- Locar tabela para fazer a bloqueio e avaria
    BEGIN
      SELECT PCESTOQUEDEPOSITOPROD.CODPROD
        INTO vnCONTADOR
        FROM PCESTOQUEDEPOSITOPROD
       WHERE PCESTOQUEDEPOSITOPROD.CODFILIAL = psCODFILIAL
         AND PCESTOQUEDEPOSITOPROD.CODDEPOSITO = pnCODDEPOSITO
         AND PCESTOQUEDEPOSITOPROD.CODPROD = pnCODPROD
      FOR UPDATE;
      -- Tudo certo ao bloquear
      psMSG_RETORNO := 'OK';
    EXCEPTION
      WHEN OTHERS THEN
        psMSG_RETORNO := 'Erro 1 - Bloquear Estoque do Depósito: Verifique os dados informados!'||CHR(13)||
                         '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                         '2 - Os dados informados podem não ser validos!'||CHR(13)||
                         'Filial......: '||psCODFILIAL||CHR(13)||
                         'Depósito....: '||TO_CHAR(pnCODDEPOSITO)||CHR(13)||
                         'Produto.....: '||TO_CHAR(pnCODPROD)||CHR(13)||
                         'Erro original: '||SQLCODE||' - '||SQLERRM;
    END;
  -- Procedure
  END PRIV_BLOQUEAR_DEPOSITO;

