  PROCEDURE PRIV_BLOQUEAR_LOTE
  IS-- Declaração das variáveis internas
  BEGIN
    SELECT PCLOTE.CODPROD
      INTO P_INTERNO.CONTADOR
      FROM PCLOTE
     WHERE PCLOTE.CODFILIAL = P_INTERNO.vtLOTE.CODFILIAL
