  END PRIV_BLOQUEAR_LOTE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor              Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  16/09/2020     Marcelo Hakenhoar  DDLEGFIN-871        Criado a procedure para administrar o processo de transferência na saída da TV10.
  /***********************************************************************************************************************/  
  PROCEDURE PRIV_COMPRAS_TERCEIRO (pnCODPROD       IN PCPRODUT.CODPROD%TYPE
                                  ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                  ,pnNUMTRANSACAO  IN PCNFENT.NUMTRANSENT%TYPE
                                  ,pnCODFORNEC     IN PCFORNEC.CODFORNEC%TYPE
                                  ,psCNPJ          IN PCFILIAL.CGC%TYPE
                                  ,psCODFISCAL     IN PCMOV.CODFISCAL%TYPE
                                  ,pnQTDE          IN PCEST.QTEST%TYPE
                                  ,psCODFILIAL     IN PCFILIAL.CODIGO%TYPE)
  IS
    vsESTOQUEEMTRANSITO PCCFO.ESTOQUEEMTRANSITO%TYPE;
    vsCODFILIALORIGEM   PCFILIAL.CODIGO%TYPE;
    vnCONTADOR          NUMBER;
    vbEH_TV10           BOOLEAN;
    vnNUMTRANSVENDA     PCNFSAID.NUMTRANSVENDA%TYPE;
  BEGIN
    BEGIN
      SELECT NVL(ESTOQUEEMTRANSITO, 'N')
        INTO vsESTOQUEEMTRANSITO
        FROM PCCFO
       WHERE CODFISCAL = psCODFISCAL;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vsESTOQUEEMTRANSITO := 'N';
    END;

    IF vsESTOQUEEMTRANSITO = 'S' THEN
        BEGIN
        SELECT NUMTRANSVENDAORIG
            INTO vnNUMTRANSVENDA
            FROM PCNFENT
        WHERE NUMTRANSENT = pnNUMTRANSACAO
		  AND ESPECIE IN ('NF', 'NE');
        EXCEPTION
        WHEN OTHERS THEN
            vnNUMTRANSVENDA := NULL;
        END;

        BEGIN
        vbEH_TV10 := FALSE;

        SELECT COUNT (1)
            INTO vnCONTADOR
            FROM PCNFSAID
        WHERE NUMTRANSVENDA = vnNUMTRANSVENDA
            AND CONDVENDA = 10;

        vbEH_TV10 := (vnCONTADOR > 0);
        EXCEPTION
        WHEN OTHERS THEN
            vbEH_TV10 := FALSE;
        END;

      IF vbEH_TV10 THEN
        BEGIN
            SELECT CODIGO
            INTO vsCODFILIALORIGEM
            FROM PCFILIAL
            WHERE CODFORNEC = pnCODFORNEC;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
            vsCODFILIALORIGEM := NULL;
            P_INTERNO.MSG_RETORNO := 'Erro 1 (PRIV_COMPRAS_TERCEIRO): O fornecedor informado não pertence a nenhuma filial';
			WHEN TOO_MANY_ROWS THEN
            P_INTERNO.MSG_RETORNO := 'Erro 2 (PRIV_COMPRAS_TERCEIRO): O fornecedor da nota fiscal está vinculado em mais de uma filial.' || CHR(13) ||
                                    'Favor, realizar o ajuste na rotina 535.' || CHR(13) ||
                                    'Transação: ' || TO_CHAR(pnNUMTRANSACAO);
            vsCODFILIALORIGEM := NULL;
        END;

        IF pnCODPROD IS NOT NULL THEN
		
		IF psCODFILIAL IS NOT NULL AND
            vsCODFILIALORIGEM IS NOT NULL AND
            psCNPJ IS NOT NULL THEN

            IF psECANCELAMENTO = 'N' THEN
            UPDATE PCEST
                SET QTESTOQUEDETERCEIRO = NVL(QTESTOQUEDETERCEIRO, 0) - pnQTDE
            WHERE CODFILIAL = vsCODFILIALORIGEM
                AND CODPROD = pnCODPROD;

            UPDATE PCEST
                SET QTTRANSITOTV10 = NVL(QTTRANSITOTV10, 0) - pnQTDE
            WHERE CODFILIAL = psCODFILIAL
                AND CODPROD = pnCODPROD;

            UPDATE PCESTOQUETERCEIRO
                SET QUANTIDADE = NVL(QUANTIDADE, 0) - pnQTDE
            WHERE CODPROD = pnCODPROD
                AND CODFILIAL = vsCODFILIALORIGEM
                AND CODFILIALDESTINO = psCODFILIAL
                AND CNPJDESTINO = psCNPJ;
            ELSE
            UPDATE PCEST
                SET QTESTOQUEDETERCEIRO = NVL(QTESTOQUEDETERCEIRO, 0) + pnQTDE
            WHERE CODFILIAL = vsCODFILIALORIGEM
                AND CODPROD = pnCODPROD;

            UPDATE PCEST
                SET QTTRANSITOTV10 = NVL(QTTRANSITOTV10, 0) + pnQTDE
            WHERE CODFILIAL = psCODFILIAL
                AND CODPROD = pnCODPROD;

            UPDATE PCESTOQUETERCEIRO
                SET QUANTIDADE = NVL(QUANTIDADE, 0) + pnQTDE
            WHERE CODPROD = pnCODPROD
                AND CODFILIAL = vsCODFILIALORIGEM
                AND CODFILIALDESTINO = psCODFILIAL
                AND CNPJDESTINO = psCNPJ;
            END IF;
        ELSE
          IF vsCODFILIALORIGEM IS NOT NULL THEN
            IF psCODFILIAL IS NULL AND psCNPJ IS NOT NULL AND P_INTERNO.TESTEPROCEDURE = 'S' THEN 
              P_INTERNO.MSG_RETORNO := 'Erro 3 (PRIV_COMPRAS_TERCEIRO): FALTA PARAMETRO FILIAL';
            ELSIF psCODFILIAL IS NOT NULL AND psCNPJ IS NULL AND P_INTERNO.TESTEPROCEDURE = 'S' THEN
              P_INTERNO.MSG_RETORNO := 'Erro 4 (PRIV_COMPRAS_TERCEIRO): FALTA PARAMETRO CNPJ';
            ELSIF P_INTERNO.TESTEPROCEDURE = 'S' THEN
              P_INTERNO.MSG_RETORNO := 'Erro 5 (PRIV_COMPRAS_TERCEIRO): FALTA PARAMETRO DE FILIAL E CNPJ'; 
            END IF;
          END IF;
        END IF;
       ELSIF P_INTERNO.TESTEPROCEDURE = 'S' THEN
         P_INTERNO.MSG_RETORNO := 'Erro 6 (PRIV_COMPRAS_TERCEIRO): FALTA PARAMETRO DE PRODUTO';
       END IF;  
      ELSIF P_INTERNO.TESTEPROCEDURE = 'S' THEN
        P_INTERNO.MSG_RETORNO := 'Erro 7 (PRIV_COMPRAS_TERCEIRO): ERRO SELECT TV10'; 
      END IF;
    ELSIF P_INTERNO.TESTEPROCEDURE = 'S' THEN
      P_INTERNO.MSG_RETORNO := 'Erro 8 (PRIV_COMPRAS_TERCEIRO): ERRO SELECT PCCFO';
    END IF;
  -- Procedure
  END PRIV_COMPRAS_TERCEIRO;
  
  FUNCTION PRIV_COMPRAS_TERCEIRO (pnCODPROD       IN PCPRODUT.CODPROD%TYPE
                                  ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                  ,pnNUMTRANSACAO  IN PCNFENT.NUMTRANSENT%TYPE
                                  ,pnCODFORNEC     IN PCFORNEC.CODFORNEC%TYPE
                                  ,psCNPJ          IN PCFILIAL.CGC%TYPE
                                  ,psCODFISCAL     IN PCMOV.CODFISCAL%TYPE
                                  ,pnQTDE          IN PCEST.QTEST%TYPE
                                  ,psCODFILIAL     IN PCFILIAL.CODIGO%TYPE
                                  ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS
  BEGIN
    psMSG_RETORNO := 'OK';
    P_INTERNO.TESTEPROCEDURE := 'S';
    PRIV_COMPRAS_TERCEIRO (pnCODPROD       

                          ,psECANCELAMENTO 
                          ,pnNUMTRANSACAO  
                          ,pnCODFORNEC     
                          ,psCNPJ          
                          ,psCODFISCAL     
                          ,pnQTDE          
                          ,psCODFILIAL);
    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
    IF psMSG_RETORNO <> 'OK' THEN
      RETURN 0;
    ELSE
      RETURN 1;
    END IF;     
  END;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Consultar dados antes de iniciar a transação
  ************************************************************************************************************************************************************
  INFORMAÇÕES IMPORTANTES:
  Esta função deve ser chamada sempre que houver a necessidade de validar a quantidade contida na transação antes da execução da PKG_ESTOQUE
  Esta função NUNCA PODE FAZER COMANDO DE ALTERAÇÃO
  /**********************************************************************************************************************************************************/
  PROCEDURE PRIV_CONS_DADOS_ANTERIORES (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                       ,pnCODPROD       IN PCPEDI.CODPROD%TYPE
                                       ,pnNUMSEQ        IN PCPEDI.NUMSEQ%TYPE
                                       ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                       ,pnCONDVENDA     OUT PCPEDC.CONDVENDA%TYPE
                                       ,psPOSICAO       OUT PCPEDC.POSICAO%TYPE
                                       ,pnQTDE          OUT PCMOV.QT%TYPE
                                       ,psCODFILIAL     OUT PCPEDC.CODFILIAL%TYPE
                                       ,psMSG_RETORNO   OUT VARCHAR2)
  IS-- Declaração das variáveis internas
    PRAGMA AUTONOMOUS_TRANSACTION;
  BEGIN
    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
    CASE -- Indústria baixar/alterar
      WHEN psOPERACAO IN ('BI', 'AI') THEN
        -- Consultando se a ordem de produção é valida
        BEGIN
          SELECT PCOPC.CODFILIAL, PCOPI.QTRESERVATUAL
            INTO psCODFILIAL, pnQTDE
            FROM PCOPI
                ,PCOPC
           WHERE PCOPI.NUMOP = PCOPC.NUMOP
             AND PCOPI.NUMOP = pnIDENTIFICADOR
             AND PCOPI.CODPROD = pnCODPROD
             AND PCOPC.POSICAO = 'P';
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 - Cons. Dados Anteriores: Não foi possível fazer a consulta do Identificador informado'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            RETURN;
        END;
      -- Ordem de serviço baixar/alterar
      WHEN psOPERACAO IN ('BO', 'AO') THEN
        --Consultando se a ordem de serviço é valido
        BEGIN
          SELECT PCORDEMSERVICO.CODFILIAL
                ,NVL(SUM(PCITEMSERVICO.QTDE), 0) QT
            INTO psCODFILIAL
                ,pnQTDE
            FROM PCORDEMSERVICO, PCORDEMSERVICOI, PCITEMSERVICO
           WHERE PCORDEMSERVICO.NUMOS = PCORDEMSERVICO.NUMOS
             AND PCORDEMSERVICOI.NUMOSSERVICO = PCITEMSERVICO.NUMOSSERVICO
             AND PCORDEMSERVICO.NUMOS = pnIDENTIFICADOR
             AND PCITEMSERVICO.CODPROD = pnCODPROD
        GROUP BY PCORDEMSERVICO.CODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 2 - Cons. Dados Anteriores: Não foi possível fazer a consulta do Identificador informado'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            RETURN;
        END;
      -- Requisição de depósito/Embalagem/Lote
      WHEN psOPERACAO IN ('BR', 'AR') THEN
        -- Consultar itens para baixar a reserva
        BEGIN
          SELECT NVL(RI.QT, 0) QT
                ,RI.CODFILIAL
                ,RI.CODDEPOSITOORIG
            INTO pnQTDE
                ,psCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCREQUISICAODEPOSITO RI
           WHERE RI.POSICAO = 'A'
             AND RI.CODREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL   := psCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 4 - Dados Anteriores: Não foi possível consultar dados do item da requisição para baixar a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            RETURN;
        END;
      -- Caso seja qualquer outro tipo de OPERAÇÃO
      ELSE
        --Validando a filial e filial retira
        psCODFILIAL := VALIDA_CODFILIAL_CEFAT( PNIDENTIFICADOR, PNCODPROD, PNNUMSEQ);
        P_INTERNO.CODFILIAL   := psCODFILIAL;
        --Consultando se o pedido é valido
        BEGIN
          SELECT PCPEDC.CONDVENDA
                ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                ,PCPEDI.QT
            INTO pnCONDVENDA
                ,psPOSICAO
                ,pnQTDE
            FROM PCPEDI, PCPEDC
           WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
             AND PCPEDI.NUMPED = pnIDENTIFICADOR
             AND PCPEDI.CODPROD = pnCODPROD
             AND PCPEDI.NUMSEQ = pnNUMSEQ;
             --AND NVL(PCPEDI.QT,0) > 0;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 3 - Cons. Dados Anteriores: Não foi possível fazer a consulta do Identificador informado'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            RETURN;
        END;
    -- Validação da OPERAÇÃO
    END CASE;
  -- Procedure
  END PRIV_CONS_DADOS_ANTERIORES;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/06/2021    Fernandes Brito    0                   Consultar dados da movimentação (PCMOV) antes de iniciar a transação para administradora
  ************************************************************************************************************************************************************
  INFORMAÇÕES IMPORTANTES:
  Esta função deve ser chamada sempre que houver a necessidade de validar a quantidade contida na transação antes da execução da PKG_ESTOQUE
  Esta função NUNCA PODE FAZER COMANDO DE ALTERAÇÃO
  /**********************************************************************************************************************************************************/
  FUNCTION PRIV_CONS_MOV_ANTERIORES (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                    ,pnNUMTRANSVENDA   IN PCMOV.NUMTRANSVENDA%TYPE
                                    ,pnNUMTRANSENT     IN PCMOV.NUMTRANSENT%TYPE
                                    ,pnCODPROD         IN PCMOV.CODPROD%TYPE
                                    ,pnNUMSEQ          IN PCMOV.NUMSEQ%TYPE
                                    ,psPROCESSO        IN VARCHAR2)
  RETURN TB_DADOS_MOV PIPELINED
  IS-- Declaração das variáveis internas
    PRAGMA AUTONOMOUS_TRANSACTION;
    vrDADOS TYPE_DADOS_MOV;
  BEGIN
    -- Buscar dados saída
    BEGIN
      SELECT CONDVENDA
        INTO vrDADOS.OLD_CONDVENDA
        FROM PCPEDC
       WHERE NUMPED = pnIDENTIFICADOR;
    EXCEPTION
      WHEN OTHERS THEN
        vrDADOS.OLD_CONDVENDA := NULL;
    END;
    -- Processo
    CASE psPROCESSO
      WHEN 'PRODUZIR' THEN
      -- Lista de itens
      FOR PEDIDOS IN (SELECT PCMOV.NUMPED
                            ,PCMOV.NUMTRANSVENDA
                            ,PCMOV.NUMTRANSENT
                            ,PCMOV.CODPROD
                            ,PCMOV.NUMSEQ
                            ,NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL) CODFILIAL
                            ,PCMOV.QT
                            ,PCMOV.QTCONT
                            ,PCMOV.DTCANCEL
                            ,PCMOV.CODOPER
                        FROM PCMOV
                       WHERE PCMOV.NUMPED = pnIDENTIFICADOR
                         AND PCMOV.CODOPER IN ('SP','EP')
                         AND (PCMOV.QT > 0 OR PCMOV.QTCONT > 0)
                         AND (pnNUMTRANSVENDA IS NULL OR PCMOV.NUMTRANSVENDA = pnNUMTRANSVENDA)
                         AND (pnNUMTRANSENT IS NULL OR PCMOV.NUMTRANSENT = pnNUMTRANSENT)
                         AND (pnCODPROD IS NULL OR PCMOV.CODPROD = pnCODPROD)
                         AND (pnNUMSEQ IS NULL OR PCMOV.NUMSEQ = pnNUMSEQ))
      LOOP
        vrDADOS.OLD_NUMPED         := PEDIDOS.NUMPED;
        vrDADOS.OLD_NUMTRANSVENDA  := PEDIDOS.NUMTRANSVENDA;
        vrDADOS.OLD_NUMTRANSENT    := PEDIDOS.NUMTRANSENT;
        vrDADOS.OLD_CODPROD        := PEDIDOS.CODPROD;
        vrDADOS.OLD_NUMSEQ         := PEDIDOS.NUMSEQ;
        vrDADOS.OLD_CODFILIAL      := PEDIDOS.CODFILIAL;
        vrDADOS.OLD_QT             := PEDIDOS.QT;
        vrDADOS.OLD_QTCONT         := PEDIDOS.QTCONT;
        vrDADOS.OLD_DTCANCEL       := PEDIDOS.DTCANCEL;
        vrDADOS.OLD_CODOPER        := PEDIDOS.CODOPER;
        -- Retornando dos dados
        PIPE ROW (vrDADOS);
      -- Lista de itens
      END LOOP;
    -- Processo
    END CASE;
  -- Procedure
  END PRIV_CONS_MOV_ANTERIORES;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  15/03/2018    Lucas Costa        0                   Consultar dados de produção industrial antes de iniciar a transação para administradora
  ************************************************************************************************************************************************************
  INFORMAÇÕES IMPORTANTES:
  Esta função deve ser chamada sempre que houver a necessidade de validar a quantidade contida na transação antes da execução da PKG_ESTOQUE
  Esta função NUNCA PODE FAZER COMANDO DE ALTERAÇÃO
  /**********************************************************************************************************************************************************/
  FUNCTION PRIV_CONS_OP_ANTERIORES (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE)
  RETURN TB_DADOS_PEDIDO PIPELINED
  IS-- Declaração das variáveis internas
    PRAGMA AUTONOMOUS_TRANSACTION;
    vrDADOS TYPE_DADOS_PEDIDO;
  BEGIN
    -- Lista os LOTES para baixar reservar
    FOR REGISTROS IN (SELECT ROUND(SUM(L.QT - NVL(L.QTREQUISITADO,0)),6) QT
                            ,L.NUMLOTE
                            ,P.CODFILIAL
                            ,L.CODPROD
                        FROM PCOPILOTE L
                            ,PCOPC P
                       WHERE P.NUMOP = L.NUMOP
                         AND P.NUMOP = pnIDENTIFICADOR
                         AND P.FINALIZAPRODUCAO = 'N'
                         AND NVL(P.QTPRODUZIDA,0) < NVL(P.QTPRODUZIR,0)
                         AND NVL(L.QTREQUISITADO,0) < NVL(L.QT,0)
                    GROUP BY P.NUMOP, L.NUMLOTE, P.CODFILIAL, L.CODPROD)
    LOOP
      vrDADOS.OLD_CODPROD   := REGISTROS.CODPROD;
      vrDADOS.OLD_NUMLOTE   := REGISTROS.NUMLOTE;
      vrDADOS.OLD_QTDE      := REGISTROS.QT;
      vrDADOS.OLD_CODFILIAL := REGISTROS.CODFILIAL;
      -- Retornando dos dados
      PIPE ROW (vrDADOS);
    END LOOP;
  -- Procedure
  END PRIV_CONS_OP_ANTERIORES;

