  -------------------------------------------------------------------------------------------------------------------------
  27/04/2021    Fernandes Brito    0                   Consultar dados do pedido antes de iniciar a transação para administradora
  ************************************************************************************************************************************************************
  INFORMAÇÕES IMPORTANTES:
  Esta função deve ser chamada sempre que houver a necessidade de validar a quantidade contida na transação antes da execução da PKG_ESTOQUE
  Esta função NUNCA PODE FAZER COMANDO DE ALTERAÇÃO
  /**********************************************************************************************************************************************************/
  FUNCTION PRIV_CONS_PEDIDOS_ANTERIORES (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                        ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                                        ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE)
  RETURN TB_DADOS_PEDIDO PIPELINED
  IS-- Declaração das variáveis internas
    PRAGMA AUTONOMOUS_TRANSACTION;
    vrDADOS TYPE_DADOS_PEDIDO;
  BEGIN
    -- Lista de itens
    FOR PEDIDOS IN (SELECT PCPEDC.NUMPED
                          ,PCPEDI.CODPROD
                          ,PCPEDI.NUMSEQ
                          ,NVL(PCPEDC.CODFILIAL, PCPEDI.CODFILIALRETIRA) CODFILIAL
                          ,PCPEDC.CONDVENDA
                          ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                          ,PCPEDI.QT QTDE
                          ,PCPEDI.NUMLOTE
                      FROM PCPEDI, PCPEDC
                     WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                       AND PCPEDI.NUMPED = pnIDENTIFICADOR
                       AND (pnCODPROD IS NULL OR PCPEDI.CODPROD = pnCODPROD)
                       AND (pnNUMSEQ IS NULL OR PCPEDI.NUMSEQ = pnNUMSEQ))
    LOOP
      vrDADOS.OLD_IDENTIFICADOR  := PEDIDOS.NUMPED;
      vrDADOS.OLD_CODPROD        := PEDIDOS.CODPROD;
      vrDADOS.OLD_NUMSEQ         := PEDIDOS.NUMSEQ;
      vrDADOS.OLD_CODFILIAL      := PEDIDOS.CODFILIAL;
      vrDADOS.OLD_CONDVENDA      := PEDIDOS.CONDVENDA;
      vrDADOS.OLD_POSICAO        := PEDIDOS.POSICAO;
      vrDADOS.OLD_QTDE           := PEDIDOS.QTDE;
      vrDADOS.OLD_NUMLOTE        := PEDIDOS.NUMLOTE;
      -- Retornando dos dados
      PIPE ROW (vrDADOS);
    -- Lista de itens
    END LOOP;
  -- Procedure
  END PRIV_CONS_PEDIDOS_ANTERIORES;

