  PROCEDURE PRIV_CONS_ESTOQUE_ATUAL (ptESTOQUE IN OUT PCEST%ROWTYPE)
  IS-- Declaração das variáveis internas
  BEGIN
    -- Consultando dados do estoque
    BEGIN
      SELECT *
        INTO ptESTOQUE
        FROM PCEST
       WHERE PCEST.CODFILIAL = ptESTOQUE.CODFILIAL
         AND PCEST.CODPROD = ptESTOQUE.CODPROD;
    EXCEPTION
      WHEN OTHERS THEN
        PTESTOQUE := PTESTOQUE;
    END;
  -- Procedure
  END PRIV_CONS_ESTOQUE_ATUAL;

