        ptHISTORICO.QTFRENTELOJA   := 0;
        ptHISTORICO.QTTRANSITOTV13 := 0;
        ptHISTORICO.QTINDUSTRIA    := 0;
    END;
  -- Procedure
  END PRIV_CONS_HISTORICO;

