  21/08/2017    Fernandes Brito    0                   Consultar informações e parâmetros do produto
  /**********************************************************************************************************************************************************/
  PROCEDURE PRIV_CONS_PRODUTO (pnCODPROD         IN PCPRODUT.CODPROD%TYPE
                              ,psUSAWMS          OUT PCPRODUT.USAWMS%TYPE
                              ,psESTOQUEPORLOTE  OUT PCPRODUT.ESTOQUEPORLOTE%TYPE
                              ,pnQTUNITCX        OUT PCPRODUT.QTUNITCX%TYPE
                              ,psTIPOMERC        OUT PCPRODUT.TIPOMERC%TYPE
                              ,psPESOVARIAVEL    OUT PCPRODUT.PESOVARIAVEL%TYPE)
  IS-- Declaração das variáveis internas
  BEGIN
    -- Consultando dados do produto
    SELECT PCPRODUT.USAWMS
          ,PCPRODUT.ESTOQUEPORLOTE
          ,PCPRODUT.QTUNITCX
          ,PCPRODUT.TIPOMERC
          ,PCPRODUT.PESOVARIAVEL
      INTO psUSAWMS
          ,psESTOQUEPORLOTE
          ,pnQTUNITCX
          ,psTIPOMERC
          ,psPESOVARIAVEL
      FROM PCPRODUT
     WHERE PCPRODUT.CODPROD = pnCODPROD;
  -- Erro na buscar do produto
  EXCEPTION
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 - Cons. Produto: Não foi possível consultar o produto!'||CHR(13)||
                               'Cód. Produto.: '||pnCODPROD||CHR(13)||
                               'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                               'MSG Original.: '||SQLERRM;
  -- Procedure
  END PRIV_CONS_PRODUTO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/11/2015   Rodrigo Santos      0.119485.2015       Migrados os métodos "PRIV_DEFINIR_MOVESTOQUE" e "PROCESSA_MOVESTOQUE" para
                                                       a package PKG_ESTOQUE.
  06/08/2019   Fernandes Brito     0                   Restruturação da PKG_ESTOQUE para padronizar e reduzir código
  ************************************************************************************************************************/
  PROCEDURE PRIV_DEFINIR_MOVESTOQUE
  IS-- Declaração das variáveis internas
  BEGIN
    --Verificação da nota original se e de cupom fiscal
    BEGIN
      IF SUBSTR(P_INTERNO.CODOPER,1,1) = 'S' THEN
        SELECT S.SERIE
              ,TD.NUMTRANSVENDA
          INTO P_INTERNO.SERIENOTAORIGEM
              ,P_INTERNO.NUMTRANSACAOORIGEM
          FROM PCTRANSFDEP TD, PCNFSAID S
         WHERE S.NUMTRANSVENDA = TD.NUMTRANSVENDA(+)
           AND TD.NUMTRANSTRANSFSAIDA = P_INTERNO.IDENTIFICADOR
           AND ROWNUM = 1;
      END IF;
      IF SUBSTR(P_INTERNO.CODOPER,1,1) = 'E' THEN
        SELECT S.SERIE
              ,TD.NUMTRANSVENDA
          INTO P_INTERNO.SERIENOTAORIGEM
              ,P_INTERNO.NUMTRANSACAOORIGEM
          FROM PCTRANSFDEP TD, PCNFSAID S
         WHERE S.NUMTRANSVENDA = TD.NUMTRANSVENDA(+)
           AND TD.NUMTRANSTRANSFENT = P_INTERNO.IDENTIFICADOR
           AND ROWNUM = 1;
      END IF;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        P_INTERNO.SERIENOTAORIGEM    := '';
        P_INTERNO.NUMTRANSACAOORIGEM := 0;
    END;
    BEGIN
      SELECT S.CONDVENDA
            ,NVL(S.BROKER, 'N')
            ,NVL(P.NUMNOTACONSIG, 0)
        INTO P_INTERNO.CONDVENDA
            ,P_INTERNO.BROKER
            ,P_INTERNO.NUMNOTACONSIG
        FROM PCNFSAID S
           , PCPEDC P
       WHERE S.NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR
         AND S.NUMPED = P.NUMPED(+);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        P_INTERNO.CONDVENDA     := 0;
        P_INTERNO.BROKER        := '';
        P_INTERNO.NUMNOTACONSIG := 0;
    END;
    -- Buscar situação da NFe para definir movimentação do estoque
    BEGIN
      SELECT NVL(PCNFSAID.SITUACAONFE,'0')
        INTO P_INTERNO.SITUACAONFE
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.SITUACAONFE := '0';
    END;
    --
    IF SUBSTR(P_INTERNO.CODOPER,1,1) = 'E' THEN
      BEGIN
        SELECT PCNFENT.DEVSIMBOLICA
          INTO P_INTERNO.DEVOLUCAOSIMBOLICA
          FROM PCNFENT
         WHERE PCNFENT.NUMTRANSENT = P_INTERNO.IDENTIFICADOR;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          P_INTERNO.DEVOLUCAOSIMBOLICA := 'N';
      END;
    END IF;
    -- Caso a operação seja de saída
    IF (SUBSTR(P_INTERNO.CODOPER,1,1) = 'S' AND P_INTERNO.SITUACAONFE NOT IN (110,205,301,302)) THEN
      -- Lista de itens
      FOR ITENS IN (SELECT PCMOV.CODPROD
                          ,PCMOV.CODOPER
                          ,PCMOV.STATUS
                          ,PCMOV.NUMTRANSENT
                          ,PCMOV.NUMTRANSVENDA
                          ,ORIGEM_TRANSFERENCIA(P_INTERNO.IDENTIFICADOR) ORIG_TRANSF
                          ,PCMOV.TIPOITEM
                          ,PCMOV.ROWID ROWID_PCMOV
                          ,NVL(PCMOVCOMPLE.VERSAOREGISTRO, '0') VERSAOREGISTRO
                      FROM PCMOV
                          ,PCMOVCOMPLE
                     WHERE PCMOV.NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR
                       AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+))
      LOOP
        -- Case seja cupom fiscal
        IF P_INTERNO.SERIENOTAORIGEM = 'CF' THEN
          BEGIN
            SELECT ORIGEM_TRANSFERENCIA(P_INTERNO.IDENTIFICADOR) ORIG_TRANSF
              INTO P_INTERNO.ORIGTRANSFORIGEM
              FROM PCMOV
             WHERE PCMOV.NUMTRANSVENDA = P_INTERNO.NUMTRANSACAOORIGEM
               AND PCMOV.CODPROD = ITENS.CODPROD
               AND ROWNUM = 1;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              P_INTERNO.ORIGTRANSFORIGEM := '';
          END;
        -- Cupom fiscal
        END IF;
        -- Processar movimentações
        P_INTERNO.CODOPER        := ITENS.CODOPER;
        P_INTERNO.STATUS         := ITENS.STATUS;
        P_INTERNO.NUMTRANSENT    := ITENS.NUMTRANSENT;
        P_INTERNO.ROWID_REGISTRO := ITENS.ROWID_PCMOV;
        PRIV_PROCESSA_MOVESTOQUE;
      -- Lista de produtos
      END LOOP;
    -- Caso seja entrada
    ELSIF P_INTERNO.CODOPER = 'E' THEN
      -- Lista de produtos
      FOR ITENS IN (SELECT PCMOV.CODPROD
                          ,PCMOV.CODOPER
                          ,PCMOV.STATUS
                          ,PCMOV.NUMTRANSENT
                          ,PCMOV.NUMTRANSVENDA
                          ,ORIGEM_TRANSFERENCIA(P_INTERNO.IDENTIFICADOR) ORIG_TRANSF
                          ,PCMOV.TIPOITEM
                          ,PCMOV.ROWID ROWID_PCMOV
                          ,NVL(PCMOVCOMPLE.VERSAOREGISTRO, '0') VERSAOREGISTRO
                      FROM PCMOV
                          ,PCMOVCOMPLE
                     WHERE PCMOV.NUMTRANSENT = P_INTERNO.IDENTIFICADOR
                       AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+))
      LOOP
        -- Caso seja copom fiscal
        IF P_INTERNO.SERIENOTAORIGEM = 'CF' THEN
          BEGIN
            SELECT ORIGEM_TRANSFERENCIA(P_INTERNO.IDENTIFICADOR) ORIG_TRANSF
              INTO P_INTERNO.ORIGTRANSFORIGEM
              FROM PCMOV
             WHERE PCMOV.NUMTRANSENT = P_INTERNO.NUMTRANSACAOORIGEM
               AND PCMOV.CODPROD = ITENS.CODPROD
               AND ROWNUM = 1;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              P_INTERNO.ORIGTRANSFORIGEM := '';
          END;
        -- Cupom fiscal
        END IF;
        -- Processar tipo de movimentações de estoque
        P_INTERNO.CODOPER        := ITENS.CODOPER;
        P_INTERNO.STATUS         := ITENS.STATUS;
        P_INTERNO.NUMTRANSENT    := ITENS.NUMTRANSENT;
        P_INTERNO.ROWID_REGISTRO := ITENS.ROWID_PCMOV;
        PRIV_PROCESSA_MOVESTOQUE;
      -- Lista de produtos
      END LOOP;
    -- Caso a operação não seja saída ou entrada
    ELSE
      -- Definindo movimentação contábil e gerencial na pcmov
      UPDATE PCMOV
         SET PCMOV.MOVESTOQUECONTABIL  = 'N',
             PCMOV.MOVESTOQUEGERENCIAL = 'N'
       WHERE PCMOV.NUMTRANSVENDA = P_INTERNO.IDENTIFICADOR;
    -- Validação do tipo de operação
    END IF;
  -- Procedure
  END PRIV_DEFINIR_MOVESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  17/03/2020     Fernandes Brito   0                   Criada função para buscar a quantidade existe no estoque do depósito atualmente
  /***********************************************************************************************************************/
  FUNCTION PRIV_DEP_ESTOQUE_ATUAL
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnQTESTOQUE_ATUAL  PCESTOQUEDEPOSITOPROD.QTESTOQUE%TYPE;
  BEGIN
    BEGIN
      SELECT QTESTOQUE
        INTO vnQTESTOQUE_ATUAL
        FROM PCESTOQUEDEPOSITOPROD
       WHERE CODFILIAL = P_INTERNO.CODFILIAL
         AND CODPROD = P_INTERNO.CODPROD
         AND CODDEPOSITO = P_INTERNO.CODDEPOSITO;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Buscar Estoque Depósito Atual: Não foi possível consultar o estoque atual do depósito'||CHR(13)||
                                 'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                 'Cód. Depósito: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
    END;
    -- Retorno
    RETURN vnQTESTOQUE_ATUAL;
  -- Função
  END PRIV_DEP_ESTOQUE_ATUAL;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  12/03/2020     Fernandes Brito   0                   Criada função para buscar o código padrão de armazenagem do depósito
  /***********************************************************************************************************************/
  FUNCTION PRIV_DEP_PADRAO_ARMAZENAGEM
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCODDEPOSITO_ARMAZENAGEM  PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
  BEGIN
    -- Padrão de armazenagem
    BEGIN
      SELECT CODDEPOSITO
        INTO vnCODDEPOSITO_ARMAZENAGEM
        FROM PCESTOQUEDEPOSITO
       WHERE CODFILIAL = P_INTERNO.CODFILIAL
         AND PADRAOARMAZENAGEM = 'S';
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Buscar_Padrão_Armazenagem: Esse processo é exclusivo para o Módulo 41.'||CHR(13)||
                                 'Para utilizar esse processo O parâmetro 4183 deve estar marcado como "Sim".'||CHR(13)||
                                 'Para este processo funcionar é necessário que exista um depósito informado como padrão de armazenagem cadastrado pela rotina 1108!'||CHR(13)||
                                 'Caso não queira utilizar o processo de multidepósitosito desmarque o parâmetrometro 4183 na rotina 132. '||CHR(13)||
                                 'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                 'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                 'Operação.....: '||P_INTERNO.TIPO_OPERACAO;
    END;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Buscou o depósito padrão para armazenagem!';
    PRIV_GERARLOG;
    -- Retorno
    RETURN vnCODDEPOSITO_ARMAZENAGEM;
  -- Função
  END PRIV_DEP_PADRAO_ARMAZENAGEM;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  12/03/2020     Fernandes Brito   0                   Criada função para buscar o código padrão de venda do depósito
  /***********************************************************************************************************************/
  FUNCTION PRIV_DEP_PADRAO_VENDA
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCODDEPOSITO_VENDA PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
  BEGIN
    -- Padrão de venda
    BEGIN
      SELECT PCESTOQUEDEPOSITO.CODDEPOSITO
        INTO vnCODDEPOSITO_VENDA
        FROM PCESTOQUEDEPOSITO
       WHERE PCESTOQUEDEPOSITO.CODFILIAL = P_INTERNO.CODFILIAL
         AND PCESTOQUEDEPOSITO.PADRAOVENDA = 'S';
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Buscar Padrão de Venda: O parâmetro "Estoque da filial controlado por depósito" esta marcado como "Sim",'||CHR(13)||
                                 'porem não existe depósito padrão para venda informado para este processo na filial selecionada!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                 'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                 'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
    END;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Buscou o depósito padrão para venda!';
    PRIV_GERARLOG;
    -- Retorno
    RETURN vnCODDEPOSITO_VENDA;
  -- Função
  END PRIV_DEP_PADRAO_VENDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  31/01/2020     Fernandes Brito   0                   Criada a função para baixar a reserva/pedencia/bloqueio/avaria do pedido
                                                       que possui itens controlados por depósito.
  ************************************************************************************************************************/
  PROCEDURE PRIV_DEP_BAIXAR
  IS-- Declaração das variáveis internas
    vnCODDEPOSITO_ARMAZENAGEM  PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
    vnCODDEPOSITO_VENDA        PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
    vnQTDE_SOLICITADA          PCPEDI.QT%TYPE;
    vtESTOQUE_DEPOSITO         T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função depósito baixar';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_BAIXAR';
    PRIV_GERARLOG;
    -- Valida se usa estoque por depósito
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
      -- Padrão de armazenagem
      vnCODDEPOSITO_ARMAZENAGEM := PRIV_DEP_PADRAO_ARMAZENAGEM;
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Padrão de venda
      vnCODDEPOSITO_VENDA := PRIV_DEP_PADRAO_VENDA;
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Valida se a massa de dados tem depósito informado
      IF NVL(P_INTERNO.CODDEPOSITO,0) = 0 THEN
        -- É proecsso de entrada?
        IF P_INTERNO.PROCESSO IN ('COMPRAR','BLOQUEAR') THEN
          -- Atualizar variável global
          P_INTERNO.CODDEPOSITO := vnCODDEPOSITO_ARMAZENAGEM;
        ELSE
          -- Atualizar variável global
          P_INTERNO.CODDEPOSITO := vnCODDEPOSITO_VENDA;
        -- Validar padrão
        END IF;
        -- Atualizar PCMOV
        IF P_INTERNO.NOME_TABELA = 'PCMOV' THEN
          UPDATE PCMOV
             SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
        -- Atualizar PCPEDI
        ELSIF P_INTERNO.NOME_TABELA = 'PCPEDI' THEN
          UPDATE PCPEDI
             SET PCPEDI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCPEDI.ROWID = P_INTERNO.ROWID_REGISTRO;
        -- Atualizar PCBONUSI
        ELSIF P_INTERNO.NOME_TABELA = 'PCBONUSI' THEN
          UPDATE PCBONUSI
             SET PCBONUSI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCBONUSI.NUMBONUS = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCORDEMSERVICOI
        ELSIF P_INTERNO.NOME_TABELA = 'PCORDEMSERVICOI' THEN
          UPDATE PCORDEMSERVICOI
             SET PCORDEMSERVICOI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCORDEMSERVICOI.NUMOS = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCAVULSA
        ELSIF P_INTERNO.NOME_TABELA = 'PCAVULSA' THEN
          UPDATE PCAVULSA
             SET PCAVULSA.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCAVULSA.NUMTRANSAVULSA = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCPREREQMATCONSUMOI
        ELSIF P_INTERNO.NOME_TABELA = 'PCPREREQMATCONSUMOI' THEN
          UPDATE PCPREREQMATCONSUMOI
             SET PCPREREQMATCONSUMOI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCPREREQMATCONSUMOI.NUMPREREQUISICAO = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCOPI
        ELSIF P_INTERNO.NOME_TABELA = 'PCOPI' THEN
          UPDATE PCOPI
             SET PCOPI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCOPI.NUMOP = P_INTERNO.IDENTIFICADOR;
        END IF;
      -- Buscar depósito
      END IF;
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (P_INTERNO.CODFILIAL
                             ,P_INTERNO.CODDEPOSITO
                             ,P_INTERNO.CODPROD
                             ,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Administrar reservada?
      IF P_INTERNO.PROCESSO IN ('COMPRAR') THEN
        -- Estoque disponivel do deposito para comprar
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO, 'C');
        vnQTDE_SOLICITADA          := P_INTERNO.QTBLOQUEADA;
      -- Administrar bloqueado?
      ELSIF P_INTERNO.PROCESSO IN ('RESERVAR','BLOQUEAR') THEN
        -- Estoque disponivel do deposito para venda
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO);
        vnQTDE_SOLICITADA          := P_INTERNO.QTRESERV;
      END IF;
      -- Estoque disponível
      IF (P_INTERNO.QTDE_DISPONIVEL < vnQTDE_SOLICITADA AND
          SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) NOT IN ('B')) THEN
        -- Mensagem de erro
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Depósito Baixar: Não existe estoque disponível no depósito informado para atender o pedido/nota fiscal!'||CHR(13)||
                                 'Identificador...: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                 'Produto.........: '||TO_CHAR(P_INTERNO.CODPROD)||CHR(13)||
                                 'Filial..........: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Depósito........: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                 'Qtde. Solicitada: '||vnQTDE_SOLICITADA||CHR(13)||
                                 'Qtde. Disponível: '||P_INTERNO.QTDE_DISPONIVEL||CHR(13)||
                                 'Operação........: '||P_INTERNO.TIPO_OPERACAO;
        RETURN;
      -- Estoque disponivel
      END IF;
      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO                := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL      := P_INTERNO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODDEPOSITO    := P_INTERNO.CODDEPOSITO;
      vtESTOQUE_DEPOSITO.CODPROD        := P_INTERNO.CODPROD;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO  := P_INTERNO.TIPO_OPERACAO;
      IF P_INTERNO.PROCESSO IN ('COMPRAR','BLOQUEAR') THEN
        vtESTOQUE_DEPOSITO.QTBLOQUEADA  := P_INTERNO.QTBLOQUEADA;
        vtESTOQUE_DEPOSITO.QTINDENIZADA := P_INTERNO.QTINDENIZ;
      ELSIF P_INTERNO.PROCESSO IN ('RESERVAR') THEN
        vtESTOQUE_DEPOSITO.QTRESERVADA  := P_INTERNO.QTRESERV;
        vtESTOQUE_DEPOSITO.QTPENDENTE   := P_INTERNO.QTPENDENTE;
      ELSIF P_INTERNO.PROCESSO IN ('PENDENTE') THEN
        vtESTOQUE_DEPOSITO.QTPENDENTE   := P_INTERNO.QTPENDENTE;
      END IF;
      -- Atualizar estoque depósito
      PRIV_CALCULAR_DEPOSITO(vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
    -- Valida parâmetro
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função depósito baixar';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_BAIXAR';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_BAIXAR;

  /************************************************************************************************************************
