  -------------------------------------------------------------------------------------------------------------------------
  09/03/2020     Fernandes Brito   0                   Criada procedure para movimentar o estoque do depósito na devolução
                                                       de aquisição de mercadorias.
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_COMPRAS_SAIDA
  IS-- Declaração das variáveis internas
    vtESTOQUE_DEPOSITO T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função depósito compras saida';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_COMPRAS_SAIDA';
    PRIV_GERARLOG;
    -- Validar se usa estoque por depósito
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
      -- Valida se a massa de dados tem depósito informado
      IF NVL(P_INTERNO.CODDEPOSITO,0) = 0 THEN
        -- Padrão de armazenagem
        P_INTERNO.CODDEPOSITO := PRIV_DEP_PADRAO_ARMAZENAGEM;
        -- Validar retorno
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          RETURN;
        END IF;
        -- Atualizar PCMOV
        BEGIN
          UPDATE PCMOV
             SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
        -- Mensagem de erro
        EXCEPTION
          WHEN OTHERS THEN
            P_INTERNO.MSG_RETORNO := 'Erro 1 - Depósito Compras Saída: Não foi possível atualizar o código do depósito na tabela de movimentação de estoque (PCMOV)!'||CHR(13)||
                                     'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                     'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                     'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                     'Cód. Depósito: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                     'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                     'MSG Original.: '||SQLERRM;
            RETURN;
        END;
      -- Buscar depósito
      END IF;
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (P_INTERNO.CODFILIAL
                             ,P_INTERNO.CODDEPOSITO
                             ,P_INTERNO.CODPROD
                             ,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Estoque disponivel do deposito
      P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO, 'C');
      -- Valida estoque disponível
      IF (P_INTERNO.QTDE_DISPONIVEL < P_INTERNO.QTESTGER AND vsROTINA NOT LIKE '%1302%' AND 
          P_INTERNO.CANCELAMENTO <> 'S') THEN
        -- Mensagem de erro
        P_INTERNO.MSG_RETORNO := 'Erro 2 - Depósito Compras Saída: Não existe estoque disponível no depósito informado para atender a nota fiscal!'||CHR(13)||
                                 'Identificador...: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                 'Produto.........: '||TO_CHAR(P_INTERNO.CODPROD)||CHR(13)||
                                 'Filial..........: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Depósito........: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                 'Qtde. Solicitada: '||P_INTERNO.QTESTGER||CHR(13)||
                                 'Qtde. Disponível: '||P_INTERNO.QTDE_DISPONIVEL||CHR(13)||
                                 'Operação........: '||P_INTERNO.TIPO_OPERACAO;
        RETURN;
      -- Valida estoque disponivel
      END IF;
      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO               := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;
      vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
      vtESTOQUE_DEPOSITO.QTESTOQUE     := P_INTERNO.QTESTGER;
      vtESTOQUE_DEPOSITO.QTBLOQUEADA   := GREATEST(NVL(P_INTERNO.QTINDENIZ,0),P_INTERNO.QTBLOQUEADA);
      vtESTOQUE_DEPOSITO.QTINDENIZADA  := P_INTERNO.QTINDENIZ;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
      -- Atualizar estoque do depósito
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
    -- Validação parâmetro
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função depósito compras saida';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_COMPRAS_SAIDA';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_COMPRAS_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2020     Fernandes Brito   0                   Criada a função para validar se já existe requisição para o pedido em questão
  12/05/2020     Fernandes Brito   0                   Alterada a função para não mais usar variáveis globais e incluida a validação
                                                       da existência de requisição para o pedido em questão.
  ************************************************************************************************************************/
  FUNCTION PRIV_EXISTE_REQUISICAO (psNOME_TABELA       IN PCREQUISICAODEPOSITO.NOME_TABELA%TYPE
                                  ,pnIDENTIFICADOR     IN PCREQUISICAODEPOSITO.IDENTIFICADOR%TYPE
                                  ,pnCODREQUISICAO     IN PCREQUISICAODEPOSITO.CODREQUISICAO%TYPE
                                  ,pnCODDEPOSITOORIG   IN PCREQUISICAODEPOSITO.CODDEPOSITOORIG%TYPE
                                  ,pnCODDEPOSITODEST   IN PCREQUISICAODEPOSITO.CODDEPOSITODEST%TYPE
                                  ,pnNUMSEQ            IN PCREQUISICAODEPOSITO.NUMSEQ%TYPE DEFAULT NULL
                                  ,pnCODPROD           IN PCREQUISICAODEPOSITO.CODPROD%TYPE DEFAULT NULL)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCODREQUISICAO  PCREQUISICAODEPOSITO.CODREQUISICAO%TYPE := NULL;
  BEGIN
    -- Existe registro para este mesmo item e sequência?
    IF (psNOME_TABELA = 'PCPEDI' AND pnIDENTIFICADOR IS NOT NULL AND pnNUMSEQ IS NOT NULL) THEN
      BEGIN
        SELECT DISTINCT (PCREQUISICAODEPOSITO.CODREQUISICAO)
          INTO vnCODREQUISICAO
          FROM PCREQUISICAODEPOSITO, PCPEDI I
         WHERE PCREQUISICAODEPOSITO.IDENTIFICADOR = pnIDENTIFICADOR
           AND PCREQUISICAODEPOSITO.CODDEPOSITOORIG = pnCODDEPOSITOORIG
           AND PCREQUISICAODEPOSITO.CODDEPOSITODEST = pnCODDEPOSITODEST
           AND PCREQUISICAODEPOSITO.IDENTIFICADOR = I.NUMPED
           AND PCREQUISICAODEPOSITO.CODPROD = pnCODPROD
           AND PCREQUISICAODEPOSITO.CODPROD = I.CODPROD
           AND PCREQUISICAODEPOSITO.NUMSEQ = I.NUMSEQ
           AND PCREQUISICAODEPOSITO.NUMSEQ = pnNUMSEQ
           AND NVL(I.NUMVIASMAPASEPRI, 0) > 0;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCODREQUISICAO := NULL;
      END;

      RETURN vnCODREQUISICAO;
    END IF;

    -- Existe registro para este mesmo identificador e impressora?
    IF (psNOME_TABELA = 'PCPEDI' AND pnIDENTIFICADOR IS NOT NULL) THEN
      BEGIN
        SELECT DISTINCT (PCREQUISICAODEPOSITO.CODREQUISICAO)
          INTO vnCODREQUISICAO
          FROM PCREQUISICAODEPOSITO, PCPEDI I
         WHERE PCREQUISICAODEPOSITO.IDENTIFICADOR = pnIDENTIFICADOR
           AND PCREQUISICAODEPOSITO.IDENTIFICADOR = I.NUMPED
           AND PCREQUISICAODEPOSITO.CODPROD = I.CODPROD
           AND PCREQUISICAODEPOSITO.NUMSEQ = I.NUMSEQ
           AND NVL(I.NUMVIASMAPASEPRI, 0) = 0
           AND PCREQUISICAODEPOSITO.CODDEPOSITOORIG = pnCODDEPOSITOORIG
           AND PCREQUISICAODEPOSITO.CODDEPOSITODEST = pnCODDEPOSITODEST
           AND NVL(PCREQUISICAODEPOSITO.IMPRESSORAREQ,'VAZIO') = NVL(P_INTERNO.IMPRESSORA,'VAZIO');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCODREQUISICAO := NULL;
      END;
    -- Existe registro para a requisição
    ELSIF (psNOME_TABELA = 'PCREQUISICAODEPOSITO' AND pnCODREQUISICAO IS NOT NULL) THEN
      -- Percorre o vetor
      BEGIN
        SELECT DISTINCT (PCREQUISICAODEPOSITO.CODREQUISICAO)
          INTO vnCODREQUISICAO
          FROM PCREQUISICAODEPOSITO
         WHERE PCREQUISICAODEPOSITO.IDENTIFICADOR = pnCODREQUISICAO
           AND PCREQUISICAODEPOSITO.CODDEPOSITOORIG = pnCODDEPOSITOORIG
           AND PCREQUISICAODEPOSITO.CODDEPOSITODEST = pnCODDEPOSITODEST
           AND PCREQUISICAODEPOSITO.POSICAO = 'A'
           AND NVL(PCREQUISICAODEPOSITO.IMPRESSORAREQ,'VAZIO') = NVL(P_INTERNO.IMPRESSORA,'VAZIO');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCODREQUISICAO := NULL;
      END;

      IF vnCODREQUISICAO IS NOT NULL THEN
        RETURN vnCODREQUISICAO;
      ELSE
        BEGIN
          SELECT DISTINCT (PCREQUISICAODEPOSITO.CODREQUISICAO)
            INTO vnCODREQUISICAO
            FROM PCREQUISICAODEPOSITO
           WHERE PCREQUISICAODEPOSITO.CODREQUISICAO = pnCODREQUISICAO
           AND PCREQUISICAODEPOSITO.POSICAO = 'A'
           AND PCREQUISICAODEPOSITO.CODDEPOSITODEST = pnCODDEPOSITODEST;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnCODREQUISICAO := NULL;
        END;

        IF vnCODREQUISICAO IS NULL THEN
          RETURN pnCODREQUISICAO;
        END IF;

        RETURN NULL;

      END IF;
    -- Não tem tabela
    END IF;
    -- Retorno da função
    RETURN vnCODREQUISICAO;
  -- Função
  END PRIV_EXISTE_REQUISICAO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para fechar a requisição de transferência entre depósito
  21/05/2020     Fernandes Brito   0                   Retirada as variáveis globais para uso em processos ficando apenas as variáveis globais
                                                       para a gravação do log. Desta forma visamos a diminuir o risto de erros e melhorar o entendimento da PKG_ESTOQUE.
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_FECHAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                            ,psMSG_RETORNO     OUT PCLOGPKG_ESTOQUE.MSG_RETORNO%TYPE)
  IS-- Declaração das variáveis internas
  BEGIN
    -- Atualizando variável
    psMSG_RETORNO := 'OK';
    -- Atualizar posição
    UPDATE PCREQUISICAODEPOSITO
       SET POSICAO = 'F'
     WHERE CODREQUISICAO = pnIDENTIFICADOR;
  -- Erro na atualização
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 1 - Depósito Fechar requisição: Erro ao atualizar a posição da requisição!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'MSG Original.: '||SQLERRM;
      RETURN;
  -- Procedure
  END PRIV_DEP_FECHAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para inserir dados da movimentação entre depósito
  21/05/2020     Fernandes Brito   0                   Retirada as variáveis globais para uso em processos ficando apenas as variáveis globais
                                                       para a gravação do log. Desta forma visamos a diminuir o risto de erros e melhorar o entendimento da PKG_ESTOQUE.
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_MOVIMENTACAO (ptMOVIMENTACAO_DEPOSITO  IN T_MOVIMENTACAO_DEPOSITO
                                  ,psMSG_RETORNO            OUT PCLOGPKG_ESTOQUE.MSG_RETORNO%TYPE)
  IS-- Declaração das variáveis internas
    vsOBSERVACAO        PCMOVESTOQUEDEPOSITO.OBS%TYPE;
    vtESTOQUE_DEPOSITO  T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := 'OK';
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função deposito movimentacao';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_MOVIMENTACAO';
    PRIV_GERARLOG;
    -- Descricao cód. operação
    CASE
      WHEN ptMOVIMENTACAO_DEPOSITO.CODOPER = 'ID' THEN
        vsOBSERVACAO := 'Inclusão de registro de depósito.';
      WHEN ptMOVIMENTACAO_DEPOSITO.CODOPER = 'TD' THEN
        vsOBSERVACAO := 'Transferência entre depósitos';
      WHEN ptMOVIMENTACAO_DEPOSITO.CODOPER = 'EI' THEN
        vsOBSERVACAO := 'Entrada por inventário no depósito.';
      WHEN ptMOVIMENTACAO_DEPOSITO.CODOPER = 'SI' THEN
        vsOBSERVACAO := 'Saída por inventário no depósitos';
    ELSE
      vsOBSERVACAO := vsOBSERVACAO||' '||'Saída com destino ao Depósito: '||TO_CHAR(ptMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST);
    -- Descricao cód. operação
    END CASE;
    -- Inserir dados na PCMOVDEPOSITO
    INSERT INTO PCMOVESTOQUEDEPOSITO
       (CODREQUISICAO          -- 1
       ,DATA                   -- 2
       ,DTGERACAO              -- 3
       ,CODPROD                -- 4
       ,CODFILIAL              -- 5
       ,CODDEPOSITOORIG        -- 6
       ,CODDEPOSITODEST        -- 7
       ,CODOPER                -- 8
       ,QT                     -- 9
       ,OBS)                   -- 10
      VALUES
       (ptMOVIMENTACAO_DEPOSITO.IDENTIFICADOR       -- 1
       ,TRUNC(SYSDATE)                              -- 2
       ,SYSDATE                                     -- 3
       ,ptMOVIMENTACAO_DEPOSITO.CODPROD             -- 4
       ,ptMOVIMENTACAO_DEPOSITO.CODFILIAL           -- 5
       ,ptMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG     -- 6
       ,ptMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST     -- 7
       ,ptMOVIMENTACAO_DEPOSITO.CODOPER             -- 8
       ,ptMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR     -- 9
       ,vsOBSERVACAO);        -- 10
    -- Atualizar Depósito Origem
    IF ptMOVIMENTACAO_DEPOSITO.CODOPER IN ('TD','SI') THEN
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (ptMOVIMENTACAO_DEPOSITO.CODFILIAL
                             ,ptMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG
                             ,ptMOVIMENTACAO_DEPOSITO.CODPROD
                             ,psMSG_RETORNO);
      -- Validar retorno
      IF psMSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Transferência com requisição manual
      IF (ptMOVIMENTACAO_DEPOSITO.CODOPER IN ('TD') AND ptMOVIMENTACAO_DEPOSITO.NOME_TABELA = 'PCREQUISICAODEPOSITO') THEN
        -- Baixa estoque reservado
        P_INTERNO.RETORNO_FUNCAO := RESERVA_BAIXAR (ptMOVIMENTACAO_DEPOSITO.IDENTIFICADOR
                                                   ,ptMOVIMENTACAO_DEPOSITO.CODPROD
                                                   ,NULL
                                                   ,'BR'
                                                   ,psMSG_RETORNO);
        -- Validar retorno
        IF psMSG_RETORNO <> 'OK' THEN
          RETURN;
        END IF;
      -- Baixar reserva
      END IF;

      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO               := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL     := ptMOVIMENTACAO_DEPOSITO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODPROD       := ptMOVIMENTACAO_DEPOSITO.CODPROD;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := ptMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG;

      IF ptMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR > 0 THEN
        IF P_INTERNO.TIPO_OPERACAO IS NOT NULL THEN
          vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
        ELSE
          vtESTOQUE_DEPOSITO.TIPO_OPERACAO := 'B';
        END IF;
        vtESTOQUE_DEPOSITO.QTBLOQUEADA   := ptMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR;
        vtESTOQUE_DEPOSITO.QTINDENIZADA  := ptMOVIMENTACAO_DEPOSITO.QTDE_A_AVARIAR;
        -- Atualizar depósito de Destino (A reserva já foi feita agora tem que baixar o estoque)
        PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,psMSG_RETORNO);
        -- Validar retorno
        IF psMSG_RETORNO <> 'OK' THEN
          vLOG.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN;
        END IF;
      END IF;

      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := 'B';
      vtESTOQUE_DEPOSITO.QTESTOQUE     := ptMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR;
      vtESTOQUE_DEPOSITO.QTRESERVADA   := ptMOVIMENTACAO_DEPOSITO.QTREQUISITADA;
      vtESTOQUE_DEPOSITO.QTBLOQUEADA   := 0;
      vtESTOQUE_DEPOSITO.QTINDENIZADA  := 0;
      -- Atualizar depósito de Destino (A reserva já foi feita agora tem que baixar o estoque)
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,psMSG_RETORNO);
      -- Validar retorno
      IF psMSG_RETORNO <> 'OK' THEN
        vLOG.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN;
      END IF;
    -- Depósito Destino
    END IF;
    -- Atualizar Depósito Destino
    IF ptMOVIMENTACAO_DEPOSITO.CODOPER IN ('TD','EI') THEN
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (ptMOVIMENTACAO_DEPOSITO.CODFILIAL
                             ,ptMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST
                             ,ptMOVIMENTACAO_DEPOSITO.CODPROD
                             ,psMSG_RETORNO);
      -- Validar retorno
      IF psMSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;

      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO               := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL     := ptMOVIMENTACAO_DEPOSITO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODPROD       := ptMOVIMENTACAO_DEPOSITO.CODPROD;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := ptMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST;

      IF ptMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR > 0 THEN
        IF P_INTERNO.TIPO_OPERACAO IS NOT NULL THEN
          vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
        ELSE
          vtESTOQUE_DEPOSITO.TIPO_OPERACAO := 'I';
        END IF;
        vtESTOQUE_DEPOSITO.QTBLOQUEADA   := ptMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR;
        vtESTOQUE_DEPOSITO.QTINDENIZADA  := ptMOVIMENTACAO_DEPOSITO.QTDE_A_AVARIAR;
        -- Atualizar depósito de Destino (A reserva já foi feita agora tem que baixar o estoque)
        PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,psMSG_RETORNO);
        -- Validar retorno
        IF psMSG_RETORNO <> 'OK' THEN
          vLOG.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN;
        END IF;
      END IF;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := 'I';
      vtESTOQUE_DEPOSITO.QTESTOQUE     := ptMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR;
      vtESTOQUE_DEPOSITO.QTBLOQUEADA   := 0;
      vtESTOQUE_DEPOSITO.QTINDENIZADA  := 0;

      -- Incluir a reserva
      IF (ptMOVIMENTACAO_DEPOSITO.CODOPER IN ('TD') AND ptMOVIMENTACAO_DEPOSITO.NOME_TABELA <> 'PCREQUISICAODEPOSITO') THEN
        -- Atualizar variáveis
        vtESTOQUE_DEPOSITO.QTRESERVADA := ptMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR;
      -- Incluir a reserva
      END IF;
      -- Atualizar depósito de Destino
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,psMSG_RETORNO);
      -- Validar retorno
      IF psMSG_RETORNO <> 'OK' THEN
        vLOG.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN;
      END IF;
    -- Depósito Destino
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função deposito movimentacao';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_MOVIMENTACAO';
    PRIV_GERARLOG;
  -- Erros
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 1 - Depósito Movimentação: Não é possível inserir dados para a tabela de movimentação entre os depósitos!'||CHR(13)||
                       'Identificador...: '||TO_CHAR(ptMOVIMENTACAO_DEPOSITO.IDENTIFICADOR)||CHR(13)||
                       'Cód. Filial.....: '||ptMOVIMENTACAO_DEPOSITO.CODFILIAL||CHR(13)||
                       'Cód. Produto....: '||ptMOVIMENTACAO_DEPOSITO.CODPROD||CHR(13)||
                       'Cód. Dep. Orig..: '||ptMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG||CHR(13)||
                       'Cód. Dep. Dest..: '||ptMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST||CHR(13)||
                       'MSG Original....: '||SQLERRM;
  -- Procedure
  END PRIV_DEP_MOVIMENTACAO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para incluir a requisição de transferência entre depósito
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_INCLUIR_REQUISICAO (ptREQUISICAO IN OUT PCREQUISICAODEPOSITO%ROWTYPE)
  IS
    -- Declaração das variáveis
    vsCODREQUISICAO            PCREQUISICAODEPOSITO.CODREQUISICAO%TYPE;
    vtFILIAL_RETIRA            PCPEDC.CODFILIAL%TYPE;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função depósito incluir requisicao';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_INCLUIR_REQUISICAO';
    PRIV_GERARLOG;

    IF ptREQUISICAO.NOME_TABELA = 'PCPEDI' AND (P_INTERNO.TIPO_ENTREGA = 'RI' OR P_INTERNO.PROGRAMA = 4159) THEN
      vsCODREQUISICAO := PRIV_EXISTE_REQUISICAO (ptREQUISICAO.NOME_TABELA
                                                 ,ptREQUISICAO.IDENTIFICADOR
                                                 ,ptREQUISICAO.CODREQUISICAO
                                                 ,ptREQUISICAO.CODDEPOSITOORIG
                                                 ,ptREQUISICAO.CODDEPOSITODEST
                                                 ,ptREQUISICAO.NUMSEQ
                                                 ,ptREQUISICAO.CODPROD);
      BEGIN
    SELECT PCPEDI.CODFILIALRETIRA
      INTO vtFILIAL_RETIRA
      FROM PCPEDI, PCPEDC
     WHERE PCPEDI.CODFILIALRETIRA <> PCPEDC.CODFILIAL
       AND PCPEDI.NUMPED = PCPEDC.NUMPED
       AND PCPEDI.CODPROD = ptREQUISICAO.CODPROD
       AND PCPEDI.NUMSEQ = ptREQUISICAO.NUMSEQ
       AND PCPEDI.NUMPED = ptREQUISICAO.IDENTIFICADOR;
    EXCEPTION
    WHEN NO_DATA_FOUND THEN
      vtFILIAL_RETIRA := NULL;
    END;
    END IF;
    -- Validar se é necessário fazer requisição
    IF (P_INTERNO.PROCESSO NOT IN ('COMPRAR','BLOQUEAR') AND
        ptREQUISICAO.CODDEPOSITOORIG <> ptREQUISICAO.CODDEPOSITODEST AND
       (P_INTERNO.TIPO_ENTREGA = 'RI' OR ptREQUISICAO.NOME_TABELA = 'PCREQUISICAODEPOSITO' OR P_INTERNO.PROGRAMA = 4159)) AND
        vsCODREQUISICAO IS NULL AND (vtFILIAL_RETIRA IS NULL) THEN
      -- Existe impressora para este mesmo item?
      IF ptREQUISICAO.NOME_TABELA = 'PCREQUISICAODEPOSITO' THEN
        ptREQUISICAO.IDENTIFICADOR := ptREQUISICAO.CODREQUISICAO;
      END IF;

      BEGIN
        SELECT E.IMPRESSORA NOMEIMPRESSORA
          INTO P_INTERNO.IMPRESSORA
          FROM PCEST EST, PCCADIMPRESSAO E
         WHERE EST.CODFILIAL = E.CODFILIAL(+)
           AND EST.MODULO = E.MODULO(+)
           AND EST.RUA = E.RUA(+)
           AND EST.CODFILIAL = ptREQUISICAO.CODFILIAL
           AND EST.CODPROD = ptREQUISICAO.CODPROD
           AND E.CODDEPOSITO = ptREQUISICAO.CODDEPOSITOORIG;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          P_INTERNO.IMPRESSORA := NULL;
      END;
      -- Validar se já existe requisição para o pedido e o item em questão
      ptREQUISICAO.CODREQUISICAO := PRIV_EXISTE_REQUISICAO (ptREQUISICAO.NOME_TABELA
                                                           ,ptREQUISICAO.IDENTIFICADOR
                                                           ,ptREQUISICAO.CODREQUISICAO
                                                           ,ptREQUISICAO.CODDEPOSITOORIG
                                                           ,ptREQUISICAO.CODDEPOSITODEST);
      -- O sequeciador da requisição já foi gerado?
      IF ptREQUISICAO.CODREQUISICAO IS NULL THEN
        -- Buscar próximo número de requisição
        SELECT DEFSEQ_CODREQUISICAO.NEXTVAL
          INTO ptREQUISICAO.CODREQUISICAO
          FROM DUAL;
      END IF;
      -- Atualizar variáveis
      ptREQUISICAO.DATA    := TRUNC(SYSDATE);
      ptREQUISICAO.POSICAO := 'A'; -- Requisição SEMRE berta ("A")
      ptREQUISICAO.IMPRESSORAREQ := P_INTERNO.IMPRESSORA;
      -- É para fazer para todos os itens?
      IF P_INTERNO.PROCESSO = 'REQUISITAR' THEN
        -- Atualizar variáveis
        P_INTERNO.CODPROD            := ptREQUISICAO.CODPROD;
        P_INTERNO.CODFILIAL          := ptREQUISICAO.CODFILIAL;
        -- Inserir requisição
        INSERT INTO PCREQUISICAODEPOSITO
          VALUES ptREQUISICAO;
        -- Reserva estoque deposito
        P_INTERNO.RETORNO_FUNCAO := RESERVA_INCLUIR (ptREQUISICAO.CODREQUISICAO
                                                    ,ptREQUISICAO.CODPROD
                                                    ,NULL
                                                    ,FALSE
                                                    ,'IR'
                                                    ,P_INTERNO.MSG_RETORNO);
        -- Validar retorno
        IF P_INTERNO.RETORNO_FUNCAO = 'N' THEN
          RETURN;
        END IF;
      ELSE
        -- Inserir requisição
        INSERT INTO PCREQUISICAODEPOSITO
          VALUES ptREQUISICAO;
      -- Todos os itens
      END IF;
    -- Gerar requisição
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função depósito incluir requisicao';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_INCLUIR_REQUISICAO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  17/10/2019     Fernandes Brito   0                   Criada procedure para controlar as movimentações de inventário do depósito
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_INVENTARIO (ptINVENTARIO IN T_INVENTARIO)
  IS-- Declaração das variáveis internas
    vtMOVIMENTACAO_DEPOSITO T_MOVIMENTACAO_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função depósito inventario';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_INVENTARIO';
    PRIV_GERARLOG;
    -- Atualizar variável
    P_INTERNO.LISTA_VALIDA := 'N';
    -- Lista de itens
    FOR INVENT IN (SELECT PCINVENTROT.NUMINVENT
                         ,PCINVENTROT.CODFILIAL
                         ,PCINVENTROT.CODPROD
                         ,PCINVENTROT.CODLOCAL CODDEPOSITO
                         ,PCINVENTROT.QTESTDEPOSITO QTDE_ANTERIOR
             ,NVL(PCINVENTROT.INVENTAVARIA, 'N') INVENTAVARIA
                         ,(CASE
                             WHEN ptINVENTARIO.USAPRIMEIRACONTAGEM = 'S' THEN
                               NVL(QT1, 0)
                           ELSE
                             CASE
                               WHEN NVL(QT2, 0) = NVL(QT1, 0) THEN
                                 NVL(QT1, 0)
                             ELSE
                               NVL(QT3, 0)
                             END
                           END) QTDE_ATUAL
                         ,(SELECT NVL(QTINDENIZADA,0)
                             FROM PCESTOQUEDEPOSITOPROD
                            WHERE CODDEPOSITO = PCINVENTROT.CODLOCAL
                              AND CODPROD = PCINVENTROT.CODPROD
                              AND CODFILIAL = PCINVENTROT.CODFILIAL) QTDE_AVARIAANT
                         ,(CASE
                             WHEN ptINVENTARIO.USAPRIMEIRACONTAGEM = 'S' THEN
                               NVL(QTAVARIA1, 0)
                           ELSE
                             CASE
                               WHEN NVL(QTAVARIA2, 0) = NVL(QTAVARIA1, 0) THEN
                                 NVL(QTAVARIA1, 0)
                             ELSE
                               NVL(QTAVARIA3, 0)
                             END
                           END) QTDE_AVARIA
                     FROM PCINVENTROT
                    WHERE PCINVENTROT.NUMINVENT = ptINVENTARIO.NUMINVENT
                      AND PCINVENTROT.DTATUALIZACAO IS NULL
                      AND PCINVENTROT.DTCANCEL IS NULL)
    LOOP
      -- Atualizar variáveis
      P_INTERNO.LISTA_VALIDA    := 'S';
      P_INTERNO.IDENTIFICADOR   := INVENT.NUMINVENT;
      P_INTERNO.CODPROD         := INVENT.CODPROD;
      P_INTERNO.CODFILIAL       := INVENT.CODFILIAL;
      P_INTERNO.CODDEPOSITOORIG := INVENT.CODDEPOSITO;
      P_INTERNO.CODDEPOSITODEST := INVENT.CODDEPOSITO;
      -- Entrada
      IF INVENT.QTDE_ANTERIOR <= INVENT.QTDE_ATUAL THEN
        P_INTERNO.CODOPER       := 'EI';
        P_INTERNO.QTESTGER      := (INVENT.QTDE_ATUAL - INVENT.QTDE_ANTERIOR);
      -- Saída
      ELSIF INVENT.QTDE_ANTERIOR >= INVENT.QTDE_ATUAL THEN
        P_INTERNO.CODOPER       := 'SI';
        P_INTERNO.QTESTGER      := (INVENT.QTDE_ANTERIOR - INVENT.QTDE_ATUAL);
      END IF;
      --Entrada Avarias
      IF INVENT.INVENTAVARIA = 'S' THEN
        IF INVENT.QTDE_AVARIAANT <= INVENT.QTDE_AVARIA THEN
          P_INTERNO.TIPO_OPERACAO := 'I';
          P_INTERNO.QTINDENIZ     := (INVENT.QTDE_AVARIA - INVENT.QTDE_AVARIAANT);
          P_INTERNO.QTBLOQUEADA   := NVL(P_INTERNO.QTINDENIZ,0);
        -- SAÍDA AVARIAS
        ELSIF INVENT.QTDE_AVARIAANT >= INVENT.QTDE_AVARIA THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
          P_INTERNO.QTINDENIZ     := (INVENT.QTDE_AVARIAANT - INVENT.QTDE_AVARIA);
          P_INTERNO.QTBLOQUEADA   := NVL(P_INTERNO.QTINDENIZ,0);
        END IF;
      ELSE
         P_INTERNO.QTINDENIZ     := 0;
         P_INTERNO.QTBLOQUEADA   := 0;
      END IF;
      -- Atualizar variáveis
      vtMOVIMENTACAO_DEPOSITO                     := NULL;
      vtMOVIMENTACAO_DEPOSITO.IDENTIFICADOR       := INVENT.NUMINVENT;
      vtMOVIMENTACAO_DEPOSITO.NOME_TABELA         := P_INTERNO.NOME_TABELA;
      vtMOVIMENTACAO_DEPOSITO.CODFILIAL           := INVENT.CODFILIAL;
      vtMOVIMENTACAO_DEPOSITO.CODPROD             := INVENT.CODPROD;
      vtMOVIMENTACAO_DEPOSITO.CODOPER             := P_INTERNO.CODOPER;
      vtMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG     := P_INTERNO.CODDEPOSITOORIG;
      vtMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST     := P_INTERNO.CODDEPOSITODEST;
      vtMOVIMENTACAO_DEPOSITO.QTREQUISITADA       := NULL;
      vtMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR   := P_INTERNO.QTESTGER;
      vtMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR     := P_INTERNO.QTBLOQUEADA;
      vtMOVIMENTACAO_DEPOSITO.QTDE_A_AVARIAR      := P_INTERNO.QTINDENIZ;
      -- Gerar movimentações entre depósito
      PRIV_DEP_MOVIMENTACAO (vtMOVIMENTACAO_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
    -- Lista de produtos
    END LOOP;
    -- Não existe registros
    IF P_INTERNO.LISTA_VALIDA = 'N' THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 - Depósito Inventário: Não é possível localizar os dados do inventário.'||CHR(13)||
                               'Verifique se o inventário em questão esta cancelado (DTCANCEL preenchido) ou já foi atualizado (DTATUALIZACAO preenchida).'||CHR(13)||
                               'Identificador...: '||TO_CHAR(ptINVENTARIO.NUMINVENT);
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função depósito inventario';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_INVENTARIO';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_INVENTARIO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  31/01/2020     Fernandes Brito   0                   Criada a função para incluir a reserva/pedencia/bloqueio/avaria do
                                                       pedido que possui itens controlados por depósito
  ************************************************************************************************************************/
  PROCEDURE PRIV_DEP_INCLUIR
  IS-- Declaração das variáveis internas
    vnCODDEPOSITO_ARMAZENAGEM  PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
    vnCODDEPOSITO_VENDA        PCESTOQUEDEPOSITO.CODDEPOSITO%TYPE;
    vnQTDE_SOLICITADA          PCPEDI.QT%TYPE;
    vtREQUISICAO               PCREQUISICAODEPOSITO%ROWTYPE;
    vtESTOQUE_DEPOSITO         T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Iniciou a função depósito reserva incluir';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_INCLUIR';
    PRIV_GERARLOG;

    -- Valida se usa estoque por depósito
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
      -- Padrão de armazenagem
      vnCODDEPOSITO_ARMAZENAGEM := PRIV_DEP_PADRAO_ARMAZENAGEM;
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Padrão de venda
      vnCODDEPOSITO_VENDA := PRIV_DEP_PADRAO_VENDA;
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Valida se a massa de dados tem depósito informado
      IF NVL(P_INTERNO.CODDEPOSITO,0) = 0 THEN
        -- É proecsso de entrada?
        IF P_INTERNO.PROCESSO IN ('COMPRAR','BLOQUEAR') THEN
          -- Atualizar variável Global
          P_INTERNO.CODDEPOSITO := vnCODDEPOSITO_ARMAZENAGEM;
        ELSE
          -- Atualizar variável Global
          P_INTERNO.CODDEPOSITO := vnCODDEPOSITO_VENDA;
        END IF;
        -- Atualizar PCMOV
        IF P_INTERNO.NOME_TABELA = 'PCMOV' THEN
          UPDATE PCMOV
             SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
        -- Atualizar PCPEDI
        ELSIF P_INTERNO.NOME_TABELA = 'PCPEDI' THEN
          UPDATE PCPEDI
             SET PCPEDI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCPEDI.ROWID = P_INTERNO.ROWID_REGISTRO;
        -- Atualizar PCBONUSI
        ELSIF P_INTERNO.NOME_TABELA = 'PCBONUSI' THEN
          UPDATE PCBONUSI
             SET PCBONUSI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCBONUSI.NUMBONUS = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCORDEMSERVICOI
        ELSIF P_INTERNO.NOME_TABELA = 'PCORDEMSERVICOI' THEN
          UPDATE PCORDEMSERVICOI
             SET PCORDEMSERVICOI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCORDEMSERVICOI.NUMOS = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCAVULSA
        ELSIF P_INTERNO.NOME_TABELA = 'PCAVULSA' THEN
          UPDATE PCAVULSA
             SET PCAVULSA.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCAVULSA.NUMTRANSAVULSA = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCPREREQMATCONSUMOI
        ELSIF P_INTERNO.NOME_TABELA = 'PCPREREQMATCONSUMOI' THEN
          UPDATE PCPREREQMATCONSUMOI
             SET PCPREREQMATCONSUMOI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCPREREQMATCONSUMOI.NUMPREREQUISICAO = P_INTERNO.IDENTIFICADOR;
        -- Atualizar PCOPI
        ELSIF P_INTERNO.NOME_TABELA = 'PCOPI' THEN
          UPDATE PCOPI
             SET PCOPI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCOPI.NUMOP = P_INTERNO.IDENTIFICADOR;
        END IF;
      -- Buscar depósito
      END IF;
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (P_INTERNO.CODFILIAL
                             ,P_INTERNO.CODDEPOSITO
                             ,P_INTERNO.CODPROD
                             ,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- É proecsso de entrada?
      IF P_INTERNO.PROCESSO IN ('COMPRAR') THEN
        -- Estoque disponivel do deposito para comprar
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO, 'C');
        vnQTDE_SOLICITADA          := P_INTERNO.QTBLOQUEADA;
      ELSIF P_INTERNO.PROCESSO IN ('RESERVAR') THEN
        -- Estoque disponivel do deposito da venda
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO, 'C');
        vnQTDE_SOLICITADA          := P_INTERNO.QTRESERV;
      ELSIF P_INTERNO.PROCESSO IN ('BLOQUEAR') THEN
        -- Estoque disponivel do deposito para venda
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO);
        vnQTDE_SOLICITADA          := P_INTERNO.QTRESERV;
      END IF;
      -- Valida estoque disponível
      IF (P_INTERNO.QTDE_DISPONIVEL < vnQTDE_SOLICITADA AND
          P_INTERNO.PROCESSO NOT IN ('COMPRAR','BLOQUEAR') AND
          SUBSTR(P_INTERNO.TIPO_OPERACAO,1,1) NOT IN ('B')) THEN
        -- Mensagem de erro
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Depósito Pedido: Não existe estoque disponível no depósito informado para atender o pedido!'||CHR(13)||
                                 'Identificador...: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                 'Produto.........: '||TO_CHAR(P_INTERNO.CODPROD)||CHR(13)||
                                 'Filial..........: '||P_INTERNO.CODFILIAL||CHR(13)||
                                 'Depósito........: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                 'Qtde. Solicitada: '||P_INTERNO.QTRESERV||CHR(13)||
                                 'Qtde. Disponível: '||P_INTERNO.QTDE_DISPONIVEL||CHR(13)||
                                 'Operação........: '||P_INTERNO.TIPO_OPERACAO;
        RETURN;
      -- Valida estoque disponivel
      END IF;
      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO               := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;
      vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
      -- Administrar reservada?
      IF P_INTERNO.PROCESSO IN ('RESERVAR') THEN
        vtESTOQUE_DEPOSITO.QTRESERVADA   := P_INTERNO.QTRESERV;
      -- Administrar pendente?
      ELSIF P_INTERNO.PROCESSO IN ('PENDENTE') THEN
        vtESTOQUE_DEPOSITO.QTPENDENTE    := P_INTERNO.QTPENDENTE;
      -- Administrar bloqueado?
      ELSIF P_INTERNO.PROCESSO IN ('COMPRAR','BLOQUEAR') THEN
        vtESTOQUE_DEPOSITO.QTBLOQUEADA   := P_INTERNO.QTBLOQUEADA;
        vtESTOQUE_DEPOSITO.QTINDENIZADA  := P_INTERNO.QTINDENIZ;
      END IF;
      -- Atualizar estoque depósito
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;

      IF (P_INTERNO.NOME_TABELA <> 'PCREQUISICAODEPOSITO') THEN
        vtREQUISICAO.IDENTIFICADOR   := P_INTERNO.IDENTIFICADOR;
        vtREQUISICAO.CODPROD         := P_INTERNO.CODPROD;
        vtREQUISICAO.NUMSEQ          := P_INTERNO.NUMSEQ;
        vtREQUISICAO.NOME_TABELA     := P_INTERNO.NOME_TABELA;
        vtREQUISICAO.CODFILIAL       := P_INTERNO.CODFILIAL;
        vtREQUISICAO.CODDEPOSITOORIG := P_INTERNO.CODDEPOSITO;
        vtREQUISICAO.CODAUXILIARORIG := P_INTERNO.CODAUXILIAR;
        vtREQUISICAO.NUMLOTEORIG     := P_INTERNO.NUMLOTE;
        vtREQUISICAO.CODDEPOSITODEST := vnCODDEPOSITO_VENDA;
        vtREQUISICAO.CODAUXILIARDEST := P_INTERNO.CODAUXILIAR;
        vtREQUISICAO.NUMLOTEDEST     := P_INTERNO.NUMLOTE;
        vtREQUISICAO.QT              := NVL(P_INTERNO.QTRESERV,P_INTERNO.QTPENDENTE);
        -- Incluir requisição
        PRIV_DEP_INCLUIR_REQUISICAO (vtREQUISICAO);
        -- Validar retorno
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          RETURN;
        END IF;
      -- Gerar requisição
      END IF;
    -- Valida parâmetro
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função depósito reserva incluir';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_INCLUIR';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_INCLUIR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  13/09/2021     DAVI BERNADO      DDESTOQUE-10847    Criada a função para incluir a avaria por padrão de avaria

  ************************************************************************************************************************/
  PROCEDURE PRIV_DEP_AVARIA
  IS
    vnCODDEPOSITO_AVARIA  NUMBER;
    vtESTOQUE_DEPOSITO         T_ESTOQUE_DEPOSITO;
  BEGIN
    SELECT CODDEPOSITO
      INTO vnCODDEPOSITO_AVARIA
      FROM PCESTOQUEDEPOSITO
     WHERE PADRAOAVARIA = 'S'
       AND CODFILIAL = P_INTERNO.CODFILIAL;

    vtESTOQUE_DEPOSITO               := NULL;
    vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIAL;
    vtESTOQUE_DEPOSITO.CODDEPOSITO   := vnCODDEPOSITO_AVARIA;
    vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
    vtESTOQUE_DEPOSITO.QTINDENIZADA  := P_INTERNO.QTINDENIZ;
    vtESTOQUE_DEPOSITO.QTBLOQUEADA   := P_INTERNO.QTBLOQUEADA;
    vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;

    PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);

  END PRIV_DEP_AVARIA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para movimentar o estoque do depósito na saída da mercadoria
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_VENDAS_SAIDA
  IS-- Declaração das variáveis internas
    vtESTOQUE_DEPOSITO T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função depósito vendas saida';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_VENDAS_SAIDA';
    PRIV_GERARLOG;
    -- Validar se usa estoque por depósito

    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
      -- Valida se a massa de dados tem depósito informado
      IF NVL(P_INTERNO.CODDEPOSITO,0) = 0 THEN
        -- Padrão de venda
        P_INTERNO.CODDEPOSITO := PRIV_DEP_PADRAO_VENDA;
        -- Validar retorno
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          RETURN;
        END IF;
        -- Atualizar PCMOV
        UPDATE PCMOV
           SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
         WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
      -- Buscar depósito
      END IF;
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (P_INTERNO.CODFILIAL
                             ,P_INTERNO.CODDEPOSITO
                             ,P_INTERNO.CODPROD
                             ,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;            

      -- Atualizar variáveis
      vtESTOQUE_DEPOSITO               := NULL;
      vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;
      vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
      vtESTOQUE_DEPOSITO.QTESTOQUE     := P_INTERNO.QTESTGER;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
	  vtESTOQUE_DEPOSITO.QTINDENIZADA  := P_INTERNO.QTINDENIZ;
      vtESTOQUE_DEPOSITO.QTBLOQUEADA   := P_INTERNO.QTBLOQUEADA;
      -- Atualizar estoque do depósito
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
      -- Validação parâmetro

      -- Atualiza estoque reservado
      IF P_INTERNO.CODDEPOSITORESERVA > 0 THEN
        -- Atualizar variáveis
        vtESTOQUE_DEPOSITO               := NULL;
        vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIALRESERVA;
        vtESTOQUE_DEPOSITO.CODDEPOSITO   := P_INTERNO.CODDEPOSITORESERVA;
        vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
        vtESTOQUE_DEPOSITO.QTRESERVADA   := P_INTERNO.QTRESERV;
        vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
        -- Atualizar estoque do depósito
        PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      END IF;
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função deposito vendas saida';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_VENDAS_SAIDA';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_VENDAS_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para movimentar o estoque do depósito na entrada de mercadoria
  /***********************************************************************************************************************/
  PROCEDURE PRIV_DEP_VENDAS_ENTRADA
  IS-- Declaração das variáveis internas
    vtESTOQUE_DEPOSITO T_ESTOQUE_DEPOSITO;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função depósito vendas entrada';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_VENDAS_ENTRADA';
    PRIV_GERARLOG;
    -- Validar se usa estoque por depósito
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
      -- Valida se a massa de dados tem depósito informado
      IF NVL(P_INTERNO.CODDEPOSITO,0) = 0 THEN
        -- Busca depósito padrão para venda
        P_INTERNO.CODDEPOSITO := PRIV_DEP_PADRAO_VENDA;
        -- Atualizar PCMOV
        BEGIN
          UPDATE PCMOV
             SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
           WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
        EXCEPTION
          WHEN OTHERS THEN
            P_INTERNO.MSG_RETORNO := 'Erro 1 - Depósito Vendas Entrada: Não foi possível atualizar o código do depósito na tabela de movimentação de estoque (PCMOV)!'||CHR(13)||
                                     'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                     'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                     'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                     'Cód. Depósito: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                     'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                     'MSG Original.: '||SQLERRM;
            RETURN;
        END;
      END IF;
      -- Bloquear estoque depósito
      PRIV_BLOQUEAR_DEPOSITO (P_INTERNO.CODFILIAL
                             ,P_INTERNO.CODDEPOSITO
                             ,P_INTERNO.CODPROD
                             ,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;

      vtESTOQUE_DEPOSITO               := NULL;
      
      IF P_INTERNO.TIPO_OPERACAO = 'I' THEN  
        SELECT ABS(LEAST(P_INTERNO.QTBLOQUEADA, GREATEST(QTESTOQUE + P_INTERNO.QTESTGER, 0)))
          INTO vtESTOQUE_DEPOSITO.QTBLOQUEADA
          FROM PCESTOQUEDEPOSITOPROD
         WHERE CODPROD = P_INTERNO.CODPROD 
           AND CODFILIAL = P_INTERNO.CODFILIAL
           AND CODDEPOSITO = P_INTERNO.CODDEPOSITO;
      ELSE
        P_INTERNO.QTDE_DISPONIVEL  := ESTOQUE_DISPONIVEL_DEPOSITO(P_INTERNO.CODPROD, P_INTERNO.CODFILIAL, P_INTERNO.CODDEPOSITO, 'V');
        
        IF (P_INTERNO.QTDE_DISPONIVEL < P_INTERNO.QTESTGER) THEN
        -- Mensagem de erro
          P_INTERNO.MSG_RETORNO := 'Erro 2 - Depósito Vendas Entradas: Não existe estoque disponível no depósito informado para atender a nota fiscal!'||CHR(13)||
                                   'Identificador...: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                   'Produto.........: '||TO_CHAR(P_INTERNO.CODPROD)||CHR(13)||
                                   'Filial..........: '||P_INTERNO.CODFILIAL||CHR(13)||
                                   'Depósito........: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                   'Qtde. Solicitada: '||P_INTERNO.QTESTGER||CHR(13)||
                                   'Qtde. Disponível: '||P_INTERNO.QTDE_DISPONIVEL||CHR(13)||
                                   'Operação........: '||P_INTERNO.TIPO_OPERACAO;
          RETURN;
        END IF;
      -- Valida estoque disponivel
        vtESTOQUE_DEPOSITO.QTBLOQUEADA := P_INTERNO.QTBLOQUEADA;
      END IF; 
      
      vtESTOQUE_DEPOSITO.CODFILIAL     := P_INTERNO.CODFILIAL;
      vtESTOQUE_DEPOSITO.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;
      vtESTOQUE_DEPOSITO.CODPROD       := P_INTERNO.CODPROD;
      vtESTOQUE_DEPOSITO.QTESTOQUE     := P_INTERNO.QTESTGER;
      vtESTOQUE_DEPOSITO.QTINDENIZADA  := P_INTERNO.QTINDENIZ;
      vtESTOQUE_DEPOSITO.TIPO_OPERACAO := P_INTERNO.TIPO_OPERACAO;
      -- Atualizar estoque do depósito
      PRIV_CALCULAR_DEPOSITO (vtESTOQUE_DEPOSITO,P_INTERNO.MSG_RETORNO);
      -- Validar retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        RETURN;
      END IF;
    -- Validação do parâmetro
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função depósito vendas entrada';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_DEP_VENDAS_ENTRADA';
    PRIV_GERARLOG;
  -- Procedure
  END PRIV_DEP_VENDAS_ENTRADA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/01/2018     Fernandes Brito   0                   Gerar log ref. ao bloqueio do estoque
  ************************************************************************************************************************/
  PROCEDURE PRIV_GERARLOGBLOQUEIO
  IS-- Declaração das variáveis internas
    vnQTDISPONIVEL  PCEST.QTESTGER%TYPE;
    vsESTDISPZERADO VARCHAR2(2);
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PRIV_GERARLOGBLOQUEIO';
    PRIV_GERARLOG;
    -- Buscando dados atuais para alteração
    BEGIN
      SELECT ESTOQUE_DISPONIVEL(PCEST.CODPROD,PCEST.CODFILIAL,'C') SALDO,
             NVL(PCEST.QTBLOQUEADA, 0) QTBLOQUEADA,
             NVL(PCEST.QTINDENIZ, 0) QTINDENIZ
        INTO P_INTERNO.QTDE_DISPONIVEL, P_INTERNO.QTBLOQUEADAANT, P_INTERNO.QTINDENIZANT
        FROM PCEST
       WHERE PCEST.CODPROD = P_INTERNO.CODPROD
         AND PCEST.CODFILIAL = P_INTERNO.CODFILIAL;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Gerar Log Bloqueio: Não foi possível pesquisar  o estoque bloqueado';
        RAISE;
    END;
    -- Validando estoque disponível
    IF vnQTDISPONIVEL = 0 THEN
      vsESTDISPZERADO := 'S';
    ELSE
      vsESTDISPZERADO := 'N';
    END IF;
    -- Inserindo o log na tabela
    BEGIN
      INSERT INTO PCLOGDESBLOQUEIO
        (NUMTRANSENT,
         DTDESBLOQUEIO,
         CODFUNCDESBLOQUEIO,
         CODPROD,
         QTBLOQUEADA,
         QTBLOQUEADAANT,
         OBS,
         ESTDISPZERADO,
         CODFILIAL,
         CODDEVOL,
         PROGRAMA,
         QTINDENIZ,
         QTINDENIZANT,
         QTDESBLOQUEADA,
         NUMBONUS)
      VALUES
        (P_INTERNO.IDENTIFICADOR
        ,SYSDATE
        ,P_INTERNO.CODFUNCLANC
        ,P_INTERNO.CODPROD
        ,P_INTERNO.QTBLOQUEADA
        ,P_INTERNO.QTBLOQUEADAANT
        ,P_INTERNO.OBSERVACAO
        ,vsESTDISPZERADO
        ,P_INTERNO.CODFILIAL
        ,P_INTERNO.CODDEVOL
        ,vsROTINA
        ,P_INTERNO.QTINDENIZ
        ,P_INTERNO.QTINDENIZANT
        ,P_INTERNO.QTDESBLOQUEADA
        ,P_INTERNO.NUMTRANSACAOORIGEM);
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 2 - Gerar Log Bloqueio: Não foi possível realizar o insert da tabela PCLOGDESBLOQUEIO!'||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
        RAISE;
    END;
    -- Buscando dados atuais para alteração
    BEGIN
      SELECT NVL(PCEST.QTBLOQUEADA, 0) QTBLOQUEADA,
             NVL(PCEST.QTINDENIZ, 0) QTINDENIZ
        INTO P_INTERNO.QTBLOQUEADAANT
            ,P_INTERNO.QTINDENIZANT
        FROM PCEST
       WHERE PCEST.CODPROD = P_INTERNO.CODPROD
         AND PCEST.CODFILIAL = P_INTERNO.CODFILIAL;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'Erro 3 - Gerar Log Bloqueio: Não foi possível pesquisar  o estoque bloqueado';
        RAISE;
    END;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a procedure - PRIV_GERARLOGBLOQUEIO';
    PRIV_GERARLOG;
  EXCEPTION
    WHEN OTHERS THEN
      -- Inserindo informações de debug (LOG)
      RAISE_APPLICATION_ERROR(-20000,CHR(13)||
                             'Erro 3 - Gerar Log Bloqueio: Erro desconhecido!'||CHR(13)||
                             'Mensagem de erro: '||CHR(13)||P_INTERNO.MSG_RETORNO||CHR(13)||
                             'Mensagem original do banco: '||CHR(13)||SQLCODE);
      RAISE;
  -- Procedure
  END PRIV_GERARLOGBLOQUEIO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/08/2019     Fernandes Brito   0                   Criado metodo para validar se a PKG_ESTOQUE esta sendo executada mais
                                                       de uma vez dentro da mesma sessão e deixando variáveis suja.
  ************************************************************************************************************************/
  PROCEDURE PRIV_LIMPAR_P_INTERNO
  IS
    vsTRANSACAO_ATUAL VARCHAR2(200);
  BEGIN
    -- Localizar transação atual
    SELECT DBMS_TRANSACTION.LOCAL_TRANSACTION_ID
      INTO vsTRANSACAO_ATUAL
      FROM DUAL;
    -- Transação mudou?
    IF P_INTERNO.TRANSACAO_ANTERIOR IS NULL OR P_INTERNO.TRANSACAO_ANTERIOR <> vsTRANSACAO_ATUAL THEN
      -- Limpa type interno
      P_INTERNO := NULL;
      P_INTERNO.MSG_RETORNO := 'OK';
      -- Atualiza variável
      P_INTERNO.TRANSACAO_ATUAL    := vsTRANSACAO_ATUAL;
      P_INTERNO.TRANSACAO_ANTERIOR := P_INTERNO.TRANSACAO_ATUAL;
    -- Transação mudou?
    END IF;
  -- Procedure
  END PRIV_LIMPAR_P_INTERNO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/07/2021    DAVI BERNADO       DDESTOQUE-9057      INCLUIR RESERVA DO LOTE
  /************************************************************************************************************************/
  FUNCTION PRIV_LOTE_RESERVA_BAIXAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                    ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                                    ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                                    ,psNUMLOTE         IN PCPEDI.NUMLOTE%TYPE
                                    ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                    ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONDVENDAANT          PCPEDC.CONDVENDA%TYPE;
    vsPOSICAOANT            PCPEDC.POSICAO%TYPE;
    vnQTDEANT               PCMOV.QT%TYPE;
    vsCODFILIALANT          PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vnQtdeNfPreFat          NUMBER;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
    vsUSAWMS                PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE        PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vsTIPOMERC              PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL          PCPRODUT.PESOVARIAVEL%TYPE;
    vnQTUNITCX              PCPRODUT.QTUNITCX%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função PRIV_LOTE_RESERVA_BAIXAR';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_BAIXAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.NUMLOTE         := psNUMLOTE;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Excutar consulta do produto
    PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    IF psOPERACAO NOT IN ('AM', 'CM', 'BA') THEN
      -- Consultar dados anteriores
      PRIV_CONS_DADOS_ANTERIORES (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,vnCONDVENDAANT,vsPOSICAOANT,vnQTDEANT,vsCODFILIALANT,psMSG_RETORNO);
      -- Verifica se deu tudo certo ao consultar dados anteriores
      IF psMSG_RETORNO <> 'OK' THEN
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
    END IF;

    -- Atualizar Variáveis
    P_INTERNO.vtLOTE               := NULL;
    P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
    P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIAL;
    P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
    P_INTERNO.vtLOTE.NUMLOTE       := psNUMLOTE;
    -- Bloquear PCLOTE
    PRIV_BLOQUEAR_LOTE;
    -- Validar se conseguiu bloquear a PCLOTE
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;

    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    CASE
      WHEN psOPERACAO IN ('AM','CM') THEN
        BEGIN
          SELECT NVL(SUM(RI.QT), 0) QT, RC.CODFILIAL
            INTO vnQTDEANT, vsCODFILIAL
            FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
           WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
             AND RI.CODOPER = 'SM'
             AND RC.NUMPREREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD
             AND RI.NUMLOTE = psNUMLOTE
        GROUP BY RC.CODFILIAL;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL  := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível consultar dados do item para fazer a reserva do lote!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;

        P_INTERNO.vtLOTE.QTRESERV    := NVL(vnQTDEANT, 0);
        --** Inicio - Indústria Baixar (BI): Usado no apontamento final **
      WHEN psOPERACAO = 'BI' THEN
        -- Obter filial de produção
        BEGIN
          SELECT PCOPC.CODFILIAL
                ,CASE
                   WHEN NVL(L.QTREQUISITADO, 0) < 0 THEN
                     (NVL(L.QTREQUISITADO, 0) * (-1))
                 ELSE
                   NVL(L.QTREQUISITADO, 0)
                 END QTRESERVALTERAR
            INTO vsCODFILIAL
                ,vnQTDEANT
            FROM PCOPILOTE L
                ,PCOPC
           WHERE L.NUMOP = PCOPC.NUMOP
             AND PCOPC.NUMOP = pnIDENTIFICADOR
             AND L.CODPROD = pnCODPROD
             AND L.QTREQUISITADO > 0
             AND L.NUMLOTE = psNUMLOTE
             AND PCOPC.POSICAO = 'P';
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL  := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 2 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível consultar dados do item para baixar a reserva do lote!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        P_INTERNO.vtLOTE.QTRESERV    := NVL(vnQTDEANT, 0);
      -- Inicio industria baixar por pedido (BA)
      WHEN psOPERACAO = 'BA' THEN
        -- Busca quantidade e filial
        BEGIN
          SELECT NVL(PCAVULSA.QT,0) QT, PCAVULSA.CODFILIAL
            INTO vnQTDEANT, vsCODFILIAL
            FROM PCAVULSA
           WHERE PCAVULSA.NUMTRANSAVULSA = pnIDENTIFICADOR
             AND PCAVULSA.CODPROD = pnCODPROD
             AND PCAVULSA.NUMSEQ = pnNUMSEQ
             AND SUBSTR(PCAVULSA.CODOPER,1,1) IN ('S','P')
             AND PCAVULSA.DTCANCEL IS NULL
             AND PCAVULSA.NUMLOTE = psNUMLOTE
             AND PCAVULSA.DTBAIXA IS NULL;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 5 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível consultar dados do item para fazer a reserva do lote!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                             'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        P_INTERNO.vtLOTE.QTRESERV    := NVL(vnQTDEANT, 0);
      -- PEDIDO DE VENDA
      WHEN psOPERACAO IN ('BQ','BV','BP','AQ','AV','AP','CQ','CV','CP','CC','FQ') THEN
        -- Valida se é corte total
        IF psOPERACAO NOT IN ('FQ') THEN
          -- Retornar dados do pedido atual
          BEGIN
            --Validar filial e filial retira
            vsCODFILIAL := VALIDA_CODFILIAL_CEFAT(PNIDENTIFICADOR, PNCODPROD, PNNUMSEQ);
            P_INTERNO.CODFILIAL   := vsCODFILIAL;
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            --
            SELECT DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                  ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
                  ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
                  ,PCPEDI.CODDEPOSITO
                  ,PCPEDI.TIPOENTREGA
                  ,PCPEDI.ROWID
              INTO vsPOSICAO
                  ,vsPEDIDOAVARIA -- DDMEDICA-620
                  ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
                  ,P_INTERNO.CODDEPOSITO
                  ,P_INTERNO.TIPO_ENTREGA
                  ,P_INTERNO.ROWID_REGISTRO
              FROM PCPEDC, PCPEDI
             WHERE PCPEDC.NUMPED = PCPEDI.NUMPED
               AND PCPEDI.NUMSEQ = pnNUMSEQ
               AND PCPEDI.CODPROD = pnCODPROD
               AND PCPEDI.NUMLOTE = psNUMLOTE
               AND PCPEDC.NUMPED = pnIDENTIFICADOR;
          EXCEPTION
            WHEN OTHERS THEN
              psMSG_RETORNO := 'Erro 7 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível validar dados para fazer a baixa da reserva  do lote!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                               'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                               'Operação.....: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
          END;
          -- Pedido de Avaria - Nao atualiza o Estoque Pendente - DDMEDICA-620
          IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
            -- Inserindo informações de debug (LOG)
            P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função PRIV_LOTE_RESERVA_BAIXAR - PED. AVARIA';
            P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_BAIXARr';
            PRIV_GERARLOG;
            RETURN 'S';
          END IF;
          -- Pedido de CrossDocking - Nao atualiza o Estoque Pendente - DDMEDICA-620
          IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
            -- Inserindo informações de debug (LOG)
            P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função PRIV_LOTE_RESERVA_BAIXAR - PED. CROSSDOCK';
            P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_BAIXARr';
            PRIV_GERARLOG;
            RETURN 'S';
          END IF;
        ELSE
          vsPOSICAO   := vsPOSICAOANT;
          vsCODFILIAL := vsCODFILIALANT;
        -- Validação do corte
        END IF;
        -- Caso seja uma NF de pré-faturamento,
        -- permitir baixar reserva a partir dela.
        SELECT COUNT(1)
          INTO vnQTDENFPREFAT
          FROM PCNFSAIDPREFAT C
         WHERE C.NUMPED = pnIDENTIFICADOR
           AND NOT EXISTS (SELECT 1
                             FROM PCNFSAID N
                            WHERE N.NUMTRANSVENDA = C.NUMTRANSVENDA);
        -- Atualizando o estoque
        IF (vsPOSICAOANT IN ('L', 'M') OR
           (vsPOSICAOANT = 'F' AND (vnQTDENFPREFAT = 1))) AND
           (vnCONDVENDAANT NOT IN (4, 7, 14)) THEN

          P_INTERNO.vtLOTE.QTRESERV    := NVL(vnQTDEANT, 0);
          -- Gravar dados analiticos
        ELSE
          psMSG_RETORNO := 'Erro 8 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível retirar o estoque da reserva  do lote.'||CHR(13)||
                           'A posição ou tipo de venda do pedido não é válido para esta operação.'||CHR(13)||
                           'O Identificador ' ||TO_CHAR(pnIDENTIFICADOR) || ' não é valido ou !'||CHR(13)||
                           'Posição......: '||vsPOSICAOANT||CHR(13)||
                           'Tipo de venda: '||TO_CHAR(vnCONDVENDAANT)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
    -- Operação inválida
    ELSE
      psMSG_RETORNO := 'Erro 9 (PRIV_LOTE_RESERVA_BAIXAR): Não foi possível baixar o estoque da reserva do lote.'||CHR(13)||
                       'O Identificador informado não é valido!'||CHR(13)||
                       'O Identificador: ' ||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.......: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da operação
    END CASE;

    -- Atualizar dados
    P_INTERNO.vtLOTE.QT          := NULL;
    P_INTERNO.TIPO_OPERACAO      := 'B';
    P_INTERNO.vtLOTE.QTEST       := NULL;
    P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
    P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
    P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
    -- Administrar estoque do lote
    PRIV_ATUALIZAR_LOTE;
    -- Validando se conseguiu atualizar o lote
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Atualizar variáveis
    P_INTERNO.QTRESERV      := P_INTERNO.vtESTOQUE.QTRESERV;
    P_INTERNO.PROCESSO      := 'RESERVAR';

    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função PRIV_LOTE_RESERVA_BAIXAR';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_BAIXAR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno cerá "S - Sim"
    RETURN 'S';
  -- Função
  END PRIV_LOTE_RESERVA_BAIXAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/07/2021    DAVI BERNADO       DDESTOQUE-9057      INCLUIR RESERVA DO LOTE
  /************************************************************************************************************************/
  FUNCTION PRIV_LOTE_RESERVA_INCLUIR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                     ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                                     ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                                     ,psNUMLOTE         IN PCPEDI.NUMLOTE%TYPE
                                     ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                     ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnQT                    PCPEDI.QT%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vnQTDISPONIVEL          PCEST.QTRESERV%TYPE;
    vsORIGEMPED             PCPEDC.ORIGEMPED%TYPE;
    vnCONDVENDA             PCPEDC.CONDVENDA%TYPE;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
    vnTIPO_MERCADORIA       PCPRODUT.TIPOMERC%TYPE;
    vsUSAWMS                PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE        PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vnQTUNITCX              PCPRODUT.QTUNITCX%TYPE;
    vsTIPOMERC              PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL          PCPRODUT.PESOVARIAVEL%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função PRIV_LOTE_RESERVA_INCLUIR';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_INCLUIR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.NUMLOTE         := psNUMLOTE;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Excutar consulta do produto
    PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina

    -- Atualizar Variáveis
    P_INTERNO.vtLOTE               := NULL;
    P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
    P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIAL;
    P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
    P_INTERNO.vtLOTE.NUMLOTE       := psNUMLOTE;
    -- Bloquear PCLOTE
    PRIV_BLOQUEAR_LOTE;
    -- Validar se conseguiu bloquear a PCLOTE
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;

    CASE
      WHEN psOPERACAO = 'IM' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL(SUM(RI.QT), 0) QT
                ,RC.CODFILIAL
                ,RI.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
           WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
             AND RI.CODOPER = 'SM'
             AND RC.SITUACAO = 'L'
             AND RC.NUMPREREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD
             AND RI.NUMLOTE = psNUMLOTE
        GROUP BY RC.CODFILIAL
                ,RI.CODDEPOSITO;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCPREREQMATCONSUMOI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (PRIV_LOTE_RESERVA_INCLUIR): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;

        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'V');
        -- Caso não existe disponivel para a reserva
        IF ((vnQT> vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0))  THEN
          psMSG_RETORNO := 'Erro 2 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                           'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Lote.........: '||CHR(9)||(psNUMLOTE)||CHR(13)||
                           'Necessidade..: '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'Disponível...: '||CHR(9)||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      --** Inicio - Indústria Incluir (II) **
      WHEN psOPERACAO = 'II' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT ROUND(SUM(L.QT - NVL(L.QTREQUISITADO,0)),6) QT
                 ,P.CODFILIAL
            INTO vnQT
                 ,vsCODFILIAL
            FROM PCOPILOTE L
                 ,PCOPC P
           WHERE P.NUMOP = L.NUMOP
             AND P.NUMOP = pnIDENTIFICADOR
             AND L.CODPROD = pnCODPROD
             AND NVL(P.FINALIZAPRODUCAO, 'N') = 'N'
             AND P.POSICAO IN ('P', 'L')
             AND NVL(P.QTPRODUZIDA,0) <= NVL(P.QTPRODUZIR,0)
             AND L.NUMLOTE = psNUMLOTE
             AND L.QTREQUISITADO > 0
           GROUP BY P.NUMOP, L.NUMLOTE;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCOPI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 3 (PRIV_LOTE_RESERVA_INCLUIR): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||TO_CHAR(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Buscar o disponível do lote
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'I');
        -- Caso não existe disponivel para a reserva
        IF ((vnQT> vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0))  THEN
          psMSG_RETORNO := 'Erro 4 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                           'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Lote.........: '||CHR(9)||(psNUMLOTE)||CHR(13)||
                           'Necessidade..: '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'Disponível...: '||CHR(9)||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação do disponível
        END IF;
      -- Inicio - Ordem de Serviço
      WHEN psOPERACAO = 'IO' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL(SUM(A.QTDE),0) AS QT
                ,A.CODFILIALRETIRA CODFILIAL
                ,I.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCITEMSERVICO A,
                 PCORDEMSERVICO O,
                 PCORDEMSERVICOI I,
                 PCTIPOORDEMSERVICO T,
                 PCCONSUM
           WHERE O.NUMOS = I.NUMOS
             AND I.NUMOSSERVICO = A.NUMOSSERVICO
             AND O.TIPOOS = T.CODTIPO(+)
             AND O.NUMTRANSVENDAPROD IS NULL
             AND NVL(A.DEMONSTRACAO,'N') = 'N'
             AND O.NUMOS = pnIDENTIFICADOR
             AND A.CODPROD = pnCODPROD
             AND A.NUMLOTE = psNUMLOTE
             AND ((NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   NVL(T.GERARCONTRECEBERPRODUTO, 'N') = 'S' AND
                   O.SITUACAO IN (2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'S' AND
                   O.SITUACAO IN (1, 2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   O.SITUACAO IN (2))
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO, 'N') = 'S' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N')
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N'))
           GROUP BY A.CODFILIALRETIRA, I.CODDEPOSITO;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCORDEMSERVICOI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 5 (PRIV_LOTE_RESERVA_INCLUIR): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Buscar o disponível do lote
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'I');
        -- Caso não existe disponivel para a reserva
        IF ((vnQT> vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0))  THEN
          psMSG_RETORNO := 'Erro 6 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                           'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Lote.........: '||CHR(9)||(psNUMLOTE)||CHR(13)||
                           'Necessidade..: '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'Disponível...: '||CHR(9)||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação do disponível
        END IF;
      -- Inicio industria incluir requisição avulsa
      WHEN psOPERACAO = 'IA' THEN
        -- Busca quantidade e filial
        BEGIN
          SELECT NVL(PCAVULSA.QT, 0) QT
                ,PCAVULSA.CODFILIAL
                ,PCAVULSA.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCAVULSA
           WHERE PCAVULSA.NUMTRANSAVULSA = pnIDENTIFICADOR
             AND PCAVULSA.NUMSEQ = pnNUMSEQ
             AND PCAVULSA.CODPROD = pnCODPROD
             AND PCAVULSA.CODOPER IN ('S','P')
             AND PCAVULSA.DTCANCEL IS NULL
             AND PCAVULSA.DTBAIXA IS NULL
             AND PCAVULSA.NUMLOTE = psNUMLOTE;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCAVULSA';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 7 (PRIV_LOTE_RESERVA_INCLUIR): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote.........: '||CHR(9)||(psNUMLOTE)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Buscar o disponível do lote
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'I');
        -- Caso não existe disponivel para a reserva
        IF ((vnQT > vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0))THEN
          psMSG_RETORNO := 'Erro 8 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                           'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto      : '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Lote         : '||CHR(9)||(psNUMLOTE)||CHR(13)||
                           'Necessidade  : '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                           'Disponível   : '||CHR(9)||TO_CHAR(vnQTDISPONIVEL)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação do disponível
        END IF;
      ELSE
        -- Consultar dados para o update no PCEST
        BEGIN
          SELECT PCPEDI.QT
                ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                ,PCPEDC.ORIGEMPED
                ,PCPEDC.CONDVENDA
                ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
                ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
                ,PCPEDI.CODDEPOSITO
                ,PCPEDI.TIPOENTREGA
                ,PCPEDI.ROWID
                ,PCPRODUT.TIPOMERC
            INTO vnQT
                ,vsCODFILIAL
                ,vsPOSICAO
                ,vsORIGEMPED
                ,vnCONDVENDA
                ,vsPEDIDOAVARIA -- DDMEDICA-620
                ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
                ,P_INTERNO.CODDEPOSITO
                ,P_INTERNO.TIPO_ENTREGA
                ,P_INTERNO.ROWID_REGISTRO
                ,vnTIPO_MERCADORIA
            FROM PCPEDI, PCPEDC, PCPRODUT
           WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
             AND PCPEDI.NUMPED = pnIDENTIFICADOR
             AND PCPEDI.CODPROD = PCPRODUT.CODPROD
             AND PCPEDI.CODPROD = pnCODPROD
             AND PCPEDI.NUMLOTE = psNUMLOTE
             --AND NVL(PCPEDI.QT,0) > 0
             AND PCPEDI.NUMSEQ = pnNUMSEQ;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCPEDI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 9 (PRIV_LOTE_RESERVA_INCLUIR): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote         : '||CHR(9)||(psNUMLOTE)||CHR(13)||
                             'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Posição inválida
        IF vsPOSICAO NOT IN ('L','M') THEN
          psMSG_RETORNO := 'Erro 10 (PRIV_LOTE_RESERVA_INCLUIR): A posição do pedido é inválida para realizar a reserva do estoque!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Posiçao......: '||vsPOSICAO||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Condição de venda inválido
        IF vnCONDVENDA IN (4,7,14) THEN
          psMSG_RETORNO := 'Erro 11 (Reserva Incluir): O cond. Venda não é válido para realizar a reservar do estoque!'||CHR(13)||
                           'Cond. Venda..: '||TO_CHAR(vnCONDVENDA)||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Venda de Avaria - DDMEDICA-620
        IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
          -- Consultando disponivel de Avaria
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'PA');
          -- Apresentar erro caso a quantidade disponivel for menor
          IF (vnQTDISPONIVEL < vnQT) THEN
            psMSG_RETORNO := 'Erro 11 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque de avaria disponível para o Pedido de Avaria!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote         : '||CHR(9)||(psNUMLOTE)||CHR(13)||
                             'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                             'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Valida disponivel
          END IF;
          -- Inserindo informações de debug (LOG)
          P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_incluir - PED. AVARIA';
          P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
          PRIV_GERARLOG;
          RETURN 'S';
        -- Condicao: Venda de Avaria - DDMEDICA-620
        END IF;
        -- Venda de CrossDocking - DDMEDICA-620
        IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
          -- Consultando disponivel bloqueado
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'PC');
          -- Apresentar erro caso a quantidade disponivel for menor
          IF (vnQTDISPONIVEL < vnQT) THEN
            psMSG_RETORNO := 'Erro 12 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque bloqueado disponível para fazer o pedido de Crossdocking!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Lote         : '||CHR(9)||(psNUMLOTE)||CHR(13)||
                             'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                             'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Valida disponivel
          END IF;
          -- Inserindo informações de debug (LOG)
          P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_incluir - PED. CROSSDOCK';
          P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
          PRIV_GERARLOG;
          RETURN 'S';
        -- Condicao: Venda de CrossDocking - DDMEDICA-620
        END IF;
        -- Consultando disponivel do produto
        IF vnTIPO_MERCADORIA = 'CB' THEN
           vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'VA');
        ELSE
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,psNUMLOTE,'P');
        END IF;
        -- Apresentar erro caso a quantidade disponivel for menor
        IF ((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND (vnCONDVENDA <> 7) THEN
          IF NOT((NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') = 'S') AND vsORIGEMPED IN ('B','R','A')) THEN
            IF (NOT vsROTINA LIKE '%998%') AND (vsROTINA NOT LIKE '%1401%') THEN
              psMSG_RETORNO := 'Erro 13 (PRIV_LOTE_RESERVA_INCLUIR): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Lote         : '||CHR(9)||(psNUMLOTE)||CHR(13)||
                               'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                               'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            -- Valida disponivel
            END IF;
          --
          END IF;
        -- Valida disponivel
        END IF;
    END CASE;

    -- Atualizar variáveis
    -- Atualizar dados
    P_INTERNO.vtLOTE.QT          := NULL;
    P_INTERNO.vtLOTE.QTEST       := NULL;
    P_INTERNO.vtLOTE.QTRESERV    := vnQT;
    P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
    P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
    P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
    -- Administrar estoque do lote
    PRIV_ATUALIZAR_LOTE;
    -- Validando se conseguiu atualizar o lote
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;

    -- Atualizar variáveis
    P_INTERNO.QTRESERV      := vnQT;
    P_INTERNO.PROCESSO      := 'RESERVAR';
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função PRIV_LOTE_RESERVA_INCLUIR';
    P_INTERNO.NOME_FUNCAO     := 'PRIV_LOTE_RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno será "S - Sim"
    RETURN 'S';
  -- Função
  END PRIV_LOTE_RESERVA_INCLUIR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  29/08/2019     Hugo Aquino       0                   Criada a procedure para enviar mensagem ao RCA ao desebloquear a mercadoria
  /***********************************************************************************************************************/
  PROCEDURE PRIV_MSG_RCA (psCODFILIAL   IN PCEST.CODFILIAL%TYPE
                         ,pnCODPROD     IN PCEST.CODPROD%TYPE)
  IS-- Declaração das variáveis internas
    vnCODPROD   PCPRODUT.CODPROD%TYPE;
    vsCODFILIAL PCFILIAL.CODIGO%TYPE;
    vsDESCRICAO PCPRODUT.DESCRICAO%TYPE;
    vsEMBALAGEM PCPRODUT.EMBALAGEM%TYPE;
    -- Lista de RCA para enviar mensagem
    CURSOR C_RCA
    IS
      SELECT PCUSUARI.CODUSUR
        FROM PCUSUARI
       WHERE PCUSUARI.DTTERMINO IS NULL
         AND NVL(PCUSUARI.CODFILIAL,'99') IN ('99', psCODFILIAL)
         AND NVL(PCUSUARI.BLOQUEIO, 'N') = 'N';
  BEGIN
    -- Produtos desbloqueados
    BEGIN
      SELECT PCPRODUT.CODPROD
           , PCEST.CODFILIAL
           , UPPER(PCPRODUT.DESCRICAO) DESCRICAO
           , UPPER(PCPRODUT.EMBALAGEM) EMBALAGEM
        INTO vnCODPROD
            ,vsCODFILIAL
            ,vsDESCRICAO
            ,vsEMBALAGEM
       FROM PCEST
          , PCPRODUT
      WHERE PCEST.CODPROD = PCPRODUT.CODPROD
        AND PCEST.CODFILIAL = psCODFILIAL
        AND PCPRODUT.CODPROD = pnCODPROD
        AND (PKG_ESTOQUE.ESTOQUE_DISPONIVEL(PCEST.CODPROD, PCEST.CODFILIAL, 'V')) > 0;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnCODPROD    := NULL;
        vsCODFILIAL  := NULL;
        vsDESCRICAO  := NULL;
        vsEMBALAGEM  := NULL;
    END;
    -- Se achou produto
    IF vnCODPROD IS NOT NULL THEN
      -- Lista de RCAs
      FOR RCA IN C_RCA
      LOOP
        INSERT INTO PCMENS
                   (CODUSUR
                  , DATA
                  , MENS1
                  , MENS2
                  , MENS3
                  , MENS4
                  , MENS5
                  , ENVIADO)
            VALUES (RCA.CODUSUR
                  , TRUNC(SYSDATE)
                  , 'ITEM DISPONÍVEL NO ESTOQUE:'
                  , TRIM(vnCODPROD || ' - ' || vsDESCRICAO)
                  , TRIM('EMBALAGEM: ' || vsEMBALAGEM)
                  , TRIM('FILIAL: ' || vsCODFILIAL)
                  , TRIM('ROTINA: ' || SYS_CONTEXT('USERENV', 'MODULE'))
                  , 'S');
      -- Lista de RCAs
      END LOOP;
    -- Produto
    END IF;
  -- Procedure
  END PRIV_MSG_RCA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Procedure de criação e manipulação dos dados analitico da reserva do produto
  /***********************************************************************************************************************/
  PROCEDURE PRIV_RESERVA_ANALITICA (pnIDENTIFICADOR      IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                   ,pnCODPROD            IN PCPEDI.CODPROD%TYPE
                                   ,pnNUMSEQ             IN PCPEDI.NUMSEQ%TYPE
                                   ,psPOSICAOPED         IN PCPEDC.POSICAO%TYPE
                                   ,psOPERACAO           IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                   ,psCODFILIALESTOQUE   IN PCMOV.CODFILIAL%TYPE
                                   ,pnQT                 IN PCPEDI.QT%TYPE
                                   ,psROTINA             IN PCMOV.ROTINACAD%TYPE
                                   ,psMSG_RETORNO        OUT VARCHAR2)
  IS-- Declaração das variáveis internas
    vnREGISTROS NUMBER;
  BEGIN
    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
    -- Validar qual tipo de processo esta sendo executado
    CASE
      WHEN PSOPERACAO IN ('IN', 'IP', 'AQ', 'AP', 'CP', 'CC') THEN
        -- Verificar se o registro já foi inserido na tabela
        SELECT COUNT(1)
          INTO vnREGISTROS
          FROM PCESTANALITICOVENDA C
         WHERE C.NUMPED = pnIDENTIFICADOR
           AND C.CODPROD = pnCODPROD
           AND C.NUMSEQ = pnNUMSEQ;
        -- Inserindo reserva/pendencia na tabela
        IF (vnREGISTROS = 0) THEN
          INSERT INTO PCESTANALITICOVENDA
            (CODFILIALESTOQUE,
             NUMPED,
             NUMSEQ,
             NUMOS,
             NUMTRANSAVULSA,
             POSICAOPED,
             POSICAOEST,
             DATA,
             CODPROD,
             QT,
             ROTINAULTALT,
             ROTINALANC)
          VALUES
            (psCODFILIALESTOQUE,
             pnIDENTIFICADOR,
             pnNUMSEQ,
             0,
             0,
             psPOSICAOPED,
             DECODE(psPOSICAOPED, 'B', 'P', 'P', 'P', 'R'),
             SYSDATE,
             pnCODPROD,
             pnQT,
             psROTINA,
             psROTINA);
        ELSE
          -- Alterando reserva/pendencia na tabela
          UPDATE PCESTANALITICOVENDA
             SET CODFILIALESTOQUE = psCODFILIALESTOQUE,
                 NUMOS            = 0,
                 NUMTRANSAVULSA   = 0,
                 POSICAOPED       = psPOSICAOPED,
                 POSICAOEST       = DECODE(psPOSICAOPED,'B','P','P','P','R'),
                 DATA             = SYSDATE,
                 QT               = pnQT,
                 ROTINAULTALT     = psROTINA
           WHERE NUMPED = pnIDENTIFICADOR
             AND CODPROD = pnCODPROD
             AND NUMSEQ = pnNUMSEQ;
        END IF;
      ELSE
        -- Retirando reserva/pendencia na tabela
        DELETE FROM PCESTANALITICOVENDA
         WHERE NUMPED = pnIDENTIFICADOR
           AND CODPROD = pnCODPROD
           AND NUMSEQ = pnNUMSEQ;
    END CASE;
  -- Procedure
  END PRIV_RESERVA_ANALITICA;

  /************************************************************************************************************************
