  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  28/01/2021     Fernandes Brito   0                   Criada a procedure para validar dados da reserva do estoque
  ************************************************************************************************************************/
  PROCEDURE PROT_ADMINISTRAR_RESERVA (p_ENTRADA IN OUT TYPE_RESERVA)
  IS-- Declaração das variáveis internas
    vsESTOQUE_DISPONIVEL PCEST.QTESTGER%TYPE;
    vsTEM_DADOS          NUMBER;
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.TIPO_OPERACAO    := p_ENTRADA.OPERACAO;
    P_INTERNO.INFORMACOES_LOG  := 'A rotina '||p_ENTRADA.ROTINA||' iniciou a procedure administradora da reserva';
    P_INTERNO.NOME_FUNCAO      := 'PROT_ADMINISTRAR_RESERVA';
    PRIV_GERARLOG;
    CASE-- Processos de reservado/pendente
      WHEN p_ENTRADA.ROTINA IN (4116) THEN
        -- Um produto?
        IF p_ENTRADA.OPERACAO = 'P' THEN
          -- Bloquear a tabela PCEST
          PRIV_BLOQUEAR_ESTOQUE(p_ENTRADA.CODFILIAL, p_ENTRADA.CODPROD, p_ENTRADA.MSG_RETORNO);
          -- Validar se conseguiu bloquear a tabela
          IF p_ENTRADA.MSG_RETORNO <> 'OK' THEN
            P_INTERNO.CODPROD       := p_ENTRADA.CODPROD;
            P_INTERNO.NUMSEQ        := p_ENTRADA.NUMSEQ;
            P_INTERNO.CODFILIAL     := p_ENTRADA.CODFILIAL;
            P_INTERNO.MSG_RETORNO   := p_ENTRADA.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN;
          END IF;
          -- Processar
          PROT_PROCESSAR_RESERVA (p_ENTRADA);
          -- Algo errado?
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            RETURN;
          END IF;
        -- Todos produtos?
        ELSE
          -- Zera contador
          vsTEM_DADOS := 0;
          -- Bloqueia todos os itens
          FOR DADOS IN (SELECT NVL(PCPEDC.CODFILIAL,PCPEDI.CODFILIALRETIRA) CODFILIAL
                              ,PCPEDI.CODPROD
                              ,PCPEDI.NUMSEQ
                          FROM PCPEDC
                              ,PCPEDI
                         WHERE PCPEDC.NUMPED = PCPEDI.NUMPED
                           AND PCPEDI.NUMPED = p_ENTRADA.NUMPED
                         UNION
                        SELECT OLD_CODFILIAL
                              ,OLD_CODPROD
                              ,OLD_NUMSEQ
                          FROM TABLE (PRIV_CONS_PEDIDOS_ANTERIORES(p_ENTRADA.NUMPED
                                                                  ,NULL
                                                                  ,NULL)))
          LOOP
            -- Atualizar contador
            vsTEM_DADOS := vsTEM_DADOS + 1;
            -- Bloquear a tabela PCEST
            PRIV_BLOQUEAR_ESTOQUE(DADOS.CODFILIAL, DADOS.CODPROD, p_ENTRADA.MSG_RETORNO);
            -- Validar se conseguiu bloquear a tabela
            IF p_ENTRADA.MSG_RETORNO <> 'OK' THEN
              P_INTERNO.CODPROD       := DADOS.CODPROD;
              P_INTERNO.NUMSEQ        := DADOS.NUMSEQ;
              P_INTERNO.CODFILIAL     := DADOS.CODFILIAL;
              P_INTERNO.MSG_RETORNO   := p_ENTRADA.MSG_RETORNO;
              PRIV_GERARLOG;
              vsTEM_DADOS             := 0;
              EXIT;
            END IF;
          END LOOP;
          -- Não tem dados
          IF vsTEM_DADOS = 0 THEN
            -- Inserindo informações de debug (LOG)
            p_ENTRADA.MSG_RETORNO      := 'Erro 4 (Administrar Reserva): Não existe dados para o idenfiticador informado ou não foi possível bloquear todos o estoque!'||CHR(13)||
                                          'Identificador.: '||TO_CHAR(p_ENTRADA.NUMPED)||CHR(13)||
                                          'Código Rotina.: '||TO_CHAR(p_ENTRADA.ROTINA);
            P_INTERNO.MSG_RETORNO      := p_ENTRADA.MSG_RETORNO;
            P_INTERNO.INFORMACOES_LOG  := 'Erro na procedure administradora da reserva';
            P_INTERNO.NOME_FUNCAO      := 'PROT_ADMINISTRAR_RESERVA';
            PRIV_GERARLOG;
          END IF;
          -- Zera contador
          vsTEM_DADOS := 0;
          -- Buscar itens
          FOR DADOS IN (SELECT NVL(PCPEDC.CODFILIAL,PCPEDI.CODFILIALRETIRA) CODFILIAL
                              ,PCPEDI.CODPROD
                              ,PCPEDI.NUMSEQ
                          FROM PCPEDC
                              ,PCPEDI
                         WHERE PCPEDC.NUMPED = PCPEDI.NUMPED
                           AND PCPEDI.NUMPED = p_ENTRADA.NUMPED
                         UNION
                        SELECT OLD_CODFILIAL
                              ,OLD_CODPROD
                              ,OLD_NUMSEQ
                          FROM TABLE (PRIV_CONS_PEDIDOS_ANTERIORES(p_ENTRADA.NUMPED
                                                                  ,NULL
                                                                  ,NULL)))
          LOOP
            -- Atualizar contador
            vsTEM_DADOS := vsTEM_DADOS + 1;
            -- Processar
            p_ENTRADA.CODFILIAL := DADOS.CODFILIAL;
            p_ENTRADA.CODPROD   := DADOS.CODPROD;
            p_ENTRADA.NUMSEQ    := DADOS.NUMSEQ;
            PROT_PROCESSAR_RESERVA (p_ENTRADA);
            -- Algo errado?
            IF p_ENTRADA.MSG_RETORNO <> 'OK' THEN
              RETURN;
            END IF;

          END LOOP;
          -- Não tem dados
          IF vsTEM_DADOS = 0 THEN
            -- Inserindo informações de debug (LOG)
            p_ENTRADA.MSG_RETORNO      := 'Erro 2 (Administrar Reserva): Não existe dados para o idenfiticador informado!'||CHR(13)||
                                          'Identificador.: '||TO_CHAR(p_ENTRADA.NUMPED)||CHR(13)||
                                          'Código Rotina.: '||TO_CHAR(p_ENTRADA.ROTINA);
            P_INTERNO.MSG_RETORNO      := p_ENTRADA.MSG_RETORNO;
            P_INTERNO.INFORMACOES_LOG  := 'Erro na procedure administradora da reserva';
            P_INTERNO.NOME_FUNCAO      := 'PROT_ADMINISTRAR_RESERVA';
            PRIV_GERARLOG;
          END IF;
        -- Operação
        END IF;
    ELSE
      -- Inserindo informações de debug (LOG)
      p_ENTRADA.MSG_RETORNO      := 'Erro 3 (Administrar Reserva): O código da rotina informada não é valido!'||CHR(13)||
                                    'Identificador.: '||TO_CHAR(p_ENTRADA.NUMPED)||CHR(13)||
                                    'Código Rotina.: '||TO_CHAR(p_ENTRADA.ROTINA);
      P_INTERNO.MSG_RETORNO      := p_ENTRADA.MSG_RETORNO;
      P_INTERNO.INFORMACOES_LOG  := 'Erro na procedure administradora da reserva';
      P_INTERNO.NOME_FUNCAO      := 'PROT_ADMINISTRAR_RESERVA';
      PRIV_GERARLOG;
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG  := P_INTERNO.PROGRAMA||' - Finalizou a procedure administradora da reserva';
    P_INTERNO.NOME_FUNCAO      := 'PROT_ADMINISTRAR_RESERVA';
    PRIV_GERARLOG;
  -- Função
  END PROT_ADMINISTRAR_RESERVA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/10/2019     Fernandes Brito   0                   Criada função para validar parâmetros de entrada da orquestradora
  01/02/2021     Fernandes Brito   0                   Alterada a função para validar parâmetros de entrada da orquestradora da reserva
  /***********************************************************************************************************************/-- 1 - Regra: Tem que ser uma operação valida.
  FUNCTION PROT_VALIDAR_PARAMETROS
  RETURN BOOLEAN
  IS-- Declaração das variáveis internas
  BEGIN
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG        := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou o processo de validação dos parâmentros.';
    P_INTERNO.NOME_FUNCAO            := 'PROT_VALIDAR_PARAMETROS';
    PRIV_GERARLOG;
    /***********************************************************************************************************************
    ##                                                Parâmetros obrigatórios                                             ##
    ************************************************************************************************************************/
    -- 1 Tem que ter Código da rotina
    IF P_INTERNO.PROGRAMA IS NULL THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 1 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'Este parâmetro é usado para identificar a rotina e consequentemente o processo macro do sistema WinThor.'||CHR(13)||
                                   'Exemplo: Comprando, vendendo ou gerenciando o estoque.'||CHR(13)||
                                   'É um parâmetro ''OBRIGATÓRIO''! Informe o códido da rotina e tente novamente.'||CHR(13)||CHR(13)||
                                   'Código da Rotina informado atualmente: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- 2 Tem que ter Processo
    ELSIF (P_INTERNO.PROGRAMA NOT IN (1147, 1108, 4159) AND (P_INTERNO.PROCESSO IS NULL OR
           P_INTERNO.PROCESSO NOT IN ('BLOQUEAR','RESERVAR','POPULAR','COMPRAR','VENDER', 'PRODUZIR','DEVOLVER'))) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 2 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'Este parâmetro é usado para identificar o processo que a rotina esta tentando executar.'||CHR(13)||
                                   'Este parâmetro é necessário quando existe mais de um processo que pode ser executado.'||CHR(13)||
                                   'Exemplo: A rotina 4116/316, pode chamar a PKG_ESTOQUE para gerenciar reserva/pendente ou para baixar estoque dos produtos de um KIT.'||CHR(13)||CHR(13)||
                                   'Veja valores existes:'||CHR(13)||
                                   'BLOQUEAR, RESERVAR, POPULAR, COMPRAR, VENDER, PRODUZIR e DEVOLVER'||CHR(13)||
                                   'Verifique se o valor informado esta correto e tente novamente.'||CHR(13)||CHR(13)||
                                   'Processo informado atualmente: '||NVL(P_INTERNO.PROCESSO,'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- 3 Tem que ter Operação
    ELSIF (P_INTERNO.OPERACAO_ENTRADA IS NULL OR
        P_INTERNO.OPERACAO_ENTRADA NOT IN ('T','P')) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 3 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'Este parâmetro é usado para direcionar como será executada a administração do estoque.'||CHR(13)||
                                   'É informando ''T'' (Todos os produtos) quando o usuário informa apenas o identificador e o código da rotina para que seja'||CHR(13)||
                                   'executada a administração de todos os itens e ''P'' (Produto) quando o usuário informa o produto e a sequencia do mesmo.'||CHR(13)||
                                   'Este parâmetro é "OBRIGATÓRIO"! Verifique se o valor informado esta correto e tente novamente.'||CHR(13)||CHR(13)||
                                   'Operação informada atualmente: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- 4 Para movimentar todos os produtos tem que ter identificador.
    ELSIF (P_INTERNO.OPERACAO_ENTRADA = 'T' AND
           P_INTERNO.IDENTIFICADOR IS NULL) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 4 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'A operação foi informada com o valor "T - Todos os produtos" e não foi informado o identificador!'||CHR(13)||
                                   'Este parâmetro é usado para identificar o pedido, nota fiscal, ordem de produção, etc, que será necessário administrar.'||CHR(13)||
                                   'Não é possível localizar os itens sem que exista um identificador. Verifique os valores informados e tente novamente.'||CHR(13)||CHR(13)||
                                   'Identificador informado atualmente: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.....: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo');
      -- Retorno falso
      RETURN FALSE;
    /***********************************************************************************************************************
    ##                                                  Outras regras                                                     ##
    ************************************************************************************************************************/
    -- 5 Para movimentar um produto de um identificador deve ser informado sempre código e a sequencia do produto.
    ELSIF (P_INTERNO.IDENTIFICADOR IS NOT NULL AND
           P_INTERNO.OPERACAO_ENTRADA = 'P' AND
           (P_INTERNO.CODPROD IS NULL OR
            (P_INTERNO.PROGRAMA NOT IN (1618) AND
             P_INTERNO.NUMSEQ IS NULL))) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 5 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'A operação foi informada com o valor ''P - Produtos'' e foi informado o identificador!'||CHR(13)||
                                   'Neste caso é necessário informar o código do produto e a sequência de inserção do item no identificador.'||CHR(13)||
                                   'Verifique os valores informados e tente novamente.'||CHR(13)||CHR(13)||
                                   'Código da rotina informado atualmente.: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo')||CHR(13)||
                                   'Identificador informado atualmente....: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.........: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo')||CHR(13)||
                                   'Processo informado atualmente.........: '||NVL(P_INTERNO.PROCESSO,'Nulo')||CHR(13)||
                                   'Código da filial informada atualmente.: '||NVL(P_INTERNO.CODFILIAL,'Nulo')||CHR(13)||
                                   'Código do produto informado atualmente: '||NVL(TO_CHAR(P_INTERNO.CODPROD),'Nulo')||CHR(13)||
                                   'Número de sequência de inserção.......: '||NVL(TO_CHAR(P_INTERNO.NUMSEQ),'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- 6 Para movimenta um produto sem informar o identificador deve ser informado sempre o código do produto, a filial e a quantidade.
    ELSIF (P_INTERNO.IDENTIFICADOR IS NULL AND
           P_INTERNO.OPERACAO_ENTRADA = 'P' AND
           P_INTERNO.PROGRAMA NOT IN (4159,1108,4116,4136,336,316,4101, 1618) AND
          (P_INTERNO.CODFILIAL IS NULL OR
           P_INTERNO.CODPROD IS NULL OR
           P_INTERNO.QUANTIDADE_1 IS NULL)) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 6 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'A operação foi informada com o valor ''P - Produtos'' e não foi informado o identificador!'||CHR(13)||
                                   'Neste caso é necessário informar o código do produto, a filial e a quantidade que deseja alterar no estoque.'||CHR(13)||
                                   'Verifique os valores informados e tente novamente.'||CHR(13)||
                                   'Código da rotina informado atualmente.: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo')||CHR(13)||
                                   'Identificador informado atualmente....: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.........: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo')||CHR(13)||
                                   'Processo informado atualmente.........: '||NVL(P_INTERNO.PROCESSO,'Nulo')||CHR(13)||
                                   'Código da filial informada atualmente.: '||NVL(P_INTERNO.CODFILIAL,'Nulo')||CHR(13)||
                                   'Código do produto informado atualmente: '||NVL(TO_CHAR(P_INTERNO.CODPROD),'Nulo')||CHR(13)||
                                   'Número de sequência de inserção.......: '||NVL(TO_CHAR(P_INTERNO.NUMSEQ),'Nulo')||CHR(13)||
                                   'Quantidade Informada..................: '||NVL(TO_CHAR(P_INTERNO.QUANTIDADE_1),'Nulo')||CHR(13);
      -- Retorno falso
      RETURN FALSE;
    -- 7 Para movimenta um produto de algumas rotinas é obrigatório informar o identificador
    ELSIF (P_INTERNO.IDENTIFICADOR IS NULL AND
           P_INTERNO.OPERACAO_ENTRADA = 'P' AND
           P_INTERNO.PROGRAMA IN (4116,4136,336,316, 4101)) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 7 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'A operação foi informada com o valor ''P - Produtos'' e foi informado um programa exige que o identificador seja informado!'||CHR(13)||
                                   'Verifique os valores informados e tente novamente.'||CHR(13)||
                                   'Código da rotina informado atualmente.: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo')||CHR(13)||
                                   'Identificador informado atualmente....: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.........: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo')||CHR(13)||
                                   'Processo informado atualmente.........: '||NVL(P_INTERNO.PROCESSO,'Nulo')||CHR(13)||
                                   'Código da filial informada atualmente.: '||NVL(P_INTERNO.CODFILIAL,'Nulo')||CHR(13)||
                                   'Código do produto informado atualmente: '||NVL(TO_CHAR(P_INTERNO.CODPROD),'Nulo')||CHR(13)||
                                   'Número de sequência de inserção.......: '||NVL(TO_CHAR(P_INTERNO.NUMSEQ),'Nulo')||CHR(13)||
                                   'Quantidade Informada..................: '||NVL(TO_CHAR(P_INTERNO.QUANTIDADE_1),'Nulo')||CHR(13);
      -- Retorno falso
      RETURN FALSE;
    -- 8 Para movimenta um identificador vinculado a uma rotina de pedido é obrigatório que o processo seja 'RESERVAR'
    ELSIF (P_INTERNO.PROGRAMA IN (4116,4136,336,316) AND
           P_INTERNO.PROCESSO NOT IN ('RESERVAR')) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 8 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'O programa informada tem referencias com pedido de venda e não foi informado o processo ''RESERVAR''!'||CHR(13)||
                                   'Neste caso é necessário informar o processo ''RESERVAR'' para prosseguir.'||CHR(13)||
                                   'Verifique os valores informados e tente novamente.'||CHR(13)||CHR(13)||
                                   'Código da rotina informado atualmente.: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo')||CHR(13)||
                                   'Identificador informado atualmente....: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.........: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo')||CHR(13)||
                                   'Processo informado atualmente.........: '||NVL(P_INTERNO.PROCESSO,'Nulo')||CHR(13)||
                                   'Código da filial informada atualmente.: '||NVL(P_INTERNO.CODFILIAL,'Nulo')||CHR(13)||
                                   'Código do produto informado atualmente: '||NVL(TO_CHAR(P_INTERNO.CODPROD),'Nulo')||CHR(13)||
                                   'Número de sequência de inserção.......: '||NVL(TO_CHAR(P_INTERNO.NUMSEQ),'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- 9 Para movimenta um identificador vinculado a uma rotina de industrialização é obrigatório que o processo seja 'PRODUZIR'
    ELSIF (P_INTERNO.PROGRAMA IN (4101,1400) AND
           P_INTERNO.PROCESSO NOT IN ('PRODUZIR','VENDER')) THEN
      P_INTERNO.NOME_FUNCAO     := 'PROT_VALIDAR_PARAMETROS';
      P_INTERNO.INFORMACOES_LOG := 'Erro na passagem de parâmetros para a função administradora de estoque';
      P_INTERNO.MSG_RETORNO     := 'Erro 9 - Validar Parâmetros:'||CHR(13)||CHR(13)||
                                   'O programa informada tem referencias com venda ou produção e o processo informado é diferente de ''PRODUZIR'' e ''VENDER''!'||CHR(13)||
                                   'Neste caso é necessário informar um dos processos ''PRODUZIR'' e ''VENDER'' para prosseguir.'||CHR(13)||
                                   'Verifique os valores informados e tente novamente.'||CHR(13)||CHR(13)||
                                   'Código da rotina informado atualmente.: '||NVL(TO_CHAR(P_INTERNO.PROGRAMA),'Nulo')||CHR(13)||
                                   'Identificador informado atualmente....: '||NVL(P_INTERNO.IDENTIFICADOR,'Nulo')||CHR(13)||
                                   'Operação informada atualmente.........: '||NVL(P_INTERNO.OPERACAO_ENTRADA,'Nulo')||CHR(13)||
                                   'Processo informado atualmente.........: '||NVL(P_INTERNO.PROCESSO,'Nulo')||CHR(13)||
                                   'Código da filial informada atualmente.: '||NVL(P_INTERNO.CODFILIAL,'Nulo')||CHR(13)||
                                   'Código do produto informado atualmente: '||NVL(TO_CHAR(P_INTERNO.CODPROD),'Nulo')||CHR(13)||
                                   'Número de sequência de inserção.......: '||NVL(TO_CHAR(P_INTERNO.NUMSEQ),'Nulo');
      -- Retorno falso
      RETURN FALSE;
    -- Regras
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG        := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou o processo de validação dos parâmentros.';
    P_INTERNO.NOME_FUNCAO            := 'PROT_VALIDAR_PARAMETROS';
    PRIV_GERARLOG;
    RETURN TRUE;
  -- Função
  END PROT_VALIDAR_PARAMETROS;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor               Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  15/08/2019     Moisés Souto Bahia  0                   Novo processo de administração de estoque
  18/10/2019     Fernandes Brito     0                   Ajustada a validação dos parâmetros de entrada e incluida a validação
                                                         das regras de inventários.
  28/01/2021     Fernandes Brito     0                   Criada regra para validar conceitos de negócio para reservar/pendente
                                                         usando como base o dados do pedido de venda.
  /***********************************************************************************************************************/
  FUNCTION ADMINISTRAR_ESTOQUE (p_ENTRADA IN OUT T_ENTRADA)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vtREQUISICAO   PCREQUISICAODEPOSITO%ROWTYPE;
    vtRESERVA      TYPE_RESERVA;
    vtFATURAR      TYPE_FATURAR;
    vtINVENTARIO   T_INVENTARIO;
    vtINDUSTRIA    T_INDUSTRIA;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug
    p_ENTRADA.MSG_RETORNO            := 'OK';
    P_INTERNO.NOME_FUNCAO            := 'ADMINISTRAR_ESTOQUE';
    P_INTERNO.INFORMACOES_LOG        := 'A rotina '||p_ENTRADA.ROTINA||' iniciou o processo da administradora';
    P_INTERNO.MSG_RETORNO            := P_INTERNO.MSG_RETORNO;
    P_INTERNO.IDENTIFICADOR          := p_ENTRADA.IDENTIFICADOR;
    P_INTERNO.PROGRAMA               := p_ENTRADA.ROTINA;
    P_INTERNO.OPERACAO_ENTRADA       := p_ENTRADA.OPERACAO;
    P_INTERNO.PROCESSO               := p_ENTRADA.PROCESSO;
    P_INTERNO.CODFILIAL              := p_ENTRADA.CODFILIAL;
    P_INTERNO.CODPROD                := p_ENTRADA.CODPROD;
    P_INTERNO.NUMSEQ                 := p_ENTRADA.NUMERICO_1;
    PRIV_GERARLOG;
    -- Validar parâmetros de entrada
    IF PROT_VALIDAR_PARAMETROS THEN
      -- Validar rotina informada
      CASE-- Processos de Industria
        WHEN p_ENTRADA.ROTINA IN (1618, 1605) THEN
          -- Atualizar variáveis
          vtINDUSTRIA            := NULL;
          vtINDUSTRIA.NUMOP      := p_ENTRADA.IDENTIFICADOR;
          vtINDUSTRIA.CODPROD    := p_ENTRADA.CODPROD;
          vtINDUSTRIA.ROTINA     := p_ENTRADA.ROTINA;
          vtINDUSTRIA.NUMLOTE    := p_ENTRADA.CARACTER_1;
          vtINDUSTRIA.NUMREMESSA := p_ENTRADA.NUMERICO_1;
          -- Administrar Industria
          PROT_ADMINISTRAR_INDUSTRIA (vtINDUSTRIA);
          -- Algo errado?
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Processos de Inventários
        WHEN p_ENTRADA.ROTINA IN (1147) THEN
          -- Atualizar variáveis
          vtINVENTARIO.NUMINVENT           := p_ENTRADA.IDENTIFICADOR;
          vtINVENTARIO.USAPRIMEIRACONTAGEM := p_ENTRADA.CARACTER_1;
          -- Administrar Inventário
          PROT_ADMINISTRAR_INVENTARIO (vtINVENTARIO);
          -- Algo errado?
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Processos de venda/produção
        WHEN p_ENTRADA.ROTINA IN (4101,1400) THEN
          -- Atualizar variáveis
          vtFATURAR               := NULL;
          vtFATURAR.NUMPED        := p_ENTRADA.IDENTIFICADOR;
          vtFATURAR.NUMTRANSVENDA := p_ENTRADA.NUMERICO_1;
          vtFATURAR.NUMTRANSENT   := p_ENTRADA.NUMERICO_2;
          vtFATURAR.ROTINA        := p_ENTRADA.ROTINA;
          vtFATURAR.OPERACAO      := p_ENTRADA.OPERACAO;
          vtFATURAR.PROCESSO      := p_ENTRADA.PROCESSO;
          -- Administrar Industria
          PROT_ADMINISTRAR_ESTOQUE (vtFATURAR);
          -- Algo errado?
          IF vtFATURAR.MSG_RETORNO <> 'OK' THEN
            p_ENTRADA.MSG_RETORNO := vtFATURAR.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Processos de reservado/pendente
        WHEN p_ENTRADA.ROTINA IN (4116,4136) THEN
          -- Atualizar variáveis
          vtFATURAR               := NULL;
          vtFATURAR.NUMPED        := p_ENTRADA.IDENTIFICADOR;
          vtFATURAR.ROTINA        := p_ENTRADA.ROTINA;
          vtFATURAR.OPERACAO      := p_ENTRADA.OPERACAO;
          vtFATURAR.PROCESSO      := 'PRODUZIR';
          -- Administrar Industria
          PROT_ADMINISTRAR_ESTOQUE (vtFATURAR);
          -- Algo errado?
          IF vtFATURAR.MSG_RETORNO <> 'OK' THEN
            p_ENTRADA.MSG_RETORNO := vtFATURAR.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Atualizar variáveis
          vtRESERVA            := NULL;
          vtRESERVA.NUMPED     := p_ENTRADA.IDENTIFICADOR;
          vtRESERVA.ROTINA     := p_ENTRADA.ROTINA;
          vtRESERVA.OPERACAO   := p_ENTRADA.OPERACAO;
          vtRESERVA.PROCESSO   := p_ENTRADA.PROCESSO;
          vtRESERVA.CODFILIAL  := p_ENTRADA.CODFILIAL;
          vtRESERVA.CODPROD    := p_ENTRADA.CODPROD;
          vtRESERVA.NUMSEQ     := p_ENTRADA.NUMERICO_1;
          vtRESERVA.NUMLOTE    := p_ENTRADA.CARACTER_1;
          -- Administrar Industria
          PROT_ADMINISTRAR_RESERVA (vtRESERVA);
          -- Algo errado?
          IF vtRESERVA.MSG_RETORNO <> 'OK' THEN
            p_ENTRADA.MSG_RETORNO := vtRESERVA.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Processos de múltiplos depósito
        WHEN p_ENTRADA.ROTINA IN (1108,4159) THEN
          -- Todos os itens?
          IF (p_ENTRADA.ROTINA = 4159 AND p_ENTRADA.OPERACAO = 'T') THEN
            FOR DADOS IN (SELECT PCPEDC.CODFILIAL
                                ,PCPEDI.CODPROD
                                ,PCPEDI.NUMSEQ
                                ,PCPEDI.QT
                                ,PCPEDI.TIPOENTREGA
                                ,PCPEDI.CODDEPOSITO
                                ,PCPEDI.CODAUXILIAR
                            FROM PCPEDI,PCPEDC
                           WHERE PCPEDI.NUMPED = p_ENTRADA.IDENTIFICADOR
                             AND PCPEDC.NUMPED = PCPEDI.NUMPED
                             AND PCPEDI.TIPOENTREGA <> 'RI')
            LOOP
              -- Atualizar variáveis
              vtREQUISICAO.CODREQUISICAO   := p_ENTRADA.NUMERICO_1;
              vtREQUISICAO.IDENTIFICADOR   := p_ENTRADA.IDENTIFICADOR;
              vtREQUISICAO.CODPROD         := DADOS.CODPROD;
              vtREQUISICAO.CODFILIAL       := DADOS.CODFILIAL;
              vtREQUISICAO.CODDEPOSITOORIG := DADOS.CODDEPOSITO;
              P_INTERNO.CODFILIAL          := DADOS.CODFILIAL;
              vtREQUISICAO.CODDEPOSITODEST := PRIV_DEP_PADRAO_VENDA;
              vtREQUISICAO.NUMSEQ          := DADOS.NUMSEQ;
              vtREQUISICAO.QT              := DADOS.QT;
              vtREQUISICAO.NOME_TABELA     := 'PCPEDI';
              P_INTERNO.NOME_TABELA        := vtREQUISICAO.NOME_TABELA;
              P_INTERNO.PROCESSO           := 'RESERVAR';
              P_INTERNO.PROGRAMA           := 4159;
              -- Incluir requisição de transferência entre depósitos
              PRIV_DEP_INCLUIR_REQUISICAO (vtREQUISICAO);
              -- Deu algo errado?
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            END LOOP;
          -- Apenas um produto?
          ELSE
            -- Atualizar variáveis
            vtREQUISICAO.CODREQUISICAO   := p_ENTRADA.NUMERICO_1;
            vtREQUISICAO.IDENTIFICADOR   := p_ENTRADA.IDENTIFICADOR;
            vtREQUISICAO.CODPROD         := p_ENTRADA.CODPROD;
            vtREQUISICAO.CODFILIAL       := p_ENTRADA.CODFILIAL;
            vtREQUISICAO.CODDEPOSITOORIG := p_ENTRADA.NUMERICO_2;
            vtREQUISICAO.CODAUXILIARORIG := p_ENTRADA.CARACTER_1;
            vtREQUISICAO.NUMLOTEORIG     := p_ENTRADA.CARACTER_2;
            vtREQUISICAO.CODDEPOSITODEST := p_ENTRADA.NUMERICO_3;
            vtREQUISICAO.CODAUXILIARDEST := p_ENTRADA.CARACTER_3;
            vtREQUISICAO.NUMLOTEDEST     := p_ENTRADA.CARACTER_4;
            vtREQUISICAO.QT              := p_ENTRADA.NUMERICO_4;
            vtREQUISICAO.NOME_TABELA     := CASE p_ENTRADA.ROTINA
                                              WHEN 1108 THEN
                                                'PCREQUISICAODEPOSITO'
                                            ELSE
                                              'PCPEDI'
                                            END;
            P_INTERNO.NOME_TABELA        := vtREQUISICAO.NOME_TABELA;
            P_INTERNO.PROCESSO           := 'REQUISITAR';
            vtREQUISICAO.TIPOEMBDEPOSITO := p_ENTRADA.CARACTER_5;
            -- Incluir requisição de transferência entre depósitos
            PRIV_DEP_INCLUIR_REQUISICAO (vtREQUISICAO);
            -- Deu algo errado?
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
          END IF;
      -- Caso o código da rotina seja inválido
      ELSE
        P_INTERNO.MSG_RETORNO := 'Erro 1 - Orquestradora: O código da rotina informado é desconhecido para a administração do esotque!'||CHR(13)||
                                 'Verifique se o código informado esta correto e caso esteja entre em contato com a TOTVS para correção das regras.'||CHR(13)||
                                 'Código da rotina informada: '||TO_CHAR(p_ENTRADA.ROTINA);
        p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Validação da rotina
      END CASE;
    -- Erro de regra
    ELSE
      -- Gerar log
      p_ENTRADA.MSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Regras Parâmetros de entrada
    END IF;
    -- Gerar log
    P_INTERNO.NOME_FUNCAO     := 'ADMINISTRAR_ESTOQUE';
    P_INTERNO.INFORMACOES_LOG := p_ENTRADA.ROTINA||' - Finalizou o processo da administradora';
    PRIV_GERARLOG;
    RETURN 'S';
  -- Função
  END ADMINISTRAR_ESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função alterar estoque pendente
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_ALTERAR (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                            ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                            ,pnNUMSEQ        IN PCMOV.NUMSEQ%TYPE
                            ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                            ,pnTIPO_CONTAGEM IN NUMBER DEFAULT NULL
                            ,psMSG_RETORNO   OUT VARCHAR2
                            ,psCODFILIAL     IN PCMOV.CODFILIAL%TYPE DEFAULT NULL)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vbBAIXOU            VARCHAR2(1);
    vbINCLUIU           VARCHAR2(1);
    vsCODOPER           VARCHAR2(2);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.LISTA_VALIDA    := 'N';
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - BLOQUEIO_ALTERAR';
    P_INTERNO.NOME_FUNCAO     := 'BLOQUEIO_ALTERAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    -- Validar codigo do produto
    IF pnCODPROD IS NOT NULL THEN
      CASE-- Valida operação
        -- Pedido de venda
        WHEN (psOPERACAO IN ('AB','CB') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
          -- Baixar estoque bloqueado
          vbBAIXOU := BLOQUEIO_BAIXAR (pnIDENTIFICADOR
                                      ,NULL
                                      ,pnCODPROD
                                      ,pnNUMSEQ
                                      ,NULL
                                      ,NULL
                                      ,psOPERACAO
                                      ,NULL
                                      ,NULL
                                      ,NULL
                                      ,NULL
                                      ,psMSG_RETORNO);
          -- Baixar corretamente
          IF vbBAIXOU = 'N' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Incluir estoque avariado no bloqueado
          vbINCLUIU := BLOQUEIO_INCLUIR (pnIDENTIFICADOR
                                        ,psCODFILIAL
                                        ,pnCODPROD
                                        ,pnNUMSEQ
                                        ,NULL
                                        ,NULL
                                        ,psOPERACAO
                                        ,NULL
                                        ,NULL
                                        ,NULL
                                        ,NULL
                                        ,psMSG_RETORNO);
          -- Incluiu corretamente
          IF vbINCLUIU = 'N' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Inventário
        WHEN psOPERACAO IN ('AD') THEN
          -- Validar tipo de contagem
          IF pnTIPO_CONTAGEM IS NOT NULL THEN
            -- Lista de produtos inventáriada
            FOR DADOS IN (SELECT PCINVENTROT.NUMINVENT
                                ,PCINVENTROT.CODPROD
                                ,PCINVENTROT.CODFUNCMONTAGEM
                                ,PCINVENTROT.CODFILIAL
                                ,(SELECT NVL(PCEST.QTINDENIZ, 0)
                                    FROM PCEST
                                   WHERE PCEST.CODPROD = PCINVENTROT.CODPROD
                                     AND PCEST.CODFILIAL = PCINVENTROT.CODFILIAL) QTINDENIZ
                                ,CASE
                                   WHEN FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
                                     (SELECT SUM(QTINDENIZADA)
                                        FROM PCESTOQUEDEPOSITOPROD
                                       WHERE CODPROD = PCINVENTROT.CODPROD
                                         AND CODFILIAL = PCINVENTROT.CODFILIAL)
                                   ELSE
                                     SUM(DECODE(pnTIPO_CONTAGEM,1,NVL(PCINVENTROT.QTAVARIA1,0),DECODE(NVL(PCINVENTROT.QTAVARIA1,0),NVL(PCINVENTROT.QTAVARIA2,0),NVL(PCINVENTROT.QTAVARIA1,0),NVL(PCINVENTROT.QTAVARIA3,0))))
                                   END QTDINVENTARIADA
                           FROM PCINVENTROT
                          WHERE PCINVENTROT.NUMINVENT = pnIDENTIFICADOR
                            AND PCINVENTROT.CODPROD = pnCODPROD
                       GROUP BY PCINVENTROT.NUMINVENT
                               ,PCINVENTROT.CODPROD
                               ,PCINVENTROT.CODFILIAL
                               ,PCINVENTROT.CODFUNCMONTAGEM
                       ORDER BY PCINVENTROT.CODPROD)
            LOOP
              -- Atualizando variável
              P_INTERNO.LISTA_VALIDA := 'S';
              --Atualiza estoque
              UPDATE PCEST
                 SET PCEST.QTINDENIZ   = DADOS.QTDINVENTARIADA
                    ,PCEST.QTBLOQUEADA = GREATEST(((NVL(PCEST.QTBLOQUEADA, 0) - NVL(PCEST.QTINDENIZ, 0)) + DADOS.QTDINVENTARIADA),0)
                    ,PCEST.DTHORAULTALTDISP = SYSDATE
               WHERE PCEST.CODFILIAL = DADOS.CODFILIAL
                 AND PCEST.CODPROD = DADOS.CODPROD;
              -- Caso exista avaria
              IF NVL(DADOS.QTDINVENTARIADA,0) > 0 THEN
                --Definir codigo de operação
                vsCODOPER := CASE
                               WHEN (NVL(DADOS.QTDINVENTARIADA,0) - NVL(DADOS.QTINDENIZ,0)) > 0 THEN
                                'EA'
                             ELSE
                               'SA'
                             END;
                -- Atualizar movimentação de avaria
                P_INTERNO.vtAVARIA.DATA          := SYSDATE;
                P_INTERNO.vtAVARIA.CODPROD       := DADOS.CODPROD;
                P_INTERNO.vtAVARIA.CODCLI        := 0;
                P_INTERNO.vtAVARIA.QT            := ABS(NVL(DADOS.QTDINVENTARIADA,0) - NVL(DADOS.QTINDENIZ,0));
                P_INTERNO.vtAVARIA.CODOPER       := vsCODOPER;
                P_INTERNO.vtAVARIA.CODFUNCLANC   := DADOS.CODFUNCMONTAGEM;
                P_INTERNO.vtAVARIA.OBS           := 'ATUALIZAÇÃO DE INVENTÁRIO';
                P_INTERNO.vtAVARIA.CODFILIAL     := DADOS.CODFILIAL;
                --vtAVARIA.CODROTINALANC := 0; -- Campo da PCMOVAVARIA está como number, será realizada nova tratativa para correção do log
                --vtAVARIA.IDENTIFICADOR := pnIDENTIFICADOR;
                PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,SUBSTR(vsCODOPER,1,1));
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              -- Inserte movimentação
              END IF;
            -- Lista de produtos
            END LOOP;
            -- Validar lista
            IF P_INTERNO.LISTA_VALIDA = 'N' THEN
              psMSG_RETORNO := 'Erro 4 (Bloqueio Alterar): Não encontramos dados para o identificador informado!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Operação.....: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            ELSE
              vbBAIXOU := 'S';
              vbINCLUIU:= 'S';
            -- Validação lista
            END IF;
          -- Não tem tipo de contagem
          ELSE
            psMSG_RETORNO := 'Erro 1 (Bloqueio Alterar): Para a operação informada é necessário informar o parâmetro do tipo de contagem!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Validação
          END IF;
      -- Caso a operação ou identificador não for valido
      ELSE
        psMSG_RETORNO := 'Erro 2 (Bloqueio Alterar): A operação ou o identificador informado não são validos para manipular a quantidade bloqueada/avariada!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Operação.....: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Validação da operação
      END CASE;
    -- Produto não é valido
    ELSE
      psMSG_RETORNO := 'Erro 3 (Bloqueio Alterar): A produto é um parâmetro obrigatorio para esta função. Favor informa-lo corretamente!'||CHR(13)||
                       'Produto.: '||TO_CHAR(pnCODPROD)||CHR(13)||
                       'Operação: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação do produto
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_ALTERAR';
    PRIV_GERARLOG;
    -- Se deu tudo certo então retorna verdadeiro
    IF ((vbBAIXOU = 'S') AND (vbINCLUIU = 'S')) THEN
      RETURN 'S';
    ELSE
      RETURN 'N';
    END IF;
  -- Função
  END BLOQUEIO_ALTERAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Função criada para alterar o estoque pendente de um pedido
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_ALTERAR_PEDIDO (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                   ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                   ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.LISTA_VALIDA    := 'N';
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - BLOQUEIO_ALTERAR_PEDIDO';
    P_INTERNO.NOME_FUNCAO     := 'BLOQUEIO_ALTERAR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    -- Valida operação
    CASE
      -- Fechar/Cancelar Bonus
      WHEN (psOPERACAO IN ('AB','CB') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT DISTINCT (PCBONUSI.CODPROD) CODPROD
                            ,PCBONUSI.NUMBONUS
                            ,PCBONUSC.CODFILIAL
                            ,1 NUMSEQ
                        FROM PCBONUSI
                            ,PCBONUSC
                       WHERE PCBONUSI.NUMBONUS = PCBONUSC.NUMBONUS
                         AND PCBONUSI.NUMBONUS = pnIDENTIFICADOR)
        LOOP
          -- Executa a alteração
          P_INTERNO.RETORNO_FUNCAO := BLOQUEIO_ALTERAR(DADOS.NUMBONUS,DADOS.CODPROD,DADOS.NUMSEQ,psOPERACAO,NULL,psMSG_RETORNO,DADOS.CODFILIAL);
          -- Validar retorno
          IF P_INTERNO.RETORNO_FUNCAO = 'N' THEN
            RETURN 'N';
          ELSE
            -- Validar lista
            P_INTERNO.LISTA_VALIDA := 'S';
          END IF;
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 1 (Bloqueio Alterar Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
    -- Caso a operação ou identificador não for valido
    ELSE
      psMSG_RETORNO := 'Erro 2 (Bloqueio Alterar Pedido): A operação ou o identificador informado não são validos para manipular a quantidade bloqueada/avariada!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da operação
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_ALTERAR_PEDIDO';
    PRIV_GERARLOG;
    -- Atualizar o retorno da função
    RETURN 'S';
  -- Função
  END BLOQUEIO_ALTERAR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função Baixar estoque pendente
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_BAIXAR (pnIDENTIFICADOR        IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                           ,psCODFILIAL            IN PCMOV.CODFILIAL%TYPE
                           ,pnCODPROD              IN PCMOV.CODPROD%TYPE
                           ,pnNUMSEQ               IN PCMOV.NUMSEQ%TYPE
                           ,pnQTDE                 IN PCMOV.QT%TYPE
                           ,pnQTAVARIA             IN PCMOV.QTAVARIA%TYPE
                           ,psOPERACAO             IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                           ,psCODOPER              IN PCMOV.CODOPER%TYPE DEFAULT NULL
                           ,pnCODDEVOL             IN PCMOV.CODDEVOL%TYPE DEFAULT 0
                           ,psOBSERVACAO           IN VARCHAR2 DEFAULT NULL
                           ,psNUMLOTE              IN PCMOV.NUMLOTE%TYPE DEFAULT NULL
                           ,psMSG_RETORNO          OUT VARCHAR2
                           ,pnCODPRODPRINC         IN PCEST.CODPROD%TYPE DEFAULT NULL
                           ,psDESBLOQPRODFAMILIA   IN VARCHAR2 DEFAULT 'N'
                           ,pnNUMBONUS             IN T_NUMBONUS DEFAULT CAST(NULL AS T_NUMBONUS)
                           ,pnQTENTRADABONUS       IN PCBONUSI.QTENTRADA%TYPE DEFAULT 0
                           ,pnCODDEPOSITO          IN PCPEDI.CODDEPOSITO%TYPE DEFAULT NULL)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnQTDE                PCMOV.QTBLOQUEADA%TYPE;
    vnQTAVARIA            PCMOV.QTAVARIA%TYPE;
    vnQTAVARIANF          PCMOV.QTAVARIA%TYPE;
    vnQTNF                PCBONUSI.QTNF%TYPE;
    vsCODOPER             PCMOV.CODOPER%TYPE;
    vsSTATUS              PCMOV.STATUS%TYPE;
    vsCODFILIAL           PCMOV.CODFILIAL%TYPE;
    vdDATA                PCMOV.DTMOV%TYPE;
    vnCODFUNC             PCMOV.CODFUNCLANC%TYPE;
    vnCODMOTIVO           PCMOV.CODDEVOL%TYPE;
    vnNUMNOTA             PCMOV.NUMNOTA%TYPE;
    vsNUMLOTE             PCMOV.NUMLOTE%TYPE;
    vnCODCLI              PCMOV.CODCLI%TYPE;
    vsUSAWMS              PCPRODUT.USAWMS%TYPE := 'N';
    vnESTOQUE_QTBLOQUEADA PCEST.QTBLOQUEADA%TYPE;
    vsROTINACAD           PCMOV.ROTINACAD%TYPE;
    vtAVARIA_GRUPO        PCGRUPOAVARIA.QT%TYPE;
    vtQTINDENIZ_TOTAL     PCEST.QTINDENIZ%TYPE;
    SALDO_DISPONIVEL_AVA  PCEST.QTBLOQUEADA%TYPE;
    vsLIBERAESTENTMERC    PCBONUSC.LIBERAESTENTMERC%TYPE;
    VSLIBERAESTFECHBONUS  PCBONUSC.LIBERAESTFECHBONUS%TYPE;
    vnGERABONUS           PCMOVCOMPLE.GERABONUS%Type;
    QTBONUS_ABERTO        NUMBER;
    vsESTOQUEPORLOTE      PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vnQTUNITCX            PCPRODUT.QTUNITCX%TYPE;
    vsTIPOMERC            PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL        PCPRODUT.PESOVARIAVEL%TYPE;
    QTANTERIOR            NUMBER;
    NUMTRANSENTDEVOLUCAO  NUMBER;
    QTDEVOLVWSM           NUMBER;
    QTDEVOLVWMSBLOQAVA    NUMBER;
    QTDEVOLVWMSBLOQUEIO   NUMBER;
    vsCODFUNCLANC         VARCHAR2(200);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    vsROTINACAD                         := '';
    psMSG_RETORNO                       := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG           := 'Iniciou a função - BLOQUEIO_BAIXAR';
    P_INTERNO.NOME_FUNCAO               := 'BLOQUEIO_BAIXAR';
    P_INTERNO.IDENTIFICADOR             := pnIDENTIFICADOR;
    P_INTERNO.CODDEPOSITO               := pnCODDEPOSITO;
    P_INTERNO.CODFILIAL                 := psCODFILIAL;
    P_INTERNO.CODPROD                   := pnCODPROD;
    P_INTERNO.NUMSEQ                    := pnNUMSEQ;
    P_INTERNO.QTPARAMETROENTRADA        := pnQTDE;
    P_INTERNO.QTPARAMETROENTRADA_AVARIA := pnQTAVARIA;
    P_INTERNO.TIPO_OPERACAO             := psOPERACAO;
    PRIV_GERARLOG;
    -- Validar codigo do produto
    IF pnCODPROD IS NOT NULL THEN

      PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
      -- Valida retorno
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
      CASE
        -- Pedido de venda
        WHEN psOPERACAO IN ('IN','AQ') THEN
          -- O identificador é obrigatório
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Consultar dados do pedido
            P_INTERNO.vtCABECALHO_ANTERIOR     := NULL;
            P_INTERNO.vtITEM_ANTERIOR          := NULL;
            P_INTERNO.vtITEM_ANTERIOR.NUMPED   := pnIDENTIFICADOR;
            P_INTERNO.vtITEM_ANTERIOR.CODPROD  := pnCODPROD;
            P_INTERNO.vtITEM_ANTERIOR.NUMSEQ   := pnNUMSEQ;
            -- Consultar dados do pedido
            BEGIN
              SELECT PCPEDI.QT
                    ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                    ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                    ,PCPEDC.USAINTEGRACAOWMS
                    ,PCPEDC.DTIMPORTACAO
                    ,PCPEDI.CODDEPOSITO
                    ,PCPEDI.ROWID
                INTO P_INTERNO.vtITEM_ANTERIOR.QT
                    ,P_INTERNO.vtITEM_ANTERIOR.CODFILIALRETIRA
                    ,P_INTERNO.vtITEM_ANTERIOR.POSICAO
                    ,P_INTERNO.vtCABECALHO_ANTERIOR.USAINTEGRACAOWMS
                    ,P_INTERNO.vtCABECALHO_ANTERIOR.DTIMPORTACAO
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                FROM PCPEDI, PCPEDC
               WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                 AND PCPEDI.NUMPED = pnIDENTIFICADOR
                 AND PCPEDI.CODPROD = pnCODPROD
                 --AND NVL(PCPEDI.QT,0) > 0
                 AND PCPEDI.NUMSEQ = pnNUMSEQ;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := P_INTERNO.vtITEM_ANTERIOR.CODFILIALRETIRA;
              P_INTERNO.NOME_TABELA := 'PCPEDI';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 16 (Bloqueio Baixar): Não foi possível consultar dados do item para fazer o bloqueio!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Validar posição do pedido
            IF (P_INTERNO.vtITEM_ANTERIOR.POSICAO IN ('L','M')
              AND NVL(P_INTERNO.vtCABECALHO_ANTERIOR.USAINTEGRACAOWMS,'N') = 'S'
              AND P_INTERNO.vtCABECALHO_ANTERIOR.DTIMPORTACAO IS NOT NULL) THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(P_INTERNO.vtITEM_ANTERIOR.CODFILIALRETIRA,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variáveis
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.TIPO_OPERACAO           := 'B';
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := P_INTERNO.vtITEM_ANTERIOR.CODFILIALRETIRA;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := P_INTERNO.vtITEM_ANTERIOR.QT;
              -- Atualizar estoque bloqueado
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Dados inválidos
            ELSE
              psMSG_RETORNO := 'Erro 10 (Bloqueio Baixar): O dados do pedido não são válidos!'||CHR(13)||
                               'Identificador......: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Posição Anterior...: '||P_INTERNO.vtITEM_ANTERIOR.POSICAO||CHR(13)||
                               'Usa Integração WMS.: '||NVL(P_INTERNO.vtCABECALHO_ANTERIOR.USAINTEGRACAOWMS,'N')||CHR(13)||
                               'Data Importação WMS: '||P_INTERNO.vtCABECALHO_ANTERIOR.DTIMPORTACAO||CHR(13)||
                               'Operação...........: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            -- Posicao do pedido
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 1 (Bloqueio Baixar): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Ordem de produção (Industria/cesta/kit)
        WHEN psOPERACAO IN ('BI','AI') THEN
          -- O identificador é obrigatório
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Buscar informações da transação
            BEGIN
              SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)
                    ,PCMOV.QTBLOQUEADA
                    ,PCMOV.QTAVARIA
                    ,PCMOV.CODOPER
                    ,PCMOV.DTMOV
                    ,PCMOV.CODCLI
                    ,PCMOV.CODOPER
                    ,PCMOV.CODFUNCLANC
                    ,PCMOV.CODDEVOL
                    ,PCMOV.NUMLOTE
                    ,PCMOV.CODDEPOSITO
                    ,PCMOV.ROWID
                INTO vsCODFILIAL
                    ,vnQTDE
                    ,vnQTAVARIA
                    ,vsCODOPER
                    ,vdDATA
                    ,vnCODCLI
                    ,vsCODOPER
                    ,vnCODFUNC
                    ,vnCODMOTIVO
                    ,vsNUMLOTE
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                FROM PCMOV
               WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                 AND PCMOV.CODPROD = pnCODPROD
                 AND PCMOV.NUMSEQ = pnNUMSEQ
                 AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0;
                -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCMOV';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 2 (Bloqueio Baixar): Não foi possível consultar dados para o identificador informado! '||CHR(13)||
                                 'É possível que não exista dados na PCMOV. Verifique!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Valida se atualizar estoque bloqueado
            IF (SUBSTR(vsCODOPER,1,1) = 'E'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQUEARENTPA','99','N') = 'S') THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variáveis
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.TIPO_OPERACAO           := 'B';
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(vnQTDE,NVL(vnQTAVARIA,0));
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(vnQTAVARIA,0);
              -- Atualizar estoque pendente
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Dados inválidos
            ELSE
              psMSG_RETORNO := 'Erro 11 (Bloqueio Baixar): Os dados da produção são inválidos!'||CHR(13)||
                               'Identificador...........: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Cód. Operação...........: '||vsCODOPER||CHR(13)||
                               'Bloq. Ent. Prod. Acabado: '||FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQUEARENTPA','99','N')||CHR(13)||
                               'Operação................: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            -- Validação do parâmetro
            END IF;
            -- Caso exista avaria
            IF NVL(vnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA.DATA          := vdDATA;
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := vnCODCLI;
              P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := vsCODOPER;
              P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
              P_INTERNO.vtAVARIA.OBS           := 'CANC. ORDEM DE PRODUÇÃO';
              P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := vsNUMLOTE;
              --vtAVARIA.CODROTINALANC := SOMENTENUMERO(vsROTINA);
              P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
              --vtAVARIA.IDENTIFICADOR := pnIDENTIFICADOR;
              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'E');
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Inserte movimentação
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 3 (Bloqueio Baixar): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Incluir durante o cancelamento do bonus (BB - Fechar Bonus / AB - Cancelar Bonos)
        WHEN psOPERACAO IN ('CB','AB') THEN
          -- Identificador válido
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Buscar dados do bonus
            BEGIN
              SELECT CODFILIAL
                    ,MAX(DTFECHAMENTO) DTFECHAMENTO
                    ,(NVL(LEAST(SUM(QTENTRADA), SUM(QTNF)),0)) AS QTENTRADA
                    ,SUM(NVL(QTAVARIA,0)) AS QTAVARIA
                    ,SUM(NVL(QTAVARIANF,0)) AS QTAVARIANF
                    ,SUM(NVL(QTNF, 0)) AS QTNF
                    ,MAX(CODFUNCFECHA) CODFUNCFECHA
                    ,MAX(CODMOTIVO) CODMOTIVO
                    ,CODDEPOSITO
                    ,LIBERAESTENTMERC
                    ,LIBERAESTFECHBONUS
               INTO vsCODFILIAL
                   ,vdDATA
                   ,vnQTDE
                   ,vnQTAVARIA
                   ,vnQTAVARIANF
                   ,vnQTNF
                   ,vnCODFUNC
                   ,vnCODMOTIVO
                   ,P_INTERNO.CODDEPOSITO
                   ,vsLIBERAESTENTMERC
                   ,vsLIBERAESTFECHBONUS
              FROM(
                   SELECT  PCBONUSC.CODFILIAL
                          ,(PCBONUSC.DTFECHAMENTO) DTFECHAMENTO
                          ,(NVL(PCBONUSI.QTENTRADA,0)) AS QTENTRADA
                          ,(NVL(PCBONUSI.QTAVARIA,0)) AS QTAVARIA
                          ,(NVL(PCBONUSI.QTAVARIANF,0)) AS QTAVARIANF
                          ,CASE
                 WHEN NVL(PCBONUSI.NUMLOTE, '0') <> '0' THEN
                               CASE
                   WHEN (NVL(PCBONUSC.USARF, 'N') = 'S') THEN
                                   (NVL(PCBONUSI.QTNF, 0))                               
                   WHEN ((NUMLOTE = NUMLOTENF) OR (NVL(NUMLOTENF, '0') = '0')) THEN
                                   (NVL(PCBONUSI.QTNF, 0))
                                 ELSE
                                   0
                                 END
                             ELSE
                              (NVL(PCBONUSI.QTNF, 0))
                           END AS QTNF
                          ,(PCBONUSC.CODFUNCFECHA) CODFUNCFECHA
                          ,(PCBONUSI.CODMOTIVO) CODMOTIVO
                          ,PCBONUSI.CODDEPOSITO CODDEPOSITO
                          ,NVL(PCBONUSC.LIBERAESTENTMERC, FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTENTMERC',vsCODFILIAL,'N')) as LIBERAESTENTMERC
                          ,NVL(PCBONUSC.LIBERAESTFECHBONUS, FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTFECHBONUS',vsCODFILIAL,'N')) as LIBERAESTFECHBONUS
                    FROM PCBONUSI
                        ,PCBONUSC
                   WHERE PCBONUSI.NUMBONUS = PCBONUSC.NUMBONUS
                     AND PCBONUSI.NUMBONUS = pnIDENTIFICADOR
                     AND PCBONUSI.CODPROD  = pnCODPROD)
              GROUP BY CODFILIAL
                      ,CODDEPOSITO
                      ,LIBERAESTENTMERC
                      ,LIBERAESTFECHBONUS;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCBONUSI';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 4 (Bloqueio Baixar): Não foi possível consultar dados para o identificador informado!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Consultar estoque
            P_INTERNO.vtESTOQUE   := NULL;
            P_INTERNO.vtESTOQUE.QTBLOQUEADA := 0;
            P_INTERNO.vtESTOQUE.QTINDENIZ   := 0;
            -- Validar se a filial desbloqueia estoque no fechamendo do bonus
            IF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'N' AND psOPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTNF;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIA;
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'S'AND psOPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA  := vnQTAVARIA;
              P_INTERNO.vtESTOQUE.QTINDENIZ    := vnQTAVARIA;
            ELSIF (((vsLIBERAESTENTMERC = 'S') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'N'))
              AND P_INTERNO.TIPO_OPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTAVARIA;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIA;
            -- Validação do parâmetro
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'N' AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTNF;
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'S' AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTDE;
            ELSIF (((vsLIBERAESTENTMERC = 'S') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'N'))
              AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTAVARIANF;
            -- Validação do parâmetro
            END IF;
            -- Atualizar variável
            P_INTERNO.TIPO_OPERACAO            := 'B';
            P_INTERNO.vtESTOQUE.IDENTIFICADOR  := pnIDENTIFICADOR;
            P_INTERNO.vtESTOQUE.CODFILIAL      := vsCODFILIAL;
            P_INTERNO.vtESTOQUE.CODPROD        := pnCODPROD;
            -- Bloquear estoque pendente do item
            PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
            -- Validar se conseguiu bloquear o estoque
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Atualizar estoque pendente
            PRIV_ATUALIZAR_ESTOQUE;
            -- Validar se conseguiu atualizar o estoque
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Caso exista avaria
            IF NVL(vnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA.DATA          := vdDATA;
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := 0;
              P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := NULL;
              P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
              P_INTERNO.vtAVARIA.NUMNOTA       := NULL;
              P_INTERNO.vtAVARIA.NUMTRANSENT   := pnIDENTIFICADOR;
              P_INTERNO.vtAVARIA.NUMTRANSVENDA := NULL;
              P_INTERNO.vtAVARIA.OBS           := 'CANC. DE BONUS';
              P_INTERNO.vtAVARIA.DTMOVLOG      := SYSDATE;
              P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := NULL;
              --vtAVARIA.CODROTINALANC := SOMENTENUMERO(vsROTINA);
              P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
              --vtAVARIA.CODROTINA     := vsROTINA;
              P_INTERNO.vtAVARIA.NUMTRANSWMS   := NULL;
              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'S');
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Inserte movimentação
            END IF;
          -- Identificador inválido
          ELSE
            psMSG_RETORNO := 'Erro 13 (Bloqueio Baixar): O identificador deve ser informado para a operação! '||CHR(13)||
                             'Verifique o identificador informado!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Identificador
          END IF;
        -- Entrada de mercadoria
        WHEN psOPERACAO IN ('BE','AE') THEN
          -- Identificador Válido
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Buscar informações da transação
            BEGIN
              SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)
                    ,PCMOV.DTMOV
                    ,PCMOV.CODCLI
                    ,PCMOV.QTBLOQUEADA
                    ,PCMOV.QTAVARIA
                    ,PCMOV.CODOPER
                    ,PCMOV.STATUS
                    ,PCMOV.NUMNOTA
                    ,PCMOV.NUMLOTE
                    ,PCMOV.CODDEPOSITO
                    ,PCMOV.ROWID
                    ,NVL(PCMOVCOMPLE.GERABONUS, 'S')
                INTO vsCODFILIAL
                    ,vdDATA
                    ,vnCODCLI
                    ,vnQTDE
                    ,vnQTAVARIA
                    ,vsCODOPER
                    ,vsSTATUS
                    ,vnNUMNOTA
                    ,vsNUMLOTE
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                    ,vnGERABONUS
                FROM PCMOV, PCMOVCOMPLE
               WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                 AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+)
                 AND PCMOV.CODPROD = pnCODPROD
                 AND PCMOV.NUMSEQ = pnNUMSEQ
                 AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0;
                -- Atualizando filial do log
              P_INTERNO.CODFILIAL    := vsCODFILIAL;
              P_INTERNO.NOME_TABELA  := 'PCMOV';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 5 (Bloqueio Baixar): Não foi possível consultar dados para o identificador informado! '||CHR(13)||
                                 'É possível que não exista dados na PCMOV. Verifique!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Validar parâmetro da rotina 132
            IF ((vsCODOPER = 'ET' AND vsSTATUS IN ('B','AB') AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQESTOQUETRANSF','99',FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N')) = 'S')
              OR (SUBSTR(vsCODOPER,1,1) = 'E' AND vsSTATUS IN ('B','AB') AND (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTENTMERC',vsCODFILIAL,'N') = 'N' OR vnGERABONUS = 'S'))) THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variável
              P_INTERNO.vtESTOQUE               := NULL;
              P_INTERNO.TIPO_OPERACAO           := 'B';
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(vnQTDE,NVL(vnQTAVARIA,0));
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(vnQTAVARIA,0);
              -- Atualizar estoque pendente
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Caso exista avaria
              IF NVL(vnQTAVARIA,0) > 0 THEN
                -- Atualizar movimentação de avaria
                P_INTERNO.vtAVARIA.DATA          := vdDATA;
                P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
                P_INTERNO.vtAVARIA.CODCLI        := vnCODCLI;
                P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
                P_INTERNO.vtAVARIA.CODOPER       := 'S';
                P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
                P_INTERNO.vtAVARIA.NUMNOTA       := vnNUMNOTA;
                P_INTERNO.vtAVARIA.NUMTRANSENT   := pnIDENTIFICADOR;
                P_INTERNO.vtAVARIA.NUMTRANSVENDA := NULL;
                P_INTERNO.vtAVARIA.OBS           := 'CANC. NF DE ENTRADA';
                P_INTERNO.vtAVARIA.DTMOVLOG      := SYSDATE;
                P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
                P_INTERNO.vtAVARIA.NUMLOTE       := vsNUMLOTE;
                --vtAVARIA.CODROTINALANC := vsROTINA;
                P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
                --vtAVARIA.CODROTINA     := SOMENTENUMERO(vsROTINA);
                P_INTERNO.vtAVARIA.NUMTRANSWMS   := NULL;
                PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'S');
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              -- Inserte movimentação
              END IF;
            -- Validação do parametro
            END IF;
          -- Identificador inválido
          ELSE
            psMSG_RETORNO := 'Erro 14 (Bloqueio Baixar): O identificador deve ser informado para a operação! '||CHR(13)||
                             'Verifique o identificador informado!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Identificador
          END IF;
        -- Caso seja desbloqueio a manual
        WHEN psOPERACAO IN ('BU','AU') THEN
          -- Validar Filial
          IF psCODFILIAL IS NOT NULL THEN
            DBMS_APPLICATION_INFO.READ_CLIENT_INFO(vsCODFUNCLANC);

            SELECT SUBSTR(vsCODFUNCLANC,INSTR(vsCODFUNCLANC, ':', -1, 1) + 1 ,LENGTH(vsCODFUNCLANC))
              INTO vsCODFUNCLANC
              FROM DUAL;

            VNCODFUNC := TO_NUMBER(vsCODFUNCLANC);
            
            IF ((vsROTINA LIKE '%PCSIS266%' OR vsROTINA LIKE '%PCSIS552%') AND (NVL(pnIDENTIFICADOR, 0) = 0)) THEN
        -- Buscar Bonus aberto
              IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
                BEGIN
                  SELECT SUM(I.QTBLOQUEADA)
                    INTO QTBONUS_ABERTO
                    FROM PCBONUSC C, PCMOV I
                   WHERE C.NUMBONUS = I.NUMBONUS
                     AND I.CODFILIAL = C.CODFILIAL
                     AND I.CODPROD = NVL(pnCODPROD,pnCODPRODPRINC)
                     AND I.CODFILIAL = psCODFILIAL
                     AND I.CODDEPOSITO = pnCODDEPOSITO
                     AND C.DTFECHAMENTO IS NULL
                     AND C.DTCANCEL IS NULL
                     AND I.CODOPER LIKE 'E%'
                     AND NVL(C.LIBERAESTENTMERC, 'N') = 'N'
                     AND NVL(I.ESTOQUEDESBLOQUEADO, 'N') = 'N'
                     AND TRUNC(C.DATABONUS) > trunc(SYSDATE - 90)
                     AND NVL(C.UTILIZOUPREENT, 'N') = 'N'
                GROUP BY I.CODPROD, I.CODFILIAL;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    QTBONUS_ABERTO := 0;
                END;
              ELSE
                BEGIN
                  SELECT SUM(I.QTBLOQUEADA)
                    INTO QTBONUS_ABERTO
                    FROM PCBONUSC C, PCMOV I
                   WHERE C.NUMBONUS = I.NUMBONUS
                     AND I.CODFILIAL = C.CODFILIAL
                     AND I.CODPROD = NVL(pnCODPROD,pnCODPRODPRINC)
                     AND I.CODFILIAL = psCODFILIAL
                     AND NVL(I.ESTOQUEDESBLOQUEADO, 'N') = 'N'
                     AND C.DTFECHAMENTO IS NULL
                     AND C.DTCANCEL IS NULL
                     AND NVL(C.LIBERAESTENTMERC, 'N') = 'N'
                     AND I.CODOPER LIKE 'E%'
                     AND trunc(C.DATABONUS) > trunc(SYSDATE - 90)
                     AND NVL(C.UTILIZOUPREENT, 'N') = 'N'
                GROUP BY I.CODPROD, I.CODFILIAL;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    QTBONUS_ABERTO := 0;
                END;
              END IF;
            ELSE  
        QTBONUS_ABERTO := 0; 
            END IF;

            -- É rotina 201?
            IF vsROTINA LIKE '%PCSIS201%' AND pnQTDE > 0 THEN
              -- Consultar produto
              PRIV_CONS_PRODUTO(NVL(pnCODPROD,pnCODPRODPRINC),vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
              -- Atualizar parâmetro
              IF (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_USAWMS', psCODFILIAL), 'N') = 'S' AND vsUSAWMS = 'S') THEN
                vsUSAWMS := 'S';
              ELSE
                vsUSAWMS := 'N';
              END IF;
              -- Lista de produtos
              FOR ESTOQUE IN (SELECT PCEST.ROWID REG
                                   , PCEST.CODFILIAL
                                   , PCEST.CODPROD
                                   , NVL(PCEST.QTESTGER, 0) QTESTGER
                                   , NVL(PCEST.QTBLOQUEADA, 0) SALDO_ESTANTERIOR
                                   , CASE WHEN vsUSAWMS = 'S' THEN 
                                       GREATEST(NVL(PCEST.QTINDENIZ, 0), NVL(WMS_QTFALTAAVARAIASEMDEVPEND(PCEST.CODPROD, PCEST.CODFILIAL, 'A'), 0))  
                                     ELSE
                                       NVL(PCEST.QTINDENIZ, 0) END SALDO_ESTINDENIZ
                                   , NVL(WMS_QTFALTAAVARAIASEMDEVPEND(PCEST.CODPROD, PCEST.CODFILIAL, 'A'), 0) SALDO_WMSAVARIADO
                                   , CASE WHEN PNQTENTRADABONUS > 0 THEN
                                       GREATEST((PCEST.QTBLOQUEADA - NVL(PNQTENTRADABONUS, 0)), GREATEST(
                                                         DECODE(vsUSAWMS, 'S', NVL(WMS_QTFALTAAVARAIASEMDEVPEND(PCEST.CODPROD, PCEST.CODFILIAL, 'B'), 0), 0)))
                                     ELSE 0 END SALDO_ESTBLOQUEAR
                                   , GREATEST(NVL((SELECT DECODE(vsESTOQUEPORLOTE, 'S', SUM(NVL(PCLOTE.QTINDENIZ, 0)), NULL)
                                                     FROM PCLOTE
                                                    WHERE PCLOTE.CODPROD = PCEST.CODPROD
                                                      AND PCLOTE.CODFILIAL = PCEST.CODFILIAL), 0), 0) SALDO_LOTEAVARIADO
                                FROM PCEST
                               WHERE PCEST.CODFILIAL = psCODFILIAL
                                 AND (((psDESBLOQPRODFAMILIA = 'S') AND PCEST.CODPROD IN (SELECT CASE WHEN (SELECT COUNT(T.CODPROD)
                                                                                                          FROM PCPRODUT T
                                                                                                         WHERE T.CODPRODPRINC = pnCODPRODPRINC
                                                                                                           AND T.DTEXCLUSAO IS NULL) > 0 THEN 
                                                                                                     PCPRODUT.CODPROD     
                                                                                                  ELSE
                                                                                                    pnCODPRODPRINC END
                                                                                              FROM PCPRODUT
                                                                                              WHERE PCPRODUT.CODPRODPRINC = pnCODPRODPRINC
                                                                                              AND PCPRODUT.DTEXCLUSAO IS NULL))
                                   OR ((psDESBLOQPRODFAMILIA = 'N') AND (PCEST.CODPROD = pnCODPROD))))
              LOOP
                vnQTDE := pnQTDE;             

                --------------------------------------
                -- Atualizar pendente na PCEST */
                IF LEAST(vnQTDE, GREATEST(ESTOQUE.QTESTGER, 0)) > 0 THEN 
                  P_INTERNO.CALCULA_ESTOQUE             := 'S';
				ELSE
				  P_INTERNO.CALCULA_ESTOQUE             := 'N';
				END IF;
                P_INTERNO.vtESTOQUE                   := NULL;
                P_INTERNO.TIPO_OPERACAO               := 'B';
                P_INTERNO.vtESTOQUE.CODFILIAL         := ESTOQUE.CODFILIAL;
                P_INTERNO.vtESTOQUE.CODPROD           := ESTOQUE.CODPROD;
                P_INTERNO.vtESTOQUE.CODDEVOL          := pnCODDEVOL;
                P_INTERNO.vtESTOQUE.MOTIVOBLOQESTOQUE := 'LIBERANDO APÓS PRECIFICAR';
                P_INTERNO.vtESTOQUE.QTBLOQUEADA       := LEAST(vnQTDE, GREATEST(ESTOQUE.QTESTGER, 0));               
                PRIV_ATUALIZAR_ESTOQUE;
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                -- Se controla estoque por lote
                IF (vsESTOQUEPORLOTE = 'S') THEN
                  -- Baixar lote
                  PRIV_BLOQUEIO_BAIXAR_LOTE (ESTOQUE.CODFILIAL
                                            ,ESTOQUE.CODPROD
                                            ,NULL
                                            ,(ESTOQUE.SALDO_ESTANTERIOR - vnQTDE)
                                            ,(pnCODDEVOL || ' - ' || 'LIBERANDO APÓS PRECIFICAR'));
                END IF;
                -- Envair mensagem para o RCA
                IF (vnQTDE > 0) AND (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ENVIAMENSRCALIBEST'), 'N') = 'S') THEN
                  PRIV_MSG_RCA(ESTOQUE.CODFILIAL, ESTOQUE.CODPROD);
                END IF;
                -- Atualizar tabela de bonus
                IF ((pnNUMBONUS.COUNT > 0) AND(pnQTENTRADABONUS > 0)) THEN
                  -- Lista de bonus
                  FOR XN_NUMBONUS IN pnNUMBONUS.FIRST .. pnNUMBONUS.LAST
                  LOOP
                    UPDATE PCBONUSI
                       SET PCBONUSI.QTBLOQUEADALIBERADA = 'S'
                     WHERE PCBONUSI.NUMBONUS = pnNUMBONUS(XN_NUMBONUS)
                       AND PCBONUSI.CODPROD = ESTOQUE.CODPROD;
                  END LOOP;
                -- Atualização do bonus
                END IF;

                QTANTERIOR := ESTOQUE.SALDO_ESTANTERIOR;
                FOR REGISTROS IN (SELECT M.CODPROD,
                                         M.CODFILIAL,
                                         M.NUMTRANSENT,
                                         M.NUMBONUS,
                                         M.QT,
                                         M.ROWID
                                    FROM PCMOV M, PCBONUSC C
                                   WHERE M.NUMBONUS = C.NUMBONUS
                                     AND C.DTFECHAMENTO IS NOT NULL
                                     AND M.CODPROD = ESTOQUE.CODPROD
                                     AND M.CODFILIAL = ESTOQUE.CODFILIAL
                                     AND M.QTBLOQUEADA > 0
                                     AND M.CODOPER LIKE 'E%'
                                     AND M.DTMOV > (SYSDATE - 360)
                               UNION ALL
                                  SELECT M.CODPROD,
                                         M.CODFILIAL,
                                         M.NUMTRANSENT,
                                         0 AS NUMBONUS,
                                         M.QT,
                                         M.ROWID
                                    FROM PCMOV M
                                   WHERE M.NUMBONUS IS NULL
                                     AND M.CODPROD = ESTOQUE.CODPROD
                                     AND M.CODFILIAL = ESTOQUE.CODFILIAL
                                     AND M.DTMOV > (SYSDATE - 360)
                                     AND M.CODOPER LIKE 'E%'
                                     AND M.QTBLOQUEADA > 0)
                LOOP
                  UPDATE PCMOV
                     SET QTBLOQUEADA = 0,
                         ESTOQUEDESBLOQUEADO = 'S'
                   WHERE CODPROD = REGISTROS.CODPROD
                     AND CODFILIAL = REGISTROS.CODFILIAL
                     AND ROWID = REGISTROS.ROWID;

                  --Gravar o Log de Bloqueio/Desbloqueio
                  P_INTERNO.IDENTIFICADOR  := REGISTROS.NUMTRANSENT;
                  P_INTERNO.CODFUNCLANC    := vnCODFUNC;
                  P_INTERNO.CODPROD        := ESTOQUE.CODPROD;
                  P_INTERNO.QTBLOQUEADA    := QTANTERIOR - REGISTROS.QT;
                  P_INTERNO.QTBLOQUEADAANT := ESTOQUE.SALDO_ESTANTERIOR;
                  P_INTERNO.OBSERVACAO     := 'DESBLOQUEIO REALIZADO PELA ROTINA PCSIS201';
                  P_INTERNO.CODFILIAL      := psCODFILIAL;
                  P_INTERNO.CODDEVOL       := pnCODDEVOL;
                  P_INTERNO.QTINDENIZANT   := ESTOQUE.SALDO_ESTINDENIZ;
                  P_INTERNO.QTDESBLOQUEADA := QTANTERIOR;

                  IF REGISTROS.NUMBONUS > 0 THEN
                    P_INTERNO.NUMTRANSACAOORIGEM := REGISTROS.NUMBONUS;
                  END IF;

                  PRIV_GERARLOGBLOQUEIO;

                  QTANTERIOR := QTANTERIOR - REGISTROS.QT;
                END LOOP;

                IF QTANTERIOR >= (ESTOQUE.SALDO_ESTANTERIOR - vnQTDE) AND (vnQTDE <> ESTOQUE.SALDO_ESTANTERIOR) THEN
                  P_INTERNO.IDENTIFICADOR  := pnIDENTIFICADOR;
                  P_INTERNO.CODFUNCLANC    := vnCODFUNC;
                  P_INTERNO.CODPROD        := ESTOQUE.CODPROD;
                  P_INTERNO.QTBLOQUEADA    := QTANTERIOR - vnQTDE;
                  P_INTERNO.QTBLOQUEADAANT := ESTOQUE.SALDO_ESTANTERIOR;
                  P_INTERNO.OBSERVACAO     := 'DESBLOQUEIO REALIZADO PELA ROTINA PCSIS201';
                  P_INTERNO.CODFILIAL      := psCODFILIAL;
                  P_INTERNO.CODDEVOL       := pnCODDEVOL;
                  P_INTERNO.QTINDENIZANT   := ESTOQUE.SALDO_ESTINDENIZ;
                  P_INTERNO.QTDESBLOQUEADA := QTANTERIOR;
                  PRIV_GERARLOGBLOQUEIO;
                END IF;
              -- Lista de produtos
              END LOOP;
              -- Se não for rotina 201
            ELSE
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE (psCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Consultar estoque
              vnESTOQUE_QTBLOQUEADA          := 0;
              P_INTERNO.vtESTOQUE            := NULL;
              P_INTERNO.vtESTOQUE.CODFILIAL  := psCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD    := pnCODPROD;
              PRIV_CONS_ESTOQUE_ATUAL (P_INTERNO.vtESTOQUE);
              QTANTERIOR := P_INTERNO.VTESTOQUE.QTBLOQUEADA;
			  
              QTDEVOLVWSM := 0;
			  
              /*IF (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_USAWMS', psCODFILIAL), 'N') = 'S') THEN
                QTDEVOLVWSM := NVL(WMS_QTFALTAAVARAIASEMDEVPEND(pnCODPROD, psCODFILIAL, 'B'), 0); 
              END IF;*/
              
              P_INTERNO.VTESTOQUE.QTBLOQUEADA := (P_INTERNO.VTESTOQUE.QTBLOQUEADA - QTDEVOLVWSM) - QTBONUS_ABERTO;
			  
              -- Validar quantidade
              IF NVL(pnQTDE, 0) > 0 THEN
                IF pnQTDE >= P_INTERNO.vtESTOQUE.QTBLOQUEADA THEN
                  IF NVL(pnQTAVARIA, 0) = 0 THEN
                    vnESTOQUE_QTBLOQUEADA := GREATEST((P_INTERNO.vtESTOQUE.QTBLOQUEADA - P_INTERNO.vtESTOQUE.QTINDENIZ), 0);
                  ELSE
                    vnESTOQUE_QTBLOQUEADA := GREATEST((P_INTERNO.vtESTOQUE.QTBLOQUEADA - GREATEST((P_INTERNO.vtESTOQUE.QTINDENIZ - pnQTAVARIA), 0)), 0);
                  END IF;
                ELSE
                  IF NVL(pnQTAVARIA, 0) = 0 THEN
                    IF (P_INTERNO.vtESTOQUE.QTBLOQUEADA - pnQTDE) >= P_INTERNO.vtESTOQUE.QTINDENIZ THEN
                      vnESTOQUE_QTBLOQUEADA := pnQTDE;
                    ELSE
                      vnESTOQUE_QTBLOQUEADA := GREATEST((P_INTERNO.vtESTOQUE.QTBLOQUEADA - P_INTERNO.vtESTOQUE.QTINDENIZ), 0);
                    END IF;
                  ELSE
                    vnESTOQUE_QTBLOQUEADA := GREATEST((P_INTERNO.vtESTOQUE.QTBLOQUEADA - GREATEST((P_INTERNO.vtESTOQUE.QTINDENIZ - pnQTAVARIA), 0)), 0);
                  END IF;
                END IF;
              END IF;
              -- Atualizar pendente na PCEST
              P_INTERNO.vtESTOQUE               := NULL;
              P_INTERNO.TIPO_OPERACAO           := 'B';
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := psCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := vnESTOQUE_QTBLOQUEADA;--NVL(pnQTDE,0);
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(pnQTAVARIA,0);
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;

              IF vnESTOQUE_QTBLOQUEADA > 0 THEN
                P_INTERNO.IDENTIFICADOR  := pnIDENTIFICADOR;
                P_INTERNO.CODFUNCLANC    := vnCODFUNC;
                P_INTERNO.CODPROD        := pnCODPROD;
                P_INTERNO.QTBLOQUEADA    := QTANTERIOR - vnESTOQUE_QTBLOQUEADA;
                P_INTERNO.QTBLOQUEADAANT := QTANTERIOR;
                P_INTERNO.OBSERVACAO     := 'DESBLOQUEIO REALIZADO PELA ROTINA PCSIS266';
                P_INTERNO.CODFILIAL      := psCODFILIAL;
                P_INTERNO.CODDEVOL       := pnCODDEVOL;                
                P_INTERNO.QTDESBLOQUEADA := vnESTOQUE_QTBLOQUEADA;
                PRIV_GERARLOGBLOQUEIO;
              END IF; 
        
        -- Validar se conseguiu inserir o log de desbloqueio
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;

              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := vnESTOQUE_QTBLOQUEADA;
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(pnQTAVARIA,0);
              -- Caso exista avaria
              IF NVL(vnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA.DATA          := TRUNC(SYSDATE);
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := NULL;
              P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := 'S';
              P_INTERNO.vtAVARIA.CODFUNCLANC   := NULL;
              P_INTERNO.vtAVARIA.NUMNOTA       := vnNUMNOTA;
              P_INTERNO.vtAVARIA.NUMTRANSENT   := pnIDENTIFICADOR;
              P_INTERNO.vtAVARIA.NUMTRANSVENDA := NULL;
              P_INTERNO.vtAVARIA.OBS           := 'SAÍDA MANUAL';
              P_INTERNO.vtAVARIA.DTMOVLOG      := SYSDATE;
              P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := vsNUMLOTE;
              --vtAVARIA.CODROTINALANC := vsROTINA;
              P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
              --vtAVARIA.CODROTINA     := SOMENTENUMERO(vsROTINA);
              P_INTERNO.vtAVARIA.NUMTRANSWMS   := NULL;
              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'S');
              -- Validar se conseguiu atualizar o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Fim inserte movimentação
              END IF;
            END IF;
          -- Não tem filial informada
          ELSE
            psMSG_RETORNO := 'Erro 16 (Bloqueio Baixar): O filial deve ser informado para a operação! '||CHR(13)||
                             'Verifique a filial informada!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Cód. Filial..: '||psCODFILIAL||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Filial
          END IF;
        -- Gestão de avaria (1181)
        WHEN psOPERACAO IN ('BG','AG') THEN
          -- A filial e o código de oper são obrigatórios
          IF (psCODFILIAL IS NOT NULL AND psCODOPER IS NOT NULL) THEN
            -- É diferente de rotina 1182?
            IF vsROTINA NOT LIKE '%PCSIS1182%' THEN
              -- Soma quantidade do item
              SELECT nvl(SUM(QT), 0)
                INTO vtAVARIA_GRUPO
                FROM PCPRODAVARIA
               WHERE CODPROD = pnCODPROD
                 AND CODFILIAL = psCODFILIAL;
              -- Utiliza depósito?
              IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
                -- Buscar quantidade avariada atual
                BEGIN
                  SELECT nvl(SUM(QT), 0)
                    INTO vtAVARIA_GRUPO
                    FROM PCPRODAVARIA
                   WHERE CODPROD = pnCODPROD
                     AND CODFILIAL = psCODFILIAL
                     AND CODDEPOSITO = pnCODDEPOSITO;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vtAVARIA_GRUPO := 0;
                END;

                BEGIN
                  SELECT QTINDENIZADA
                    INTO vtQTINDENIZ_TOTAL
                    FROM PCESTOQUEDEPOSITOPROD
                   WHERE CODPROD = pnCODPROD
                     AND CODFILIAL = psCODFILIAL
                     AND CODDEPOSITO = pnCODDEPOSITO;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vtQTINDENIZ_TOTAL := 0;
                END;
              ELSE
                -- Buscar quantidade avariada atual
                BEGIN
                  SELECT QTINDENIZ
                    INTO vtQTINDENIZ_TOTAL
                    FROM PCEST
                   WHERE CODPROD = pnCODPROD
                     AND CODFILIAL = psCODFILIAL;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vtQTINDENIZ_TOTAL := 0;
                END;
              END IF;
              -- Saldo disponível
              SALDO_DISPONIVEL_AVA := vtQTINDENIZ_TOTAL - pnQTAVARIA;
            ELSE
              SALDO_DISPONIVEL_AVA := 1;
              vtAVARIA_GRUPO       := 0;
            END IF;
            -- Valida saldo
            IF SALDO_DISPONIVEL_AVA >= vtAVARIA_GRUPO THEN
              -- Caso exista avaria
              IF NVL(pnQTAVARIA,0) > 0 THEN
                -- Atualizar movimentação de avaria */
                P_INTERNO.vtAVARIA.NUMTRANSVENDA := NVL(pnIDENTIFICADOR,0);
                P_INTERNO.vtAVARIA.DATA          := TRUNC(SYSDATE);
                P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
                P_INTERNO.vtAVARIA.CODCLI        := NULL;
                P_INTERNO.vtAVARIA.QT            := pnQTAVARIA;
                P_INTERNO.vtAVARIA.CODOPER       := psCODOPER;
                P_INTERNO.vtAVARIA.CODFUNCLANC   := NULL;
                P_INTERNO.vtAVARIA.OBS           := CASE
                                                      WHEN NVL(psOBSERVACAO,'X') <> 'X' THEN
                                                        SUBSTR(psOBSERVACAO, 1, 60)
                                                      WHEN psCODOPER = 'SR' THEN
                                                        'SAÍDA POR REAPROVEITAMENTO (AVARIA)'
                                                      WHEN psCODOPER = 'SI' THEN
                                                        'SAÍDA INDENIZADA'
                                                      WHEN psCODOPER = 'SP' THEN
                                                        'SAÍDA POR PERDA'
                                                    ELSE
                                                      'AÇÃO NÃO MAPEADA'
                                                    END;
                P_INTERNO.vtAVARIA.CODFILIAL     := psCODFILIAL;
                P_INTERNO.vtAVARIA.NUMLOTE       := psNUMLOTE;
                P_INTERNO.vtAVARIA.CODDEVOL      := CASE
                                                      WHEN NVL(pnCODDEVOL,0) > 0 THEN
                                                         pnCODDEVOL
                                                    ELSE
                                                      NULL
                                                    END;
                P_INTERNO.vtAVARIA.CODROTINALANC := PRIV_SOMENTENUMERO (vsROTINA);
                P_INTERNO.vtAVARIA.NUMTRANSWMS   := NVL(pnIDENTIFICADOR,0);
                P_INTERNO.vtAVARIA.CODDEPOSITO   := pnCODDEPOSITO;

                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                -- Bloquear estoque pendente do item
                PRIV_BLOQUEAR_ESTOQUE(psCODFILIAL,pnCODPROD,psMSG_RETORNO);
                -- Validar se conseguiu bloquear o estoque
                IF psMSG_RETORNO <> 'OK' THEN
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                -- Atualizar variável
                P_INTERNO.vtESTOQUE               := NULL;
                P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
                P_INTERNO.vtESTOQUE.CODFILIAL     := psCODFILIAL;
                P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
                P_INTERNO.vtESTOQUE.QTBLOQUEADA   := pnQTAVARIA;
                P_INTERNO.vtESTOQUE.QTINDENIZ     := pnQTAVARIA;
                P_INTERNO.NOME_TABELA             := 'USUARIO';
                -- Atualizar estoque pendente
                PRIV_ATUALIZAR_ESTOQUE;
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;

                IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S') AND (vsROTINA LIKE '%PCSIS1182%') THEN
                  BEGIN
                    SELECT CODDEPOSITO
                      INTO P_INTERNO.CODDEPOSITO
                      FROM PCESTOQUEDEPOSITO
                     WHERE PADRAOAVARIA = 'S'
                       AND CODFILIAL = psCODFILIAL;
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      P_INTERNO.CODDEPOSITO := NULL;
                  END;

                  P_INTERNO.vtAVARIA.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;

                  P_INTERNO.CODFILIAL     := psCODFILIAL;
                  P_INTERNO.CODPROD       := pnCODPROD;
                  P_INTERNO.QTBLOQUEADA   := pnQTAVARIA;
                  P_INTERNO.QTINDENIZ     := pnQTAVARIA;

                  PRIV_DEP_AVARIA;

                  -- Validar se conseguiu atualizar o estoque
                  IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                    PRIV_GERARLOG;
                    RETURN 'N';
                  END IF;
                END IF;

                PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'S');

                -- Caso o produto seja controlado por lote, atualiza PCLOTE
                IF NVL(vsESTOQUEPORLOTE,'N') = 'S' AND (psNUMLOTE IS NOT NULL) AND (psCODOPER <> 'SP') THEN
                  -- Valida se o lote existe
                  P_INTERNO.vtLOTE           := NULL;
                  P_INTERNO.vtLOTE.CODFILIAL := psCODFILIAL;
                  P_INTERNO.vtLOTE.CODPROD   := pnCODPROD;
                  P_INTERNO.vtLOTE.NUMLOTE   := psNUMLOTE;
                  PRIV_CONS_LOTE;
                  -- Validar se o lote existe
                  IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                    PRIV_GERARLOG;
                    RETURN 'N';
                  END IF;
                  -- Bloquear PCLOTE
                  PRIV_BLOQUEAR_LOTE;
                  -- Validar se conseguiu bloquear a PCLOTE
                  IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                    psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                    PRIV_GERARLOG;
                    RETURN 'N';
                  END IF;
                  -- Atualizar dados
                  P_INTERNO.vtLOTE.QT          := NULL;
                  P_INTERNO.vtLOTE.QTEST       := NULL;
                  P_INTERNO.vtLOTE.QTRESERV    := NULL;
                  P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
                  P_INTERNO.vtLOTE.QTBLOQUEADA := pnQTAVARIA;
                  P_INTERNO.vtLOTE.QTINDENIZ   := pnQTAVARIA;
                  -- Administrar estoque do lote
                  PRIV_ATUALIZAR_LOTE;
                END IF;
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              -- Qtde Avaria inválida
              ELSE
                psMSG_RETORNO := 'Erro 6 (Bloqueio Baixar): A quantidade avariada não é valida!'||CHR(13)||
                                 'Para este tipo de operação a quantidade avariada é obrigatória!'||CHR(13)||
                                 'Qtde. Avariada: '||pnQTAVARIA||CHR(13)||
                                 'Operação......: '||psOPERACAO;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              -- Inserte movimentação
              END IF;
          ELSE
            psMSG_RETORNO := 'ERRO 7 (BLOQUEIO BAIXAR): Não é possível desbloquear pois esse produto possui avarias '||CHR(13)||
                             'inseridas pela rotina 1182 e que devem ser desbloqueadas pela própria rotina 1182.'||CHR(13)||
                             'Para identificar os bloqueios para os produtos informados, acesse a rotina 1118 na aba estoque bloqueado.' ||CHR(13)||
                             'CodProd....: '||pnCODPROD||CHR(13)||
                             'Qtde. Avariada.: '||vtAVARIA_GRUPO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- A filial e o código de oper são obrigatórios
        ELSE
          psMSG_RETORNO := 'Erro 8 (Bloqueio Baixar): A filial ou código de operação não são validos!'||CHR(13)||
                           'Para este tipo de operação a filial e o código de opereção são obrigatórios!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Cód. Oper....: '||psCODOPER||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Caso a operação ou identificador não for valido
      ELSE
        psMSG_RETORNO := 'Erro 9 (Bloqueio Baixar): A operação ou o identificador informado não são validos para manipular a quantidade bloqueada/avariada!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Operação.....: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Validação da operação
      END CASE;
    -- Produto não é valido
    ELSE
      psMSG_RETORNO := 'Erro 10 (Bloqueio Baixar): A produto é um parâmetro obrigatorio para esta função. Favor informa-lo corretamente!'||CHR(13)||
                       'Produto.: '||TO_CHAR(pnCODPROD)||CHR(13)||
                       'Operação: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação do produto
    END IF;

    IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S') AND (vsROTINA NOT LIKE '%PCSIS1182%') THEN
      -- Atualizar variáveis
      P_INTERNO.PROCESSO      := 'BLOQUEAR';
      P_INTERNO.QTBLOQUEADA   := P_INTERNO.vtESTOQUE.QTBLOQUEADA;
      P_INTERNO.QTINDENIZ     := P_INTERNO.vtESTOQUE.QTINDENIZ;
      -- Movimenta estoque do depósito
      PRIV_DEP_BAIXAR;
      -- Valida se movimentação do depósito ficou correta
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_BAIXAR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno cerá "S - Sim"
    RETURN 'S';
  -- Função
  END BLOQUEIO_BAIXAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Função criada para baixar o estoque pendente de um pedido
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_BAIXAR_PEDIDO (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                  ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                  ,psCODOPER       IN PCMOV.CODOPER%TYPE DEFAULT NULL
                                  ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vbBAIXOU  VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.LISTA_VALIDA    := 'N';
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - BLOQUEIO_BAIXAR_PEDIDO';
    P_INTERNO.NOME_FUNCAO     := 'BLOQUEIO_BAIXAR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    -- Valida operação
    CASE
      -- Pedido de venda
      WHEN (psOPERACAO IN ('CB','AB') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT PCBONUSC.CODFILIAL
                            ,PCBONUSI.CODPROD
                            ,PCBONUSI.NUMSEQ
                            ,NVL(PCBONUSI.QTENTRADA,0) AS QTBLOQUEADA
                            ,NVL(PCBONUSI.QTAVARIA,0) AS QTAVARIA
                            ,PCBONUSC.CODFUNCFECHA
                            ,PCBONUSI.CODMOTIVO
                        FROM PCBONUSI
                            ,PCBONUSC
                       WHERE PCBONUSI.NUMBONUS = PCBONUSC.NUMBONUS
                         AND PCBONUSI.NUMBONUS = pnIDENTIFICADOR)
        LOOP
          -- Validar lista
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Baixar estoque bloqueado
          vbBAIXOU := BLOQUEIO_BAIXAR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QTBLOQUEADA,DADOS.QTAVARIA,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO,NULL);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 1 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
      -- Entradas
      WHEN (psOPERACAO IN ('BE','AE') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL) CODFILIAL
                            ,PCMOV.CODPROD
                            ,PCMOV.NUMSEQ
                            ,PCMOV.QTBLOQUEADA
                            ,PCMOV.QTAVARIA
                        FROM PCMOV
                       WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                         AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0)
        LOOP
          -- Validar lista
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Baixar estoque bloqueado
          vbBAIXOU := BLOQUEIO_BAIXAR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QTBLOQUEADA,DADOS.QTAVARIA,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 2 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
    -- Caso a operação ou identificador não for valido
    ELSE
      psMSG_RETORNO := 'Erro 3 (Bloqueio Baixar Pedido): A operação ou o identificador informado não são validos para manipular a quantidade bloqueada/avariada!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da operação
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_BAIXAR_PEDIDO';
    PRIV_GERARLOG;
    -- Atualizar o retorno da função
    RETURN vbBAIXOU;
  -- Função
  END BLOQUEIO_BAIXAR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função Incluir quantidade bloqueada
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_INCLUIR (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                            ,psCODFILIAL     IN PCMOV.CODFILIAL%TYPE
                            ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                            ,pnNUMSEQ        IN PCMOV.NUMSEQ%TYPE
                            ,pnQTDE          IN PCMOV.QT%TYPE
                            ,pnQTAVARIA      IN PCMOV.QTAVARIA%TYPE
                            ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                            ,psCODOPER       IN PCMOV.CODOPER%TYPE DEFAULT NULL
                            ,pnCODDEVOL      IN PCMOV.CODDEVOL%TYPE DEFAULT 0
                            ,psOBSERVACAO    IN VARCHAR2 DEFAULT NULL
                            ,psNUMLOTE       IN PCMOV.NUMLOTE%TYPE DEFAULT NULL
                            ,psMSG_RETORNO   OUT VARCHAR2
                            ,pnCODDEPOSITO   IN PCMOV.CODDEPOSITO%TYPE DEFAULT NULL)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnQTDE                  PCMOV.QTBLOQUEADA%TYPE;
    vnQTDENF                PCMOV.QTBLOQUEADA%TYPE;
    vnQTAVARIA              PCMOV.QTAVARIA%TYPE;
    vnQTAVARIANF            PCMOV.QTAVARIA%TYPE;
    vsCODOPER               PCMOV.CODOPER%TYPE;
    vnCODCLI                PCMOV.CODCLI%TYPE;
    vsSTATUS                PCMOV.STATUS%TYPE;
    vsCODFILIAL             PCMOV.CODFILIAL%TYPE;
    vdDATA                  PCMOV.DTMOV%TYPE;
    vnCODFUNC               PCMOV.CODFUNCLANC%TYPE;
    vnCODMOTIVO             PCMOV.CODDEVOL%TYPE;
    vsNUMLOTE               PCMOV.NUMLOTE%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vdDTIMPORTACAO          PCPEDC.DTIMPORTACAO%TYPE;
    vsUSAINTEGRACAOWMS      PCPEDC.USAINTEGRACAOWMS%TYPE;
    vsROTINACAD             PCMOV.ROTINACAD%TYPE;
    vbpQTBLOQUEADO          PCEST.QTBLOQUEADA%TYPE;
    vbpQTINDENIZ            PCEST.QTINDENIZ%TYPE;
    vsLIBERAESTENTMERC      PCBONUSC.LIBERAESTENTMERC%TYPE;
    vsLIBERAESTFECHBONUS    PCBONUSC.LIBERAESTFECHBONUS%TYPE;
    vnGERABONUS             PCMOVCOMPLE.GERABONUS%Type;
    vsUSAWMS                PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE        PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vnQTUNITCX              PCPRODUT.QTUNITCX%TYPE;
    vsTIPOMERC              PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL          PCPRODUT.PESOVARIAVEL%TYPE;
    vnDISPONIVEL            PCEST.QTESTGER%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    vsROTINACAD                         := '';
    psMSG_RETORNO                       := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG           := 'Iniciou a função - BLOQUEIO_INCLUIR';
    P_INTERNO.NOME_FUNCAO               := 'BLOQUEIO_INCLUIR';
    P_INTERNO.IDENTIFICADOR             := pnIDENTIFICADOR;
    P_INTERNO.CODFILIAL                 := psCODFILIAL;
    P_INTERNO.CODPROD                   := pnCODPROD;
    P_INTERNO.NUMSEQ                    := pnNUMSEQ;
    P_INTERNO.QTPARAMETROENTRADA        := pnQTDE;
    P_INTERNO.QTPARAMETROENTRADA_AVARIA := pnQTAVARIA;
    P_INTERNO.TIPO_OPERACAO             := psOPERACAO;
    P_INTERNO.CODDEPOSITO               := pnCODDEPOSITO;
    PRIV_GERARLOG;
    -- Validar codigo do produto
    IF pnCODPROD IS NOT NULL THEN
      --Busca todos os dados do produto
      PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
      CASE-- Valida operação
        -- Pedido de venda
        WHEN psOPERACAO IN ('IN','AQ') THEN
          -- O identificador é obrigatório
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Consultar dados do pedido
            BEGIN
              SELECT PCPEDI.QT
                    ,PCPEDC.CODCLI
                    ,PCPEDC.DATA
                    ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                    ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                    ,PCPEDC.USAINTEGRACAOWMS
                    ,PCPEDC.DTIMPORTACAO
                    ,PCPEDI.CODDEPOSITO
                    ,PCPEDI.ROWID
                INTO vnQTDE
                    ,vnCODCLI
                    ,vdDATA
                    ,vsCODFILIAL
                    ,vsPOSICAO
                    ,vsUSAINTEGRACAOWMS
                    ,vdDTIMPORTACAO
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                FROM PCPEDI, PCPEDC
               WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                 AND PCPEDI.NUMPED = pnIDENTIFICADOR
                 AND PCPEDI.CODPROD = pnCODPROD
                 --AND NVL(PCPEDI.QT,0) > 0
                 AND PCPEDI.NUMSEQ = pnNUMSEQ;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCPEDI';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 1 (Bloqueio Incluir): Não foi possível consultar dados do item para fazer o bloqueio!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Validar posição do pedido
            IF (vsPOSICAO IN ('L','M')
              AND NVL(vsUSAINTEGRACAOWMS,'N') = 'S'
              AND vdDTIMPORTACAO IS NOT NULL) THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variável
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := vnQTDE;
              -- Atualizar estoque bloqueado
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Validação posicao do pedido
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 2 (Bloqueio Incluir): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Corte em pedido de venda
        WHEN psOPERACAO IN ('FQ') THEN
          -- O identificador e quantidades cortada são obrigatórios
          IF (NVL(pnIDENTIFICADOR,0) > 0 AND pnQTDE > 0) THEN
            -- Valida parâmetro para bloqueio
            IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQITENSCORTE936','99','N') = 'S' THEN
              -- Buacar dados do pedido
              BEGIN
                SELECT NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                      ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                      ,PCPEDI.CODDEPOSITO
                      ,PCPEDI.ROWID
                  INTO vsCODFILIAL
                      ,vsPOSICAO
                      ,P_INTERNO.CODDEPOSITO
                      ,P_INTERNO.ROWID_REGISTRO
                  FROM PCPEDI, PCPEDC
                 WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                   AND PCPEDI.NUMPED = pnIDENTIFICADOR
                   AND PCPEDI.CODPROD = pnCODPROD
                   --AND NVL(PCPEDI.QT,0) > 0
                   AND PCPEDI.NUMSEQ = pnNUMSEQ;
                -- Atualizando filial do log
                P_INTERNO.CODFILIAL   := vsCODFILIAL;
                P_INTERNO.NOME_TABELA := 'PCPEDI';
              EXCEPTION
                WHEN OTHERS THEN
                  psMSG_RETORNO := 'Erro 3 (Bloqueio Incluir): Não foi possível consultar dados para o identificador informado!'||CHR(13)||
                                   'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                   'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                   'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                   'Operação.....: '||psOPERACAO||CHR(13)||
                                   'MSG Original.: '||SQLERRM;
                  P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
              END;
              -- Atualizar disponível
              vnQTDE := ESTOQUE_DISPONIVEL (pnCODPROD,vsCODFILIAL,'V');
              -- Verifica se tem disponível
              IF (vnQTDE - pnQTDE) >= 0 THEN
                -- Bloquear estoque pendente do item
                PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
                -- Validar se conseguiu bloquear o estoque
                IF psMSG_RETORNO <> 'OK' THEN
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                -- Atualizar variável
                P_INTERNO.vtESTOQUE := NULL;
                P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
                P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
                P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
                P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(pnQTDE,0);
                -- Atualizar estoque bloqueado
                PRIV_ATUALIZAR_ESTOQUE;
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              --
              ELSE
                psMSG_RETORNO := 'Erro 16 (Bloqueio Incluir): Não foi possivel realizar o corte, estoque disponivel insuficiente!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Estoque Disp: ' ||TO_CHAR((vnQTDE - pnQTDE))||
                                 'Qtde. Cortada: '||TO_CHAR(pnQTDE)||CHR(13)||
                                 'Operação.....: '||psOPERACAO;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              -- Validação do disponivel
              END IF;
            -- Validação do parâmetro
            END IF;
          -- O identificador e quantidades cortada são obrigatórios
          ELSE
            psMSG_RETORNO := 'Erro 4 (Bloqueio Incluir): O identificador ou a quantidade cortada não foram informados!'||CHR(13)||
                             'Para este tipo de operação o identificador e a quantidade cortada são obrigatórios!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Qtde. Cortada: '||TO_CHAR(pnQTDE)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Ordem de produção (Industria/cesta/kit)
        WHEN psOPERACAO IN ('II','AI') THEN
          -- O identificador é obrigatório
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Buscar informações da transação
            BEGIN
              SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)
                    ,PCMOV.QTBLOQUEADA
                    ,PCMOV.QTAVARIA
                    ,PCMOV.CODOPER
                    ,PCMOV.DTMOV
                    ,PCMOV.CODCLI
                    ,PCMOV.CODOPER
                    ,PCMOV.CODFUNCLANC
                    ,PCMOV.CODDEVOL
                    ,PCMOV.NUMLOTE
                    ,PCMOV.CODDEPOSITO
                    ,PCMOV.ROWID
                INTO vsCODFILIAL
                    ,vnQTDE
                    ,vnQTAVARIA
                    ,vsCODOPER
                    ,vdDATA
                    ,vnCODCLI
                    ,vsCODOPER
                    ,vnCODFUNC
                    ,vnCODMOTIVO
                    ,vsNUMLOTE
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                FROM PCMOV
               WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                 AND PCMOV.CODPROD = pnCODPROD
                 AND PCMOV.NUMSEQ = pnNUMSEQ
                 AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCMOV';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 5 (Bloqueio Incluir): Não foi possível consultar dados para o identificador informado! '||CHR(13)||
                                 'É possível que não exista dados na PCMOV. Verifique!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Valida se atualizar estoque bloqueado
            IF (SUBSTR(vsCODOPER,1,1) = 'E'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQUEARENTPA','99','N') = 'S') THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variável
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(vnQTDE,NVL(vnQTAVARIA,0));
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(vnQTAVARIA,0);
              -- Atualizar  estoque bloqueado
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Validação do parâmetro
            END IF;
            -- Caso exista avaria
            IF NVL(vnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA               := NULL;
              P_INTERNO.vtAVARIA.DATA          := vdDATA;
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := vnCODCLI;
              P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := vsCODOPER;
              P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
              P_INTERNO.vtAVARIA.OBS           := 'ENT. ORDEM DE PRODUÇÃO';
              P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := vsNUMLOTE;
              -- vtAVARIA.CODROTINALANC := SOMENTENUMERO(vsROTINA);
              P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
              -- vtAVARIA.IDENTIFICADOR := pnIDENTIFICADOR;
              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'E');
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Inserte movimentação
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 6 (Bloqueio Incluir): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Cancelamento de bonus/inclusão Avaria
        WHEN psOPERACAO IN ('CB','AB') THEN
          -- O identificador é obrigatório
          IF (NVL(pnIDENTIFICADOR,0) > 0 AND NVL(pnCODPROD,0) > 0) THEN
            -- Buscar dados do bonus
            vnDISPONIVEL := ESTOQUE_DISPONIVEL (pnCODPROD,psCODFILIAL,'C');
            BEGIN
              SELECT CODFILIAL
                    ,MAX(DTFECHAMENTO) DTFECHAMENTO
                    ,CASE
                       WHEN (NVL(LEAST(SUM(QTENTRADA), SUM(QTNF)),0)) > vnDISPONIVEL THEN
                         vnDISPONIVEL
                       ELSE (NVL(LEAST(SUM(QTENTRADA), SUM(QTNF)),0))
                     END AS QTENTRADA
                    ,CASE
                       WHEN SUM(NVL(QTAVARIA,0)) > vnDISPONIVEL THEN
                         vnDISPONIVEL
                       ELSE SUM(NVL(QTAVARIA,0))
                     END AS QTAVARIA
                    ,CASE
                       WHEN SUM(NVL(QTAVARIANF,0)) > vnDISPONIVEL THEN
                         vnDISPONIVEL
                       ELSE SUM(NVL(QTAVARIANF,0))
                     END AS QTAVARIANF
                    ,CASE
                       WHEN SUM(NVL(QTNF, 0)) > vnDISPONIVEL THEN
                         vnDISPONIVEL
                       ELSE SUM(NVL(QTNF, 0))
                     END AS QTNF
                    ,MAX(CODFUNCFECHA) CODFUNCFECHA
                    ,MAX(CODMOTIVO) CODMOTIVO
                    ,CODDEPOSITO
                    ,LIBERAESTENTMERC
                    ,LIBERAESTFECHBONUS
               INTO vsCODFILIAL
                   ,vdDATA
                   ,vnQTDE
                   ,vnQTAVARIA
                   ,vnQTAVARIANF
                   ,vnQTDENF
                   ,vnCODFUNC
                   ,vnCODMOTIVO
                   ,P_INTERNO.CODDEPOSITO
                   ,vsLIBERAESTENTMERC
                   ,vsLIBERAESTFECHBONUS
              FROM(
                   SELECT  PCBONUSC.CODFILIAL
                          ,(PCBONUSC.DTFECHAMENTO) DTFECHAMENTO
                          ,(NVL(PCBONUSI.QTENTRADA,0)) AS QTENTRADA
                          ,(NVL(PCBONUSI.QTAVARIA,0)) AS QTAVARIA
                          ,(NVL(PCBONUSI.QTAVARIANF,0)) AS QTAVARIANF
                          ,CASE
                 WHEN NVL(PCBONUSI.NUMLOTE, '0') <> '0' THEN
                               CASE
                   WHEN (NVL(PCBONUSC.USARF, 'N') = 'S') THEN
                                   (NVL(PCBONUSI.QTNF, 0))                               
                   WHEN ((NUMLOTE = NUMLOTENF) OR (NVL(NUMLOTENF, '0') = '0')) THEN
                                   (NVL(PCBONUSI.QTNF, 0))
                                 ELSE
                                   0
                                 END
                             ELSE
                              (NVL(PCBONUSI.QTNF, 0))
                           END AS QTNF
                          ,(PCBONUSC.CODFUNCFECHA) CODFUNCFECHA
                          ,(PCBONUSI.CODMOTIVO) CODMOTIVO
                          ,PCBONUSI.CODDEPOSITO CODDEPOSITO
                          ,NVL(PCBONUSC.LIBERAESTENTMERC, FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTENTMERC',vsCODFILIAL,'N')) as LIBERAESTENTMERC
                          ,NVL(PCBONUSC.LIBERAESTFECHBONUS, FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTFECHBONUS',vsCODFILIAL,'N')) as LIBERAESTFECHBONUS
                    FROM PCBONUSI
                        ,PCBONUSC
                   WHERE PCBONUSI.NUMBONUS = PCBONUSC.NUMBONUS
                     AND PCBONUSI.NUMBONUS = pnIDENTIFICADOR
                     AND PCBONUSI.CODPROD  = pnCODPROD)
              GROUP BY CODFILIAL
                      ,CODDEPOSITO
                      ,LIBERAESTENTMERC
                      ,LIBERAESTFECHBONUS;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCBONUSI';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 7 (Bloqueio Incluir): Não foi possível consultar dados para o identificador informado!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Atualizar vtESTOQUE
            P_INTERNO.vtESTOQUE              := NULL;
            P_INTERNO.vtESTOQUE.QTBLOQUEADA := 0;
            P_INTERNO.vtESTOQUE.QTINDENIZ   := 0;
            IF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'N' AND P_INTERNO.TIPO_OPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTDENF;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'S' AND P_INTERNO.TIPO_OPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTDE;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
            ELSIF (((vsLIBERAESTENTMERC = 'S') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'N'))
              AND P_INTERNO.TIPO_OPERACAO <> 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTAVARIANF;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIANF;
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'S' AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTAVARIA;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIA;
            ELSIF (((vsLIBERAESTENTMERC = 'N') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'S'))
              AND vsLIBERAESTFECHBONUS = 'N'  AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTDENF;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIA;
            ELSIF (((vsLIBERAESTENTMERC = 'S') OR (vsROTINACAD LIKE '%1124%'
              AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQESTOQUETRANSF',vsCODFILIAL,'N') = 'N'))
              AND P_INTERNO.TIPO_OPERACAO = 'AB')
            THEN
              P_INTERNO.vtESTOQUE.QTBLOQUEADA := vnQTAVARIA;
              P_INTERNO.vtESTOQUE.QTINDENIZ   := vnQTAVARIA;
            END IF;
            -- Bloquear estoque pendente do item
            PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
            -- Validar se conseguiu bloquear o estoque
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Atualizar variável
            P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
            P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
            -- Atualizar estoque bloqueado
            PRIV_ATUALIZAR_ESTOQUE;
            BEGIN
              SELECT DISTINCT
                     PCEST.QTBLOQUEADA,
                     PCEST.QTINDENIZ
                INTO vbpQTBLOQUEADO,
                     vbpQTINDENIZ
                FROM PCEST
               WHERE PCEST.CODPROD = pnCODPROD
                 AND PCEST.CODFILIAL = vsCODFILIAL;
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 8 (Bloqueio Incluir): Não é possível localizar dados na PCEST!'||CHR(13)||
                                 'Cód. Filial..: '||vsCODFILIAL||CHR(13)||
                                 'Cód. Produto.: '||TO_CHAR(pnCODPROD);
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            IF (psOPERACAO = 'AB') AND (vbpQTBLOQUEADO < vbpQTINDENIZ) THEN
              UPDATE PCEST
                 SET QTBLOQUEADA = GREATEST(QTBLOQUEADA + vnQTAVARIA ,QTINDENIZ)
                    ,PCEST.DTHORAULTALTDISP = SYSDATE
               WHERE CODPROD = pnCODPROD
                 AND CODFILIAL = vsCODFILIAL;
            END IF;
            -- Validar se conseguiu atualizar o estoque
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Caso exista avaria
            IF NVL(vnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA               := NULL;
              P_INTERNO.vtAVARIA.DATA          := vdDATA;
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := NULL;
              P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := 'BC';
              P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
              P_INTERNO.vtAVARIA.OBS           := 'CANC. DE BONUS';
              P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := NULL;
              -- vtAVARIA.CODROTINALANC := SOMENTENUMERO(vsROTINA);
              P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
              -- Atualizar
              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'E');
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Inserte movimentação
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 8 (Bloqueio Incluir): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Entrada de mercadoria
        WHEN psOPERACAO IN ('IE','AE') THEN
          -- O identificador é obrigatório
          IF NVL(pnIDENTIFICADOR,0) > 0 THEN
            -- Buscar informações da transação
            BEGIN
              SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)
                    ,PCMOV.QTBLOQUEADA
                    ,PCMOV.QTAVARIA
                    ,PCMOV.CODOPER
                    ,PCMOV.STATUS
                    ,PCMOV.DTMOV
                    ,PCMOV.NUMLOTE
                    ,PCMOV.CODCLI
                    ,PCMOV.CODFUNCLANC
                    ,PCMOV.CODDEVOL
                    ,PCMOV.CODDEPOSITO
                    ,PCMOV.ROWID
                    ,NVL(PCMOVCOMPLE.GERABONUS, 'S')
                INTO vsCODFILIAL
                    ,vnQTDE
                    ,vnQTAVARIA
                    ,vsCODOPER
                    ,vsSTATUS
                    ,vdDATA
                    ,vsNUMLOTE
                    ,vnCODCLI
                    ,vnCODFUNC
                    ,vnCODMOTIVO
                    ,P_INTERNO.CODDEPOSITO
                    ,P_INTERNO.ROWID_REGISTRO
                    ,vnGERABONUS
                FROM PCMOV, PCMOVCOMPLE
               WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                 AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+)
                 AND PCMOV.CODPROD = pnCODPROD
                 AND PCMOV.NUMSEQ = pnNUMSEQ
                 AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0;
              -- Atualizando filial do log
              P_INTERNO.CODFILIAL   := vsCODFILIAL;
              P_INTERNO.NOME_TABELA := 'PCMOV';
            EXCEPTION
              WHEN OTHERS THEN
                psMSG_RETORNO := 'Erro 9 (Bloqueio Incluir): Não foi possível consultar dados para o identificador informado! '||CHR(13)||
                                 'É possível que não exista dados na PCMOV. Verifique!'||CHR(13)||
                                 'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                                 'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                                 'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                                 'Operação.....: '||psOPERACAO||CHR(13)||
                                 'MSG Original.: '||SQLERRM;
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END;
            -- Validar parâmetro da rotina 132
            IF ((vsCODOPER = 'ET' AND vsSTATUS IN ('B','AB') AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('BLOQESTOQUETRANSF','99',FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('BLOQESTOQUETRANSF',vsCODFILIAL,'N')) = 'S')
              OR (vsCODOPER = 'ED' AND vsSTATUS IN ('B','AB') AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQDEVCLI',vsCODFILIAL,'N') = 'S')
              OR (SUBSTR(vsCODOPER,1,1) = 'E' AND vsSTATUS IN ('B','AB') AND (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('LIBERAESTENTMERC',vsCODFILIAL,'N') = 'N' OR vnGERABONUS = 'S'))) THEN
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variável
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(vnQTDE,NVL(vnQTAVARIA,0));
              P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(vnQTAVARIA,0);
              -- Atualizar estoque bloquedo
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Caso exista avaria
              IF NVL(vnQTAVARIA,0) > 0 THEN
                -- Atualizar movimentação de avaria
                P_INTERNO.vtAVARIA               := NULL;
                P_INTERNO.vtAVARIA.DATA          := vdDATA;
                P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
                P_INTERNO.vtAVARIA.CODCLI        := vnCODCLI;
                P_INTERNO.vtAVARIA.QT            := vnQTAVARIA;
                P_INTERNO.vtAVARIA.CODOPER       := vsCODOPER;
                P_INTERNO.vtAVARIA.CODFUNCLANC   := vnCODFUNC;
                P_INTERNO.vtAVARIA.OBS           := CASE
                                                      WHEN vsCODOPER = 'ET' THEN
                                                        'ENT. DE TRANSFERÊNCIA'
                                                      WHEN vsCODOPER = 'ED' THEN
                                                        'ENT. DE DEVOL. CLIENTE'
                                                    ELSE
                                                      'ENTRADA DE MERCADORIA'
                                                    END;
                P_INTERNO.vtAVARIA.CODFILIAL     := vsCODFILIAL;
                P_INTERNO.vtAVARIA.NUMLOTE       := vsNUMLOTE;
                P_INTERNO.vtAVARIA.CODDEVOL      := vnCODMOTIVO;
                PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'E');
                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              -- Inserte movimentação
              END IF;
            -- Validação do parametro
            END IF;
          -- O identificador é obrigatório
          ELSE
            psMSG_RETORNO := 'Erro 10 (Bloqueio Incluir): O identificador não foi informado!'||CHR(13)||
                             'Para este tipo de operação o identificador é obrigatório!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Gestão de avaria (1181)
        WHEN psOPERACAO IN ('IG','AG') THEN
          -- A filial e o código de oper são obrigatórios
          IF (psCODFILIAL IS NOT NULL AND psCODOPER IS NOT NULL) THEN
            -- Caso exista avaria
            IF NVL(pnQTAVARIA,0) > 0 THEN
              -- Atualizar movimentação de avaria
              P_INTERNO.vtAVARIA               := NULL;
              P_INTERNO.vtAVARIA.NUMTRANSENT   := NVL(pnIDENTIFICADOR,0);
              P_INTERNO.vtAVARIA.DATA          := TRUNC(SYSDATE);
              P_INTERNO.vtAVARIA.CODPROD       := pnCODPROD;
              P_INTERNO.vtAVARIA.CODCLI        := NULL;
              P_INTERNO.vtAVARIA.QT            := pnQTAVARIA;
              P_INTERNO.vtAVARIA.CODOPER       := psCODOPER;
              P_INTERNO.vtAVARIA.CODFUNCLANC   := NULL;
              P_INTERNO.vtAVARIA.OBS           := CASE
                                                    WHEN nvl(psOBSERVACAO,'X') <> 'X' THEN
                                                      SUBSTR(psOBSERVACAO, 1, 60)
                                                    WHEN psCODOPER = 'EA' THEN
                                                      'ENTRADA DE AVARIA'
                                                    WHEN psCODOPER = 'EI' THEN
                                                      'ENTRADA INDENIZADA'
                                                    WHEN psCODOPER = 'EP' THEN
                                                      'ENTRADA DE PERDA'
                                                  ELSE
                                                    'AÇÃO NÃO MAPEADA'
                                                  END;
              P_INTERNO.vtAVARIA.CODFILIAL     := psCODFILIAL;
              P_INTERNO.vtAVARIA.NUMLOTE       := psNUMLOTE;
              P_INTERNO.vtAVARIA.CODDEVOL      := CASE
                                                    WHEN NVL(pnCODDEVOL,0) > 0 THEN
                                                       pnCODDEVOL
                                                    ELSE
                                                      NULL
                                                    END;
              P_INTERNO.vtAVARIA.CODROTINALANC := PRIV_SOMENTENUMERO (vsROTINA);
              P_INTERNO.vtAVARIA.NUMTRANSWMS   := NVL(pnIDENTIFICADOR,0);
              P_INTERNO.vtAVARIA.CODDEPOSITO   := pnCODDEPOSITO;

              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Bloquear estoque pendente do item
              PRIV_BLOQUEAR_ESTOQUE(psCODFILIAL,pnCODPROD,psMSG_RETORNO);
              -- Validar se conseguiu bloquear o estoque
              IF psMSG_RETORNO <> 'OK' THEN
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
              -- Atualizar variáveis
              P_INTERNO.vtESTOQUE := NULL;
              P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
              P_INTERNO.vtESTOQUE.CODFILIAL     := psCODFILIAL;
              P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
              P_INTERNO.vtESTOQUE.QTBLOQUEADA   := pnQTAVARIA;
              P_INTERNO.vtESTOQUE.QTINDENIZ     := pnQTAVARIA;
              P_INTERNO.NOME_TABELA   := 'USUARIO';
              -- Atualizar estoque bloqueado
              PRIV_ATUALIZAR_ESTOQUE;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;

              IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S') AND (vsROTINA LIKE '%PCSIS1182%') THEN
                BEGIN
                  SELECT CODDEPOSITO
                    INTO P_INTERNO.CODDEPOSITO
                    FROM PCESTOQUEDEPOSITO
                   WHERE PADRAOAVARIA = 'S'
                     AND CODFILIAL = psCODFILIAL;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    P_INTERNO.CODDEPOSITO := NULL;
                END;

                P_INTERNO.vtAVARIA.CODDEPOSITO   := P_INTERNO.CODDEPOSITO;

                P_INTERNO.CODFILIAL     := psCODFILIAL;
                P_INTERNO.CODPROD       := pnCODPROD;
                P_INTERNO.QTBLOQUEADA   := pnQTAVARIA;
                P_INTERNO.QTINDENIZ     := pnQTAVARIA;

                PRIV_DEP_AVARIA;

                -- Validar se conseguiu atualizar o estoque
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
              END IF;

              PRIV_ATUALIZAR_PCMOVAVARIA (P_INTERNO.vtAVARIA,'E');

              -- Caso o produto seja controlado por lote, atualiza PCLOTE
              IF NVL(vsESTOQUEPORLOTE,'N') = 'S' AND  psNUMLOTE IS NOT NULL THEN
                -- Valida se o lote existe
                P_INTERNO.vtLOTE           := NULL;
                P_INTERNO.vtLOTE.CODFILIAL := psCODFILIAL;
                P_INTERNO.vtLOTE.CODPROD   := pnCODPROD;
                P_INTERNO.vtLOTE.NUMLOTE   := psNUMLOTE;
                PRIV_CONS_LOTE;
                -- Caso não exista o lote
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                -- Bloquear PCLOTE
                PRIV_BLOQUEAR_LOTE;
                -- Validar se conseguiu bloquear a PCLOTE
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 'N';
                END IF;
                P_INTERNO.vtLOTE.QT          := NULL;
                P_INTERNO.vtLOTE.QTEST       := NULL;
                P_INTERNO.vtLOTE.QTRESERV    := NULL;
                P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
                P_INTERNO.vtLOTE.QTBLOQUEADA := pnQTAVARIA;
                P_INTERNO.vtLOTE.QTINDENIZ   := pnQTAVARIA;
                -- Administrar estoque por lote
                PRIV_ATUALIZAR_LOTE;
              END IF;
              -- Validar se conseguiu atualizar o estoque
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            ELSE
              psMSG_RETORNO := 'Erro 11 (Bloqueio Incluir): A quantidade avariada não é valida!'||CHR(13)||
                               'Para este tipo de operação a quantidade avariada é obrigatória!'||CHR(13)||
                               'Qtde. Avariada: '||pnQTAVARIA||CHR(13)||
                               'Operação......: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            -- Inserte movimentação
            END IF;
          -- A filial e o código de oper são obrigatórios
          ELSE
            psMSG_RETORNO := 'Erro 12 (Bloqueio Incluir): A filial ou código de operação não são validos!'||CHR(13)||
                             'Para este tipo de operação a filial e o código de opereção são obrigatórios!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Cód. Oper....: '||psCODOPER||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
        -- Bloqueio manual
        WHEN psOPERACAO IN ('IU') THEN
          -- A filial é obrigatória
          IF psCODFILIAL IS NOT NULL THEN
            -- Bloquear estoque pendente do item
            PRIV_BLOQUEAR_ESTOQUE(psCODFILIAL,pnCODPROD,psMSG_RETORNO);
            -- Validar se conseguiu bloquear o estoque
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Atualizar variáveis
            P_INTERNO.CODDEPOSITO             := pnCODDEPOSITO;
            P_INTERNO.vtESTOQUE               := NULL;
            P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtESTOQUE.CODFILIAL     := psCODFILIAL;
            P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
            P_INTERNO.vtESTOQUE.QTBLOQUEADA   := NVL(pnQTDE,NVL(pnQTAVARIA,0));
            P_INTERNO.vtESTOQUE.QTINDENIZ     := NVL(pnQTAVARIA,0);
            P_INTERNO.NOME_TABELA             := 'USUARIO';
            -- Atualizar estoque bloqueado
            PRIV_ATUALIZAR_ESTOQUE;
            -- Validar se conseguiu atualizar o estoque
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
          -- A filial é obrigatória
          ELSE
            psMSG_RETORNO := 'Erro 13 (Bloqueio Incluir): A filial não é valida!'||CHR(13)||
                             'Para este tipo de operação a filial é obrigatória!'||CHR(13)||
                             'Filial..: '||TO_CHAR(psCODFILIAL)||CHR(13)||
                             'Operação: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
      -- Caso a operação ou identificador não for valido
      ELSE
        psMSG_RETORNO := 'Erro 14 (Bloqueio Incluir): A operação informada não é valida!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Operação.....: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Validação da operação
      END CASE;
    -- Produto não é valido
    ELSE
      psMSG_RETORNO := 'Erro 15 (Bloqueio Incluir): A produto é um parâmetro obrigatorio para esta função. Favor informa-lo corretamente!'||CHR(13)||
                       'Produto.: '||TO_CHAR(pnCODPROD)||CHR(13)||
                       'Operação: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação do produto
    END IF;

    IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S') AND (vsROTINA NOT LIKE '%PCSIS1182%') THEN
      -- Atualizar variáveis
      P_INTERNO.TIPO_OPERACAO := psOPERACAO;
      P_INTERNO.PROCESSO      := 'BLOQUEAR';
      P_INTERNO.QTBLOQUEADA   := P_INTERNO.vtESTOQUE.QTBLOQUEADA;
      P_INTERNO.QTINDENIZ     := P_INTERNO.vtESTOQUE.QTINDENIZ;
      -- Movimenta estoque do depósito
      PRIV_DEP_INCLUIR;
      -- Valida se movimentação do depósito ficou correta
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
    END IF;

    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_INCLUIR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno será "S - Sim"
    RETURN 'S';
  -- Função
  END BLOQUEIO_INCLUIR;

  /************************************************************************************************************************
   ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  27/02/2018    Fernando Araujo    LOG-1627            Criada a procedure para deixar item 16 da 504 na PKG_ESTOQUE
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_INCLUIR_LOTE (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                 ,psCODFILIAL     IN PCMOV.CODFILIAL%TYPE
                                 ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                                 ,psNUMLOTE       IN PCMOV.NUMLOTE%TYPE
                                 ,pnNUMSEQ        IN PCMOV.NUMSEQ%TYPE
                                 ,pnNUMDIAS       IN NUMBER
                                 ,pnQTDE          IN PCMOV.QT%TYPE
                                 ,pnQTAVARIA      IN PCMOV.QTAVARIA%TYPE
                                 ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                 ,psCODOPER       IN PCMOV.CODOPER%TYPE DEFAULT NULL
                                 ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Próximo número para o erro:
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - BLOQUEIO_INCLUIR_LOTE';
    P_INTERNO.NOME_FUNCAO     := 'BLOQUEIO_INCLUIR_LOTE';
    P_INTERNO.CODFILIAL       := psCODFILIAL;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    -- Inserindo informações de debug
    PRIV_GERARLOG;
    -- Lista de Lotes para bloqueio por validade
    FOR CONSLOTE IN (SELECT PCLOTE.CODFILIAL
                           ,PCLOTE.NUMLOTE
                           ,PCLOTE.CODPROD
                           ,PCLOTE.DTVALIDADE
                           ,ESTOQUE_DISPONIVEL_LOTE(PCLOTE.CODFILIAL,PCPRODUT.CODPROD,PCLOTE.NUMLOTE) AS QTDISP
                           ,NVL(PCLOTE.QT,0) AS QT
                           ,NVL(PCLOTE.QTBLOQUEADA,0) AS QTBLOQUEADA
                           ,NVL(PCLOTE.QTINDENIZ,0) AS QTINDENIZ
                           ,NVL(PCLOTE.QTRESERV,0) AS QTRESERV
                       FROM PCLOTE
                           ,PCPRODUT
                      WHERE PCLOTE.DTVALIDADE <= (TRUNC(SYSDATE)+ pnNUMDIAS)
                        AND PCLOTE.CODPROD = PCPRODUT.CODPROD
                        AND PCPRODUT.ESTOQUEPORLOTE = 'S'
                        AND ESTOQUE_DISPONIVEL_LOTE(PCLOTE.CODFILIAL,PCPRODUT.CODPROD,PCLOTE.NUMLOTE) > 0
                        AND PCPRODUT.TIPOMERC IN ('PA','MP','MA','M','L','EM')
                        AND PCLOTE.CODFILIAL = psCODFILIAL
                      UNION
                     SELECT PCLOTE.CODFILIAL
                           ,PCLOTE.NUMLOTE
                           ,PCLOTE.CODPROD
                           ,PCLOTE.DTVALIDADE
                           ,ESTOQUE_DISPONIVEL_LOTE(PCLOTE.CODFILIAL,PCPRODUT.CODPROD,PCLOTE.NUMLOTE) AS QTDISP
                           ,NVL(PCLOTE.QT,0) AS QT
                           ,NVL(PCLOTE.QTBLOQUEADA,0) AS QTBLOQUEADA
                           ,NVL(PCLOTE.QTINDENIZ,0) AS QTINDENIZ
                           ,NVL(PCLOTE.QTRESERV,0) AS QTRESERV
                       FROM PCLOTE, PCPRODUT
                      WHERE PCLOTE.DTVALIDADE <= TRUNC(SYSDATE)
                        AND PCLOTE.CODPROD=PCPRODUT.CODPROD
                        AND PCLOTE.QT > 0
                        AND PCLOTE.CODFILIAL = psCODFILIAL
                        AND PCPRODUT.TIPOMERC IN ('PA', 'MP'))
    LOOP
      -- Altera quantidade bloqueada a partir do código do produto e lote na PCLOTE
      UPDATE PCLOTE
         SET QTBLOQUEADA = (NVL(QTBLOQUEADA,0) + CONSLOTE.QTDISP)
            ,OBSBLOQUEIO = 'QUARENTENA VENCIMENTO EM '||pnNUMDIAS||' DIAS.'
            ,DTBLOQUEIO1 = SYSDATE
       WHERE NUMLOTE = CONSLOTE.NUMLOTE
         AND CODPROD = CONSLOTE.CODPROD
         AND CODFILIAL = CONSLOTE.CODFILIAL;
      -- Altera quantidade bloqueada na PCEST
      UPDATE PCEST
         SET QTBLOQUEADA = GREATEST((NVL(QTBLOQUEADA,0) + CONSLOTE.QTDISP), 0)
            ,PCEST.DTHORAULTALTDISP = SYSDATE
       WHERE CODPROD = CONSLOTE.CODPROD
         AND CODFILIAL = CONSLOTE.CODFILIAL;
      -- Inserindo log
      IF CONSLOTE.QTDISP > 0 THEN
        -- Gera log de DESBLOQUEIO
        P_INTERNO.CODPROD         := CONSLOTE.CODPROD;
        P_INTERNO.NUMLOTE         := CONSLOTE.NUMLOTE;
        P_INTERNO.DTGERACAO       := TRUNC(SYSDATE);
        P_INTERNO.QTDE_DISPONIVEL := CONSLOTE.QTDISP;
        P_INTERNO.QTBLOQUEADA     := CONSLOTE.QTBLOQUEADA;
        P_INTERNO.INFORMACOES_LOG := 'QUARENTENA VENCIMENTO EM '||pnNUMDIAS||' DIAS PELA ROTINA 504';
        PRIV_GERARLOGBLOQUEIO;
        psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
      -- Insert PCLOGDESBLOQUEIO
      END IF;
    -- Lista de produtos
    END LOOP;
    -- Inserindo informações de debug
    P_INTERNO.INFORMACOES_LOG     := 'Finalizou a função - BLOQUEIO_INCLUIR_LOTE';
    PRIV_GERARLOG;
    -- Retorno
    RETURN 'S';
    -- Inserindo informações de debug
    PRIV_GERARLOG;
  -- Função
  END BLOQUEIO_INCLUIR_LOTE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função incluir o estoque pendente através de um pedido
  ************************************************************************************************************************/
  FUNCTION BLOQUEIO_INCLUIR_PEDIDO (pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                   ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                   ,psCODOPER       IN PCMOV.CODOPER%TYPE DEFAULT NULL
                                   ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vbINCLUIU  VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.LISTA_VALIDA    := 'N';
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - BLOQUEIO_INCLUIR_PEDIDO';
    P_INTERNO.NOME_FUNCAO     := 'BLOQUEIO_INCLUIR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    CASE
      -- Pedido de venda
      WHEN (psOPERACAO IN ('IN','AQ') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT PCPEDI.QT
                            ,PCPEDI.CODPROD
                            ,PCPEDI.NUMSEQ
                            ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL) CODFILIAL
                            ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                        FROM PCPEDI, PCPEDC
                       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                         AND PCPEDI.NUMPED = pnIDENTIFICADOR)
                         --AND NVL(PCPEDI.QT,0) > 0)
        LOOP
          -- Atualizando variável
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Incluir Bloqueio
          vbINCLUIU := BLOQUEIO_INCLUIR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QT,0,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 1 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
      -- Order de produção (Idustria)
      WHEN (psOPERACAO IN ('II','AI') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL) CODFILIAL
                            ,PCMOV.QTBLOQUEADA
                            ,PCMOV.QTAVARIA
                            ,PCMOV.CODPROD
                            ,PCMOV.NUMSEQ
                            ,PCMOV.NUMLOTE
                        FROM PCMOV
                       WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                         AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0)
        LOOP
          -- Atualizando variável
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Incluir Bloqueio
          vbINCLUIU := BLOQUEIO_INCLUIR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QTBLOQUEADA,DADOS.QTAVARIA,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 2 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
      -- Cancelamento de bonus
      WHEN (psOPERACAO IN ('CB','AB') AND NVL(pnIDENTIFICADOR,0) > 0) THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT PCBONUSC.CODFILIAL
                            ,PCBONUSI.CODPROD
                            ,NVL(PCBONUSI.QTENTRADA,0) AS QTBLOQUEADA
                            ,NVL(PCBONUSI.QTAVARIA,0) AS QTAVARIA
                            ,PCBONUSI.NUMSEQ
                            ,PCBONUSI.CODMOTIVO
                        FROM PCBONUSI
                            ,PCBONUSC
                       WHERE PCBONUSI.NUMBONUS = PCBONUSC.NUMBONUS
                         AND PCBONUSI.NUMBONUS = pnIDENTIFICADOR)
        LOOP
          -- Atualizando variável
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Incluir Bloqueio
          vbINCLUIU := BLOQUEIO_INCLUIR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QTBLOQUEADA,DADOS.QTAVARIA,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 3 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
      -- Entradas
      WHEN psOPERACAO IN ('IE','AE') THEN
        -- Lista de produtos
        FOR DADOS IN (SELECT NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL) CODFILIAL
                            ,PCMOV.QTBLOQUEADA
                            ,PCMOV.QTAVARIA
                            ,PCMOV.CODPROD
                            ,PCMOV.NUMSEQ
                        FROM PCMOV
                       WHERE PCMOV.NUMTRANSENT = pnIDENTIFICADOR
                         AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0)
        LOOP
          -- Atualizando variável
          P_INTERNO.LISTA_VALIDA := 'S';
          -- Incluir Bloqueio
          vbINCLUIU := BLOQUEIO_INCLUIR (pnIDENTIFICADOR,DADOS.CODFILIAL,DADOS.CODPROD,DADOS.NUMSEQ,DADOS.QTBLOQUEADA,DADOS.QTAVARIA,psOPERACAO,psCODOPER,NULL,NULL,NULL,psMSG_RETORNO);
        -- Lista de produtos
        END LOOP;
        -- Validar lista
        IF P_INTERNO.LISTA_VALIDA = 'N' THEN
          psMSG_RETORNO := 'Erro 4 (Bloqueio Incluir Pedido): Não encontramos dados para o identificador informado!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação lista
        END IF;
    -- Caso a operação ou identificador não for valido
    ELSE
      psMSG_RETORNO := 'Erro 5 (Bloqueio Incluir Pedido): A operação ou o identificador informado não são validos para manipular a quantidade bloqueada/avariada!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da operação
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - BLOQUEIO_INCLUIR_PEDIDO';
    PRIV_GERARLOG;
    -- Atualizar o retorno da função
    RETURN vbINCLUIU;
  -- Função
  END BLOQUEIO_INCLUIR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_ENTRADA_PROD (pnNUMTRANSACAO            IN PCMOV.NUMTRANSENT%TYPE
                                ,pnCODPROD                 IN PCMOV.CODPROD%TYPE
                                ,psAPENAS_QTEST_QTESTGER   IN VARCHAR2
                                ,psECANCELAMENTO           IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                ,psMSG_RETORNO             OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS       NUMBER                   := 0;
    vnESTOQUE_QTEST           PCEST.QTEST%TYPE         := 0;
    vnESTOQUE_QTESTGER        PCEST.QTESTGER%TYPE      := 0;
    vnESTOQUE_QTINDENIZ       PCEST.QTINDENIZ%TYPE     := 0;
    vnESTOQUE_QTBLOQUEADA     PCEST.QTBLOQUEADA%TYPE   := 0;
    vnESTOQUE_QTPEDIDA        PCEST.QTPEDIDA%TYPE      := 0;
    vnESTOQUE_DISPONIVEL      PCEST.QTRESERV%TYPE      := 0;
    vnESTOQUE_TRANSITO        PCEST.QTTRANSITO%TYPE    := 0;
    vnESTOQUE_QTULTENT        PCEST.QTULTENT%TYPE      := 0;
    vnQTULTENTRADA_ANT        PCEST.QTULTENT%TYPE      := 0;
    vnQTULTENTRADA            PCEST.QTULTENT%TYPE      := 0;
    vsBLOQUEIAESTOQUE         VARCHAR2(1);
    vnCODPROD_ANT             PCEST.CODPROD%TYPE;
    vnESTOQUE_CROSSDOCK       PCEST.QTCROSSDOCK%TYPE; -- DDMEDICA-1400
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    P_INTERNO.vtESTOQUE_DEPOSITO.QTBLOQUEADA   := 0;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO                   := 'OK';
    P_INTERNO.INFORMACOES_LOG       := 'Iniciou a função - COMPRAS_ENTRADA_PROD';
    P_INTERNO.NOME_FUNCAO           := 'COMPRAS_ENTRADA_PROD';
    P_INTERNO.IDENTIFICADOR         := pnNUMTRANSACAO;
    P_INTERNO.NUMTRANSENT           := pnNUMTRANSACAO;
    P_INTERNO.CODPROD               := pnCODPROD;
    P_INTERNO.CANCELAMENTO          := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO           := psMSG_RETORNO;
    PRIV_GERARLOG;
    --Atribuindo valor inicial -1 para comparação com o produto atual.
    vnCODPROD_ANT       := -1;
    vnQTULTENTRADA_ANT  := 0;
    vnCONTADORREGISTROS := 0;
    --
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Compras Entrada Prod): O numtransação informado não é valido'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    -- Lista de produtos para analise
    FOR REGISTROS IN (WITH MOVIMENTACAO AS
                        (SELECT PCMOV.ROWID LINHAID,
                                PCMOV.CODPROD,
                                NVL(PCNFENT.TIPODESCARGA, 'X') TIPODESCARGA,
                                NVL(PCNFENT.MOVESTOQUEIMPORT, 'N') MOVESTOQUEIMPORT,
                               (CASE
                                  WHEN ((NVL(PCNFENT.TIPODESCARGA, 'X') = '1') OR
                                       ((NVL(PCNFENT.TIPODESCARGA, 'X') = 'R') AND
                                       (NVL((SELECT TIPODESCARGA 
                                               FROM PCNFENT E 
                                              WHERE NUMTRANSENT IN(SELECT NUMTRANSENT 
                                                                     FROM PCDEVFORNEC 
                                                                    WHERE NUMTRANSVENDA = PCNFENT.NUMTRANSVENDAORIG)
												AND ROWNUM = 1
                                             ), 'X') <> 'H')) OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'S') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'A') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = '5') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'J') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'B') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'I')) AND
                                       ((NVL(PCMOV.STATUS, 'X') = 'AB') OR
                                       (NVL(PCMOV.STATUS, 'X') = 'B')) THEN
                                   'S'
                                  ELSE
                                   'N'
                                END) MOVESTOQUEGERENCIAL,
                               (CASE
                                  WHEN ((NVL(PCNFENT.TIPODESCARGA, 'X') = '1') OR
                                       ((NVL(PCNFENT.TIPODESCARGA, 'X') = 'R') AND
                                       (NVL((SELECT TIPODESCARGA 
                                               FROM PCNFENT E 
                                              WHERE NUMTRANSENT IN(SELECT NUMTRANSENT 
                                                                     FROM PCDEVFORNEC 
                                                                    WHERE NUMTRANSVENDA = PCNFENT.NUMTRANSVENDAORIG)
												AND ROWNUM = 1
                                             ), 'X') <> 'H')) Or
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'S') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'A') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = '5') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'J') OR
                                       ((NVL(PCNFENT.TIPODESCARGA, 'X') = '2') AND
                                       (NVL(PCNFENT.NFENTREGAFUTURA, 'N') = 'N')) OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = '4') OR
                                       (NVL(PCNFENT.TIPODESCARGA, 'X') = 'B') OR
                                       ((NVL(PCNFENT.TIPODESCARGA, 'X') = 'I') AND
                                       (NVL(PCNFENT.MOVESTOQUEIMPORT, 'N') = 'I') AND
                                       (NVL(PCNFENT.ATUALIZOUCUSTOCONT, 'N') = 'N')) OR
                                       ((NVL(PCNFENT.TIPODESCARGA, 'X') = 'N') AND
                                       ((NVL(PCNFENT.ATUALIZOUCUSTOCONT,'N') = 'S') OR
                                       (NVL(PCNFENT.ATUALIZOUCUSTOCONT,'N') = 'N') AND
                                       (NVL(PCNFENT.MOVESTOQUEIMPORT, 'N') = 'N')))) AND
                                       ((NVL(PCMOV.STATUS, 'X') = 'AB') OR
                                       (NVL(PCMOV.STATUS, 'X') = 'A')) THEN
                                   'S'
                                  ELSE
                                   'N'
                                END) MOVESTOQUECONTABIL,
                                NVL(PCNFENT.CROSSDOCKING,'N') CROSSDOCKING,
                                PCNFENT.CODFORNEC,
                                PCNFENT.CGCFILIAL AS CNPJ
                           FROM PCNFENT, PCMOV, PCCONSUM
                          WHERE PCNFENT.NUMTRANSENT = PCMOV.NUMTRANSENT
                            AND ((PCNFENT.CODCONT = NVL(PCNFENT.CODCONTFOR,PCCONSUM.CODCONTFOR)) OR
                                 (PCNFENT.CODCONT = PCCONSUM.CODCONTAJUSTEEST AND PCNFENT.TIPODESCARGA = '4') OR
                                 (PCNFENT.TIPODESCARGA = 'S' AND ((PCNFENT.ESPECIE = 'NF') OR (PCNFENT.ESPECIE = 'NE'))))
                            AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0
                            AND PCMOV.NUMTRANSENT = pnNUMTRANSACAO)
                         /* Listando os produtos e seu estoque */
                         SELECT PCMOV.ROWID NOTA_ROWID,
                                PCEST.CODPROD,
                                PCEST.CODFILIAL,
                                PCMOV.CODOPER,
                                PCMOV.DESCRICAO,
                                PCMOV.STATUS,
                                DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) NOTA_QT,
                                CASE
                                  WHEN ((MOVIMENTACAO.TIPODESCARGA = 'I') AND
                                       (NVL(MOVIMENTACAO.MOVESTOQUEIMPORT,'N') = 'I')) THEN
                                    NVL(PCMOV.QT, 0)
                                ELSE
                                  NVL(PCMOV.QTCONT, 0)
                                END NOTA_QTCONT,
                                NVL(PCMOV.QTAVARIA, 0) NOTA_QTAVARIA,
                                NVL(PCMOV.QTBLOQUEADA, 0) NOTA_QTBLOQUEADA,
                                CASE
                                  WHEN (MOVIMENTACAO.MOVESTOQUEGERENCIAL = 'S')
                                       AND ((PCMOV.CODOPER <> 'EB')
                                       OR  (PCMOV.CODOPER = 'EB' AND NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('ALIMENTAQTULTENTENTRADABONIFICADA'), 'N') = 'S'))
                                  THEN
                                    CASE
                                      WHEN (PCMOV.CODOPER <> 'ET') THEN
                                       'S'
                                      WHEN (PCMOV.CODOPER = 'ET' AND
                                           (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_ATUALIZACUSTOULTENTRANSF',
                                                                               NVL(PCMOV.CODFILIALNF,
                                                                                   PCMOV.CODFILIAL)),
                                                 'N') = 'S') AND
                                           (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ATUALIZACUSTOULTENTRANSF'),
                                                 'N') = 'S')) THEN
                                       'S'
                                    ELSE
                                     'N'
                                    END
                                ELSE
                                  'N'
                                END ATUALIZA_QTULTENT,
                                DECODE(NVL(PCMOV.NUMPED, 0),0,0,DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0))) NOTA_QTPEDIDA,
                                MOVIMENTACAO.MOVESTOQUEGERENCIAL,
                                MOVIMENTACAO.MOVESTOQUECONTABIL,
                                MOVIMENTACAO.TIPODESCARGA,
                                MOVIMENTACAO.MOVESTOQUEIMPORT,
                                NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') AUTOSERVICO,
                                NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC,
                                NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'),'N') BLOQESTOQUETRANSF,
                                NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_BLOQESTOQUETRANSF',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') BLOQESTOQUETRANSF_FIL,
                                NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') ACEITAVENDABALCAOESTNEG,
                                PCMOV.CODDEPOSITO,
                                MOVIMENTACAO.CROSSDOCKING,
                                PCMOV.DATAESTOQUE,
                                PCMOV.DTMOV,
                                PCMOV.CODFISCAL,
                                PCMOV.NUMTRANSENT,
                                MOVIMENTACAO.CODFORNEC,
                                MOVIMENTACAO.CNPJ,
                                PCMOV.NUMBONUS,
                                PCMOV.NUMLOTE
                           FROM PCMOV
                               ,PCEST
                               ,MOVIMENTACAO
                          WHERE PCMOV.CODPROD = PCEST.CODPROD
                            AND PCMOV.ROWID = MOVIMENTACAO.LINHAID
                            AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = PCEST.CODFILIAL
                            AND (NVL(PCMOV.QT,0) + NVL(PCMOV.QTCONT,0)) > 0
                            AND PCMOV.NUMTRANSENT = pnNUMTRANSACAO
                            AND (NVL(pnCODPROD, 0) = 0 OR PCMOV.CODPROD = pnCODPROD)
                       ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (Compras Entrada Prod):A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (Compras Entrada Prod): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;
      --Validando estoque bloqueado
      IF (psECANCELAMENTO = 'S') AND (
       (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',REGISTROS.CODFILIAL),'N') = 'N') OR
     (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_VALIDARESTOQUEAUTOSERVICO'),'N') = 'S'))
    THEN
        PRIV_VALIDA_EST_DISPONIVEL_DEV(REGISTROS.CODPROD, REGISTROS.CODFILIAL, REGISTROS.NOTA_QTBLOQUEADA, REGISTROS.NOTA_QTAVARIA, REGISTROS.NUMBONUS, REGISTROS.NUMLOTE);
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO         := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG       := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL             := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD               := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Validando quantidade informada
      IF (REGISTROS.NOTA_QT <= 0) THEN
        psMSG_RETORNO         := 'Erro 4 (Compras Entrada Prod): Quantidade declarada na transação e menor/igual a zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      -- Validando quantidade bloqueada informada
      ELSIF (REGISTROS.NOTA_QTBLOQUEADA < 0 AND NVL(psAPENAS_QTEST_QTESTGER, 'N') = 'N') THEN
        psMSG_RETORNO         := 'Erro 5 (Compras Entrada Prod): Quantidade bloqueada declarada na transação e menor que zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      -- Validando quantidade indenizada informada
      ELSIF (REGISTROS.NOTA_QTAVARIA < 0 AND NVL(psAPENAS_QTEST_QTESTGER, 'N') = 'N') THEN
        psMSG_RETORNO         := 'Erro 6 (Compras Entrada Prod): Quantidade avariada declarada na transação e menor que zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      ELSE
      -- Atualizando a variavel
        vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      END IF;
      -- Buscando quantidades do estoque atual
      SELECT NVL(PCEST.QTEST, 0) ESTOQUE_QTEST
            ,NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
            ,NVL(PCEST.QTPEDIDA, 0) ESTOQUE_QTPEDIDA
            ,NVL(PCEST.QTULTENT, 0) ESTOQUE_QTULTENT
            ,(NVL(PCEST.QTESTGER, 0) - NVL(PCEST.QTRESERV, 0)) ESTOQUE_DISPONIVEL
            ,NVL(PCEST.QTTRANSITO, 0) ESTOQUE_QTTRANSITO
            ,NVL(PCEST.QTCROSSDOCK,0) ESTOQUE_CROSSDOCK
        INTO vnESTOQUE_QTEST
            ,vnESTOQUE_QTESTGER
            ,vnESTOQUE_QTPEDIDA
            ,vnESTOQUE_QTULTENT
            ,vnESTOQUE_DISPONIVEL
            ,vnESTOQUE_TRANSITO
            ,vnESTOQUE_CROSSDOCK
        FROM PCEST
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      -- Atualizar Qtde da ultima entrada?
      IF (REGISTROS.ATUALIZA_QTULTENT = 'S' AND psECANCELAMENTO = 'N') THEN
        -- O produto mudou?
        IF vnCODPROD_ANT <> REGISTROS.CODPROD THEN
          vnQTULTENTRADA     := REGISTROS.NOTA_QT;
          vnQTULTENTRADA_ANT := 0;
        -- O produto ainda não mudou!
        ELSE
          vnQTULTENTRADA := (REGISTROS.NOTA_QT + vnQTULTENTRADA_ANT);
        END IF;
      ELSE
        vnQTULTENTRADA := vnESTOQUE_QTULTENT;
      -- Validação da Qtde da ultima entrada
      END IF;
      -- Não é nota fiscal de importação?
      IF (REGISTROS.TIPODESCARGA <> 'N') THEN
        -- Caso seja cancelamento e movimente apenas gerencial
        IF ((psECANCELAMENTO = 'S') AND (REGISTROS.MOVESTOQUEGERENCIAL = 'S')) THEN
          -- Atualizando variavel
          vsBLOQUEIAESTOQUE := 'S';
          -- Caso exista quantidade bloqueada na NF
          vnESTOQUE_QTBLOQUEADA := REGISTROS.NOTA_QTBLOQUEADA;
          vnESTOQUE_QTINDENIZ   := REGISTROS.NOTA_QTAVARIA;
          -- Validando se a filial vende sem estoque
          IF ((REGISTROS.ACEITAVENDABALCAOESTNEG = 'N') OR (REGISTROS.AUTOSERVICO = 'N')) THEN
            IF ((vnESTOQUE_QTINDENIZ > vnESTOQUE_QTBLOQUEADA) OR (vnESTOQUE_QTINDENIZ < 0)) THEN
               vnESTOQUE_QTINDENIZ := GREATEST(LEAST(vnESTOQUE_QTBLOQUEADA, vnESTOQUE_QTINDENIZ), 0);
            END IF;
          -- Caso não aceite venda sem estoque
          ELSE
            IF (vnESTOQUE_QTINDENIZ > vnESTOQUE_QTBLOQUEADA) THEN
               vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTINDENIZ, 0);
            END IF;
          END IF;
          -- Tem estoque disponível?
          IF ((vnESTOQUE_DISPONIVEL < REGISTROS.NOTA_QT) AND
              ((REGISTROS.ACEITAVENDABALCAOESTNEG = 'N') OR
               (REGISTROS.AUTOSERVICO = 'N'))) THEN
             psMSG_RETORNO := 'Erro 7 (Compras Entrada Prod): Quantidade disponível insuficiente para cancelamento de estoque.'||CHR(13)||
                              'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO||CHR(13)||
                              'Qtde disponível: '||TO_CHAR(vnESTOQUE_DISPONIVEL - vnESTOQUE_QTINDENIZ)||' - Qtde Nota: '||TO_CHAR(REGISTROS.NOTA_QT)||' = '||TO_CHAR(vnESTOQUE_DISPONIVEL - vnESTOQUE_QTINDENIZ - REGISTROS.NOTA_QT);
            PRIV_GERARLOG;
            RETURN vnCONTADORREGISTROS;
          END IF;
        -- Caso não seja cancelamento e movimente estoque gerencial
        ELSIF ((psECANCELAMENTO = 'N') AND (REGISTROS.MOVESTOQUEGERENCIAL = 'S')) THEN
          -- Atualizando variavel
          vsBLOQUEIAESTOQUE := 'N';
          -- Libera o estoque na entrada?
          IF (REGISTROS.CODOPER <> 'ET' AND ((REGISTROS.LIBERAESTENTMERC = 'N') OR (REGISTROS.NOTA_QTBLOQUEADA > 0))) OR
             (vsROTINA LIKE '%1124%' AND (REGISTROS.NOTA_QTBLOQUEADA > 0)) THEN
            vsBLOQUEIAESTOQUE := 'S';
          -- É transferencia!
          ELSE
            IF (REGISTROS.BLOQESTOQUETRANSF = 'S') AND
               (REGISTROS.CODOPER = 'ET') AND
               (REGISTROS.BLOQESTOQUETRANSF_FIL = 'S') THEN
              vsBLOQUEIAESTOQUE := 'S';
            END IF;
          -- Validação de transferencia
          END IF;
          -- Bloqueia o estoque?
          IF vsBLOQUEIAESTOQUE = 'S' THEN
            -- Se bloqueia igual sim o campo QTBLOQUEADA deve conter valor
            IF REGISTROS.NOTA_QTBLOQUEADA = 0 THEN
              UPDATE PCMOV
                 SET QTBLOQUEADA = REGISTROS.NOTA_QT
               WHERE ROWID = REGISTROS.NOTA_ROWID;
            END IF;
            -- Atualizar variável de bloqueio com valor correto
            vnESTOQUE_QTINDENIZ   := REGISTROS.NOTA_QTAVARIA;
            vnESTOQUE_QTBLOQUEADA := CASE
                                       WHEN REGISTROS.NOTA_QTBLOQUEADA = 0 THEN
                                         REGISTROS.NOTA_QT
                                     ELSE
                                       REGISTROS.NOTA_QTBLOQUEADA
                                     END;
		  ELSE 
		    vnESTOQUE_QTBLOQUEADA := 0;
          END IF;
          -- Atualizar quantidade Indenizada
          IF (REGISTROS.NOTA_QTAVARIA > 0 AND REGISTROS.CODOPER = 'ET' AND (vsROTINA LIKE '%1124%' OR vsROTINA LIKE '%1301%')) THEN
            vnESTOQUE_QTINDENIZ := REGISTROS.NOTA_QTAVARIA;
            -- Valida quantidade
            IF (vnESTOQUE_QTINDENIZ > vnESTOQUE_QTBLOQUEADA) THEN
              vnESTOQUE_QTBLOQUEADA := vnESTOQUE_QTINDENIZ;
            END IF;
          -- Indenizada
          END IF;
        -- Validação de cancelada
        END IF;
      -- Validação da NF importação
      END IF;
      -- Caso a NF seja de importação
      IF (REGISTROS.TIPODESCARGA IN ('N', 'I')) THEN
        -- Caso seja nota tipo N
        IF ((REGISTROS.TIPODESCARGA = 'N') AND
            (REGISTROS.MOVESTOQUEIMPORT = 'I')) THEN
          IF (psECANCELAMENTO = 'N') THEN
            vnESTOQUE_TRANSITO := vnESTOQUE_TRANSITO + REGISTROS.NOTA_QTCONT;
          ELSE
            vnESTOQUE_TRANSITO := vnESTOQUE_TRANSITO - REGISTROS.NOTA_QTCONT;
          END IF;
        -- Validação da NF tipo N
        END IF;
        -- Caso seja nota tipo I
        IF ((REGISTROS.TIPODESCARGA = 'I') AND
           (REGISTROS.MOVESTOQUEIMPORT = 'I')) THEN
          IF (psECANCELAMENTO = 'N') THEN
            vnESTOQUE_TRANSITO := vnESTOQUE_TRANSITO - REGISTROS.NOTA_QT;
          ELSE
            vnESTOQUE_TRANSITO := vnESTOQUE_TRANSITO + REGISTROS.NOTA_QT;
          END IF;
        END IF;
      -- Validação de NFs de importação
      END IF;
      -- Caso a NF seja de crossdocking - DDMEDICA-1400
      IF (REGISTROS.CROSSDOCKING = 'S') THEN
        IF (psECANCELAMENTO = 'N') THEN
          vnESTOQUE_CROSSDOCK := vnESTOQUE_CROSSDOCK + REGISTROS.NOTA_QTCONT;
        ELSE
          vnESTOQUE_CROSSDOCK := vnESTOQUE_CROSSDOCK - REGISTROS.NOTA_QTCONT;
        END IF;
      END IF;
      -- Sair do laço caso mensagem diferente de 'OK'
      EXIT WHEN psMSG_RETORNO <> 'OK';
      -- Atualizando o estoque
      UPDATE PCEST
         SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
             PCEST.QTEST = CASE
                             WHEN psECANCELAMENTO = 'N' THEN
                               NVL(PCEST.QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                             ELSE
                               NVL(PCEST.QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                           END,
             PCEST.QTESTGER = CASE
                                WHEN psECANCELAMENTO = 'N' THEN
                                  NVL(PCEST.QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                ELSE
                                  NVL(PCEST.QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                              END,
             PCEST.QTPEDIDA = DECODE(REGISTROS.TIPODESCARGA,'I',PCEST.QTPEDIDA,CASE
                                                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                                                   GREATEST(NVL(PCEST.QTPEDIDA, 0) - REGISTROS.NOTA_QTPEDIDA,0)
                                                                                 ELSE
                                                                                   GREATEST(NVL(PCEST.QTPEDIDA, 0) + REGISTROS.NOTA_QTPEDIDA,0)
                                                                               END),
             PCEST.QTENTDIA = DECODE(REGISTROS.TIPODESCARGA,'N',PCEST.QTENTDIA,CASE
                                                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                                                   NVL(PCEST.QTENTDIA, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                                                                 ELSE
                                                                                   NVL(PCEST.QTENTDIA, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                                                               END),
             PCEST.QTENTMES = DECODE(REGISTROS.TIPODESCARGA,'N',PCEST.QTENTMES,CASE
                                                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                                                   NVL(PCEST.QTENTMES, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                                                                 ELSE
                                                                                   NVL(PCEST.QTENTMES, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT, 0)
                                                                               END)
            ,PCEST.QTTRANSITO = vnESTOQUE_TRANSITO
            ,PCEST.QTULTENT = vnQTULTENTRADA
            ,PCEST.QTBLOQUEADA = GREATEST(CASE
                                   WHEN psECANCELAMENTO = 'N' THEN
                                     GREATEST(NVL(PCEST.QTBLOQUEADA, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',vnESTOQUE_QTBLOQUEADA, 0), DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',vnESTOQUE_QTBLOQUEADA, 0))
                                   ELSE
                                     NVL(PCEST.QTBLOQUEADA, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',vnESTOQUE_QTBLOQUEADA, 0)
                                 END, 0)
            ,PCEST.QTINDENIZ = GREATEST(CASE
                                 WHEN psECANCELAMENTO = 'N' THEN
                                   NVL(PCEST.QTINDENIZ, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',vnESTOQUE_QTINDENIZ, 0)
                                 ELSE
                                   NVL(PCEST.QTINDENIZ, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',vnESTOQUE_QTINDENIZ, 0)
                               END, 0)
            ,PCEST.QTCROSSDOCK = vnESTOQUE_CROSSDOCK
            ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        ELSE
          P_INTERNO.TIPO_OPERACAO := 'I';
        END IF;
        -- Atualizar variáveis para movimentar depósito
        P_INTERNO.PROCESSO         := 'COMPRAR';
        P_INTERNO.CODFILIAL        := REGISTROS.CODFILIAL;
        P_INTERNO.ROWID_REGISTRO   := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER         := REGISTROS.NOTA_QT;
        IF vsBLOQUEIAESTOQUE = 'S' THEN
          P_INTERNO.QTBLOQUEADA      := LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA,REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT);
          P_INTERNO.QTINDENIZ        := GREATEST(LEAST(REGISTROS.NOTA_QTAVARIA, REGISTROS.NOTA_QT),0);
        ELSE
          P_INTERNO.QTBLOQUEADA      := 0;
          P_INTERNO.QTINDENIZ        := 0;
        END IF;

        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
          -- Administrar estoque do depósito
          PRIV_DEP_COMPRAS_ENTRADA;
        END IF;

        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Atualizando a nota fiscal
      IF psECANCELAMENTO = 'N' THEN
        -- Atualizar variáveis
        vnCODPROD_ANT      := REGISTROS.CODPROD;
        vnQTULTENTRADA_ANT := (vnQTULTENTRADA_ANT + REGISTROS.NOTA_QT);
        -- Atualizar PCMOV
        UPDATE PCMOV
           SET PCMOV.QTULTENTANT = vnESTOQUE_QTULTENT,
               PCMOV.QTBLOQUEADA = DECODE(psAPENAS_QTEST_QTESTGER,'S',PCMOV.QTBLOQUEADA,DECODE(vsBLOQUEIAESTOQUE,'S',PCMOV.QTBLOQUEADA,NVL(PCMOV.QTAVARIA, 0))),
               PCMOV.QTESTGERANT = vnESTOQUE_QTESTGER,
               PCMOV.QTESTANT    = vnESTOQUE_QTEST,
               PCMOV.MOVESTOQUEGERENCIAL = REGISTROS.MOVESTOQUEGERENCIAL,
               PCMOV.MOVESTOQUECONTABIL = REGISTROS.MOVESTOQUECONTABIL,
         PCMOV.QTSALDOEST  = CASE
                                       WHEN psECANCELAMENTO = 'N' THEN
                                         NVL(vnESTOQUE_QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                                       ELSE
                                         NVL(vnESTOQUE_QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                                       END,
               PCMOV.QTSALDOESTGER = CASE
                                       WHEN psECANCELAMENTO = 'N' THEN
                                         NVL(vnESTOQUE_QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                       ELSE
                                         NVL(vnESTOQUE_QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                       END
         WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque*/
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
      -- Movimentar o estoque de terceiro caso seja entrada de transferência de venda TV-10.
      PRIV_COMPRAS_TERCEIRO (REGISTROS.CODPROD
                            ,psECANCELAMENTO
                            ,REGISTROS.NUMTRANSENT
                            ,REGISTROS.CODFORNEC
                            ,REGISTROS.CNPJ
                            ,REGISTROS.CODFISCAL
                            ,REGISTROS.NOTA_QT
                            ,REGISTROS.CODFILIAL);

      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
    -- Lista de produtos
    END LOOP;
    -- Marcar no cabeçalho a utilização da package
    IF vnContadorRegistros > 0 THEN
      IF (psECANCELAMENTO = 'S') THEN
      UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
    ELSE
      UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'N'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
    END IF;
    -- Validando se tem registros
    ELSIF vnCONTADORREGISTROS = 0 THEN
      UPDATE PCNFENT
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSENT = pnNUMTRANSACAO;
      psMSG_RETORNO := 'Erro 8 (Compras Entrada Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||' - '||SQLERRM||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_ENTRADA_PROD';
    PRIV_GERARLOG;
    -- Retorno da função
    RETURN vnCONTADORREGISTROS;
  -- Função
  EXCEPTION
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_ENTRADA_PROD com erro' ||' - '||SQLERRM;
      PRIV_GERARLOG;
      RETURN 0;
  END COMPRAS_ENTRADA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_ENTRADA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSENT%TYPE
                           ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                           ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    CURSOR BLOQUEIA_ESTOQUE_TRNASACAO
    IS
     SELECT distinct CODPROD, CODFILIAL FROM PCMOV WHERE NUMTRANSENT = pnNUMTRANSACAO ORDER BY CODPROD;

    vnTENTATIVA NUMBER := 0;
    vnRETORNO   NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Iniciando a variável de retorno
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - COMPRAS_ENTRADA';
    P_INTERNO.NOME_FUNCAO     := 'COMPRAS_ENTRADA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;

  FOR REGISTROS IN BLOQUEIA_ESTOQUE_TRNASACAO
    LOOP
      WHILE (vnTENTATIVA < 5) LOOP
        BEGIN
          SELECT CODPROD
            INTO vnTENTATIVA
            FROM PCEST
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIAL
             FOR UPDATE;
          vnTENTATIVA := 5;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 - COMPRAS_ENTRADA: Verifique os dados informados!'||CHR(13)||
                             '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                             '2 - Os dados informados podem não ser validos!'||CHR(13)||
                             'TRANSAÇÃO: '||pnNUMTRANSACAO||' - '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            vnTENTATIVA := vnTENTATIVA + 1;
        END;
      END LOOP;
      psMSG_RETORNO := 'OK';
      vnTENTATIVA := 0;
    END LOOP;

  IF psMSG_RETORNO = 'OK' THEN
      -- Executa a função por produto
      vnRETORNO := COMPRAS_ENTRADA_PROD(pnNUMTRANSACAO,0,'N',psECANCELAMENTO,psMSG_RETORNO);
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_ENTRADA';
      P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Retornando valores
      RETURN vnRETORNO;
  ELSE
    -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Erro 1 - COMPRAS_ENTRADA: Falha ao bloquear produtos na função';
      P_INTERNO.NOME_FUNCAO     := 'COMPRAS_ENTRADA:';
      PRIV_GERARLOG;
      RETURN 0;
  END IF;
  -- Função
  END COMPRAS_ENTRADA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_ENTRADA_BENEFIC_PROD (pnNUMTRANSACAO  IN PCMOV.NUMTRANSENT%TYPE
                                        ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                        ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Próximo número para o erro:
    vnCONTADORREGISTROS       NUMBER := 0;
    vnESTOQUE_QTEST           PCEST.QTEST%TYPE;
    vnESTOQUE_QTESTGER        PCEST.QTESTGER%TYPE;
    vnESTOQUE_QTINDENIZ       PCEST.QTINDENIZ%TYPE;
    vnESTOQUE_QTBLOQUEADA     PCEST.QTBLOQUEADA%TYPE;
    vnESTOQUE_QTULTENT        PCEST.QTULTENT%TYPE;
    vnESTOQUE_DISPONIVEL      PCEST.QTRESERV%TYPE;
    vnCODPROD_ANT             PCEST.CODPROD%TYPE;
    vnQTULTENTRADA_ANT        PCEST.QTULTENT%TYPE;
    vnQTULTENTRADA            PCEST.QTULTENT%TYPE;
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    --
    P_INTERNO.NOME_FUNCAO := 'COMPRAS_ENTRADA_BENEFIC_PROD';
    psMSG_RETORNO         := 'OK';
    vnCODPROD_ANT         := -1;
    vnQTULTENTRADA_ANT    := 0;
    vnQTULTENTRADA        := 0;
    --
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Compras Entrada Benefic Prod): O numtransação informado não é valido' || CHR(13) || 'Identificador: ' || pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    --
    FOR REGISTROS IN (SELECT PCMOV.CODPROD
                           , PCMOV.CODFILIAL
                           , DECODE(NVL(PCMOV.QTCONT, 0), 0, NVL(PCMOV.QT, 0), NVL(PCMOV.QTCONT, 0)) QT
                           , NVL(PCMOV.QTCONT, 0) QTCONT
                           , NVL(PCMOV.QTAVARIA, 0) QTAVARIA
                           , NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA
                           , NVL(PCMOV.MOVESTOQUEGERENCIAL
                           , (CASE WHEN((PCMOV.CODOPER = 'EG') AND(PCMOV.STATUS = 'AB')) THEN 'S' ELSE 'N' END)) MOVESTOQUEGERENCIAL
                           , NVL(PCMOV.MOVESTOQUECONTABIL
                           , (CASE WHEN((PCMOV.CODOPER = 'EG') AND(PCMOV.STATUS = 'AB')) THEN 'S' ELSE 'N' END)) MOVESTOQUECONTABIL
                           , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO', PCMOV.CODFILIAL), 'N') AUTOSERVICO
                           , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC
                           , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'), 'N') BLOQESTOQUETRANSF
                           , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'), 'N') ACEITAVENDABALCAOESTNEG
                           , PCMOV.CODDEPOSITO
                           , PCMOV.ROWID NOTA_ROWID
                           , PCMOV.DATAESTOQUE
                           , PCMOV.DTMOV
                        FROM PCMOV
                       WHERE PCMOV.DTCANCEL IS NULL
                         AND PCMOV.NUMTRANSENT = pnNUMTRANSACAO
                         AND (((PCMOV.CODOPER = 'EG') AND (PCMOV.STATUS = 'AB')) OR ((PCMOV.CODOPER = 'EV') AND(PCMOV.STATUS = 'A')))
                    ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (COMPRAS_ENTRADA_BENEFIC_PROD): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (COMPRAS_ENTRADA_BENEFIC_PROD): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;
      --
      P_INTERNO.INFORMACOES_LOG     := 'INICIOU A FUNÇÃO - COMPRAS_ENTRADA_BENEFIC';
      P_INTERNO.IDENTIFICADOR       := pnNUMTRANSACAO;
      P_INTERNO.CODFILIAL           := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTROS.MOVESTOQUECONTABIL;
      P_INTERNO.CANCELAMENTO        := psECANCELAMENTO;
      P_INTERNO.MSG_RETORNO         := psMSG_RETORNO;
      PRIV_GERARLOG;
      --
      IF (REGISTROS.QT <= 0) THEN
        psMSG_RETORNO := 'Erro 4 (Compras Entrada Benefic Prod): Quantidade declarada na transação e menor/igual a zero.' || CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD);
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      END IF;
      --
      IF (REGISTROS.QTBLOQUEADA < 0) THEN
        psMSG_RETORNO := 'Erro 5 (Compras Entrada Benefic Prod): Quantidade bloqueada declarada na transação e menor que zero.' || CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD);
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      END IF;
      -- Atualizando a variavel
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      --
      SELECT NVL(PCEST.QTEST, 0) ESTOQUE_QTEST
           , NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
           , GREATEST(GREATEST(NVL(PCEST.QTBLOQUEADA, 0), NVL(PCEST.QTINDENIZ, 0)), 0) ESTOQUE_QTBLOQUEADA
           , GREATEST(NVL(PCEST.QTINDENIZ, 0), 0) ESTOQUE_QTINDENIZ
           , NVL(PCEST.QTULTENT, 0) ESTOQUE_QTULTENT
           , (NVL(PCEST.QTESTGER, 0) - NVL(PCEST.QTRESERV, 0)) ESTOQUE_DISPONIVEL
        INTO vnESTOQUE_QTEST
           , vnESTOQUE_QTESTGER
           , vnESTOQUE_QTBLOQUEADA
           , vnESTOQUE_QTINDENIZ
           , vnESTOQUE_QTULTENT
           , vnESTOQUE_DISPONIVEL
        FROM PCEST
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      --
      IF psECANCELAMENTO = 'N' THEN
        IF vnCODPROD_ANT <> REGISTROS.CODPROD THEN
          vnQTULTENTRADA     := REGISTROS.QT;
          vnQTULTENTRADA_ANT := 0;
        ELSE
          vnQTULTENTRADA     :=(REGISTROS.QT + vnQTULTENTRADA_ANT);
        END IF;
      ELSIF psECANCELAMENTO = 'S' THEN
        vnQTULTENTRADA        := vnESTOQUE_QTULTENT;
      END IF;
      --
      UPDATE PCEST
         SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO
           , PCEST.QTEST = (CASE
                              WHEN psECANCELAMENTO = 'N' THEN
                                NVL(PCEST.QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTCONT, 0)
                            ELSE
                              NVL(PCEST.QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTCONT, 0)
                            END)
           , PCEST.QTESTGER = (CASE
                                 WHEN psECANCELAMENTO = 'N' THEN
                                   NVL(PCEST.QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               ELSE
                                 NVL(PCEST.QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               END)
           , PCEST.QTBLOQUEADA = GREATEST(CASE
                                             WHEN psECANCELAMENTO = 'N' THEN
                                               CASE
                                                 WHEN REGISTROS.LIBERAESTENTMERC = 'N' THEN
                                                   NVL(PCEST.QTBLOQUEADA, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTBLOQUEADA, 0)
                                               ELSE
                                                 PCEST.QTBLOQUEADA
                                               END
                                           ELSE
                                             NVL(PCEST.QTBLOQUEADA, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QTBLOQUEADA, 0)
                                           END, 0)
           , PCEST.QTINDENIZ = LEAST(GREATEST(CASE
                                                WHEN psECANCELAMENTO = 'N' THEN
                                                  CASE
                                                    WHEN REGISTROS.LIBERAESTENTMERC = 'N'THEN
                                                      NVL(PCEST.QTINDENIZ, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTAVARIA, 0)
                                                  ELSE
                                                    PCEST.QTINDENIZ
                                                  END
                                              ELSE
                                                NVL(PCEST.QTINDENIZ, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTAVARIA, 0)
                                              END, 0), PCEST.QTBLOQUEADA)
           , PCEST.QTENTDIA = (CASE
                                 WHEN psECANCELAMENTO = 'N' THEN
                                   NVL(PCEST.QTENTDIA, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               ELSE
                                 NVL(PCEST.QTENTDIA, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               END)
           , PCEST.QTENTMES = (CASE
                                 WHEN psECANCELAMENTO = 'N' THEN
                                   NVL(PCEST.QTENTMES, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               ELSE
                                 NVL(PCEST.QTENTMES, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                               END)
           , PCEST.QTULTENT = vnQTULTENTRADA
           ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        END IF;
        -- Atualizar variáveis para movimentar depósito
        P_INTERNO.PROCESSO         := 'COMPRAR';
        P_INTERNO.CODFILIAL        := REGISTROS.CODFILIAL;
        P_INTERNO.ROWID_REGISTRO   := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER         := REGISTROS.QT;
        P_INTERNO.QTBLOQUEADA      := LEAST(GREATEST(REGISTROS.QTBLOQUEADA,REGISTROS.QTAVARIA),REGISTROS.QT);
        P_INTERNO.QTINDENIZ        := GREATEST(LEAST(REGISTROS.QTAVARIA, REGISTROS.QT),0);
        -- Administrar estoque do depósito
        PRIV_DEP_COMPRAS_ENTRADA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      --
      P_INTERNO.INFORMACOES_LOG     := 'FINALIZOU A FUNÇÃO - COMPRAS_ENTRADA_BENEFIC';
      P_INTERNO.IDENTIFICADOR       := pnNUMTRANSACAO;
      P_INTERNO.CODFILIAL           := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTROS.MOVESTOQUECONTABIL;
      P_INTERNO.CANCELAMENTO        := psECANCELAMENTO;
      P_INTERNO.MSG_RETORNO         := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
     --
    END LOOP;
    -- Validando se tem registros
    IF vnCONTADORREGISTROS = 0 THEN
      psMSG_RETORNO := 'Erro 7 (Compras Entrada Benefic Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    RETURN vnCONTADORREGISTROS;
  -- Função
  END COMPRAS_ENTRADA_BENEFIC_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_ENTRADA_BENEFIC (pnNUMTRANSACAO    IN  PCMOV.NUMTRANSENT%TYPE
                                   ,psECANCELAMENTO   IN  PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                   ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Gerar log
    P_INTERNO.INFORMACOES_LOG      := 'Iniciou a função - COMPRAS_ENTRADA_BENEFIC';
    P_INTERNO.NOME_FUNCAO          := 'COMPRAS_ENTRADA_BENEFIC';
    P_INTERNO.IDENTIFICADOR        := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO         := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO          := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Executar função
    RETURN COMPRAS_ENTRADA_BENEFIC_PROD(pnNUMTRANSACAO, psECANCELAMENTO, psMSG_RETORNO);
    -- Gerar log
    P_INTERNO.INFORMACOES_LOG      := 'Finalizou a função - COMPRAS_ENTRADA_BENEFIC';
    P_INTERNO.MSG_RETORNO          := psMSG_RETORNO;
    PRIV_GERARLOG;
  -- Função
  END COMPRAS_ENTRADA_BENEFIC;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_SAIDA_PROD (pnNUMTRANSACAO            IN PCMOV.NUMTRANSVENDA%TYPE
                              ,pnCODPROD                 IN PCMOV.CODPROD%TYPE
                              ,psAPENAS_QTEST_QTESTGER   IN VARCHAR2
                              ,psECANCELAMENTO           IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                              ,psMSG_RETORNO             OUT VARCHAR2)
  RETURN NUMBER
  IS-- Variaveis do estoque atual
    vnCONTADORREGISTROS       NUMBER                  := 0;
    vnESTOQUE_QTEST           PCEST.QTEST%TYPE        := 0;
    vnESTOQUE_QTESTGER        PCEST.QTESTGER%TYPE     := 0;
    vnESTOQUE_QTINDENIZ       PCEST.QTINDENIZ%TYPE    := 0;
    vnESTOQUE_QTBLOQUEADA     PCEST.QTBLOQUEADA%TYPE  := 0;
    vnESTOQUE_QTRESERV        PCEST.QTRESERV%TYPE     := 0;
    vnESTOQUE_QTULTENT        PCEST.QTULTENT%TYPE     := 0;
    vnCONTADORREGISTROSPCMOV  NUMBER                  := 0;
    vnDTMOVPRIMERIO           DATE;
    VNCODDEV                  NUMBER                  := 0;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO                   := 'OK';
    P_INTERNO.INFORMACOES_LOG       := 'Iniciou a função - COMPRAS_SAIDA_PROD';
    P_INTERNO.NOME_FUNCAO           := 'COMPRAS_SAIDA_PROD';
    P_INTERNO.IDENTIFICADOR         := pnNUMTRANSACAO;
    P_INTERNO.CODPROD               := pnCODPROD;
    P_INTERNO.CANCELAMENTO          := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO           := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Buscando nome da rotina que esta usando o processo
    vsROTINA := SUBSTR(SYS_CONTEXT('USERENV', 'MODULE'),0, 33);
    --
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Compras Saida Prod): O numtransação informado não é valido'||CHR(13)||
                       'Identificador: '||pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    --  Lista de produtos
    FOR REGISTROS IN (WITH MOVIMENTACAO AS
                         (SELECT PCMOV.ROWID LINHAID,
                                (CASE
                                  WHEN ((NVL(PCNFSAID.TIPODEVOL, 'X') = '1') OR
                                       (NVL(PCNFSAID.TIPODEVOL, 'X') = '4') OR
                                       (NVL(PCNFSAID.TIPODEVOL, 'X') = '6') OR
                                       (NVL(PCNFSAID.TIPODEVOL, 'X') = '7')) AND
                                       ((NVL(PCMOV.STATUS, 'X') = 'AB') OR
                                       (NVL(PCMOV.STATUS, 'X') = 'B')) THEN
                                    'S'
                                 ELSE
                                   'N'
                                 END) MOVESTOQUEGERENCIAL,
                                (CASE
                                   WHEN ((NVL(PCNFSAID.TIPODEVOL, 'X') = '1') OR
                                        ((NVL(PCNFSAID.TIPODEVOL, 'X') = '2') AND
                                        (NVL(PCNFSAID.NFDEVENTFUTURA, 'N') = 'N')) OR
                                        (NVL(PCNFSAID.TIPODEVOL, 'X') = '4') OR
                                        (NVL(PCNFSAID.TIPODEVOL, 'X') = '6') OR
                                        (NVL(PCNFSAID.TIPODEVOL, 'X') = '7')) AND
                                        ((NVL(PCMOV.STATUS, 'X') = 'AB') OR
                                        (NVL(PCMOV.STATUS, 'X') = 'A')) THEN
                                     'S'
                                 ELSE
                                   'N'
                                 END) MOVESTOQUECONTABIL
                                ,PCMOV.CODDEPOSITO
                            FROM PCNFSAID, PCMOV
                           WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA
                             AND PCMOV.NUMTRANSVENDA = pnNUMTRANSACAO
                             AND PCMOV.DTCANCEL IS NULL
                             AND PCNFSAID.TIPODEVOL > 0)
                          SELECT PCMOV.ROWID NOTA_ROWID,
                                 PCEST.CODPROD,
                                 PCEST.CODFILIAL,
                                 PCMOV.CODOPER,
                                 PCMOV.DESCRICAO,
                                 PCMOV.STATUS,
                                 DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) NOTA_QT,
                                 NVL(PCMOV.QTCONT, 0) NOTA_QTCONT,
                                 NVL(PCMOV.QTAVARIA, 0) NOTA_QTAVARIA,
                                 NVL(PCMOV.QTBLOQUEADA, 0) NOTA_QTBLOQUEADA,
                                 CASE
                                   WHEN MOVIMENTACAO.MOVESTOQUEGERENCIAL = 'S' AND
                                        PCMOV.CODOPER <> 'SB' THEN
                                     DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0))
                                 ELSE
                                   NVL(PCEST.QTULTENT, 0)
                                 END NOTA_QTULTENTRADA,
                                 MOVIMENTACAO.MOVESTOQUEGERENCIAL,
                                 MOVIMENTACAO.MOVESTOQUECONTABIL
                                ,MOVIMENTACAO.CODDEPOSITO
                                ,PCMOV.DATAESTOQUE
                                ,PCMOV.DTMOV
                                ,PCMOV.NUMLOTE
                ,PCMOV.NUMBONUS
                            FROM PCMOV, PCEST, MOVIMENTACAO
                           WHERE PCMOV.CODPROD = PCEST.CODPROD
                             AND PCMOV.NUMTRANSVENDA = pnNUMTRANSACAO
                             AND (NVL(pnCODPROD, 0) = 0 OR PCMOV.CODPROD = pnCODPROD)
                             AND PCMOV.ROWID = MOVIMENTACAO.LINHAID
                             AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = PCEST.CODFILIAL
                             AND PCMOV.DTCANCEL IS NULL
                        ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (COMPRAS_SAIDA_PROD): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (COMPRAS_SAIDA_PROD): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;

    -- validando estoque bloqueado
      IF (psECANCELAMENTO = 'N') AND (
       (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',REGISTROS.CODFILIAL),'N') = 'N') OR
     (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_VALIDARESTOQUEAUTOSERVICO'),'N') = 'S'))
    THEN
        PRIV_VALIDA_EST_DISPONIVEL_DEV(REGISTROS.CODPROD, REGISTROS.CODFILIAL, REGISTROS.NOTA_QTBLOQUEADA, REGISTROS.NOTA_QTAVARIA, REGISTROS.NUMBONUS, REGISTROS.NUMLOTE);
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO         := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      END IF;
      -- Inserindo informações de debug (LOG)
      IF vnCONTADORREGISTROS = 0 THEN
        P_INTERNO.INFORMACOES_LOG       := 'Executando a lista de produtos';
        P_INTERNO.CODFILIAL             := REGISTROS.CODFILIAL;
        P_INTERNO.CODPROD               := REGISTROS.CODPROD;
        P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
        P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
        PRIV_GERARLOG;
      -- Gera log
      END IF;
      -- Validando quantidade informada
      IF (REGISTROS.NOTA_QT <= 0) THEN
        psMSG_RETORNO         := 'Erro 4 (Compras Saida Prod): Quantidade declarada na transação e menor/igual a zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      -- Validando quantidade bloqueada informada
      ELSIF (REGISTROS.NOTA_QTBLOQUEADA < 0 AND
             NVL(psAPENAS_QTEST_QTESTGER, 'N') = 'N') THEN
        psMSG_RETORNO         := 'Erro 5 (Compras Saida Prod): Quantidade bloqueada declarada na transação e menor que zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      -- Validando quantidade indenizada informada
      ELSIF (REGISTROS.NOTA_QTAVARIA < 0 AND
             NVL(psAPENAS_QTEST_QTESTGER, 'N') = 'N') THEN
        psMSG_RETORNO         := 'Erro 6 (Compras Saida Prod): Quantidade avariada declarada na transação e menor que zero.'||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' - '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      ELSE
      -- Atualizando a variavel
        vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      END IF;
      -- Carregando campos estoque
      SELECT NVL(PCEST.QTEST, 0) ESTOQUE_QTEST
            ,NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
            ,GREATEST(GREATEST(NVL(PCEST.QTBLOQUEADA, 0),NVL(PCEST.QTINDENIZ, 0)), 0) ESTOQUE_QTBLOQUEADA
            ,GREATEST(NVL(PCEST.QTINDENIZ, 0), 0) ESTOQUE_QTINDENIZ
            ,NVL(PCEST.QTRESERV, 0) ESTOQUE_QTRESERV --Pedida para venda / reservada
            ,NVL(PCEST.QTULTENT, 0) ESTOQUE_QTULTENT --Quantidade da ultima entrada
        INTO vnESTOQUE_QTEST
            ,vnESTOQUE_QTESTGER
            ,vnESTOQUE_QTBLOQUEADA
            ,vnESTOQUE_QTINDENIZ
            ,vnESTOQUE_QTRESERV
            ,vnESTOQUE_QTULTENT
        FROM PCEST
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      -- Calculando estoque bloqueado e indenizado
      IF psECANCELAMENTO = 'N' AND REGISTROS.MOVESTOQUECONTABIL = 'S' THEN
        vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA - LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA,REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT),0);
        vnESTOQUE_QTINDENIZ := LEAST(GREATEST(vnESTOQUE_QTINDENIZ - REGISTROS.NOTA_QTAVARIA,0),vnESTOQUE_QTBLOQUEADA);
      ELSIF psECANCELAMENTO = 'S' AND REGISTROS.MOVESTOQUECONTABIL = 'S' THEN
        vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA + LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA,REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT),0);
        vnESTOQUE_QTINDENIZ := LEAST(GREATEST(vnESTOQUE_QTINDENIZ + REGISTROS.NOTA_QTAVARIA,0),vnESTOQUE_QTBLOQUEADA);
      END IF;
      -- Calculando estoque avariado - Ajustando o estoque avariado
      vnESTOQUE_QTINDENIZ := GREATEST(LEAST(vnESTOQUE_QTINDENIZ,vnESTOQUE_QTBLOQUEADA),0);
      -- Atualizando o estoque
      UPDATE PCEST
         SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
             PCEST.QTEST = CASE
                             WHEN psECANCELAMENTO = 'N' THEN
                               NVL(PCEST.QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S',REGISTROS.NOTA_QTCONT,0)
                           ELSE
                             NVL(PCEST.QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                           END,
             PCEST.QTESTGER = CASE
                                WHEN psECANCELAMENTO = 'N' THEN
                                  NVL(PCEST.QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S', REGISTROS.NOTA_QT,0)
                              ELSE
                                NVL(PCEST.QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                              END,
             PCEST.QTBLOQUEADA = DECODE(psAPENAS_QTEST_QTESTGER,'S',PCEST.QTBLOQUEADA,GREATEST(vnESTOQUE_QTBLOQUEADA, 0)),
             PCEST.QTINDENIZ = DECODE(psAPENAS_QTEST_QTESTGER,'S',PCEST.QTINDENIZ,vnESTOQUE_QTINDENIZ)
            ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      -- Atualizando a nota fiscal
      UPDATE PCMOV
         SET PCMOV.QTESTGERANT = vnESTOQUE_QTESTGER,
             PCMOV.QTESTANT    = vnESTOQUE_QTEST,
             PCMOV.MOVESTOQUEGERENCIAL = REGISTROS.MOVESTOQUEGERENCIAL,
             PCMOV.MOVESTOQUECONTABIL = REGISTROS.MOVESTOQUECONTABIL,
       PCMOV.QTSALDOEST  = CASE
                                       WHEN psECANCELAMENTO = 'S' THEN
                                         NVL(vnESTOQUE_QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                                       ELSE
                                         NVL(vnESTOQUE_QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL,'S',REGISTROS.NOTA_QTCONT,0)
                                       END,
             PCMOV.QTSALDOESTGER = CASE
                                       WHEN psECANCELAMENTO = 'S' THEN
                                         NVL(vnESTOQUE_QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                       ELSE
                                         NVL(vnESTOQUE_QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL,'S',REGISTROS.NOTA_QT,0)
                                       END
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'N' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        ELSE
          P_INTERNO.TIPO_OPERACAO := 'I';
        END IF;
        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN
          -- Atualizar variáveis internas
          P_INTERNO.PROCESSO       := 'COMPRAR';
          P_INTERNO.CODFILIAL      := REGISTROS.CODFILIAL;
          P_INTERNO.ROWID_REGISTRO := REGISTROS.NOTA_ROWID;
          P_INTERNO.CODDEPOSITO    := REGISTROS.CODDEPOSITO;
          P_INTERNO.CODPROD        := REGISTROS.CODPROD;
          P_INTERNO.QTBLOQUEADA    := LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA,REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT);
          P_INTERNO.QTINDENIZ      := GREATEST(LEAST(REGISTROS.NOTA_QTAVARIA, REGISTROS.NOTA_QT),0);
          P_INTERNO.QTESTGER       := REGISTROS.NOTA_QT;

          -- Administrar estoque do depósito
          IF REGISTROS.CODOPER = 'SD' THEN
            BEGIN
              SELECT TIPODEVOL
                INTO VNCODDEV
                FROM PCNFSAID
               WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
            EXCEPTION
              WHEN OTHERS THEN
                 VNCODDEV := 0;
            END;

            IF VNCODDEV = 7 THEN
              BEGIN
                SELECT CODDEPOSITO
                  INTO P_INTERNO.CODDEPOSITO
                  FROM PCDEVAVARIAC C, PCGRUPOAVARIA G
                 WHERE C.NUMTRANSVENDA = pnNUMTRANSACAO
                   AND G.CODGRUPO = C.CODGRUPOAVARIA
                   AND G.CODPROD = REGISTROS.CODPROD
                   AND G.CODFILIAL = REGISTROS.CODFILIAL;
              EXCEPTION
                WHEN OTHERS THEN
                   P_INTERNO.CODDEPOSITO := REGISTROS.CODDEPOSITO;
              END;

              IF P_INTERNO.CODDEPOSITO > 0 THEN
                BEGIN
                  UPDATE PCMOV
                     SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
                   WHERE PCMOV.ROWID = P_INTERNO.ROWID_REGISTRO;
                   -- Mensagem de erro
                EXCEPTION
                  WHEN OTHERS THEN
                    P_INTERNO.MSG_RETORNO := 'Erro 7 (Compras Saida Prod) Não foi possível atualizar o código do depósito na tabela de movimentação de estoque (PCMOV)!'||CHR(13)||
                                         'Identificador: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                                         'Cód. Filial..: '||P_INTERNO.CODFILIAL||CHR(13)||
                                         'Cód. Produto.: '||P_INTERNO.CODPROD||CHR(13)||
                                         'Cód. Depósito: '||P_INTERNO.CODDEPOSITO||CHR(13)||
                                         'Operação.....: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                                         'MSG Original.: '||SQLERRM;
                    RETURN 0;
                END;
              END IF;
            END IF;
          END IF;

          PRIV_DEP_COMPRAS_SAIDA;
          -- Erro na administração do estoque depósito
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 0;
          END IF;
        END IF;
      -- Administração depósito
      END IF;

      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Marcar no cabeçalho a utilização da package
    IF vnContadorRegistros > 0 THEN
      IF (psECANCELAMENTO = 'S') THEN
      UPDATE PCNFSAID
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    ELSE
      UPDATE PCNFSAID
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'N'
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    END IF;
    -- Validando se tem registros
    ELSIF vnCONTADORREGISTROS = 0 THEN
      UPDATE PCNFSAID
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      psMSG_RETORNO := 'Erro 7 (Compras Saida Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_SAIDA_PROD';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADORREGISTROS;
  -- Função
  END COMPRAS_SAIDA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Rodrigo Santos    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_SAIDA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                         ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                         ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnRETORNO   NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - COMPRAS_SAIDA';
    P_INTERNO.NOME_FUNCAO     := 'COMPRAS_SAIDA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Executando a função por produto
    vnRETORNO := COMPRAS_SAIDA_PROD(pnNUMTRANSACAO,0,'N',psECANCELAMENTO,psMSG_RETORNO);
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_SAIDA';
    P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnRETORNO;
  -- Função
  END COMPRAS_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_SAIDA_BENEFIC_PROD (pnNUMTRANSACAO    IN  PCMOV.NUMTRANSVENDA%TYPE
                                      ,psECANCELAMENTO   IN  PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                      ,psMSG_RETORNO     OUT VARCHAR2)
   RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS       NUMBER := 0;
    vnESTOQUE_QTEST           PCEST.QTEST%TYPE;
    vnESTOQUE_QTESTGER        PCEST.QTESTGER%TYPE;
    vnESTOQUE_QTINDENIZ       PCEST.QTINDENIZ%TYPE;
    vnESTOQUE_QTBLOQUEADA     PCEST.QTBLOQUEADA%TYPE;
    vnESTOQUE_DISPONIVEL      PCEST.QTRESERV%TYPE;
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    P_INTERNO.NOME_FUNCAO := 'COMPRAS_SAIDA_BENEFIC_PROD';
    psMSG_RETORNO         := 'OK';
    -- Erro na passagem de parâmetros
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Compras Saida Benefic Prod): O numtransação informado não é valido' || CHR(13) ||
                       'Identificador: ' || pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    --
    FOR REGISTROS IN (SELECT  PCMOV.CODPROD
                            , PCMOV.CODFILIAL
                            , DECODE(NVL(PCMOV.QTCONT, 0), 0, NVL(PCMOV.QT, 0), NVL(PCMOV.QTCONT, 0)) QT
                            , NVL(PCMOV.QTCONT, 0) QTCONT
                            , NVL(PCMOV.QTAVARIA, 0) QTAVARIA
                            , NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA
                            , NVL(PCMOV.MOVESTOQUEGERENCIAL
                            , (CASE WHEN((PCMOV.CODOPER = 'SN') AND(PCMOV.STATUS = 'AB')) THEN 'S' ELSE 'N' END)) MOVESTOQUEGERENCIAL
                            , NVL(PCMOV.MOVESTOQUECONTABIL
                            , (CASE WHEN((PCMOV.CODOPER = 'SN') AND(PCMOV.STATUS = 'AB')) THEN 'S' ELSE 'N' END)) MOVESTOQUECONTABIL
                            , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO', PCMOV.CODFILIAL), 'N') AUTOSERVICO
                            , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',PCMOV.CODFILIAL), 'N') LIBERAESTENTMERC
                            , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'), 'N') BLOQESTOQUETRANSF
                            , NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'), 'N') ACEITAVENDABALCAOESTNEG
                            , PCMOV.CODDEPOSITO
                            , PCMOV.ROWID NOTA_ROWID
                            , PCMOV.DATAESTOQUE
                            , PCMOV.DTMOV
                         FROM PCMOV
                        WHERE PCMOV.DTCANCEL IS NULL
                          AND PCMOV.NUMTRANSVENDA = pnNUMTRANSACAO
                          AND ((PCMOV.STATUS = 'AB') AND(PCMOV.CODOPER = 'SN'))
                     ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (COMPRAS_SAIDA_BENEFIC_PROD): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'Transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (COMPRAS_SAIDA_BENEFIC_PROD): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'Transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        --
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      --
      END IF;
      --
      P_INTERNO.INFORMACOES_LOG     := 'INICIOU A FUNÇÃO - COMPRAS_SAIDA_BENEFIC_PROD';
      P_INTERNO.IDENTIFICADOR       := pnNUMTRANSACAO;
      P_INTERNO.CODFILIAL           := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTROS.MOVESTOQUECONTABIL;
      P_INTERNO.CANCELAMENTO        := psECANCELAMENTO;
      P_INTERNO.MSG_RETORNO         := psMSG_RETORNO;
      PRIV_GERARLOG;
      --
      IF (REGISTROS.QT <= 0) THEN
        psMSG_RETORNO := 'Erro 4 (Compras Saida Benefic Prod): Quantidade declarada na transação e menor/igual a zero.' || CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD);
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      END IF;
      --
      IF (REGISTROS.QTBLOQUEADA < 0) THEN
        psMSG_RETORNO := 'Erro 5 (Compras Saida Benefic Prod): Quantidade bloqueada declarada na transação e menor que zero.' || CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD);
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      END IF;
      --
      IF (REGISTROS.QTAVARIA < 0) THEN
        psMSG_RETORNO := 'Erro 6 (Compras Saida Benefic Prod): Quantidade avariada declarada na transação e menor que zero.' || CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD);
        PRIV_GERARLOG;
        RETURN vnCONTADORREGISTROS;
      END IF;
      -- Atualizando a variavel
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      --
      SELECT NVL(PCEST.QTEST, 0) ESTOQUE_QTEST
           , NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
           , GREATEST(GREATEST(NVL(PCEST.QTBLOQUEADA, 0), NVL(PCEST.QTINDENIZ, 0)), 0) ESTOQUE_QTBLOQUEADA
           , GREATEST(NVL(PCEST.QTINDENIZ, 0), 0) ESTOQUE_QTINDENIZ
           , (NVL(PCEST.QTESTGER, 0) - NVL(PCEST.QTRESERV, 0)) ESTOQUE_DISPONIVEL
        INTO vnESTOQUE_QTEST
           , vnESTOQUE_QTESTGER
           , vnESTOQUE_QTBLOQUEADA
           , vnESTOQUE_QTINDENIZ
           , vnESTOQUE_DISPONIVEL
        FROM PCEST
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      --
      IF (psECANCELAMENTO = 'N') THEN
         vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA - LEAST(GREATEST(REGISTROS.QTBLOQUEADA, REGISTROS.QTAVARIA), REGISTROS.QT), 0);
         vnESTOQUE_QTINDENIZ := LEAST(GREATEST(vnESTOQUE_QTINDENIZ - REGISTROS.QTAVARIA, 0), vnESTOQUE_QTBLOQUEADA);
      ELSE
         vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA + LEAST(GREATEST(REGISTROS.QTBLOQUEADA, REGISTROS.QTAVARIA), REGISTROS.QT), 0);
         vnESTOQUE_QTINDENIZ := LEAST(GREATEST(vnESTOQUE_QTINDENIZ + REGISTROS.QTAVARIA, 0), vnESTOQUE_QTBLOQUEADA);
      END IF;
      --
      vnESTOQUE_QTINDENIZ := GREATEST(LEAST(vnESTOQUE_QTINDENIZ, vnESTOQUE_QTBLOQUEADA), 0);
      --
      IF ((psECANCELAMENTO = 'N') AND
          ((vnESTOQUE_DISPONIVEL - vnESTOQUE_QTINDENIZ) < REGISTROS.QT) AND
          ((REGISTROS.ACEITAVENDABALCAOESTNEG = 'N') OR(REGISTROS.AUTOSERVICO = 'N'))) THEN
        psMSG_RETORNO := 'Erro 7 (Compras Saida Benefic Prod): Quantidade disponível insuficiente para saída de estoque.' || CHR(13) ||
                         'Produto........: ' || TO_CHAR(REGISTROS.CODPROD) || CHR(13) ||
                         'Qtde disponível: ' || TO_CHAR(vnESTOQUE_DISPONIVEL - vnESTOQUE_QTINDENIZ) ||
                         ' - Qtde Nota: ' || TO_CHAR(REGISTROS.QT) ||
                         ' = ' || TO_CHAR(vnESTOQUE_DISPONIVEL - vnESTOQUE_QTINDENIZ - REGISTROS.QT);
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
      --
      UPDATE PCEST
         SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO
           , PCEST.QTEST = CASE
                             WHEN psECANCELAMENTO = 'N' THEN
                               NVL(PCEST.QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTCONT, 0)
                           ELSE
                             NVL(PCEST.QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.QTCONT, 0)
                           END
           , PCEST.QTESTGER = CASE
                                WHEN psECANCELAMENTO = 'N' THEN
                                  NVL(PCEST.QTESTGER, 0) - DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                              ELSE
                                NVL(PCEST.QTESTGER, 0) + DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', REGISTROS.QT, 0)
                              END
           , PCEST.QTBLOQUEADA = GREATEST(vnESTOQUE_QTBLOQUEADA, 0)
           , PCEST.QTINDENIZ = vnESTOQUE_QTINDENIZ
           ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
       WHERE PCEST.CODFILIAL = REGISTROS.CODFILIAL
         AND PCEST.CODPROD = REGISTROS.CODPROD;
      --
      P_INTERNO.INFORMACOES_LOG     := 'FINALIZOU A FUNÇÃO - COMPRAS_SAIDA_BENEFIC_PROD';
      P_INTERNO.IDENTIFICADOR       := pnNUMTRANSACAO;
      P_INTERNO.CODFILIAL           := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTROS.MOVESTOQUECONTABIL;
      P_INTERNO.CANCELAMENTO        := psECANCELAMENTO;
      P_INTERNO.MSG_RETORNO         := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    END LOOP;
    -- Validando se tem registros
    IF vnCONTADORREGISTROS = 0 THEN
      psMSG_RETORNO := 'Erro 8 (Compras Saida Benefic Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Retorno da função
    RETURN vnCONTADORREGISTROS;
  -- Função
  END COMPRAS_SAIDA_BENEFIC_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_SAIDA_BENEFIC (pnNUMTRANSACAO    IN  PCMOV.NUMTRANSVENDA%TYPE
                                 ,psECANCELAMENTO   IN  PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                 ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Gerar log
    P_INTERNO.INFORMACOES_LOG      := 'Iniciou a função - COMPRAS_SAIDA_BENEFIC';
    P_INTERNO.NOME_FUNCAO          := 'COMPRAS_SAIDA_BENEFIC';
    P_INTERNO.IDENTIFICADOR        := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO         := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO          := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Executar função
    RETURN COMPRAS_SAIDA_BENEFIC_PROD(pnNUMTRANSACAO, psECANCELAMENTO, psMSG_RETORNO);
    -- Gerar log
    P_INTERNO.INFORMACOES_LOG      := 'Finalizou a função - COMPRAS_SAIDA_BENEFIC';
    P_INTERNO.MSG_RETORNO          := psMSG_RETORNO;
    PRIV_GERARLOG;
  -- Função
  END COMPRAS_SAIDA_BENEFIC;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_MOVIMENTACAO_PROD (pnNUMTRANSENT             IN PCMOV.NUMTRANSENT%TYPE
                                     ,pnNUMTRANSVENDA           IN PCMOV.NUMTRANSVENDA%TYPE
                                     ,pnCODPROD                 IN PCMOV.CODPROD%TYPE
                                     ,psAPENAS_QTEST_QTESTGER   IN VARCHAR2
                                     ,psECANCELAMENTO           IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                     ,psMSG_RETORNO             OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vsMSGRETORNO_SAIDA VARCHAR2(1000);
    vsMSGRETORNO_ENT   VARCHAR2(1000);
    vnRESULTS          NUMBER := 0;
    vnRESULTE          NUMBER := 0;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    /* Inserindo informações de debug (LOG) */
    psMSG_RETORNO                   := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG       := 'Iniciou a função - COMPRAS_MOVIMENTACAO_PROD';
    P_INTERNO.NOME_FUNCAO           := 'COMPRAS_MOVIMENTACAO_PROD';
    P_INTERNO.IDENTIFICADOR         := pnNUMTRANSENT;
    P_INTERNO.CODPROD               := pnCODPROD;
    P_INTERNO.CANCELAMENTO          := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO           := psMSG_RETORNO;
    PRIV_GERARLOG;
    /* Realizando a entrada de mercadoria */
    IF (pnNUMTRANSENT > 0) THEN
      vnRESULTE := COMPRAS_ENTRADA_PROD (pnNUMTRANSENT,pnCODPROD,psAPENAS_QTEST_QTESTGER,psECANCELAMENTO,vsMSGRETORNO_ENT);
    END IF;
    /* Realizando a saída de mercadoria */
    IF (pnNUMTRANSVENDA > 0) THEN
      vnRESULTS := COMPRAS_SAIDA_PROD (pnNUMTRANSVENDA,pnCODPROD,psAPENAS_QTEST_QTESTGER,psECANCELAMENTO,vsMSGRETORNO_SAIDA);
    END IF;
    /* Validar se a entrada e a saída foram executadas corretamente */
    IF ((NVL(vsMSGRETORNO_ENT, 'OK') <> 'OK') AND
       (NVL(vsMSGRETORNO_SAIDA, 'OK') <> 'OK')) THEN
      psMSG_RETORNO := 'Erro mov. entrada: '||vsMSGRETORNO_ENT||CHR(13)||
                     'Erro mov. saída: '||vsMSGRETORNO_SAIDA;
    ELSIF (NVL(vsMSGRETORNO_ENT, 'OK') <> 'OK') THEN
      psMSG_RETORNO := 'Erro mov. entrada: '||vsMSGRETORNO_ENT;
    ELSIF (NVL(vsMSGRETORNO_SAIDA, 'OK') <> 'OK') THEN
      psMSG_RETORNO := 'Erro mov. saída: '||vsMSGRETORNO_SAIDA;
    END IF;
    -- Retornando os valores
    RETURN(vnRESULTE + vnRESULTS);
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_MOVIMENTACAO_PROD';
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
  -- Função
  END COMPRAS_MOVIMENTACAO_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION COMPRAS_MOVIMENTACAO (pnNUMTRANSENT     IN PCMOV.NUMTRANSENT%TYPE
                                ,pnNUMTRANSVENDA   IN PCMOV.NUMTRANSVENDA%TYPE
                                ,psECANCELAMENTO   IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnRETORNO   NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    /* Inserindo informações de debug (LOG) */
    psMSG_RETORNO                   := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG       := 'Iniciou a função - COMPRAS_MOVIMENTACAO';
    P_INTERNO.NOME_FUNCAO           := 'COMPRAS_MOVIMENTACAO';
    P_INTERNO.IDENTIFICADOR         := pnNUMTRANSENT;
    P_INTERNO.CANCELAMENTO          := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO           := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Executa a função COMPRAS_MOVIMENTACAO_PROD
    vnRETORNO := COMPRAS_MOVIMENTACAO_PROD (pnNUMTRANSENT,pnNUMTRANSVENDA,0,'N',psECANCELAMENTO,psMSG_RETORNO);
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - COMPRAS_MOVIMENTACAO';
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnRETORNO;
  -- Função
  END COMPRAS_MOVIMENTACAO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para transferir o estoque da PCEST para o estoque do depósito
  /***********************************************************************************************************************/
  PROCEDURE DEPOSITO_POPULAR_ESTOQUE (psCODFILIAL     IN PCESTOQUEDEPOSITOPROD.CODFILIAL%TYPE
                                     ,pnCODFUNCLANC   IN PCESTOQUEDEPOSITOPROD.CODFUNCLANC%TYPE
                                     ,pbCOMMIT        IN BOOLEAN
                                     ,psMSG_RETORNO   OUT VARCHAR2
                                     ,pnCODPROD       IN NUMBER DEFAULT 0)
  IS-- Declaração das variáveis internas
    vtMOVIMENTACAO_DEPOSITO T_MOVIMENTACAO_DEPOSITO;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    psMSG_RETORNO := NVL(P_INTERNO.MSG_RETORNO,'OK');
    BEGIN
      -- Tem transação
      IF P_INTERNO.IDENTIFICADOR IS NULL THEN
        -- Buscar próximo número de transação para a movimentação
        SELECT DEFSEQ_NUMTRANS_MOVDEP.NEXTVAL
          INTO P_INTERNO.IDENTIFICADOR
          FROM DUAL;
      -- Tem transação
      END IF;
      -- Lista de produtos que não tem deposito já cadastrado
      FOR REGISTROS IN (SELECT PCESTOQUEDEPOSITO.CODFILIAL
                             , PCEST.CODPROD
                             , PCESTOQUEDEPOSITO.CODDEPOSITO
                             , PCEST.QTESTGER
                             , PCEST.QTRESERV
                             , PCEST.QTBLOQUEADA
                             , PCEST.QTPENDENTE
                             , PCEST.QTINDENIZ
                          FROM PCESTOQUEDEPOSITO
                             , PCPRODUT
                             , PCEST
                         WHERE PCEST.CODFILIAL = PCESTOQUEDEPOSITO.CODFILIAL
                           AND PCEST.CODPROD = PCPRODUT.CODPROD
                           AND (PCESTOQUEDEPOSITO.CODFILIAL = psCODFILIAL OR psCODFILIAL = '99')
                           AND (pnCODPROD = 0 OR PCEST.CODPROD = pnCODPROD)
                           AND NOT EXISTS (SELECT 1
                                             FROM PCESTOQUEDEPOSITOPROD C
                                            WHERE C.CODFILIAL = PCESTOQUEDEPOSITO.CODFILIAL
                                              AND C.CODPROD = PCPRODUT.CODPROD
                                              AND C.CODDEPOSITO = PCESTOQUEDEPOSITO.CODDEPOSITO)
                      ORDER BY PCEST.CODPROD, PCESTOQUEDEPOSITO.CODFILIAL, PCESTOQUEDEPOSITO.CODDEPOSITO)
      LOOP
        --
        SELECT COUNT(1)
          INTO P_INTERNO.CONTADOR
          FROM PCESTOQUEDEPOSITOPROD C
         WHERE C.CODFILIAL = REGISTROS.CODFILIAL
           AND C.CODPROD = REGISTROS.CODPROD;
        -- Replica estoque da PCEST
        IF P_INTERNO.CONTADOR = 0 THEN
          P_INTERNO.QTESTGER    := REGISTROS.QTESTGER;
          P_INTERNO.QTRESERV    := REGISTROS.QTRESERV;
          P_INTERNO.QTPENDENTE  := REGISTROS.QTPENDENTE;
          P_INTERNO.QTBLOQUEADA := REGISTROS.QTBLOQUEADA;
          P_INTERNO.QTINDENIZ   := REGISTROS.QTINDENIZ;
        ELSE
          P_INTERNO.QTESTGER    := 0;
          P_INTERNO.QTRESERV    := 0;
          P_INTERNO.QTPENDENTE  := 0;
          P_INTERNO.QTBLOQUEADA := 0;
          P_INTERNO.QTINDENIZ   := 0;
        END IF;
        -- Alimenta dados necessários
        P_INTERNO.CODFILIAL       := REGISTROS.CODFILIAL;
        P_INTERNO.CODDEPOSITOORIG := NULL;
        P_INTERNO.CODDEPOSITODEST := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD         := REGISTROS.CODPROD;
        P_INTERNO.CODOPER         := 'ID';
        P_INTERNO.CODFUNCLANC     := pnCODFUNCLANC;
        -- Inserir registros
        INSERT
          INTO PCESTOQUEDEPOSITOPROD
              (CODFILIAL                -- 1
              ,CODDEPOSITO              -- 2
              ,CODPROD                  -- 3
              ,QTESTOQUE                -- 4
              ,QTRESERVADA              -- 5
              ,QTPENDENTE               -- 6
              ,QTBLOQUEADA              -- 7
              ,QTINDENIZADA             -- 8
              ,DTLANC                   -- 9
              ,CODFUNCLANC)             -- 10
        VALUES
              (REGISTROS.CODFILIAL      -- 1
              ,REGISTROS.CODDEPOSITO    -- 2
              ,REGISTROS.CODPROD        -- 3
              ,P_INTERNO.QTESTGER       -- 4
              ,P_INTERNO.QTRESERV       -- 5
              ,P_INTERNO.QTPENDENTE     -- 6
              ,P_INTERNO.QTBLOQUEADA    -- 7
              ,P_INTERNO.QTINDENIZ      -- 8
              ,SYSDATE                  -- 9
              ,pnCODFUNCLANC);          -- 10
        -- Atualizar variáveis
        vtMOVIMENTACAO_DEPOSITO                   := NULL;
        vtMOVIMENTACAO_DEPOSITO.IDENTIFICADOR     := P_INTERNO.IDENTIFICADOR;
        vtMOVIMENTACAO_DEPOSITO.NOME_TABELA       := NULL;
        vtMOVIMENTACAO_DEPOSITO.CODFILIAL         := REGISTROS.CODFILIAL;
        vtMOVIMENTACAO_DEPOSITO.CODPROD           := REGISTROS.CODPROD;
        vtMOVIMENTACAO_DEPOSITO.CODOPER           := P_INTERNO.CODOPER;
        vtMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG   := NULL;
        vtMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST   := REGISTROS.CODDEPOSITO;
        vtMOVIMENTACAO_DEPOSITO.QTREQUISITADA     := NULL;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR := P_INTERNO.QTESTGER;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR   := NULL;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_AVARIAR    := NULL;
        -- Gerar movimentações do depósito
        PRIV_DEP_MOVIMENTACAO (vtMOVIMENTACAO_DEPOSITO,P_INTERNO.MSG_RETORNO);
        -- Valida retorno da procedure
        IF NVL(P_INTERNO.MSG_RETORNO,'X') <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        END IF;
      -- Lista de produtos
      END LOOP;
      -- Lista de produtos com deposito já existente
      BEGIN
        FOR REGISTROS_SEM_PCEST IN (SELECT PCESTOQUEDEPOSITO.CODFILIAL
                                         , PCESTOQUEDEPOSITO.CODDEPOSITO
                                         , 0 QTESTGER
                                         , 0 QTRESERV
                                         , 0 QTBLOQUEADA
                                         , 0 QTPENDENTE
                                         , 0 QTINDENIZ
                                         , PCPRODUT.CODPROD
                                      FROM PCESTOQUEDEPOSITO
                                         , PCPRODUT
                                     WHERE (PCESTOQUEDEPOSITO.CODFILIAL = psCODFILIAL OR psCODFILIAL = '99')
                                       AND (pnCODPROD = 0 OR PCPRODUT.CODPROD = pnCODPROD)
                                       AND NOT EXISTS (SELECT 1
                                                         FROM PCESTOQUEDEPOSITOPROD C
                                                        WHERE C.CODFILIAL = PCESTOQUEDEPOSITO.CODFILIAL
                                                          AND C.CODPROD = PCPRODUT.CODPROD
                                                          AND C.CODDEPOSITO = PCESTOQUEDEPOSITO.CODDEPOSITO)
                                  ORDER BY PCESTOQUEDEPOSITO.CODFILIAL, PCESTOQUEDEPOSITO.CODDEPOSITO)
        LOOP
          -- Alimenta dados necessários
          P_INTERNO.QTESTGER        := REGISTROS_SEM_PCEST.QTESTGER;
          P_INTERNO.QTRESERV        := REGISTROS_SEM_PCEST.QTRESERV;
          P_INTERNO.QTPENDENTE      := REGISTROS_SEM_PCEST.QTPENDENTE;
          P_INTERNO.QTBLOQUEADA     := REGISTROS_SEM_PCEST.QTBLOQUEADA;
          P_INTERNO.QTINDENIZ       := REGISTROS_SEM_PCEST.QTINDENIZ;
          P_INTERNO.CODFILIAL       := REGISTROS_SEM_PCEST.CODFILIAL;
          P_INTERNO.CODDEPOSITOORIG := NULL;
          P_INTERNO.CODDEPOSITODEST := REGISTROS_SEM_PCEST.CODDEPOSITO;
          P_INTERNO.CODPROD         := REGISTROS_SEM_PCEST.CODPROD;
          P_INTERNO.CODOPER         := 'ID';
          P_INTERNO.CODFUNCLANC     := pnCODFUNCLANC;
          -- Inserir registros
          INSERT
            INTO PCESTOQUEDEPOSITOPROD
                (CODFILIAL                -- 1
                ,CODDEPOSITO              -- 2
                ,CODPROD                  -- 3
                ,QTESTOQUE                -- 4
                ,QTRESERVADA              -- 5
                ,QTPENDENTE               -- 6
                ,QTBLOQUEADA              -- 7
                ,QTINDENIZADA             -- 8
                ,DTLANC                   -- 9
                ,CODFUNCLANC)             -- 10
          VALUES
                (REGISTROS_SEM_PCEST.CODFILIAL      -- 1
                ,REGISTROS_SEM_PCEST.CODDEPOSITO    -- 2
                ,REGISTROS_SEM_PCEST.CODPROD        -- 3
                ,0                        -- 4
                ,0                        -- 5
                ,0                        -- 6
                ,0                        -- 7
                ,0                        -- 8
                ,SYSDATE                  -- 9
                ,pnCODFUNCLANC);          -- 10
          -- Valida retorno da procedure
          IF NVL(P_INTERNO.MSG_RETORNO,'X') <> 'OK' THEN
            psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          END IF;
        -- Lista de produtos
        END LOOP;
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
      -- Commit a gravação
      IF pbCOMMIT THEN
        COMMIT;
      END IF;
    -- Erro
    EXCEPTION
      WHEN OTHERS THEN
        psMSG_RETORNO := 'Erro 1 - Popular Estoque no Depósito: Não foi possível popular tabela de estoque para o depósito.'||CHR(13)||
                         'Identificador...: '||TO_CHAR(P_INTERNO.IDENTIFICADOR)||CHR(13)||
                         'Cód. Filial.....: '||P_INTERNO.CODFILIAL||CHR(13)||
                         'Cód. Produto....: '||P_INTERNO.CODPROD||CHR(13)||
                         'Operação........: '||P_INTERNO.TIPO_OPERACAO||CHR(13)||
                         'MSG Original....: '||SQLERRM;
    END;
  -- Procedure
  END DEPOSITO_POPULAR_ESTOQUE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada procedure para transferir a quantidade requisitada de um depósito para o outro
  21/05/2020     Fernandes Brito   0                   Retirada as variáveis globais para uso em processos ficando apenas as variáveis globais
                                                       para a gravação do log. Desta forma visamos a diminuir o risto de erros e melhorar o entendimento da PKG_ESTOQUE.
  /***********************************************************************************************************************/
  PROCEDURE DEPOSITO_TRANSFERENCIA (pnCODREQUISICAO     IN NUMBER
                                   ,psMSG_RETORNO       OUT VARCHAR2)
  IS-- Declaração das variáveis internas
    vsLISTA_VALIDA           VARCHAR2(1) := 'N';
    vtMOVIMENTACAO_DEPOSITO  T_MOVIMENTACAO_DEPOSITO;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO        := 'OK';
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a procedure - DEPOSITO_TRANSFERENCIA';
    P_INTERNO.NOME_FUNCAO     := 'DEPOSITO_TRANSFERENCIA';
    vLOG.IDENTIFICADOR   := pnCODREQUISICAO;
    PRIV_GERARLOG;
    -- Lista de produtos
    FOR ITEM_REQ IN (SELECT *
                       FROM PCREQUISICAODEPOSITO
                      WHERE CODREQUISICAO = pnCODREQUISICAO
                        AND POSICAO = 'A')
    LOOP
      -- Tem dados
      vsLISTA_VALIDA := 'S';
      -- Valida quantidade separada
      IF ITEM_REQ.QTSEPARADA <= ITEM_REQ.QT THEN
        -- Atualizar dados originais
        IF ITEM_REQ.NOME_TABELA = 'PCPEDI' THEN
          -- Atualizar dados do pedido
          BEGIN
            UPDATE PCPEDI
               SET CODDEPOSITO = ITEM_REQ.CODDEPOSITODEST
             WHERE NUMPED = ITEM_REQ.IDENTIFICADOR
               AND CODPROD = ITEM_REQ.CODPROD
               AND NUMSEQ = ITEM_REQ.NUMSEQ;
          EXCEPTION
            WHEN OTHERS THEN
              psMSG_RETORNO := 'Erro 1 - Transferência Depósito: Não foi possível atualizar o código do depósito na tabela PCPEDI.'||CHR(13)||
                               'Cód. Filial....: '||TO_CHAR(ITEM_REQ.CODFILIAL)||CHR(13)||
                               'Cód. Produto...: '||TO_CHAR(ITEM_REQ.CODPROD)||CHR(13)||
                               'Cód. Depósito..: '||TO_CHAR(ITEM_REQ.CODDEPOSITODEST)||CHR(13)||
                               'Nome da Tabela.: '||ITEM_REQ.NOME_TABELA||CHR(13)||
                               'MSG Original...: '||SQLERRM;
              vLOG.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN;
          END;
        END IF;
        -- Atualizar variáveis
        vtMOVIMENTACAO_DEPOSITO                    := NULL;
        vtMOVIMENTACAO_DEPOSITO.IDENTIFICADOR      := ITEM_REQ.CODREQUISICAO;
        vtMOVIMENTACAO_DEPOSITO.NOME_TABELA        := ITEM_REQ.NOME_TABELA;
        vtMOVIMENTACAO_DEPOSITO.CODFILIAL          := ITEM_REQ.CODFILIAL;
        vtMOVIMENTACAO_DEPOSITO.CODPROD            := ITEM_REQ.CODPROD;
        vtMOVIMENTACAO_DEPOSITO.CODOPER            := 'TD';
        vtMOVIMENTACAO_DEPOSITO.CODDEPOSITOORIG    := ITEM_REQ.CODDEPOSITOORIG;
        vtMOVIMENTACAO_DEPOSITO.CODDEPOSITODEST    := ITEM_REQ.CODDEPOSITODEST;
        vtMOVIMENTACAO_DEPOSITO.QTREQUISITADA      := ITEM_REQ.QT;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_TRANSFERIR  := ITEM_REQ.QTSEPARADA;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_BLOQUEAR    := NULL;
        vtMOVIMENTACAO_DEPOSITO.QTDE_A_AVARIAR     := NULL;
        -- Gerar movimentações entre depósito
        PRIV_DEP_MOVIMENTACAO (vtMOVIMENTACAO_DEPOSITO
                              ,psMSG_RETORNO);
        -- Validar retorno
        IF psMSG_RETORNO <> 'OK' THEN
          vLOG.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN;
        END IF;
      -- Erro
      ELSE
        psMSG_RETORNO := 'Erro 2 - Transferência Depósito: A quantidade separada é superior a quantidade requisitada!'||CHR(13)||
                         'Requisição.......: '||TO_CHAR(ITEM_REQ.CODREQUISICAO)||CHR(13)||
                         'Cód. Filial......: '||ITEM_REQ.CODFILIAL||CHR(13)||
                         'Cód. Produto.....: '||ITEM_REQ.CODPROD||CHR(13)||
                         'Qtde. Requisitada: '||ITEM_REQ.QT||CHR(13)||
                         'Qtde. Separada...: '||ITEM_REQ.QTSEPARADA;
        vLOG.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN;
      -- Validação qtseparada
      END IF;
    -- Lista de produtos
    END LOOP;
    -- Se tem item então fechar
    IF vsLISTA_VALIDA = 'S' THEN
      -- Fechar requisição
      PRIV_DEP_FECHAR (pnCODREQUISICAO,psMSG_RETORNO);
      -- Validar retorno
      IF psMSG_RETORNO <> 'OK' THEN
        vLOG.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN;
      END IF;
    -- Não tem itens validos
    ELSE
      psMSG_RETORNO := 'Erro 3 (Depósito de transferência): A requisição informada não existe ou não esta mais aberta (posição = ''A'')!'||CHR(13)||
                       'Requisição.........: '||TO_CHAR(pnCODREQUISICAO);
      vLOG.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN;
    END IF;
  -- Inserindo informações de debug (LOG)
  P_INTERNO.INFORMACOES_LOG := 'Finalizou a procedure - DEPOSITO_TRANSFERENCIA';
  PRIV_GERARLOG;
  -- Procedure
  END DEPOSITO_TRANSFERENCIA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  01/01/2018     Fernandes Brito                       Criada função para retonar o estoque disponível do produto na filial
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  -------------------------------------------------------------------------------------------------------------------------
                                                       Validar estoque disponível para o produto
  ************************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL (pnCODPROD      IN PCPEDI.CODPROD%TYPE
                              ,psCODFILIAL    IN PCPEDC.CODFILIAL%TYPE
                              ,psPROCESSO     IN VARCHAR2
                              ,pdDATA         IN PCHISTEST.DATA%TYPE DEFAULT NULL
                              ,pCOMGREATEST   IN VARCHAR2 DEFAULT 'S'
                              ,pnQTDE_REDUZIR IN PCPEDI.QT%TYPE DEFAULT 0)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnESTOQUE_DISPONIVEL   PCEST.QTESTGER%TYPE;
    vnESTOQUE_DISPONIVELCB PCEST.QTESTGER%TYPE;
    vnQTMINAUTOSERVICO     PCEST.QTESTGER%TYPE;
    vsUSAWMS               PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE       PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vnQTUNITCX             PCPRODUT.QTUNITCX%TYPE;
    vsTIPOMERC             PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL         PCPRODUT.PESOVARIAVEL%TYPE;
    vnQTDE_REDUZIR         PCPEDI.QT%TYPE;
    vsCOMGREATEST          VARCHAR2(1);
    -- PROCESSO:
   /*
   'VA' - USADO NAS ROTINAS DO MODULO DE VENDAS. TEM COMO PRINCIPAL OBJETIVO BUSCAR
         O ESTOQUE DISPONÍVEL DA CESTA E SOMA-LO AO ESTOQUE DISPONÍVEL DO PRODUTO.
         LEVANDO EM CONTA O CALCULO PADRÃO DE ESTOQUE DISPONÍVEL
   'VP' - USADO NAS ROTINAS DO MODULO DE VENDAS. TEM COMO PRINCIPAL OBJETIVO BUSCAR
         O ESTOQUE DISPONÍVEL DA CESTA E SOMA-LO AO ESTOQUE DISPONÍVEL DO PRODUTO.
         NÃO USA O ESTOQUE PENDENTE MESMO QUE O PARÂMETRO ESTEJA MARCADO PARA CONSIDERAR.
   'C' - USADO NAS ROTINAS DO MODULO DE COMPRAS. ESTA OPÇÃO NÃO FAZ O USO DOS ESTOQUES
         BLOQUEADO E PENDENTE (CONCEITO DE COMPRAS), MAS FAZ O USO DO INDENIZADO.
   'P' - USADO NAS ROTINAS DO MODULO DE VENDAS. ESTA OPÇÃO NÃO FAZ O USO DO ESTOQUE
         PENDENTE MESMO QUE O PARÂMETRO ESTEJA MARCADO PARA CONSIDERAR.
   'V' - ESTE É O PADRÃO USADO EM TODAS AS DEMAIS CELULAS. SEMPRE CONSIDERA OS PARÂMETROS
   'D' USADO NA QUANTIDADE DISPONIVEL DEMANDA
   'PA'- USADO NAS ROTINAS DO MODULO DE MEDICAMENTOS. TEM COMO PRINCIPAL OBJETIVO BUSCAR
         O ESTOQUE INDENIZADO AO DIGITAR UM PEDIDO DE AVARIA - DDMEDICA-620
   'PC'- USADO NAS ROTINAS DO MODULO DE MEDICAMENTOS. TEM COMO PRINCIPAL OBJETIVO BUSCAR
         O ESTOQUE BLOQUEADO AO DIGITAR UM PEDIDO DE CROSSDOCKING - DDMEDICA-620 / DDMEDICA-1400 --*/
  BEGIN
    -- Valor default
    IF pCOMGREATEST IS NULL THEN
      vsCOMGREATEST := 'S';
    ELSE
      vsCOMGREATEST := pCOMGREATEST;
    END IF;
    -- Valor default
    IF pnQTDE_REDUZIR IS NULL THEN
      vnQTDE_REDUZIR := 0;
    ELSE
      vnQTDE_REDUZIR := pnQTDE_REDUZIR;
    END IF;
    -- Obtendo a quantidade minima do auto serviço
    BEGIN
      SELECT NVL(PCPRODFILIAL.QTMINAUTOSERV, 0)
        INTO vnQTMINAUTOSERVICO
        FROM PCPRODFILIAL
       WHERE PCPRODFILIAL.CODPROD = pnCODPROD
         AND PCPRODFILIAL.CODFILIAL = psCODFILIAL;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnQTMINAUTOSERVICO := 0;
    END;
    -- Decidindo se pega PCHISTEST ou PCEST para fazer o calculo
    IF (pdDATA IS NOT NULL AND pdDATA < TRUNC(SYSDATE)) THEN
      -- Consultar dados historico do estoque
      P_INTERNO.vtHISTORICO           := NULL;
      P_INTERNO.vtHISTORICO.CODFILIAL := psCODFILIAL;
      P_INTERNO.vtHISTORICO.CODPROD   := pnCODPROD;
      P_INTERNO.vtHISTORICO.DATA      := pdDATA;
      PRIV_CONS_HISTORICO(P_INTERNO.vtHISTORICO);
      -- Definindo qual o calculo será feito
      vnESTOQUE_DISPONIVEL := CASE--Calculo Padrão compras
                                WHEN psPROCESSO = 'C' THEN
                                  (NVL(P_INTERNO.vtHISTORICO.QTESTGER, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTINDENIZ, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END))
                                --Calculo vendas sem estoque pendente
                                WHEN psPROCESSO IN ('P','VP') THEN
                                  (NVL(P_INTERNO.vtHISTORICO.QTESTGER, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTBLOQUEADA, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END))
                                --Calculo Pedido de Avaria - DDMEDICA-620
                                WHEN (psPROCESSO = 'PA') THEN
                                  GREATEST(NVL(P_INTERNO.vtHISTORICO.QTINDENIZ, 0),0)
                                --Calculo Pedido de CrossDocking - DDMEDICA-620
                                WHEN (psPROCESSO = 'PC') THEN
                                  GREATEST(NVL(P_INTERNO.vtHISTORICO.QTCROSSDOCK, 0),0)
                                --Calculo Padrão vendas
                                ELSE
                                  (NVL(P_INTERNO.vtHISTORICO.QTESTGER, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTBLOQUEADA, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtHISTORICO.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                    ,psCODFILIAL
                                                                    ,'S'
                                                                    ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtHISTORICO.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('BLOQUEIAVENDAESTPENDENTE'
                                                                               ,psCODFILIAL)
                                                                               ,PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQUEIAVENDAESTPENDENTE'))
                                     WHEN 'S' THEN
                                       NVL(P_INTERNO.vtHISTORICO.QTPENDENTE, 0)
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_CALCESTDISPCOMQTMINAUTOSERV'
                                                                               ,psCODFILIAL)
                                                                               ,'N')
                                     WHEN 'S' THEN
                                       vnQTMINAUTOSERVICO
                                   ELSE
                                     0
                                   END))
                              END;
    ELSE
      -- Consultar dados do estoque
      P_INTERNO.vtESTOQUE           := NULL;
      P_INTERNO.vtESTOQUE.CODFILIAL := psCODFILIAL;
      P_INTERNO.vtESTOQUE.CODPROD   := pnCODPROD;
      PRIV_CONS_ESTOQUE_ATUAL (P_INTERNO.vtESTOQUE);
      -- Consultar dados do produto
      PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
      -- Definindo qual o calculo será feito
      vnESTOQUE_DISPONIVEL := CASE-- Calculo Padrão compras
                                WHEN psPROCESSO = 'C' THEN
                                  ((NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) + vnQTDE_REDUZIR) -
                                   NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END))
                                -- Calculo da quantidade disponivel de demanda (Usado na 336)
                                WHEN psPROCESSO = 'D' THEN
                                  CASE
                                    WHEN ((NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) + vnQTDE_REDUZIR) -
                                          NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                          NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                         (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                            ,psCODFILIAL
                                                                            ,'S'
                                                                            ,'N')
                                            WHEN 'S' THEN
                                              CASE
                                                WHEN vsCOMGREATEST = 'S'THEN
                                                  GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                              ELSE
                                                ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                              END
                                          ELSE
                                            0
                                          END) -
                                          NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) -
                                          NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0)) < 0 THEN
                                      ABS(NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) -
                                          NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                          NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                         (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                            ,psCODFILIAL
                                                                            ,'S'
                                                                            ,'N')
                                            WHEN 'S' THEN
                                              CASE
                                                WHEN vsCOMGREATEST = 'S' THEN
                                                  GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                              ELSE
                                                ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                              END
                                          ELSE
                                            0
                                          END) -
                                          NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) -
                                          NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0))
                                  ELSE
                                    0
                                  END
                                -- Calculo sem considerar o pendente
                                WHEN psPROCESSO IN ('P','VP')  THEN
                                  ((NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) + vnQTDE_REDUZIR) -
                                   NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END))
                                -- Calculo Pedido de Avaria - DDMEDICA-620
                                WHEN (psPROCESSO = 'PA') THEN
                                  NVL(P_INTERNO.vtESTOQUE.QTINDENIZ, 0)
                                -- Calculo Pedido de CrossDocking - DDMEDICA-620
                                WHEN (psPROCESSO = 'PC') THEN
                                  GREATEST(NVL(P_INTERNO.vtESTOQUE.QTCROSSDOCK, 0),0)
                                -- Calculo Estoque disponivel por Caixa
                                WHEN (psPROCESSO = 'VC') THEN
                                  ((NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) + vnQTDE_REDUZIR) -
                                   NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('BLOQUEIAVENDAESTPENDENTE'
                                                                              ,psCODFILIAL)
                                                                              ,PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQUEIAVENDAESTPENDENTE'))
                                     WHEN 'S' THEN
                                       NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0)
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_CALCESTDISPCOMQTMINAUTOSERV'
                                                                               ,psCODFILIAL)
                                                                               ,'N')
                                     WHEN 'S' THEN
                                       vnQTMINAUTOSERVICO
                                   ELSE
                                     0
                                   END))
                                / (CASE
                                     WHEN NVL(vnQTUNITCX,0) = 0 THEN
                                       1
                                   ELSE
                                     vnQTUNITCX
                                   END)
                                --Calculo Padrão vendas
                                ELSE
                                  ((NVL(P_INTERNO.vtESTOQUE.QTESTGER, 0) + vnQTDE_REDUZIR) -
                                   NVL(P_INTERNO.vtESTOQUE.QTBLOQUEADA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTINDUSTRIA, 0) -
                                   NVL(P_INTERNO.vtESTOQUE.QTRESERV, 0) -
                                  (CASE PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA'
                                                                     ,psCODFILIAL
                                                                     ,'S'
                                                                     ,'N')
                                     WHEN 'S' THEN
                                       CASE
                                         WHEN vsCOMGREATEST = 'S' THEN
                                           GREATEST(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0), 0)
                                       ELSE
                                         ABS(NVL(P_INTERNO.vtESTOQUE.QTFRENTELOJA, 0))
                                       END
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('BLOQUEIAVENDAESTPENDENTE'
                                                                               ,psCODFILIAL)
                                                                               ,PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQUEIAVENDAESTPENDENTE'))
                                     WHEN 'S' THEN
                                       NVL(P_INTERNO.vtESTOQUE.QTPENDENTE, 0)
                                   ELSE
                                     0
                                   END) -
                                  (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_CALCESTDISPCOMQTMINAUTOSERV'
                                                                               ,psCODFILIAL)
                                                                               ,'N')
                                     WHEN 'S' THEN
                                       vnQTMINAUTOSERVICO
                                   ELSE
                                     0
                                   END))
                              END;
    -- Validação da tabela
    END IF;
    -- Usa Greatest para zera o estoque?
    IF vsCOMGREATEST = 'S' THEN
      vnESTOQUE_DISPONIVEL := GREATEST(vnESTOQUE_DISPONIVEL,0);
    END IF;
    -- Se tipo de chamada igual a VA
    IF psPROCESSO IN ('VA','VP') THEN
      -- Consultar dados do estoque
      PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
      -- Se produto for cesta básica
      IF (vsTIPOMERC = 'CB') AND
         (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_MONTARKITAUTOMATICAMENTE',psCODFILIAL,'N') = 'S') THEN
        -- Buscar disponível da cesta
        SELECT NVL(QTDISP, 0)
          INTO vnESTOQUE_DISPONIVELCB
          FROM TABLE(ESTOQUE_DISPONIVEL_CB(pnCODPROD, psCODFILIAL));
        -- Somando disponível da cesta ao disponível do produto
        vnESTOQUE_DISPONIVEL := (vnESTOQUE_DISPONIVEL + vnESTOQUE_DISPONIVELCB);
      -- Produto cesta
      END IF;
    -- Chamada VA
    END IF;
    -- Retornando o estoque disponível
    RETURN vnESTOQUE_DISPONIVEL;
  -- Função
  END ESTOQUE_DISPONIVEL;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/01/2022     Davi Bernado      DDESTOQUE-12423     Criando função que retorna o Bloqueado disponivel para transferencia.
  ************************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL_BLOQUEADO (pnCODPROD    IN PCPEDI.CODPROD%TYPE
                                         ,psCODFILIAL  IN PCPEDC.CODFILIAL%TYPE)
  RETURN NUMBER
  IS
    vnESTOQUE_BLOQUEADO       NUMBER;
    vnESTOQUE_BLOQUEADO_DISP  NUMBER;
  BEGIN
    vnESTOQUE_BLOQUEADO_DISP := 0;
    BEGIN
      SELECT NVL(PCEST.QTBLOQUEADA - PCEST.QTINDENIZ, 0)
        INTO vnESTOQUE_BLOQUEADO
        FROM PCEST
       WHERE CODFILIAL = psCODFILIAL
         AND CODPROD = pnCODPROD;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnESTOQUE_BLOQUEADO := 0;
    END;

    IF vnESTOQUE_BLOQUEADO > 0 THEN
      BEGIN
        SELECT SUM(I.QTBLOQUEADA)
          INTO vnESTOQUE_BLOQUEADO_DISP
          FROM PCBONUSC C, PCMOV I
         WHERE C.NUMBONUS = I.NUMBONUS
           AND I.CODFILIAL = C.CODFILIAL
           AND I.CODPROD = pnCODPROD
           AND I.CODFILIAL = psCODFILIAL
           AND NVL(I.ESTOQUEDESBLOQUEADO, 'N') = 'N'
           AND C.DTFECHAMENTO IS NULL
           AND C.DTCANCEL IS NULL
           AND NVL(C.LIBERAESTENTMERC, 'N') = 'N'
           AND I.CODOPER LIKE 'E%'
           AND trunc(C.DATABONUS) > trunc(SYSDATE - 90)
           AND NVL(C.UTILIZOUPREENT, 'N') = 'N'
       GROUP BY I.CODPROD, I.CODFILIAL;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnESTOQUE_BLOQUEADO_DISP := 0;
      END;

      vnESTOQUE_BLOQUEADO_DISP := vnESTOQUE_BLOQUEADO - vnESTOQUE_BLOQUEADO_DISP;
    END IF;

    RETURN vnESTOQUE_BLOQUEADO_DISP;
  END ESTOQUE_DISPONIVEL_BLOQUEADO;

  /************************************************************************************************************************
