  FUNCTION ESTOQUE_DISPONIVEL_LOTE_BLOQ (pnCODPROD     IN PCPEDI.CODPROD%TYPE
                                         ,psCODFILIAL   IN PCPEDC.CODFILIAL%TYPE
                                         ,psNUMLOTE     IN PCLOTE.NUMLOTE%TYPE)
  RETURN NUMBER
  IS
    vnESTOQUE_BLOQUEADO       NUMBER;
    vnESTOQUE_BLOQUEADO_DISP  NUMBER;
  BEGIN
    vnESTOQUE_BLOQUEADO_DISP := 0;
    BEGIN
      SELECT NVL(E.QTBLOQUEADA - E.QTINDENIZ, 0)
        INTO vnESTOQUE_BLOQUEADO
        FROM PCLOTE E
       WHERE E.CODFILIAL = psCODFILIAL
         AND E.CODPROD = pnCODPROD
         AND E.NUMLOTE = psNUMLOTE;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnESTOQUE_BLOQUEADO := 0;
    END;

    IF vnESTOQUE_BLOQUEADO > 0 THEN
      BEGIN
        SELECT SUM(I.QTBLOQUEADA)
          INTO vnESTOQUE_BLOQUEADO_DISP
          FROM PCBONUSC C, PCMOV I
         WHERE C.NUMBONUS = I.NUMBONUS
           AND I.CODFILIAL = C.CODFILIAL
           AND I.CODPROD = pnCODPROD
           AND I.CODFILIAL = psCODFILIAL
           AND NVL(I.ESTOQUEDESBLOQUEADO, 'N') = 'N'
           AND C.DTFECHAMENTO IS NULL
           AND C.DTCANCEL IS NULL
           AND NVL(C.LIBERAESTENTMERC, 'N') = 'N'
           AND I.CODOPER LIKE 'E%'
           AND I.NUMLOTE = psNUMLOTE
           AND trunc(C.DATABONUS) > trunc(SYSDATE - 90)
           AND NVL(C.UTILIZOUPREENT, 'N') = 'N'
       GROUP BY I.CODPROD, I.CODFILIAL;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnESTOQUE_BLOQUEADO_DISP := 0;
      END;

      vnESTOQUE_BLOQUEADO_DISP := vnESTOQUE_BLOQUEADO - vnESTOQUE_BLOQUEADO_DISP;
    END IF;

    RETURN vnESTOQUE_BLOQUEADO_DISP;
  END ESTOQUE_DISPONIVEL_LOTE_BLOQ;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/07/2018     Raniere Costa     0                   Criada a função do estoque de CB para corrigir erro de chamada
                                                       cíclica entre a pkg e o vendas
  22/08/2018     Fernandes Brito   0                   Alterada a função para contempla a embalagem, caso a filial use venda por embalagem
  ************************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL_CB (pnCODPROD   IN NUMBER DEFAULT 0
                                 ,psCODFILIAL IN VARCHAR2 DEFAULT '99')
  RETURN TB_ESTOQUE PIPELINED
  IS-- Declaração das variáveis internas
    -- Type interno
    TYPE TR_CESTAS IS RECORD
      (CODPRODCB   PCFORMPROD.CODPRODACAB%TYPE
      ,CODPRODMP   PCFORMPROD.CODPRODMP%TYPE
      ,QTEST_CB    PCEST.QTEST%TYPE
      ,QTESTGER_CB PCEST.QTESTGER%TYPE
      ,QTDISP_CB   PCEST.QTESTGER%TYPE);
    -- Type para formula
    TYPE TR_FORMULA IS RECORD (
       NUMSEQ              NUMBER
      ,CODFILIAL           PCEST.CODFILIAL%TYPE
      ,CODPRODACAB         PCFORMPROD.CODPRODACAB%TYPE
      ,QTPRODACAB          PCFORMPROD.QTPRODACAB%TYPE
      ,CODPRODMP           PCFORMPROD.CODPRODMP%TYPE
      ,QTPRODMP            PCFORMPROD.QTPRODMP%TYPE
      ,BAIXAESTOQUE        PCFORMPROD.BAIXAESTOQUE%TYPE
      ,QTESTMP             PCEST.QTEST%TYPE
      ,QTESTGERMP          PCEST.QTESTGER%TYPE
      ,CODAUXILIARMP       PCFORMPROD.CODAUXILIARMP%TYPE
      ,ESTOQUEDIPONIVEL_MP PCEST.QTESTGER%TYPE);
    -- Tabela do tipo Type
    TYPE TB_CESTAS IS TABLE OF TR_CESTAS;
    -- Variáveis
    vrDADOS           TR_FORMULA;
    DADOS_SAIDA       T_ESTOQUE;
    TB_MMC            TB_CESTAS := TB_CESTAS(NULL,NULL,NULL);
    vnMMC             NUMBER;
    vnQTPRODACAB      PCFORMPROD.CODPRODACAB%TYPE;
    vnCONTADOR        NUMBER;
    vcCURSOR          SYS_REFCURSOR;
    vsSQL             VARCHAR2(4000);
  BEGIN
    --Limpando campos calculados
    DADOS_SAIDA.QTDISP      := 0;
    DADOS_SAIDA.QTEST       := 0;
    DADOS_SAIDA.QTESTGER    := 0;
    DADOS_SAIDA.MSG_RETORNO := 'OK';
    TB_MMC.DELETE;
    -- Usa venda por embalagem na filial
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAVENDAPOREMBALAGEM',psCODFILIAL,'N') = 'S' THEN
      -- Buscar itens da formula
      SELECT COUNT(*)
        INTO vnCONTADOR
        FROM PCPRODUT, PCEST, PCFORMPROD
       WHERE PCEST.CODPROD = PCFORMPROD.CODPRODMP
         AND PCPRODUT.CODPROD = PCFORMPROD.CODPRODACAB
         AND NVL(PCFORMPROD.CODAUXILIARMP, PCPRODUT.CODAUXILIAR) IS NULL
         AND PCEST.CODFILIAL = psCODFILIAL
         AND PCPRODUT.CODPROD = pnCODPROD
         AND PCPRODUT.TIPOMERC = 'CB';
      -- Valida se existe CÓDIGO DE BARRAS para todos itens da cesta
      IF vnCONTADOR > 0 THEN
        -- Mensagem de erro
        DADOS_SAIDA.MSG_RETORNO := 'A filial trabalha com "Venda por embalagem" e o produto não tem código de barras informada no cadastro da fórmula (Verificar rotina 1122).';
        -- Preencher tabela de saída
        PIPE ROW(DADOS_SAIDA);
        RETURN;
      -- Código de barras
      END IF;
    -- Venda por embalagem
    END IF;
    -- Buscar dados dos itens da cesta
    vsSQL :=  ' SELECT ROWNUM NUMSEQ
                      ,PCEST.CODFILIAL
                      ,PCFORMPROD.CODPRODACAB
                      ,(SELECT MIN(DECODE(C.QTPRODACAB,NULL,1,0,1,C.QTPRODACAB))
                          FROM PCFORMPROD C
                         WHERE C.CODPRODACAB = PCFORMPROD.CODPRODACAB) QTPRODACAB
                      ,PCFORMPROD.CODPRODMP
                      ,PCFORMPROD.QTPRODMP
                      ,NVL(PCFORMPROD.BAIXAESTOQUE,''S'') BAIXAESTOQUE
                      ,PCEST.QTEST QTESTMP
                      ,PCEST.QTESTGER QTESTGERMP
                      ,PCFORMPROD.CODAUXILIARMP'||CHR(13);
-- Se trabalhar com venda por embalagem
IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAVENDAPOREMBALAGEM',psCODFILIAL,'N') = 'S' THEN
  vsSQL := vsSQL ||'      ,((PKG_ESTOQUE.ESTOQUE_DISPONIVEL(PCFORMPROD.CODPRODMP,PCEST.CODFILIAL,''V'')/ NVL(PCEMBALAGEM.QTUNIT,1))) ESTOQUEDIPONIVEL_MP'||CHR(13);
ELSE
  vsSQL := vsSQL ||'      ,(PKG_ESTOQUE.ESTOQUE_DISPONIVEL(PCFORMPROD.CODPRODMP,PCEST.CODFILIAL,''V'')) ESTOQUEDIPONIVEL_MP'||CHR(13);
END IF;
  vsSQL := vsSQL ||'  FROM PCPRODUT, PCEST, PCFORMPROD';
-- Se trabalhar com venda por embalagem
IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAVENDAPOREMBALAGEM',psCODFILIAL,'N') = 'S' THEN
  vsSQL := vsSQL ||', PCEMBALAGEM'||CHR(13);
END IF;
  vsSQL := vsSQL ||' WHERE PCEST.CODPROD = PCFORMPROD.CODPRODMP
                       AND PCPRODUT.CODPROD = PCFORMPROD.CODPRODACAB'||CHR(13);
-- Se trabalhar com venda por embalagem
IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAVENDAPOREMBALAGEM',psCODFILIAL,'N') = 'S' THEN
  vsSQL := vsSQL ||'   AND PCEST.CODFILIAL = PCEMBALAGEM.CODFILIAL
                       AND PCFORMPROD.CODAUXILIARMP = PCEMBALAGEM.CODAUXILIAR'||CHR(13);
END IF;
  vsSQL := vsSQL ||'   AND PCEST.CODFILIAL = '||CHR(39)||psCODFILIAL||CHR(39)||'
                       AND PCPRODUT.CODPROD = '||pnCODPROD||'
                       AND PCPRODUT.TIPOMERC = ''CB''
                  ORDER BY 1, 2';
   -- Abrindo o cursor com base no sql
   OPEN vcCURSOR FOR vsSQL;
   -- Buscando os dados da primeira linha do cursor
   FETCH vcCURSOR INTO vrDADOS;
   -- Enquanto não chegar no final das linhas faça
   WHILE NOT vcCURSOR%NOTFOUND LOOP
     -- Criar tabela de itens
     WHILE NOT TB_MMC.EXISTS(vrDADOS.NUMSEQ)
     LOOP
       TB_MMC.EXTEND;
     END LOOP;
     -- Atualizar variáveis de retorno
     vnQTPRODACAB                     := vrDADOS.QTPRODACAB;
     TB_MMC(vrDADOS.NUMSEQ).CODPRODCB := vrDADOS.CODPRODACAB;
     TB_MMC(vrDADOS.NUMSEQ).CODPRODMP := vrDADOS.CODPRODMP;
     DADOS_SAIDA.CODFILIAL            := vrDADOS.CODFILIAL;
     DADOS_SAIDA.CODPROD              := vrDADOS.CODPRODACAB;
     -- Se Baixa estoque então faz o calculo.
     IF vrDADOS.BAIXAESTOQUE = 'S' THEN
       TB_MMC(vrDADOS.NUMSEQ).QTDISP_CB := TRUNC(vrDADOS.ESTOQUEDIPONIVEL_MP / vrDADOS.QTPRODMP);
     ELSE
       TB_MMC(vrDADOS.NUMSEQ).QTDISP_CB := 99999999;
     END IF;
     -- Soma do estoque disponível dos itens da cesta
     TB_MMC(vrDADOS.NUMSEQ).QTEST_CB    := TRUNC(vrDADOS.QTESTMP / vrDADOS.QTPRODMP);
     TB_MMC(vrDADOS.NUMSEQ).QTESTGER_CB := TRUNC(vrDADOS.QTESTGERMP / vrDADOS.QTPRODMP);
     -- Indo para a proxima linha do cursor
     FETCH vcCURSOR INTO vrDADOS;
   -- Materias primas
   END LOOP;
   -- Iniciar MMC
   vnMMC := 99999999;
   -- Calcular mmc entre os itens da cesta com estoque disponível
   IF TB_MMC.EXISTS(1) THEN
     FOR X IN 1..TB_MMC.LAST
     LOOP
       IF TB_MMC.EXISTS(X) THEN
         vnMMC := LEAST(vnMMC, NVL(TB_MMC(X).QTDISP_CB,0));
         DADOS_SAIDA.QTEST    := NVL(DADOS_SAIDA.QTEST,0) + TB_MMC(X).QTEST_CB;
         DADOS_SAIDA.QTESTGER := NVL(DADOS_SAIDA.QTESTGER,0) + TB_MMC(X).QTESTGER_CB;
       END IF;
     END LOOP;
   -- Calculo do MMC
   END IF;
   -- Atualizar MMC do disponível
   DADOS_SAIDA.QTDISP   := NVL((vnMMC * vnQTPRODACAB),0);
   -- Preencher tabela de saída
   PIPE ROW(DADOS_SAIDA);
   -- Fechando o curso
   CLOSE vcCURSOR;
   -- Retorno
   RETURN;
  -- Função
  END ESTOQUE_DISPONIVEL_CB;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/09/2019     Fernando Carmo    0                   Criada a função do estoque por filial retira
  ************************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL_RETIRA ( pnCODPROD     IN PCPEDI.CODPROD%TYPE     DEFAULT 0
                                     , psCODAUXILIAR IN PCPEDI.CODAUXILIAR%TYPE DEFAULT 0
                                     , psCODFILIAL   IN PCPEDC.CODFILIAL%TYPE   DEFAULT '99')
  RETURN TB_ESTOQUE
  PARALLEL_ENABLE
  PIPELINED
  IS
    REGISTRO               T_ESTOQUE;
    vsFILIALPRODFILIAL     PCFILIAL.CODIGO%TYPE;
    vsFILIALPRODUTO        PCFILIAL.CODIGO%TYPE;
    vsCDVIRTUAL            VARCHAR2(1);
    vsUSAVENDAPOREMBALAGEM VARCHAR2(1);
    vnQUANTIDADEEMBALAGENS NUMBER;
    vsPROXIMOREGISTRO      VARCHAR2(1);
  BEGIN
    --Inicializando variáveis locais
    vsFILIALPRODFILIAL := '99';
    vsFILIALPRODUTO    := '99';
    vsUSAVENDAPOREMBALAGEM := FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAVENDAPOREMBALAGEM', psCODFILIAL, 'N');
    --Listando as filiais no cadastro de produtos e produto por filial
    FOR CONSULTA IN (SELECT PCEST.CODFILIAL
                          , PCEST.CODPROD
                          , DECODE(PCEST.CODFILIAL, PCPRODFILIAL.CODFILIALRETIRA, -2, -1) PRIORIDADEFILIAL
                          , DECODE(NVL(PCPRODFILIAL.PESOBRUTOMASTER,0), 0, DECODE(NVL(PCPRODUT.PESOBRUTOMASTER,0), 0, 1, PCPRODUT.PESOBRUTOMASTER), PCPRODFILIAL.PESOBRUTOMASTER) PESOBRUTOMASTER
                          , DECODE(NVL(PCPRODFILIAL.PESOPECA,0), 0, DECODE(NVL(PCPRODUT.PESOPECA,0), 0, 1, PCPRODUT.PESOPECA), PCPRODFILIAL.PESOPECA) PESOPECA
                          , NVL(PCEST.QTEST,0) QTEST
                          , NVL(PCEST.QTESTGER,0) QTESTGER
                          , NVL(PCEST.QTBLOQUEADA,0) QTBLOQUEADA
                          , NVL(PCEST.QTRESERV,0) QTRESERV
                          , NVL(PCEST.QTPENDENTE,0) QTPENDENTE
                          , NVL(PCEST.QTESTGER,0)
                          - NVL(PCEST.QTBLOQUEADA,0)
                          - NVL(PCEST.QTRESERV,0)
                          - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) QTDISPONIVEL
                          , NVL(PCEST.QTEST,0)
                          - NVL(PCEST.QTBLOQUEADA,0)
                          - NVL(PCEST.QTRESERV,0)
                          - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) QTDISPONIVELCONT
                       FROM PCEST
                          , PCCONSUM
                          , PCPRODFILIAL
                          , PCPRODUT
                          , PCFILIAL
                      WHERE PCPRODUT.CODPROD       = pnCODPROD
                        AND PCPRODUT.CODPROD       = PCPRODFILIAL.CODPROD
                        AND PCPRODFILIAL.CODFILIAL = psCODFILIAL
                        -- Dados da filial de venda
                        AND PCFILIAL.CODIGO        = PCPRODFILIAL.CODFILIAL
                        AND PCFILIAL.DTEXCLUSAO   IS NULL
                        -- Dados do estoque
                        AND PCEST.CODPROD          = PCPRODUT.CODPROD
                        AND PCEST.CODFILIAL       IN (PCPRODFILIAL.CODFILIALRETIRA, PCPRODUT.CODFILIALRETIRA)
                        AND PCEST.CODFILIAL   NOT IN ('99') --No cadastro do produto pode ter um 99
                        AND NVL(PCEST.QTESTGER,0)
                          - NVL(PCEST.QTBLOQUEADA,0)
                          - NVL(PCEST.QTRESERV,0)
                          - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) > 0 --Tem que ter estoque
                      ORDER --Filial da PCPRODFILIAL e prioridade sobre a PCPRODUT
                         BY DECODE(PCEST.CODFILIAL, PCPRODFILIAL.CODFILIALRETIRA, -2, -1))
    LOOP
      --
      vsPROXIMOREGISTRO := 'N';
      --
      IF vsUSAVENDAPOREMBALAGEM = 'S' THEN
        --
        SELECT COUNT(1)
          INTO vnQUANTIDADEEMBALAGENS
          FROM PCEMBALAGEM EB
         WHERE EB.CODFILIAL = CONSULTA.CODFILIAL
           AND EB.CODPROD = CONSULTA.CODPROD
           AND EB.CODAUXILIAR = psCODAUXILIAR;
        --
        IF vnQUANTIDADEEMBALAGENS < 1 THEN
          vsPROXIMOREGISTRO := 'S';
        END IF;

      END IF;
      --
      IF vsPROXIMOREGISTRO = 'N' THEN
        REGISTRO.CODFILIAL       := CONSULTA.CODFILIAL;
        REGISTRO.CODPROD         := CONSULTA.CODPROD;
        REGISTRO.PRIORIDADE      := CONSULTA.PRIORIDADEFILIAL;
        REGISTRO.QTEST           := CONSULTA.QTEST;
        REGISTRO.QTESTGER        := CONSULTA.QTESTGER;
        REGISTRO.QTDISP          := CONSULTA.QTDISPONIVEL;
        REGISTRO.QTDISP_CONT     := CONSULTA.QTDISPONIVELCONT;
        REGISTRO.PESOPECA        := CONSULTA.PESOPECA;
        REGISTRO.PESOBRUTOMASTER := CONSULTA.PESOBRUTOMASTER;
        --
        IF CONSULTA.PESOBRUTOMASTER <> 0 THEN
          REGISTRO.QTDISPPESOBRUTO      := CONSULTA.QTDISPONIVEL / CONSULTA.PESOBRUTOMASTER;
          REGISTRO.QTDISP_CONTPESOBRUTO := CONSULTA.QTDISPONIVELCONT / CONSULTA.PESOBRUTOMASTER;
        ELSE
          REGISTRO.QTDISPPESOBRUTO      := 0;
          REGISTRO.QTDISP_CONTPESOBRUTO := 0;
        END IF;
        --
        IF CONSULTA.PESOPECA <> 0 THEN
          REGISTRO.QTDISPPECA           := CONSULTA.QTDISPONIVEL / CONSULTA.PESOPECA;
          REGISTRO.QTDISP_CONTPECA      := CONSULTA.QTDISPONIVELCONT / CONSULTA.PESOPECA;
        ELSE
          REGISTRO.QTDISPPECA           := 0;
          REGISTRO.QTDISP_CONTPECA      := 0;
        END IF;
        --
        REGISTRO.MSG_RETORNO    := 'OK';
        -- Marcando o código da filial utilizado
        IF vsFILIALPRODFILIAL = '99' THEN
          vsFILIALPRODFILIAL := CONSULTA.CODFILIAL; --1º filial e da PCPRODFILIAL, se for maior que dois
        ELSE
          vsFILIALPRODUTO    := CONSULTA.CODFILIAL; --2º filial, se tiver, e da PCPRODUT
        END IF;
        --
        PIPE ROW(REGISTRO);
      END IF;
    --
    END LOOP;
    --
    vsCDVIRTUAL := FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CDVIRTUALIMPORTACAO', psCODFILIAL, 'N');
    -- Verificando se a filial de venda usa CD Virtual Importação, sem sim não busca nas filiais retira
    IF vsCDVIRTUAL = 'N' THEN
      --Verificando filial retira
      FOR CONSULTA IN (SELECT PCEST.CODFILIAL
                            , PCEST.CODPROD
                            , NVL(PCFILIALRETIRA.PRIORIDADEFILIAL,0) PRIORIDADEFILIAL
                            , DECODE(NVL(PCPRODFILIAL.PESOBRUTOMASTER,0), 0, DECODE(NVL(PCPRODUT.PESOBRUTOMASTER,0), 0, 1, PCPRODUT.PESOBRUTOMASTER), PCPRODFILIAL.PESOBRUTOMASTER) PESOBRUTOMASTER
                            , DECODE(NVL(PCPRODFILIAL.PESOPECA,0), 0, DECODE(NVL(PCPRODUT.PESOPECA,0), 0, 1, PCPRODUT.PESOPECA), PCPRODFILIAL.PESOPECA) PESOPECA
                            , NVL(PCEST.QTEST,0) QTEST
                            , NVL(PCEST.QTESTGER,0) QTESTGER
                            , NVL(PCEST.QTBLOQUEADA,0) QTBLOQUEADA
                            , NVL(PCEST.QTRESERV,0) QTRESERV
                            , NVL(PCEST.QTPENDENTE,0) QTPENDENTE
                            , NVL(PCEST.QTESTGER,0)
                            - NVL(PCEST.QTBLOQUEADA,0)
                            - NVL(PCEST.QTRESERV,0)
                            - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) QTDISPONIVEL
                            , NVL(PCEST.QTEST,0)
                            - NVL(PCEST.QTBLOQUEADA,0)
                            - NVL(PCEST.QTRESERV,0)
                            - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) QTDISPONIVELCONT
                         FROM PCFILIAL DADOSFILIALVENDA
                            , PCFILIAL DADOSFILIALRETIRA
                            , PCFILIALRETIRA
                            , PCEST
                            , PCCONSUM
                            , PCPRODUT
                            , PCPRODFILIAL
                              --Dados da filial de venda
                        WHERE DADOSFILIALVENDA.CODIGO               = psCODFILIAL
                          AND DADOSFILIALVENDA.USAESTOQUEDEPFECHADO = 'S' --Obrigatório saber se a filial de venda usa o controle de filial retira
                              --Dados da filial retira
                          AND PCFILIALRETIRA.CODFILIALVENDA         = DADOSFILIALVENDA.CODIGO
                          AND PCFILIALRETIRA.CODFILIALRETIRA        = DADOSFILIALRETIRA.CODIGO
                          AND DADOSFILIALRETIRA.DTEXCLUSAO          IS NULL
                          --Retornando os dados do estoque
                          AND PCEST.CODFILIAL                       = PCFILIALRETIRA.CODFILIALRETIRA
                          AND PCEST.CODPROD                         = pnCODPROD
                          --Dados do produto
                          AND PCEST.CODPROD                         = PCPRODUT.CODPROD
                          AND PCEST.CODPROD                         = PCPRODFILIAL.CODPROD
                          AND PCEST.CODFILIAL                       = PCPRODFILIAL.CODFILIAL
                          AND NVL(PCEST.QTESTGER,0)
                            - NVL(PCEST.QTBLOQUEADA,0)
                            - NVL(PCEST.QTRESERV,0)
                            - DECODE(PCCONSUM.BLOQUEIAVENDAESTPENDENTE, 'S', NVL(PCEST.QTPENDENTE,0), 0) > 0 --Tem que ter estoque
                        ORDER
                           BY NVL(PCFILIALRETIRA.PRIORIDADEFILIAL,0) --Depois da prioridade usa o código da própria filial
                            , LPAD(PCFILIALRETIRA.CODFILIALRETIRA, 2, '0'))
      LOOP
        --
        vsPROXIMOREGISTRO := 'N';
        --
        IF vsUSAVENDAPOREMBALAGEM = 'S' THEN
          BEGIN
            SELECT COUNT(1)
              INTO vnQUANTIDADEEMBALAGENS
              FROM PCEMBALAGEM EB
             WHERE EB.CODFILIAL = CONSULTA.CODFILIAL
               AND EB.CODPROD = CONSULTA.CODPROD
               AND EB.CODAUXILIAR = psCODAUXILIAR;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnQUANTIDADEEMBALAGENS := 0;
          END;
          --
          IF vnQUANTIDADEEMBALAGENS < 1 THEN
            vsPROXIMOREGISTRO := 'S';
          END IF;
        --
        END IF;
        --
        IF vsPROXIMOREGISTRO = 'N' THEN
          REGISTRO.CODFILIAL       := CONSULTA.CODFILIAL;
          REGISTRO.CODPROD         := CONSULTA.CODPROD;
          REGISTRO.PRIORIDADE      := CONSULTA.PRIORIDADEFILIAL;
          REGISTRO.QTEST           := CONSULTA.QTEST;
          REGISTRO.QTESTGER        := CONSULTA.QTESTGER;
          REGISTRO.QTDISP          := CONSULTA.QTDISPONIVEL;
          REGISTRO.QTDISP_CONT     := CONSULTA.QTDISPONIVELCONT;
          REGISTRO.PESOPECA        := CONSULTA.PESOPECA;
          REGISTRO.PESOBRUTOMASTER := CONSULTA.PESOBRUTOMASTER;
          REGISTRO.MSG_RETORNO     := 'OK';
          --
          IF CONSULTA.PESOBRUTOMASTER <> 0 THEN
            REGISTRO.QTDISPPESOBRUTO      := CONSULTA.QTDISPONIVEL / CONSULTA.PESOBRUTOMASTER;
            REGISTRO.QTDISP_CONTPESOBRUTO := CONSULTA.QTDISPONIVELCONT / CONSULTA.PESOBRUTOMASTER;
          ELSE
            REGISTRO.QTDISPPESOBRUTO      := 0;
            REGISTRO.QTDISP_CONTPESOBRUTO := 0;
          END IF;
          --
          IF CONSULTA.PESOPECA <> 0 THEN
            REGISTRO.QTDISPPECA           := CONSULTA.QTDISPONIVEL / CONSULTA.PESOPECA;
            REGISTRO.QTDISP_CONTPECA      := CONSULTA.QTDISPONIVELCONT / CONSULTA.PESOPECA;
          ELSE
            REGISTRO.QTDISPPECA           := 0;
            REGISTRO.QTDISP_CONTPECA      := 0;
          END IF;

          PIPE ROW(REGISTRO);
        --
        END IF;
      --
      END LOOP;
    --
    END IF;
    --
    RETURN;
  --
  END;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Fernandes Brito   0                   Criada função para buscar o estoque disponível do depósito na filial
  /***********************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL_DEPOSITO (pnCODPROD      IN PCESTOQUEDEPOSITOPROD.CODPROD%TYPE
                                       ,psCODFILIAL    IN PCESTOQUEDEPOSITOPROD.CODFILIAL%TYPE
                                       ,pnCODDEPOSITO  IN PCESTOQUEDEPOSITOPROD.CODDEPOSITO%TYPE
                                       ,psPROCESSO     IN VARCHAR2 DEFAULT NULL)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnESTOQUE_DISPONIVEL   PCESTOQUEDEPOSITOPROD.QTESTOQUE%TYPE;
  BEGIN
    -- Retornando o estoque disponível
    SELECT CASE-- Calculo Padrão compras
              WHEN psPROCESSO = 'C' THEN
                GREATEST((NVL(PCESTOQUEDEPOSITOPROD.QTESTOQUE, 0) -
                          NVL(PCESTOQUEDEPOSITOPROD.QTINDENIZADA, 0) -
                          NVL(PCESTOQUEDEPOSITOPROD.QTRESERVADA, 0))
                        ,0)
           ELSE
             GREATEST((NVL(PCESTOQUEDEPOSITOPROD.QTESTOQUE, 0) -
                       NVL(PCESTOQUEDEPOSITOPROD.QTBLOQUEADA, 0) -
                       NVL(PCESTOQUEDEPOSITOPROD.QTRESERVADA, 0) -
                      (CASE COALESCE(PARAMFILIAL.OBTERCOMOVARCHAR2('BLOQUEIAVENDAESTPENDENTE'
                                                                   ,psCODFILIAL)
                                                                   ,PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQUEIAVENDAESTPENDENTE'))
                         WHEN 'S' THEN
                           NVL(PCESTOQUEDEPOSITOPROD.QTPENDENTE, 0)
                       ELSE
                         0
                       END))
                     ,0)
           END
      INTO vnESTOQUE_DISPONIVEL
      FROM PCESTOQUEDEPOSITOPROD
     WHERE PCESTOQUEDEPOSITOPROD.CODFILIAL = psCODFILIAL
       AND PCESTOQUEDEPOSITOPROD.CODPROD = pnCODPROD
       AND PCESTOQUEDEPOSITOPROD.CODDEPOSITO = pnCODDEPOSITO;
    --
    RETURN vnESTOQUE_DISPONIVEL;
  --
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0;
    WHEN OTHERS THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 (Estoque Disponível Depósito): Não possível verificar estoque dispónivel do depósito.'||CHR(13)||
                               'Cód. Filial...: '||psCODFILIAL||CHR(13) ||
                               'Cód. Produto..: '||pnCODPROD||CHR(13) ||
                               'Cód. Depósito.: '||pnCODDEPOSITO||CHR(13) ||
                               'Erro Original.: '||SQLERRM;
      PRIV_GERARLOG;
      RETURN 0;
  -- Função
  END ESTOQUE_DISPONIVEL_DEPOSITO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/08/2019     Fernandes Brito   0                   Validar estoque disponível para o produto
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  ************************************************************************************************************************/
  FUNCTION ESTOQUE_DISPONIVEL_LOTE (psCODFILIAL   IN PCPEDC.CODFILIAL%TYPE
                                   ,pnCODPROD     IN PCPEDI.CODPROD%TYPE
                                   ,psNUMLOTE     IN PCMOV.NUMLOTE%TYPE
                                   ,psPROCESSO    IN VARCHAR2 DEFAULT 'I'
                                   ,pdDATA        IN PCHISTESTLOTE.DATA%TYPE DEFAULT NULL)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnESTOQUE_DISPONIVEL_LOTE  PCEST.QTESTGER%TYPE;
  BEGIN
    -- Decidindo se pega PCHISTEST ou PCEST para fazer o calculo
    IF (pdDATA IS NOT NULL AND pdDATA < TRUNC(SYSDATE)) THEN
      -- Definindo qual o calculo será feito
      BEGIN
        SELECT CASE
                 --Calculo Pedido de Avaria - DDMEDICA-620
                 WHEN (NVL(psPROCESSO,'X') = 'PA') THEN
                   GREATEST(NVL(PCHISTESTLOTE.QTINDENIZ, 0),0)
                 --Calculo Pedido de CrossDocking - DDMEDICA-620
                 WHEN (NVL(psPROCESSO,'X') = 'PC') THEN
                   GREATEST(NVL(PCHISTESTLOTE.QTCROSSDOCK, 0),0)
               ELSE
                 GREATEST((NVL(PCHISTESTLOTE.QT, 0) -
                         NVL(PCHISTESTLOTE.QTRESERV, 0) -
                         NVL(PCHISTESTLOTE.QTINDUSTRIA, 0) -
                         NVL(PCHISTESTLOTE.QTBLOQUEADA, 0)),0)
               END DISPONIVEL
          INTO vnESTOQUE_DISPONIVEL_LOTE
          FROM PCHISTESTLOTE
         WHERE PCHISTESTLOTE.CODFILIAL = psCODFILIAL
           AND PCHISTESTLOTE.CODPROD = pnCODPROD
           AND PCHISTESTLOTE.NUMLOTE = psNUMLOTE
           AND PCHISTESTLOTE.DATA    = pdDATA;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnESTOQUE_DISPONIVEL_LOTE := 0;
      END;
    -- Normal
    ELSE
      -- Definindo qual o calculo será feito
      BEGIN
        SELECT CASE
                 --Calculo Pedido de Avaria - DDMEDICA-620
                 WHEN (NVL(psPROCESSO,'X') = 'PA') THEN
                   GREATEST(NVL(PCLOTE.QTINDENIZ, 0),0)
                 --Calculo Pedido de CrossDocking - DDMEDICA-620
                 WHEN (NVL(psPROCESSO,'X') = 'PC') THEN
                   GREATEST(NVL(PCLOTE.QTCROSSDOCK, 0),0)
               ELSE
                 GREATEST((NVL(PCLOTE.QT, 0) -
                         NVL(PCLOTE.QTRESERV, 0) -
                         NVL(PCLOTE.QTINDUSTRIA, 0) -
                         NVL(PCLOTE.QTBLOQUEADA, 0)),0)
               END DISPONIVEL
          INTO vnESTOQUE_DISPONIVEL_LOTE
          FROM PCLOTE
         WHERE PCLOTE.CODFILIAL = psCODFILIAL
           AND PCLOTE.CODPROD = pnCODPROD
           AND PCLOTE.NUMLOTE = psNUMLOTE;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnESTOQUE_DISPONIVEL_LOTE := 0;
      END;
    -- Validação da tabela
    END IF;
    -- Retornando o estoque disponível
    RETURN vnESTOQUE_DISPONIVEL_LOTE;
  -- Função
  END ESTOQUE_DISPONIVEL_LOTE;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  07/07/2017     Fernandes Brito   0                   Incluir Qt. Frente Loja para controle do disponível
  /***********************************************************************************************************************/
  FUNCTION FRENTELOJA_ATUALIZAR_PCEST (psCODFILIAL     IN PCPEDC.CODFILIAL%TYPE
                                      ,pnCODPROD       IN PCPEDI.CODPROD%TYPE
                                      ,pnQTDE          IN PCPEDI.QT%TYPE
                                      ,psOPERACAO      IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                      ,psMSG_RETORNO   OUT VARCHAR2
                                      ,pnIDENTIFICADOR IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE DEFAULT NULL)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Consultar dados do estoque
    P_INTERNO.vtESTOQUE                := NULL;
    P_INTERNO.vtESTOQUE.CODFILIAL      := psCODFILIAL;
    P_INTERNO.vtESTOQUE.CODPROD        := pnCODPROD;
    PRIV_CONS_ESTOQUE_ATUAL (P_INTERNO.vtESTOQUE);
    -- Verificando reserva anterior
    P_INTERNO.QTFRENTELOJAANT    := P_INTERNO.vtESTOQUE.QTFRENTELOJA;
    P_INTERNO.QTFRENTELOJA       := P_INTERNO.QTFRENTELOJAANT;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO                := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG    := 'Iniciou a função - FRENTELOJA_ATUALIZAR_PCEST';
    P_INTERNO.CODFILIAL          := psCODFILIAL;
    P_INTERNO.CODPROD            := pnCODPROD;
    P_INTERNO.QTPARAMETROENTRADA := pnQTDE;
    P_INTERNO.TIPO_OPERACAO      := psOPERACAO;
    P_INTERNO.MSG_RETORNO        := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Reserva estoque do Qt. Frente de loja?
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('BAIXAESTQTFRENTELOJA',psCODFILIAL,'N') = 'S' THEN
      -- Atualizar sem movimentação?
      IF (psCODFILIAL IS NOT NULL AND
          pnCODPROD IS NOT NULL AND
          pnQTDE IS NOT NULL AND
          psOPERACAO IS NOT NULL) THEN
          -- Atualizar o estoque
        BEGIN
          UPDATE PCEST
             SET IDENTIFICADOR = pnIDENTIFICADOR
                ,QTFRENTELOJA = (NVL(QTFRENTELOJA, 0) + (CASE
                                                                    WHEN SUBSTR(psOPERACAO,1,1) IN ('B') THEN
                                                                     (NVL(pnQTDE, 0)*(-1))
                                                                  ELSE
                                                                    NVL(pnQTDE, 0)
                                                                  END))
                ,PCEST.DTHORAULTALTDISP = SYSDATE
           WHERE CODFILIAL = psCODFILIAL
             AND CODPROD = pnCODPROD
             AND CONTROLANUMEROSERIE.FUNC_CONTROLA_NUMERO_SERIE(PCEST.CODFILIAL, PCEST.CODPROD) = 'N';
        -- Erro ao fazer update na PCEST
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (Frente de loja): Não foi possível atualizar a tabela de estoque durante a atualização da "Qt. Frente Loja".'||CHR(13)||
                             'Cód. Filial....: '||TO_CHAR(psCODFILIAL)||CHR(13)||
                             'Cód. Produto...: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Qtde. Informada: '||TO_CHAR(pnQTDE)||CHR(13)||
                             'Operação.......: '||psOPERACAO||CHR(13)||
                             'MSG Original...: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
      -- Dados não informados
      ELSE
        psMSG_RETORNO := 'Erro 2 (Frente de loja): Não foram informados todos os parâmetros ao executar a função de baixa do estoque de frente de loja.'||CHR(13)||
                         'Cód. Filial....: '||TO_CHAR(psCODFILIAL)||CHR(13)||
                         'Cód. Produto...: '||TO_CHAR(pnCODPROD)||CHR(13)||
                         'Qtde. Informada: '||TO_CHAR(pnQTDE)||CHR(13)||
                         'Operação.......: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Parâmetros de entrada
      END IF;
    -- Usar processo de frente de loja
    END IF;
    -- Consultar dados do estoque
    P_INTERNO.vtESTOQUE           := NULL;
    P_INTERNO.vtESTOQUE.CODFILIAL := psCODFILIAL;
    P_INTERNO.vtESTOQUE.CODPROD   := pnCODPROD;
    PRIV_CONS_ESTOQUE_ATUAL (P_INTERNO.vtESTOQUE);
    -- Verificando atualização da quantidade de frente de loja
    P_INTERNO.QTFRENTELOJA  := P_INTERNO.vtESTOQUE.QTFRENTELOJA;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG   := 'FINALIZOU A FUNÇÃO - FRENTELOJA_ATUALIZAR_PCEST';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno será "S - Sim"
    RETURN 'S';
  -- Função
  END FRENTELOJA_ATUALIZAR_PCEST;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  22/08/2017     Fernandes Brito   0                   Criada a função para voltar estoque da devolução da ordem de serviço avulsa
  /***********************************************************************************************************************/
  FUNCTION INDUSTRIA_DEVOLUCAO_AVULSA (pnNUMTRANSAVULSA IN PCOPC.NUMOP%TYPE
                                      ,pnNUMOP          IN PCOPC.NUMOP%TYPE
                                      ,psCODFILIAL      IN PCFILIAL.CODIGO%TYPE
                                      ,psOPERACAO       IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                      ,PSCANCELAMENTO   IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                      ,psMSG_RETORNO    OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS NUMBER := 0;
    vnDTMOVPRIMERIO     DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - INDUSTRIA_DEVOLUCAO_AVULSA';
    P_INTERNO.NOME_FUNCAO     := 'INDUSTRIA_DEVOLUCAO_AVULSA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSAVULSA;
    P_INTERNO.CODFILIAL       := psCODFILIAL;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Lista de produtos
    FOR REGISTROS IN (SELECT PCMOV.CODPROD
                            ,PCMOV.QT
                            ,PCMOV.CODFILIAL
                            ,PCMOV.CODDEPOSITO
                            ,NVL(PCMOV.MOVESTOQUEGERENCIAL,'S') MOVESTOQUEGERENCIAL
                            ,PCMOV.ROWID NOTA_ROWID
                            ,PCMOV.DATAESTOQUE
                            ,PCMOV.DTMOV
                        FROM PCMOV
                       WHERE PCMOV.NUMTRANSAVULSA = pnNUMTRANSAVULSA
                         AND PCMOV.CODOPER = 'EX'
                         AND PCMOV.CODFILIAL = psCODFILIAL
                         AND PCMOV.DTCANCEL IS NULL
                    ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      IF PSCANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 1 (INDUSTRIA_DEVOLUCAO_AVULSA): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'Transação: ' || TO_CHAR(pnNUMTRANSAVULSA);
          RETURN 'N';
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROS = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 2 (INDUSTRIA_DEVOLUCAO_AVULSA): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'Transação: ' || TO_CHAR(pnNUMTRANSAVULSA);
          RETURN 'N';
        END IF;
      END IF;
      -- Atualizando a variavel
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG  := 'Iniciando laço para o produto - INDUSTRIA_DEVOLUCAO_AVULSA';
      P_INTERNO.CODPROD          := REGISTROS.CODPROD;
      PRIV_GERARLOG;
      -- Atualizar a PCEST
      BEGIN
        UPDATE PCEST
           SET PCEST.QTESTGER = CASE
                                  WHEN PSCANCELAMENTO = 'N' THEN
                                    ROUND(NVL(QTESTGER,0) + (REGISTROS.QT),6)
                                ELSE
                                  ROUND(NVL(QTESTGER,0) - (REGISTROS.QT),6)
                                END
              ,PCEST.QTEST = CASE
                               WHEN PSCANCELAMENTO = 'N' THEN
                                 ROUND(NVL(QTEST,0) + (REGISTROS.QT),6)
                             ELSE
                               ROUND(NVL(QTEST,0) - (REGISTROS.QT),6)
                             END
              ,PCEST.DTHORAULTALTDISP = SYSDATE
         WHERE PCEST.CODPROD = REGISTROS.CODPROD
           AND PCEST.CODFILIAL = REGISTROS.CODFILIAL;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 3 (Industria Dev. Avulsa): Não foi possível baixa o estoque do produto '||TO_CHAR(REGISTROS.CODPROD)||' na filial '||REGISTROS.CODFILIAL||CHR(13)||
                           'Por favor tente mais tarde!'||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
      END;
      -- Atualizar a ordem de produção avulsa
      BEGIN
        UPDATE PCAVULSA
           SET PCAVULSA.DTBAIXA = SYSDATE,
               PCAVULSA.DTCANCEL = CASE
                                     WHEN PSCANCELAMENTO='N' THEN
                                       NULL
                                   ELSE
                                     SYSDATE
                                   END,
               PCAVULSA.OBS = CASE
                                WHEN PSCANCELAMENTO='N' THEN
                                  'DEVOLUÇÃO AVULSA PELAS ROTINAS 1690,1632'
                              ELSE
                                'CANCELAMENTO DE DEVOLUÇAÕ AVULSA PELA ROTINA 1617'
                              END
         WHERE PCAVULSA.CODOPER = 'E'
           AND PCAVULSA.CODFILIAL = psCODFILIAL
       AND PCAVULSA.CODPROD = REGISTROS.CODPROD
           AND PCAVULSA.NUMTRANSAVULSA = pnNUMTRANSAVULSA;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 4 (Industria Dev. Avulsa): Não foi possível atualizar dados da ordem de produção!'||CHR(13)||
                           'Produto..........: '||CHR(9)||TO_CHAR(REGISTROS.CODPROD)||CHR(13)||
                           'Ordem de produção: '||CHR(9)||TO_CHAR(pnNUMTRANSAVULSA)||CHR(13)||
                           'Operação.........: '||psOPERACAO||CHR(13)||
                           'MSG Original.....: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
      END;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variáveis para movimentar depósito
        P_INTERNO.CODFILIAL        := REGISTROS.CODFILIAL;
        P_INTERNO.ROWID_REGISTRO   := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER         := REGISTROS.QT;
        -- Administrar estoque do depósito
        PRIV_DEP_COMPRAS_ENTRADA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG  := 'Fim do laço para o produto - INDUSTRIA_DEVOLUCAO_AVULSA';
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Validando se tem registros
    IF vnCONTADORREGISTROS = 0 THEN
      psMSG_RETORNO := 'Erro 5 (Industria Dev. Avulsa): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSAVULSA);
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - INDUSTRIA_DEVOLUCAO_AVULSA';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN 'S';
  -- Procedure
  END INDUSTRIA_DEVOLUCAO_AVULSA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  28/02/2018     Waldes Souza      LOG-2345            Criada a função
  /***********************************************************************************************************************/
  FUNCTION INDUSTRIA_DESBLOQUEAR (pnNUMREMESSA     IN PCREMESSAPRODUCAO.NUMREMESSA%TYPE
                                 ,PSCANCELAMENTO   IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                 ,psMSG_RETORNO  OUT VARCHAR2)

  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS NUMBER := 0;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - DESBLQUEAR INDUSTRIA';
    P_INTERNO.NOME_FUNCAO     := 'INDUSTRIA_DESBLOQUEAR';
    P_INTERNO.IDENTIFICADOR   := pnNUMREMESSA;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    P_INTERNO.CANCELAMENTO    := PSCANCELAMENTO;
    PRIV_GERARLOG;
    -- Lista de produtos
    FOR REGISTROS  IN (SELECT PCREMESSAPRODUCAO.CODFILIAL,
                              PCREMESSAPRODUCAOI.CODPROD,
                              PCREMESSAPRODUCAOI.NUMLOTE,
                              SUM(PCREMESSAPRODUCAOI.QUANTIDADE)QT
                         FROM PCREMESSAPRODUCAO, PCREMESSAPRODUCAOI
                        WHERE PCREMESSAPRODUCAO.NUMREMESSA = PCREMESSAPRODUCAOI.NUMREMESSA
                          AND PCREMESSAPRODUCAO.NUMREMESSA = pnNUMREMESSA
                     GROUP BY PCREMESSAPRODUCAOI.CODPROD, PCREMESSAPRODUCAOI.NUMLOTE,
                              PCREMESSAPRODUCAO.CODFILIAL)
    LOOP
      -- Atualizando a variavel
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG  := 'INICIANDO LAÇO PARA O PRODUTO - DESBLQUEAR INDUSTRIA';
      P_INTERNO.CODFILIAL        := REGISTROS.CODFILIAL;
      P_INTERNO.CODPROD          := REGISTROS.CODPROD;
      P_INTERNO.NUMLOTE          := REGISTROS.NUMLOTE;
      PRIV_GERARLOG;
      BEGIN
        UPDATE PCEST
           SET PCEST.QTINDUSTRIA = CASE
                                     WHEN PSCANCELAMENTO='N' THEN
                                       ROUND(NVL(QTINDUSTRIA,0) + (REGISTROS.QT),6)
                                   ELSE
                                     ROUND(NVL(QTINDUSTRIA,0) - (REGISTROS.QT),6)
                                   END
              ,PCEST.DTHORAULTALTDISP = SYSDATE
         WHERE PCEST.CODPROD   = REGISTROS.CODPROD
           AND PCEST.CODFILIAL = REGISTROS.CODFILIAL;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 1 (Industria desbloquear): Não foi possível desbloquear o estoque indústria do produto '||CHR(13)||
                           'Cod. Filial..: '||CHR(9)||REGISTROS.CODFILIAL||CHR(13)||
                           'Cod.Prod.....: '||CHR(9)||TO_CHAR(REGISTROS.CODPROD)||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
      END;
      -- Valida se o lote exite
      P_INTERNO.vtLOTE               := NULL;
      P_INTERNO.vtLOTE.CODFILIAL     := REGISTROS.CODFILIAL;
      P_INTERNO.vtLOTE.CODPROD       := REGISTROS.CODPROD;
      P_INTERNO.vtLOTE.NUMLOTE       := REGISTROS.NUMLOTE;
      PRIV_CONS_LOTE;
      -- Caso não exista lote
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
      -- Bloquear PCLOTE
      PRIV_BLOQUEAR_LOTE;
      -- Caso não consiga bloquear a PCLOTE
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
      -- Atualizar variáveis
      P_INTERNO.vtLOTE.IDENTIFICADOR := pnNUMREMESSA;
      P_INTERNO.vtLOTE.QTINDUSTRIA   := REGISTROS.QT;
      P_INTERNO.vtLOTE.QT            := NULL;
      P_INTERNO.vtLOTE.QTEST         := NULL;
      P_INTERNO.vtLOTE.QTRESERV      := NULL;
      P_INTERNO.vtLOTE.QTBLOQUEADA   := NULL;
      P_INTERNO.vtLOTE.QTINDENIZ     := NULL;
      -- Valida se é cancelamento
      IF psCANCELAMENTO = 'N' THEN
        P_INTERNO.TIPO_OPERACAO := 'II';
      ELSE
        P_INTERNO.TIPO_OPERACAO := 'BI';
      END IF;
      -- Administrar lote
      PRIV_ATUALIZAR_LOTE;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG  := 'FIM DO LAÇO PARA O PRODUTO - DESBLQUEAR INDUSTRIA';
      PRIV_GERARLOG;
    -- Laço dos produtos
    END LOOP;
    -- Validando se tem registros
    IF vnCONTADORREGISTROS = 0 THEN
      psMSG_RETORNO := 'Erro 1 (Industria desbloquear): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMREMESSA);
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'FINALIZOU A FUNÇÃO - INDUSTRIA DESBLOQUEAR';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN 'S';
  -- Procedure
  END INDUSTRIA_DESBLOQUEAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Iago Souza        0                   Criada a função
  *************************************************************************************************************************/
  FUNCTION LOGISTICA_SAIDA_PROD (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                                ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                                ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnContadorRegistros       NUMBER;
    vnDTMOVPRIMERIO           DATE;
    vnCODIGOPRODUTO           PCMOV.CODPROD%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Iniciando variaveis
    vnContadorRegistros       := 0;
    vnCODIGOPRODUTO           := 0;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - LOGISTICA_SAIDA_PROD';
    P_INTERNO.NOME_FUNCAO     := 'LOGISTICA_SAIDA_PROD';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.NUMTRANSVENDA   := pnNUMTRANSACAO;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Transação valida?
    IF pnNUMTRANSACAO <= 0 THEN
      P_INTERNO.MSG_RETORNO := 'Erro 1 (Logistica Saída Prod): O numtransação informado não é valido'||CHR(13)||
                               'Identificador: '||pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    -- Atualiza operação
    P_INTERNO.TIPO_OPERACAO := 'B';
    -- Validas se é cancelamento
    IF psECANCELAMENTO = 'S' THEN
      P_INTERNO.TIPO_OPERACAO := 'C';
    END IF;
    -- Lista de produtos
    FOR REGISTROS IN (SELECT PCMOV.CODPROD
                            ,ESTOQUECONTABIL.CODFILIAL  CODFILIALCONTABIL
                            ,ESTOQUEGERENCIAL.CODFILIAL CODFILIALGERENCIAL
                            ,PCMOV.CODFILIAL            CODFILIALVENDA
                             -- Dados da nota fiscal
                            ,PCMOV.CODOPER,
                             PCMOV.DESCRICAO,
                             PCMOV.STATUS,
                             PCMOV.ROWID NOTA_ROWID,
                             ABS(DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0))) NOTA_QT,
                             ABS(NVL(PCMOV.QTCONT, 0)) NOTA_QTCONT,
                             ABS(NVL(PCMOV.QTAVARIA, 0)) NOTA_QTAVARIA,
                             ABS(NVL(PCMOV.QTBLOQUEADA, 0)) NOTA_QTBLOQUEADA,
                             NVL(ESTOQUEGERENCIAL.QTRESERV, 0) ESTOQUERESERVADO
                             ----------------------------------------------------------
                            ,NVL(PCMOV.MOVESTOQUEGERENCIAL,DECODE(PCMOV.STATUS, 'A', 'N', 'S')) MOVESTOQUEGERENCIAL,
                             NVL(PCMOV.MOVESTOQUECONTABIL,DECODE(PCMOV.STATUS, 'B', 'N', 'S')) MOVESTOQUECONTABIL
                            ,PCMOV.CODDEPOSITO
                            ,PCMOV.DATAESTOQUE
                            ,PCMOV.DTMOV
                        FROM PCMOV,
                             PCEST ESTOQUEGERENCIAL
                            ,PCEST ESTOQUECONTABIL
                       WHERE PCMOV.CODPROD = ESTOQUEGERENCIAL.CODPROD
                         AND PCMOV.CODPROD = ESTOQUECONTABIL.CODPROD
                         AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = ESTOQUECONTABIL.CODFILIAL
                         AND NVL(PCMOV.CODFILIALRETIRA, PCMOV.CODFILIAL) = ESTOQUEGERENCIAL.CODFILIAL
                         AND PCMOV.NUMTRANSVENDA = pnNUMTRANSACAO
                         AND (NVL(pnCODPROD, 0) = 0 OR PCMOV.CODPROD = pnCODPROD)
                         AND ((psECANCELAMENTO = 'S' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) < 0 ) OR
                             (psECANCELAMENTO = 'N' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) > 0))
                         AND SUBSTR(CODOPER,1,1) IN ('S','R')
                    ORDER BY PCMOV.CODPROD, PCMOV.NUMSEQ)
    LOOP
      vnCODIGOPRODUTO := REGISTROS.CODPROD;

      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (Logistica Saída Prod): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROS = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (Logistica Saída Prod): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG       := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL             := REGISTROS.CODFILIALVENDA;
      P_INTERNO.CODPROD               := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Validando quantidade informada
      IF (REGISTROS.NOTA_QT <= 0) THEN
        P_INTERNO.MSG_RETORNO := 'Erro 4 (Logistica Saída Prod): Quantidade declarada na transação não pode ser menor/igual a zero.' ||CHR(13)||
                                 'Produto: '||TO_CHAR(REGISTROS.CODPROD) ||' '|| REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
      --
      IF REGISTROS.STATUS IN ('B','AB') THEN
        REGISTROS.MOVESTOQUEGERENCIAL := 'S';
      ELSE
        REGISTROS.MOVESTOQUEGERENCIAL := 'N';
      END IF;
      --
      IF REGISTROS.STATUS IN ('A','AB') THEN
        REGISTROS.MOVESTOQUECONTABIL := 'S';
      ELSE
        REGISTROS.MOVESTOQUECONTABIL := 'N';
      END IF;
      --
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      -- Carregando campos estoque contábil
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') OR (REGISTROS.MOVESTOQUECONTABIL = 'S')  THEN
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnNUMTRANSACAO;
        P_INTERNO.vtESTOQUE.CODFILIAL     := REGISTROS.CODFILIALGERENCIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := REGISTROS.CODPROD;
        --
        IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
          P_INTERNO.vtESTOQUE.QTESTGER    := REGISTROS.NOTA_QT;
        END IF;
        --
        IF REGISTROS.MOVESTOQUECONTABIL = 'S' THEN
          P_INTERNO.vtESTOQUE.QTEST       := REGISTROS.NOTA_QTCONT;
        END IF;
        --
        P_INTERNO.vtESTOQUE.QTINDENIZ     := REGISTROS.NOTA_QTAVARIA;
        P_INTERNO.vtESTOQUE.QTBLOQUEADA   := REGISTROS.NOTA_QTBLOQUEADA;
        -- Atualizar estoques
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      --
      END IF;
      -- Administrar estoque depósito
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S')  THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'I';
        END IF;
        -- Atualizar variáveis internas
        P_INTERNO.PROCESSO       := 'VENDER';
        P_INTERNO.CODFILIAL      := REGISTROS.CODFILIALGERENCIAL;
        P_INTERNO.ROWID_REGISTRO := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO    := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD        := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER       := REGISTROS.NOTA_QT;
        -- Administrar estoque do depósito

        PRIV_DEP_VENDAS_SAIDA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;

    PRIV_ATUALIZAR_CUSTO (pnNUMTRANSACAO,'S');
	-- Validando se tem registros
    IF vnCONTADORREGISTROS > 0 THEN
      IF (psECANCELAMENTO = 'S') THEN
        UPDATE PCNFSAID
           SET PCT_ESTOQUE = 'S',
               PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      ELSE
        UPDATE PCNFSAID
           SET PCT_ESTOQUE = 'S',
               PCT_ESTOQUE_CANCELAMENTO = 'N'
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      END IF;
    -- Validando se tem registros
    ELSIF vnCONTADORREGISTROS = 0 THEN
      UPDATE PCNFSAID
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      P_INTERNO.MSG_RETORNO := 'Erro 5 (Logistica Saída Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                               'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - LOGISTICA_SAIDA_PROD';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnContadorRegistros;
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 6 (Logistica Saída Prod): '||CHR(13)||
                       'Produto: ' || TO_CHAR(vnCODIGOPRODUTO) || CHR(13) ||
                       'Msg. original: '||SQLERRM;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 0;
  -- Função
  END LOGISTICA_SAIDA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Iago Souza        0                   Criada a função
  *************************************************************************************************************************/
  FUNCTION LOGISTICA_ENTRADA_PROD (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                                  ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                                  ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                  ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vsOPERACAO                PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE;
    vnCONTADORREGISTROS       NUMBER;
    vnDTMOVPRIMERIO           DATE;
    vnCODIGOPRODUTO           PCMOV.CODPROD%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Iniciando variaveis
    vnCONTADORREGISTROS       := 0;
    vnCODIGOPRODUTO           := 0;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := 'OK';
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - LOGISTICA_ENTRADA_PROD';
    P_INTERNO.NOME_FUNCAO     := 'LOGISTICA_ENTRADA_PROD';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.NUMTRANSENT     := pnNUMTRANSACAO;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Validar transação
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Logistica Entrada Prod): O numtransação informado não é valido'||CHR(13)||
                       'Identificador: '||pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    -- Atualizar operação
    vsOPERACAO := 'I';
    IF psECANCELAMENTO = 'S' THEN
      vsOPERACAO := 'B';
    END IF;
    -- Lista de produtos
    FOR REGISTROS IN (SELECT PCMOV.CODPROD -- Dados do estoque
                            ,ESTOQUECONTABIL.CODFILIAL  CODFILIALCONTABIL
                            ,ESTOQUEGERENCIAL.CODFILIAL CODFILIALGERENCIAL
                            ,PCMOV.CODFILIAL            CODFILIALVENDA
                             -- Dados da nota fiscal
                            ,PCMOV.CODOPER,
                             PCMOV.DESCRICAO,
                             PCMOV.STATUS,
                             PCMOV.ROWID NOTA_ROWID,
                             ABS(DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0))) NOTA_QT,
                             ABS(NVL(PCMOV.QTCONT, 0)) NOTA_QTCONT,
                             ABS(NVL(PCMOV.QTAVARIA, 0)) NOTA_QTAVARIA,
                             ABS(NVL(PCMOV.QTBLOQUEADA, 0)) NOTA_QTBLOQUEADA,
                             NVL(ESTOQUEGERENCIAL.QTRESERV, 0) ESTOQUERESERVADO
                             ----------------------------------------------------------
                            ,NVL(PCMOV.MOVESTOQUEGERENCIAL,DECODE(PCMOV.STATUS, 'A', 'N', 'S')) MOVESTOQUEGERENCIAL,
                             NVL(PCMOV.MOVESTOQUECONTABIL,DECODE(PCMOV.STATUS, 'B', 'N', 'S')) MOVESTOQUECONTABIL
                            ,PCMOV.CODDEPOSITO
                            ,PCMOV.DATAESTOQUE
                            ,PCMOV.DTMOV
                        FROM PCMOV,
                             PCEST ESTOQUEGERENCIAL
                            ,PCEST ESTOQUECONTABIL
                       WHERE PCMOV.CODPROD = ESTOQUEGERENCIAL.CODPROD
                         AND PCMOV.CODPROD = ESTOQUECONTABIL.CODPROD
                         AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = ESTOQUECONTABIL.CODFILIAL
                         AND NVL(PCMOV.CODFILIALRETIRA, PCMOV.CODFILIAL) = ESTOQUEGERENCIAL.CODFILIAL
                         AND PCMOV.NUMTRANSENT = pnNUMTRANSACAO
                         AND (NVL(pnCODPROD, 0) = 0 OR PCMOV.CODPROD = pnCODPROD)
                         AND ((psECANCELAMENTO = 'S' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) < 0 ) OR
                             (psECANCELAMENTO = 'N' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) > 0))
                         AND PCMOV.CODOPER LIKE 'E%'
                    ORDER BY PCMOV.CODPROD, PCMOV.NUMSEQ)
    LOOP
      vnCODIGOPRODUTO := REGISTROS.CODPROD;

      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (LOGISTICA_ENTRADA_PROD): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROS = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (LOGISTICA_ENTRADA_PROD): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG       := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL             := REGISTROS.CODFILIALVENDA;
      P_INTERNO.CODPROD               := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Validando quantidade informada
      IF (REGISTROS.NOTA_QT <= 0) THEN
        psMSG_RETORNO := 'Erro 4 (Logistica Entrada Prod): Quantidade declarada na transação não pode ser menor/igual a zero.' ||CHR(13) ||
                         'Produto: ' || TO_CHAR(REGISTROS.CODPROD) || ' ' ||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
      -- Mov. Gerencial?
      IF REGISTROS.STATUS IN ('B','AB') THEN
        REGISTROS.MOVESTOQUEGERENCIAL := 'S';
      ELSE
        REGISTROS.MOVESTOQUEGERENCIAL := 'N';
      END IF;
      -- Mov. Contábil?
      IF REGISTROS.STATUS IN ('A','AB') THEN
        REGISTROS.MOVESTOQUECONTABIL := 'S';
      ELSE
        REGISTROS.MOVESTOQUECONTABIL := 'N';
      END IF;
      -- Atualizar contador
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      -- Carregando campos estoque contábil
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') OR (REGISTROS.MOVESTOQUECONTABIL = 'S')  THEN
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnNUMTRANSACAO;
        P_INTERNO.vtESTOQUE.CODFILIAL     := REGISTROS.CODFILIALGERENCIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := REGISTROS.CODPROD;
        --
        IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
          P_INTERNO.vtESTOQUE.QTESTGER    := REGISTROS.NOTA_QT;
        END IF;
        --
        IF REGISTROS.MOVESTOQUECONTABIL = 'S' THEN
          P_INTERNO.vtESTOQUE.QTEST       := REGISTROS.NOTA_QTCONT;
        END IF;
        --
        P_INTERNO.vtESTOQUE.QTINDENIZ     := REGISTROS.NOTA_QTAVARIA;
        P_INTERNO.vtESTOQUE.QTBLOQUEADA   := REGISTROS.NOTA_QTBLOQUEADA;
        -- Atualizar estoque
        P_INTERNO.TIPO_OPERACAO := vsOPERACAO;
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      END IF;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        END IF;
        -- Atualizar variáveis para movimentar depósito
        P_INTERNO.PROCESSO         := 'VENDER';
        P_INTERNO.CODFILIAL        := REGISTROS.CODFILIALGERENCIAL;
        P_INTERNO.ROWID_REGISTRO   := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER         := REGISTROS.NOTA_QT;
        P_INTERNO.QTBLOQUEADA      := REGISTROS.NOTA_QTBLOQUEADA;
        P_INTERNO.QTINDENIZ        := REGISTROS.NOTA_QTAVARIA;
        -- Administrar estoque do depósito
        PRIV_DEP_VENDAS_ENTRADA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;

    PRIV_ATUALIZAR_CUSTO (pnNUMTRANSACAO,'E');
	-- Validando se tem registros
  IF vnCONTADORREGISTROS > 0 THEN
       IF (psECANCELAMENTO = 'S') THEN
         UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
             PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
      ELSE
        UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'N'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
      END IF;
  ELSE
      -- Validando se tem registros
      UPDATE PCNFENT
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSENT = pnNUMTRANSACAO;

      psMSG_RETORNO := 'Erro 5 (Logistica Entrada Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;

    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - LOGISTICA_ENTRADA_PROD';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADORREGISTROS;
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 6 (Logistica Entrada Prod): '||CHR(13)||
                       'Produto: ' || TO_CHAR(vnCODIGOPRODUTO) || CHR(13) ||
                       'Msg. original: '||SQLERRM;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 0;
  -- Função
  END LOGISTICA_ENTRADA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Iago Souza        0                   Criada a função
  *************************************************************************************************************************/
  FUNCTION LOGISTICA_SAIDA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                           ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                           ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - LOGISTICA_SAIDA';
    P_INTERNO.NOME_FUNCAO     := 'LOGISTICA_SAIDA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Executar função
    RETURN LOGISTICA_SAIDA_PROD (pnNUMTRANSACAO,0,psECANCELAMENTO,psMSG_RETORNO);
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - LOGISTICA_SAIDA';
    PRIV_GERARLOG;
  -- Função
  END LOGISTICA_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  30/05/2019     Iago Souza        0                   Criada função para validar se o usuário tem permissão de acesso valida
  *************************************************************************************************************************/
  FUNCTION LOGISTICA_ENTRADA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                             ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                             ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    CURSOR BLOQUEIA_ESTOQUE_TRNASACAO
    IS
     SELECT distinct CODPROD, CODFILIAL FROM PCMOV WHERE NUMTRANSENT = pnNUMTRANSACAO ORDER BY CODPROD;

    vnTENTATIVA NUMBER := 0;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - LOGISTICA_ENTRADA';
    P_INTERNO.NOME_FUNCAO     := 'LOGISTICA_ENTRADA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Bloqueando o Estoque para a transação
    WHILE (vnTENTATIVA < 5) LOOP
      BEGIN
        FOR REGISTROS IN BLOQUEIA_ESTOQUE_TRNASACAO
        LOOP
          SELECT CODPROD
            INTO vnTENTATIVA
            FROM PCEST
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIAL
             FOR UPDATE;
           vnTENTATIVA := 0;
        END LOOP;
        vnTENTATIVA := 5;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 1 - LOGISTICA_ENTRADA: Verifique os dados informados!'||CHR(13)||
                           '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                           '2 - Os dados informados podem não ser validos!'||CHR(13)||
                           'TRANSAÇÃO: '||pnNUMTRANSACAO||' - '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          vnTENTATIVA := vnTENTATIVA + 1;
      END;
    END LOOP;
    IF psMSG_RETORNO = 'OK' THEN
      RETURN LOGISTICA_ENTRADA_PROD (pnNUMTRANSACAO,0,psECANCELAMENTO,psMSG_RETORNO);
    ELSE
      RETURN 0;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Falha ao bloquear produtos na função - LOGISTICA_ENTRADA';
      PRIV_GERARLOG;
    END IF;
  -- Função
  END LOGISTICA_ENTRADA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION MOVIMENTACAO_BENEFIC_ENTRADA (pnNUMTRANSENT    IN PCMOV.NUMTRANSENT%TYPE
                                        ,psECANCELAMENTO  IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADOR                NUMBER := 0;
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - MOVIMENTACAO_BENEFIC_ENTRADA';
    P_INTERNO.NOME_FUNCAO     := 'MOVIMENTACAO_BENEFIC_ENTRADA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSENT;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Lista de produtos
    FOR REGISTRO IN (SELECT PCEST.ROWID LINHA,
                            PCMOV.NUMTRANSENT TRANSACAO,
                            NVL(PCMOV.QT, 0) QT,
                            PCMOV.CODPROD,
                            PCMOV.CODFILIAL,
                            NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA,
                            NVL(PCMOV.QTAVARIA, 0) QTAVARIA,
                            NVL(PCMOV.QTCONT, 0) QTCONT,
                            PCMOV.CODOPER,
                            NVL(PCMOV.MOVESTOQUEGERENCIAL,(CASE
                                                             WHEN ((PCMOV.CODOPER IN ('ET', 'EG')) AND
                                                                   (NVL(PCMOV.STATUS, 'X') IN ('B', 'AB'))) THEN
                                                              'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUEGERENCIAL,
                            NVL(PCMOV.MOVESTOQUECONTABIL,(CASE
                                                            WHEN ((PCMOV.CODOPER IN ('EG')) AND
                                                                 (NVL(PCMOV.STATUS, 'X') IN ('AB'))) THEN
                                                             'S'
                                                          ELSE
                                                            'N'
                                                          END)) MOVESTOQUECONTABIL,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') AUTOSERVICO,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'),'N') BLOQESTOQUETRANSF,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') ACEITAVENDABALCAOESTNEG
                           ,PCMOV.CODDEPOSITO
                           ,PCMOV.ROWID NOTA_ROWID
                           ,PCMOV.DATAESTOQUE
                           ,PCMOV.DTMOV
                       FROM PCMOV
                           ,PCEST
                      WHERE PCMOV.DTCANCEL IS NULL
                        AND PCMOV.NUMTRANSENT = pnNUMTRANSENT
                        AND PCMOV.STATUS IN ('B', 'AB')
                        AND PCMOV.CODOPER IN ('ET', 'EG')
                        AND PCMOV.CODPROD = PCEST.CODPROD
                        AND PCMOV.CODFILIAL = PCEST.CODFILIAL
                   ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTRO.DATAESTOQUE IS NOT NULL THEN
          RETURN 0;
        END IF;
        -- Verificando se o transacao ja foi alterada
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTRO.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTRO.DTMOV THEN
          RETURN 0;
        END IF;
        --
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG     := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL           := REGISTRO.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTRO.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTRO.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTRO.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      --
      IF REGISTRO.CODOPER IN ('ET', 'EG') THEN
        vnCONTADOR := vnCONTADOR + 1;
        UPDATE PCEST
           SET PCEST.IDENTIFICADOR = pnNUMTRANSENT,
               PCEST.QTEST = CASE
                               WHEN psECANCELAMENTO = 'N' THEN
                                 NVL(PCEST.QTEST, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             ELSE
                               NVL(PCEST.QTEST, 0) - DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             END,
               PCEST.QTESTGER = CASE
                                  WHEN psECANCELAMENTO = 'N' THEN
                                    NVL(PCEST.QTESTGER, 0) + DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                ELSE
                                  NVL(PCEST.QTESTGER, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                END,
               PCEST.QTBLOQUEADA = GREATEST(CASE
                                              WHEN psECANCELAMENTO = 'N' THEN
                                                CASE
                                                  WHEN REGISTRO.LIBERAESTENTMERC = 'N' THEN
                                                    NVL(PCEST.QTBLOQUEADA, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTBLOQUEADA,0)
                                                ELSE
                                                  PCEST.QTBLOQUEADA
                                                END
                                            ELSE
                                              NVL(PCEST.QTBLOQUEADA, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QTBLOQUEADA,0)
                                            END,
                                            0),
               PCEST.QTINDENIZ = GREATEST(CASE
                                            WHEN psECANCELAMENTO = 'N' THEN
                                              CASE
                                                WHEN REGISTRO.LIBERAESTENTMERC = 'N' THEN
                                                  NVL(PCEST.QTINDENIZ, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTAVARIA,0)
                                              ELSE
                                                PCEST.QTINDENIZ
                                              END
                                            ELSE
                                              NVL(PCEST.QTINDENIZ, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QTAVARIA,0)
                                          END,
                                         0),
         PCEST.DTHORAULTALTDISP = DECODE(REGISTRO.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
         WHERE PCEST.ROWID = REGISTRO.LINHA;
      --
      END IF;
      -- Administrar estoque depósito
      IF REGISTRO.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        END IF;
        -- Atualizar variáveis para movimentar depósito
        P_INTERNO.PROCESSO         := 'COMPRAR';
        P_INTERNO.CODFILIAL        := REGISTRO.CODFILIAL;
        P_INTERNO.ROWID_REGISTRO   := REGISTRO.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTRO.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTRO.CODPROD;
        P_INTERNO.QTESTGER         := REGISTRO.QT;
        P_INTERNO.QTBLOQUEADA      := REGISTRO.QTBLOQUEADA;
        P_INTERNO.QTINDENIZ        := REGISTRO.QTAVARIA;
        -- Administrar estoque do depósito
        PRIV_DEP_COMPRAS_ENTRADA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTRO.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - MOVIMENTACAO_BENEFIC_ENTRADA';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADOR;
  -- Função
  END MOVIMENTACAO_BENEFIC_ENTRADA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION MOVIMENTACAO_BENEFIC_SAIDA (pnNUMTRANSVENDA  IN PCMOV.NUMTRANSVENDA%TYPE
                                      ,psECANCELAMENTO  IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADOR                NUMBER := 0;
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - MOVIMENTACAO_BENEFIC_SAIDA';
    P_INTERNO.NOME_FUNCAO     := 'MOVIMENTACAO_BENEFIC_SAIDA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSVENDA;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;

  IF psECANCELAMENTO = 'N' THEN
      P_INTERNO.TIPO_OPERACAO := 'B';
    END IF;


    -- Lista de produtos
    FOR REGISTRO IN (SELECT PCEST.ROWID LINHA,
                            PCMOV.NUMTRANSVENDA TRANSACAO,
                            NVL(PCMOV.QT, 0) QT,
                            NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA,
                            NVL(PCMOV.QTCONT, 0) QTCONT,
                            PCMOV.CODFILIAL,
                            PCMOV.CODPROD,
                            PCMOV.CODOPER,
                            NVL(PCMOV.MOVESTOQUEGERENCIAL,(CASE
                                                             WHEN ((PCMOV.CODOPER IN ('SN', 'ST')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('AB', 'B'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUEGERENCIAL,
                            NVL(PCMOV.MOVESTOQUECONTABIL, (CASE
                                                             WHEN ((PCMOV.CODOPER IN ('SN')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('AB'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUECONTABIL,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') AUTOSERVICO,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'),'N') BLOQESTOQUETRANSF,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') ACEITAVENDABALCAOESTNEG
                           ,PCMOV.CODDEPOSITO
                           ,PCMOV.ROWID NOTA_ROWID
                           ,PCMOV.DATAESTOQUE
                           ,PCMOV.DTMOV
                       FROM PCMOV
                           ,PCEST
                      WHERE PCMOV.DTCANCEL IS NULL
                        AND PCMOV.NUMTRANSVENDA = pnNUMTRANSVENDA
                        AND PCMOV.STATUS IN ('AB', 'B')
                        AND PCMOV.CODOPER IN ('SN', 'ST')
                        AND PCMOV.CODPROD = PCEST.CODPROD
                        AND PCMOV.CODFILIAL = PCEST.CODFILIAL
                   ORDER BY PCMOV.CODPROD,PCMOV.NUMSEQ)
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTRO.DATAESTOQUE IS NOT NULL THEN
          RETURN 0;
        END IF;
        -- Verificando se o transacao ja foi alterada
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTRO.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTRO.DTMOV THEN
          RETURN 0;
        END IF;
        --
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG     := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL           := REGISTRO.CODFILIAL;
      P_INTERNO.CODPROD             := REGISTRO.CODPROD;
      P_INTERNO.ROWID_REGISTRO      := REGISTRO.NOTA_ROWID;
      P_INTERNO.CODDEPOSITO         := REGISTRO.CODDEPOSITO;
      P_INTERNO.QTESTGER            := REGISTRO.QT;
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTRO.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL  := REGISTRO.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Validando o tipo de processo
      IF REGISTRO.CODOPER IN ('SN', 'ST') THEN
        -- Atualizando contador
        vnCONTADOR := vnCONTADOR + 1;
        -- Atualizando dados na PCEST
        UPDATE PCEST
           SET PCEST.IDENTIFICADOR = pnNUMTRANSVENDA,
               PCEST.QTEST = CASE
                               WHEN psECANCELAMENTO = 'N' THEN
                                 NVL(PCEST.QTEST, 0) - DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             ELSE
                               NVL(PCEST.QTEST, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             END,
               PCEST.QTESTGER = CASE
                                  WHEN psECANCELAMENTO = 'N' THEN
                                    NVL(PCEST.QTESTGER, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                ELSE
                                  NVL(PCEST.QTESTGER, 0) + DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                END,
         PCEST.DTHORAULTALTDISP = DECODE(REGISTRO.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
         WHERE PCEST.ROWID = REGISTRO.LINHA;
      -- Validação do tipo de processo
      END IF;
      -- Administrar estoque depósito
      IF REGISTRO.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'I';
        END IF;
        P_INTERNO.PROCESSO := 'COMPRAR';
        -- Administrar estoque do depósito
        PRIV_DEP_COMPRAS_SAIDA;
        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTRO.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'FINALIZOU A FUNÇÃO - MOVIMENTACAO_BENEFIC_SAIDA';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADOR;
  -- Função
  END MOVIMENTACAO_BENEFIC_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Fernando Carmo    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION MOVIMENTACAO_BENEFICIAMENTO (pnNUMTRANSENT    IN PCMOV.NUMTRANSENT%TYPE
                                       ,pnNUMTRANSVENDA  IN PCMOV.NUMTRANSVENDA%TYPE
                                       ,psECANCELAMENTO  IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADOR                NUMBER := 0;
    vnCONTADORREGISTROSPCMOV  NUMBER := 0;
    vnDTMOVPRIMERIO           DATE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - MOVIMENTACAO_BENEFICIAMENTO';
    P_INTERNO.NOME_FUNCAO     := 'MOVIMENTACAO_BENEFICIAMENTO';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSVENDA;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Lista de produtos
    FOR REGISTRO IN (SELECT PCEST.ROWID LINHA,
                            PCMOV.NUMTRANSENT TRANSACAO,
                            PCMOV.CODFILIAL,
                            PCMOV.CODPROD,
                            NVL(PCMOV.QT, 0) QT,
                            NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA,
                            NVL(PCMOV.QTCONT, 0) QTCONT,
                            PCMOV.CODOPER,
                            NVL(PCMOV.MOVESTOQUEGERENCIAL,(CASE
                                                             WHEN ((PCMOV.CODOPER IN ('ET', 'EG')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('B', 'AB'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUEGERENCIAL,
                            NVL(PCMOV.MOVESTOQUECONTABIL, (CASE
                                                             WHEN ((PCMOV.CODOPER IN ('EG')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('AB'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUECONTABIL,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') AUTOSERVICO,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'),'N') BLOQESTOQUETRANSF,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') ACEITAVENDABALCAOESTNEG
                           ,PCMOV.CODDEPOSITO
                           ,PCMOV.ROWID NOTA_ROWID
                           ,PCMOV.DATAESTOQUE
                           ,PCMOV.DTMOV
                       FROM PCMOV
                           ,PCEST
                      WHERE PCMOV.DTCANCEL IS NULL
                        AND PCMOV.CODPROD = PCEST.CODPROD
                        AND PCMOV.CODFILIAL = PCEST.CODFILIAL
                        AND PCMOV.NUMTRANSENT = pnNUMTRANSENT
                     UNION
                     SELECT PCEST.ROWID LINHA,
                            PCMOV.NUMTRANSVENDA TRANSACAO,
                            PCMOV.CODFILIAL,
                            PCMOV.CODPROD,
                            NVL(PCMOV.QT, 0) QT,
                            NVL(PCMOV.QTBLOQUEADA, 0) QTBLOQUEADA,
                            NVL(PCMOV.QTCONT, 0) QTCONT,
                            PCMOV.CODOPER,
                            NVL(PCMOV.MOVESTOQUEGERENCIAL,(CASE
                                                             WHEN ((PCMOV.CODOPER IN ('SN', 'ST')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('AB', 'B'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUEGERENCIAL,
                            NVL(PCMOV.MOVESTOQUECONTABIL, (CASE
                                                             WHEN ((PCMOV.CODOPER IN ('SN')) AND
                                                                  (NVL(PCMOV.STATUS, 'X') IN ('AB'))) THEN
                                                               'S'
                                                           ELSE
                                                             'N'
                                                           END)) MOVESTOQUECONTABIL,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') AUTOSERVICO,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('LIBERAESTENTMERC',NVL(PCMOV.CODFILIALNF,PCMOV.CODFILIAL)),'N') LIBERAESTENTMERC,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_BLOQESTOQUETRANSF'),'N') BLOQESTOQUETRANSF,
                            NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') ACEITAVENDABALCAOESTNEG
                           ,PCMOV.CODDEPOSITO
                           ,PCMOV.ROWID NOTA_ROWID
                           ,PCMOV.DATAESTOQUE
                           ,PCMOV.DTMOV
                       FROM PCMOV
                           ,PCEST
                      WHERE PCMOV.DTCANCEL IS NULL
                        AND PCMOV.CODPROD = PCEST.CODPROD
                        AND PCMOV.CODFILIAL = PCEST.CODFILIAL
                        AND (PCMOV.NUMTRANSVENDA = pnNUMTRANSVENDA OR
                             ((NVL(PCMOV.NUMTRANSVENDA, 0) > 0 AND
                              (NVL(PCMOV.NUMTRANSENT, 0) = pnNUMTRANSENT)))))
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTRO.DATAESTOQUE IS NOT NULL THEN
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTRO.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTRO.DTMOV THEN
          RETURN 0;
        END IF;
        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;
      -- Validando se o tipo de processo é saída de transferencia
      IF REGISTRO.CODOPER IN ('SN', 'ST') THEN
        vnCONTADOR := vnCONTADOR + 1;
        UPDATE PCEST
           SET PCEST.IDENTIFICADOR = pnNUMTRANSVENDA,
               PCEST.QTEST = CASE
                               WHEN psECANCELAMENTO = 'N' THEN
                                 NVL(PCEST.QTEST, 0) - DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             ELSE
                               NVL(PCEST.QTEST, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                             END,
               PCEST.QTESTGER = CASE
                                  WHEN psECANCELAMENTO = 'N' THEN
                                    NVL(PCEST.QTESTGER, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                ELSE
                                  NVL(PCEST.QTESTGER, 0) + DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                END,
         PCEST.DTHORAULTALTDISP = DECODE(REGISTRO.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
         WHERE PCEST.ROWID = REGISTRO.LINHA;
        -- Administrar estoque depósito
        IF REGISTRO.MOVESTOQUEGERENCIAL = 'S' THEN
          -- Atualizar variável para movimentar depósito
          IF psECANCELAMENTO = 'S' THEN
            P_INTERNO.TIPO_OPERACAO := 'I';
      ELSE
        P_INTERNO.TIPO_OPERACAO := 'B';
          END IF;
          P_INTERNO.PROCESSO := 'COMPRAR';
      P_INTERNO.MOVESTOQUEGERENCIAL := REGISTRO.MOVESTOQUEGERENCIAL;
          P_INTERNO.MOVESTOQUECONTABIL  := REGISTRO.MOVESTOQUECONTABIL;
          P_INTERNO.CODFILIAL           := REGISTRO.CODFILIAL;
          P_INTERNO.CODPROD             := REGISTRO.CODPROD;
          P_INTERNO.ROWID_REGISTRO      := REGISTRO.NOTA_ROWID;
          P_INTERNO.CODDEPOSITO         := REGISTRO.CODDEPOSITO;
          P_INTERNO.QTESTGER            := REGISTRO.QT;
          P_INTERNO.QTBLOQUEADA         := REGISTRO.QTBLOQUEADA;
          -- Administrar estoque do depósito
          PRIV_DEP_COMPRAS_SAIDA;
          -- Erro na administração do estoque depósito
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 0;
          END IF;
        -- Administração depósito
        END IF;
      -- Caso não seja saída de transferência
      ELSE
        -- Caso o tipo de processo seja entrada de transferência
        IF REGISTRO.CODOPER IN ('ET', 'EG') THEN
          -- Atualizando o contador
          vnCONTADOR := vnCONTADOR + 1;
          -- Atualizando os dados na PCEST
          UPDATE PCEST
             SET PCEST.IDENTIFICADOR = pnNUMTRANSENT,
                 PCEST.QTEST = CASE
                                 WHEN psECANCELAMENTO = 'N' THEN
                                   NVL(PCEST.QTEST, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                               ELSE
                                 NVL(PCEST.QTEST, 0) - DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTCONT,0)
                               END,
                 PCEST.QTESTGER = CASE
                                    WHEN psECANCELAMENTO = 'N' THEN
                                      NVL(PCEST.QTESTGER, 0) + DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                  ELSE
                                    NVL(PCEST.QTESTGER, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QT,0)
                                  END,
                 PCEST.QTBLOQUEADA = GREATEST(CASE
                                                WHEN psECANCELAMENTO = 'N' THEN
                                                  CASE
                                                    WHEN REGISTRO.LIBERAESTENTMERC = 'N' THEN
                                                      NVL(PCEST.QTBLOQUEADA, 0) + DECODE(REGISTRO.MOVESTOQUECONTABIL,'S',REGISTRO.QTBLOQUEADA,0)
                                                  ELSE
                                                    PCEST.QTBLOQUEADA
                                                  END
                                              ELSE
                                                NVL(PCEST.QTBLOQUEADA, 0) - DECODE(REGISTRO.MOVESTOQUEGERENCIAL,'S',REGISTRO.QTBLOQUEADA,0)
                                              END,
                                              0),
         PCEST.DTHORAULTALTDISP = DECODE(REGISTRO.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
           WHERE PCEST.ROWID = REGISTRO.LINHA;
        -- Atualização da PCEST
        END IF;
        -- Administrar estoque depósito
        IF REGISTRO.MOVESTOQUEGERENCIAL = 'S' THEN
          -- Atualizar variável para movimentar depósito
          IF psECANCELAMENTO = 'S' THEN
            P_INTERNO.TIPO_OPERACAO := 'B';
          ELSE
            P_INTERNO.TIPO_OPERACAO := 'I';
          END IF;
          -- Administrar estoque do depósito
          P_INTERNO.PROCESSO            := 'COMPRAR';
          P_INTERNO.MOVESTOQUEGERENCIAL := REGISTRO.MOVESTOQUEGERENCIAL;
          P_INTERNO.MOVESTOQUECONTABIL  := REGISTRO.MOVESTOQUECONTABIL;
          P_INTERNO.CODFILIAL           := REGISTRO.CODFILIAL;
          P_INTERNO.CODPROD             := REGISTRO.CODPROD;
          P_INTERNO.ROWID_REGISTRO      := REGISTRO.NOTA_ROWID;
          P_INTERNO.CODDEPOSITO         := REGISTRO.CODDEPOSITO;
          P_INTERNO.QTESTGER            := REGISTRO.QT;
          P_INTERNO.QTBLOQUEADA         := REGISTRO.QTBLOQUEADA;
          PRIV_DEP_COMPRAS_ENTRADA;
          -- Erro na administração do estoque depósito
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 0;
          END IF;
        -- Administração depósito
        END IF;
      -- Validação do tipo de processo
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTRO.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - MOVIMENTACAO_BENEFICIAMENTO';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADOR;
  -- Função
  END MOVIMENTACAO_BENEFICIAMENTO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  18/11/2015   Rodrigo Santos      0.119485.2015       Migrados os métodos "ORIGEM_TRANSFERENCIA" e "TIPO_TRANSFERENCIA" para a package PKG_ESTOQUE.
  *************************************************************************************************************************/
  FUNCTION ORIGEM_TRANSFERENCIA (pnNUMTRANSTRANSF IN PCMOV.NUMTRANSVENDA%TYPE)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnREGTRANSFDEP      NUMBER(10);
    vnREGTRANSFDEPDEVOL NUMBER(10);
    vnNUMPEDTV10        PCPEDC.NUMPED%TYPE;
    vsCODOPER           PCMOV.CODOPER%TYPE;
    vsMSG_RETORNO       VARCHAR2(30);
  BEGIN
    -- Testar se a nf é de transferencia de filial retira (1436 ou 1470)
    BEGIN
      SELECT COUNT(1)
        INTO vnREGTRANSFDEP
        FROM PCTRANSFDEP
       WHERE PCTRANSFDEP.NUMTRANSTRANSFSAIDA = pnNUMTRANSTRANSF;
      SELECT COUNT(1)
        INTO vnREGTRANSFDEPDEVOL
        FROM PCTRANSFDEPDEVOL
       WHERE PCTRANSFDEPDEVOL.NUMTRANSTRANSFSAIDA = pnNUMTRANSTRANSF;
    EXCEPTION
      WHEN OTHERS THEN
        vnREGTRANSFDEP      := 0;
        vnREGTRANSFDEPDEVOL := 0;
    END;
    -- Validando se a origem é filial retira
    IF (vnREGTRANSFDEP > 0) OR (vnREGTRANSFDEPDEVOL > 0) THEN
      vsMSG_RETORNO := 'RETIRA';
    END IF;
    -- Testar se a nf é de transferencia tv10 (316)
    BEGIN
      SELECT NVL(NUMPED, 0)
        INTO vnNUMPEDTV10
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = pnNUMTRANSTRANSF
         AND CONDVENDA = 10;
    EXCEPTION
      WHEN OTHERS THEN
        vnNUMPEDTV10 := 0;
    END;
    -- Validando se a origem é venda TV10
    IF (vnREGTRANSFDEP = 0) AND (vnREGTRANSFDEPDEVOL = 0) AND
       (vnNUMPEDTV10 <> 0) THEN
      vsMSG_RETORNO := 'TV10';
    END IF;
    -- Testar se a nf é de transferencia de filial virtual (1419 ou 1423)
    BEGIN
      SELECT CODOPER
        INTO vsCODOPER
        FROM PCMOV
       WHERE NUMTRANSVENDA = pnNUMTRANSTRANSF
         AND ROWNUM = 1;
    EXCEPTION
      WHEN OTHERS THEN
        vsCODOPER := 'X';
    END;
    -- Validando se a origem é virtual
    IF (vnREGTRANSFDEP = 0) AND (vnREGTRANSFDEPDEVOL = 0) AND
       (vnNUMPEDTV10 = 0) AND ((vsCODOPER = 'ET') OR (vsCODOPER = 'ST')) THEN
      vsMSG_RETORNO := 'VIRTUAL';
    END IF;
    -- Caso não tenha origem definida
    IF NVL(vsMSG_RETORNO, 'X') = 'X' THEN
      vsMSG_RETORNO := 'NÃO É TRANSFERÊNCIA';
    END IF;
    RETURN vsMSG_RETORNO;
  -- Função
  END ORIGEM_TRANSFERENCIA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função Incluir item na pendencia
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  ************************************************************************************************************************/
  FUNCTION PENDENTE_INCLUIR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                            ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                            ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                            ,pbPEDIDO          IN BOOLEAN
                            ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                            ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADOR              NUMBER;
    vnQT                    PCPEDI.QT%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PENDENTE_INCLUIR';
    P_INTERNO.NOME_FUNCAO     := 'PENDENTE_INCLUIR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Validando se a chamada é direta.
    -- Caso Não: Validar se o item do pedido pode ser colocado no estoque pendente
    IF NOT (pbPEDIDO) THEN
      -- Verificar se existe o pedido
      BEGIN
        SELECT COUNT(1)
          INTO vnCONTADOR
          FROM PCPEDI, PCPEDC
         WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
           AND DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) IN ('P', 'B')
           AND PCPEDC.CONDVENDA NOT IN (4, 7, 14)
           AND PCPEDI.QT > 0
           AND PCPEDC.NUMPED = pnIDENTIFICADOR
           AND PCPEDI.CODPROD = pnCODPROD
           AND PCPEDI.NUMSEQ = pnNUMSEQ;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 1 (Pendente Incluir): Não foi possível validar a posição e a condição de venda para colocar o estoque como pendente!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
      END;
      -- Caso não exista o pedido
      IF vnCONTADOR = 0 THEN
        psMSG_RETORNO := 'Erro 2 (Pendente Incluir): O Identificador não é válido para colocar o estoque como pendencia!'||CHR(13)||
                         'Verifique a posição e o tipo de venda do Identificador.'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Operação.....: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Mensagem
      END IF;
    -- Validação dos produtos
    END IF;
    -- Consultar dados do pedido para fazer o update no PCEST
    BEGIN
      SELECT PCPEDI.QT
            ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
            ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
            ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
            ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
            ,PCPEDI.CODDEPOSITO
            ,PCPEDI.ROWID
            ,PCPEDI.TIPOENTREGA
        INTO vnQT
            ,vsCODFILIAL
            ,vsPOSICAO
            ,vsPEDIDOAVARIA -- DDMEDICA-620
            ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
            ,P_INTERNO.CODDEPOSITO
            ,P_INTERNO.ROWID_REGISTRO
            ,P_INTERNO.TIPO_ENTREGA
        FROM PCPEDI, PCPEDC
       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
         AND (PCPEDC.CONDVENDA <> 11 OR (PCPEDC.CONDVENDA = 11 AND NVL(PCPEDI.QT,0) > 0))
         AND PCPEDI.NUMPED = pnIDENTIFICADOR
         AND PCPEDI.CODPROD = pnCODPROD
         AND PCPEDI.NUMSEQ = pnNUMSEQ;
      -- Atualizando filial do log
      P_INTERNO.NOME_TABELA := 'PCPEDI';
      P_INTERNO.CODFILIAL   := vsCODFILIAL;
    EXCEPTION
      WHEN OTHERS THEN
        psMSG_RETORNO := 'Erro 3 (Pendente Incluir): Não foi possível consultar dados do item para fazer colocar o estoque como pendente!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                         'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                         'Operação.....: '||psOPERACAO||CHR(13)||
                         'MSG Original.: '||SQLERRM;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
    END;
    -- Pedido de Avaria - Nao atualiza o Estoque Pendente - DDMEDICA-620
    IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_INCLUIR - Ped. Avaria';
      PRIV_GERARLOG;
      RETURN 'S';
    END IF;
    -- Pedido de CrossDocking - Nao atualiza o Estoque Pendente - DDMEDICA-620
    IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_INCLUIR - Ped. Crossdock.';
      PRIV_GERARLOG;
      RETURN 'S';
    END IF;
    -- Bloquear estoque pendente do item
    PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
    -- Validar se conseguiu bloquear o estoque
    IF psMSG_RETORNO <> 'OK' THEN
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Atualizar variáveis
    P_INTERNO.vtESTOQUE               := NULL;
    P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
    P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
    P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
    P_INTERNO.vtESTOQUE.QTPENDENTE    := vnQT;
    -- Atualizar estoque bloqueado
    PRIV_ATUALIZAR_ESTOQUE;
    -- Validar se conseguiu atualizar o estoque
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Atualizar variáveis
    P_INTERNO.PROCESSO      := 'PENDENTE';
    P_INTERNO.QTPENDENTE    := vnQT;
    P_INTERNO.TIPO_OPERACAO := 'IN';
    -- Movimenta estoque do depósito
    PRIV_DEP_INCLUIR;
    -- Valida se movimentação do depósito ficou correta
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_INCLUIR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno será "S - Sim"
    RETURN 'S';
  -- Função
  END PENDENTE_INCLUIR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0                   Criada a função Baixar estoque pendente
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  21/08/2020     Fernandes Brito   DDESTOQUE-6569      Ajustada a função para pegar o código do depósito do pedido para manipular o estoque
  ************************************************************************************************************************/
  FUNCTION PENDENTE_BAIXAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                           ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                           ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                           ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                           ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONDVENDAANT          PCPEDC.CONDVENDA%TYPE;
    vsPOSICAOANT            PCPEDC.POSICAO%TYPE;
    vnQTDEANT               PCMOV.QT%TYPE;
    vsCODFILIALANT          PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PENDENTE_BAIXAR';
    P_INTERNO.NOME_FUNCAO     := 'PENDENTE_BAIXAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Consultar dados anteriores
    PRIV_CONS_DADOS_ANTERIORES(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,vnCONDVENDAANT,vsPOSICAOANT,vnQTDEANT,vsCODFILIALANT,psMSG_RETORNO);
    -- Verifica se deu tudo certo ao consultar dados anteriores
    IF psMSG_RETORNO <> 'OK' THEN
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;

    IF NVL(psOPERACAO, 'X') <> 'FQ' THEN
    -- Retornar dados do pedido atual
      BEGIN
        --validando filial e filial retira
        vsCODFILIAL := VALIDA_CODFILIAL_CEFAT( PNIDENTIFICADOR, PNCODPROD, PNNUMSEQ);
      P_INTERNO.CODFILIAL   := vsCODFILIAL;
      IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        SELECT DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
              ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
              ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
              ,PCPEDI.CODDEPOSITO
              ,PCPEDI.TIPOENTREGA
          INTO vsPOSICAO
              ,vsPEDIDOAVARIA -- DDMEDICA-620
              ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
              ,P_INTERNO.CODDEPOSITO
              ,P_INTERNO.TIPO_ENTREGA
          FROM PCPEDC, PCPEDI
         WHERE PCPEDC.NUMPED = PCPEDI.NUMPED
           AND PCPEDI.NUMSEQ = pnNUMSEQ
           AND PCPEDI.CODPROD = pnCODPROD
           AND PCPEDC.NUMPED = pnIDENTIFICADOR;
      EXCEPTION
        WHEN OTHERS THEN
          psMSG_RETORNO := 'Erro 1 (Pendente Baixar): Não foi possível validar dados anteriores para fazer a baixa do estoque pendente!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
      END;
    END IF;
  -- Pedido de Avaria - Nao atualiza o Estoque Pendente - DDMEDICA-620
    IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_BAIXAR - Ped. Avaria';
      PRIV_GERARLOG;
      RETURN 'S';
    END IF;
    -- Pedido de CrossDocking - Nao atualiza o Estoque Pendente - DDMEDICA-620
    IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_BAIXAR - Ped. Crossdock.';
      PRIV_GERARLOG;
      RETURN 'S';
    END IF;
    -- Atualizando o estoque
    IF ((vsPOSICAOANT IN ('P', 'B')) AND (vnCONDVENDAANT NOT IN (4, 7, 14))) THEN
      -- Validar se o pedido esta sendo alterado.
      --Caso não, fazer processo de lock do registro a ser alterado
      IF NVL(psOPERACAO, 'X') NOT IN ('AQ') THEN
        -- Bloquear estoque pendente do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
      END IF;
      -- Validar se conseguiu bloquear o estoque
      IF psMSG_RETORNO <> 'OK' THEN
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
      -- Atualizar variáveis
      P_INTERNO.vtESTOQUE := NULL;
      P_INTERNO.TIPO_OPERACAO           := 'B';
      P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
      P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIALANT;
      P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
      P_INTERNO.vtESTOQUE.QTPENDENTE    := NVL(vnQTDEANT, 0);
      -- Atualizar estoque bloqueado
      PRIV_ATUALIZAR_ESTOQUE;
      -- Validar se conseguiu atualizar o estoque
      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
    --
    ELSE
      psMSG_RETORNO := 'Erro 2 (Pendente Baixar): Não foi possível baixar o estoque pendente. O pedido não é valido para esta operação.'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                       'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    --
    END IF;
    -- Atualizar variáveis
    P_INTERNO.PROCESSO      := 'PENDENTE';
    P_INTERNO.QTPENDENTE    := vnQTDEANT;
    P_INTERNO.TIPO_OPERACAO := 'BQ';
    -- Movimenta estoque do depósito
    PRIV_DEP_BAIXAR;
    -- Valida se movimentação do depósito ficou correta
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_BAIXAR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno cerá "S - Sim"
    RETURN 'S';
  -- Função
  END PENDENTE_BAIXAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0               Criada a função alterar estoque pendente
  ************************************************************************************************************************/
  FUNCTION PENDENTE_ALTERAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                            ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                            ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                            ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                            ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONDVENDAANT      PCPEDC.CONDVENDA%TYPE;
    vnCONDVENDA         PCPEDC.CONDVENDA%TYPE;
    vsPOSICAOANT        PCPEDC.POSICAO%TYPE;
    vsPOSICAO           PCPEDC.POSICAO%TYPE;
    vnQTDEANT           PCMOV.QT%TYPE;
    vsCODFILIALANT      PCPEDC.CODFILIAL%TYPE;
    vnQTDE              PCMOV.QT%TYPE;
    vbBAIXOU            VARCHAR2(1);
    vbINCLUIU           VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PENDENTE_ALTERAR';
    P_INTERNO.NOME_FUNCAO     := 'PENDENTE_ALTERAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Consultar dados para o update no PCEST
    PRIV_CONS_DADOS_ANTERIORES (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,vnCONDVENDAANT,vsPOSICAOANT,vnQTDEANT,vsCODFILIALANT,psMSG_RETORNO);
    -- Verifica se deu tudo certo ao consultar dados anteriores
    IF psMSG_RETORNO <> 'OK' THEN
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Consultar dados do pedido para fazer o update no PCEST
    BEGIN
      SELECT PCPEDI.QT
            ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
            ,PCPEDC.CONDVENDA
        INTO vnQTDE
            ,vsPOSICAO
            ,vnCONDVENDA
        FROM PCPEDI, PCPEDC
       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
         AND PCPEDI.NUMPED = pnIDENTIFICADOR
         AND PCPEDI.CODPROD = pnCODPROD
         AND PCPEDI.NUMSEQ = pnNUMSEQ;
         --AND NVL(PCPEDI.QT,0) > 0;
    EXCEPTION
      WHEN OTHERS THEN
        psMSG_RETORNO := 'Erro 1 (Pendente Alterar): Não foi possível consultar dados do Identificador para colocar o estoque na pendencia!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Cód. Prod....: '||TO_CHAR(pnCODPROD)||CHR(13)||
                         'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                         'Operação.....: '||psOPERACAO||CHR(13)||
                         'MSG Original.: '||SQLERRM;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
    END;
    -- Validando se o pedido pode ser alterado
    IF ((vnCONDVENDA NOT IN (4, 7, 14)) AND
        (vsPOSICAO IN ('P', 'B')) AND
        (vnQTDEANT <> vnQTDE)) THEN
      -- Bloquear estoque pendente do item
      PRIV_BLOQUEAR_ESTOQUE(vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
      -- Validar se conseguiu bloquear o estoque
      IF psMSG_RETORNO <> 'OK' THEN
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
      -- Aciona a baixa do estoque pendente
      vbBAIXOU := PENDENTE_BAIXAR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,psMSG_RETORNO);
      -- Aciona a inclusão do estoque pendente
      vbINCLUIU := PENDENTE_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,psOPERACAO,psMSG_RETORNO);
      -- Caso não seja possivel alterar o estoque pendente do pedido
    ELSE
      psMSG_RETORNO := 'Erro 2 (Pendente Alterar): Não existe pendencia a ser feita ou desfeita para o item informado!'||CHR(13)||
                       'Verifique se a função e a operação executadas estão corretas'||CHR(13)||
                       'Função chamada: PENDENTE_ALTERAR_PEDIDO ou PENDENTE_ALTERAR'||CHR(13)||
                       'Operação......: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'FINALIZOU A FUNÇÃO - PENDENTE_ALTERAR';
    PRIV_GERARLOG ;
    -- Se deu tudo certo então retorna verdadeiro
    IF ((vbBAIXOU = 'S') AND (vbINCLUIU = 'S')) THEN
      RETURN 'S';
    ELSE
      RETURN 'N';
    END IF;
  -- Função
  END PENDENTE_ALTERAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  04/07/2016     Fernandes Brito   0               Criada a função incluir o estoque pendente através de um pedido
  ************************************************************************************************************************/
  FUNCTION PENDENTE_INCLUIR_PEDIDO (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                   ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                   ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vsVALIDO   VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.LISTA_VALIDA    := 'N';
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - PENDENTE_INCLUIR_PEDIDO';
    P_INTERNO.NOME_FUNCAO     := 'PENDENTE_INCLUIR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Lista de produtos do pedido
    FOR ITENS IN (SELECT PCPEDI.NUMPED, PCPEDI.CODPROD, PCPEDI.NUMSEQ
                    FROM PCPEDI
                        ,PCPEDC
                   WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                     AND PCPEDI.NUMPED = pnIDENTIFICADOR
                     AND DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) IN ('P', 'B')
                     AND PCPEDC.CONDVENDA NOT IN (4, 7, 14)
                     AND PCPEDI.QT > 0
                ORDER BY PCPEDI.CODPROD, PCPEDI.NUMSEQ)
    LOOP
      -- Atualizar variável
      P_INTERNO.LISTA_VALIDA := 'S';
      -- Fazer a inclusão do estoque pendente produto a produto
      vsVALIDO := PENDENTE_INCLUIR(pnIDENTIFICADOR,ITENS.CODPROD,ITENS.NUMSEQ,TRUE,psOPERACAO,psMSG_RETORNO);

    IF psMSG_RETORNO <> 'OK' THEN
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
    END IF;
      -- Lista de produtos
    END LOOP;
    -- Caso não tenha registros válidos
    IF P_INTERNO.LISTA_VALIDA = 'N' THEN
      psMSG_RETORNO := 'Erro 1 (Pendente Incluir Ped): Não foi possível validar a posição e a condição de venda para colocar o estoque como pendente!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.....: '||psOPERACAO||CHR(13)||
                       'MSG Original.: '||SQLERRM;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Finalizou a função - PENDENTE_INCLUIR_PEDIDO';
    PRIV_GERARLOG;
    -- Atualizar o retorno da função
    RETURN vsVALIDO;
  -- Função
  END PENDENTE_INCLUIR_PEDIDO;

