                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'FINALIZOU A FUNÇÃO - PENDENTE_BAIXAR_PEDIDO';
    PRIV_GERARLOG;
    -- Atualizar o retorno da função
    RETURN vsVALIDO;
