  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  02/12/2020     Fernandes Brito   DDESTOQUE-4578      Criada função para validar se já pode faturar o pedido TV8 que tem
                                                       requisição vinculada ao mesmo.
  ************************************************************************************************************************/
  FUNCTION PODE_FATURAR (pnIDENTIFICADOR  IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE)
   RETURN VARCHAR2
   IS
     vnCONTADOR VARCHAR(1);
  BEGIN
    BEGIN
      SELECT COUNT(1) CONTADOR
        INTO vnCONTADOR
        FROM PCREQUISICAODEPOSITO
       WHERE PCREQUISICAODEPOSITO.IDENTIFICADOR = pnIDENTIFICADOR
         AND PCREQUISICAODEPOSITO.POSICAO = 'A';
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnCONTADOR := 0;
    END;

    IF vnCONTADOR <> 0 THEN
      RETURN 'N';
    ELSE
      RETURN 'S';
    END IF;

  END PODE_FATURAR;

