  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017     Fernandes Brito   0                   Incluir item na reserva
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  /***********************************************************************************************************************/
FUNCTION RESERVA_INCLUIR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                           ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                           ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                           ,pbPEDIDO          IN BOOLEAN
                           ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                           ,psMSG_RETORNO     OUT VARCHAR2
                           ,pnCODFUNC         IN PCEMPR.MATRICULA%TYPE DEFAULT 0)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnQT                    PCPEDI.QT%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vnQTDISPONIVEL          PCEST.QTRESERV%TYPE;
    vsORIGEMPED             PCPEDC.ORIGEMPED%TYPE;
    vnCONDVENDA             PCPEDC.CONDVENDA%TYPE;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
    vnTIPO_MERCADORIA       PCPRODUT.TIPOMERC%TYPE;
    vsUSAWMS                PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE        PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vnQTUNITCX              PCPRODUT.QTUNITCX%TYPE;
    vsTIPOMERC              PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL          PCPRODUT.PESOVARIAVEL%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função reserva incluir';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Excutar consulta do produto
    PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    CASE
      WHEN psOPERACAO = 'IM' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL(SUM(RI.QT), 0) QT
                ,RC.CODFILIAL
                ,RI.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
           WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
             AND RI.CODOPER = 'SM'
             AND RC.SITUACAO = 'L'
             AND RC.NUMPREREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD
        GROUP BY RC.CODFILIAL
                ,RI.CODDEPOSITO;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCPREREQMATCONSUMOI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Consultando disponivel do produto
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'V');
        -- Apresentar erro caso a quantidade disponivel for menor
        IF ((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND
           vsPESOVARIAVEL = 'N' AND
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
           FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S')  THEN
          psMSG_RETORNO := 'Erro 16 (Reserva Incluir): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                           'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valida disponivel
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      --** Inicio - Indústria Incluir (II) **
      WHEN psOPERACAO = 'II' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL((ROUND(PCOPI.QTRESERVALTERAR,6)), 0) QT
                ,PCOPC.CODFILIAL
                ,PCOPI.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCOPI, PCOPC
           WHERE PCOPI.NUMOP = PCOPC.NUMOP
             AND PCOPC.NUMOP = pnIDENTIFICADOR
             AND NVL(PCOPC.QTPRODUZIDA, 0) <= NVL(PCOPC.QTPRODUZIR, 0)
             AND NVL(PCOPC.FINALIZAPRODUCAO, 'N') = 'N'
             AND PCOPC.POSICAO IN ('P', 'L')
             AND PCOPI.CODPROD = pnCODPROD
             AND PCOPI.QTRESERVALTERAR > 0;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCOPI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 2 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE (vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Consultando disponivel do produto
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'V');
        -- Apresentar erro caso a quantidade disponivel for menor
        IF ((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND
           vsPESOVARIAVEL = 'N' AND
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
           FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
          psMSG_RETORNO := 'Erro 3 (Reserva Incluir): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                           'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Necessidade..: '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                           'Disponível...: '||CHR(9)||TO_CHAR(vnQTDISPONIVEL)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valida disponivel
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizando a ordem de producao
        BEGIN
          UPDATE PCOPI
             SET QTRESERVATUAL = NVL(QTRESERVATUAL,0) + NVL(vnQT,0)
                ,QTRESERVALTERAR = NVL(QTRESERVALTERAR,0) - NVL(vnQT,0)
           WHERE NUMOP = pnIDENTIFICADOR
             AND CODPROD = pnCODPROD;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 4 (Reserva incluir): não foi possível atualizar a ordem de produção (PCOPI) durante a reserva (PCEST).'||CHR(13)||
                             'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Verifica se o produto consultado trabalha com lote
        IF (vsESTOQUEPORLOTE = 'S') THEN
          -- Lista os LOTES para reservar
          FOR REGISTROS IN (SELECT ROUND(SUM(L.QT - NVL(L.QTREQUISITADO,0)),6) QT
                                  ,P.NUMOP
                                  ,L.NUMLOTE
                              FROM PCOPILOTE L
                                  ,PCOPC P
                             WHERE P.NUMOP = L.NUMOP
                               AND P.NUMOP = pnIDENTIFICADOR
                               AND L.CODPROD = pnCODPROD
                               AND P.FINALIZAPRODUCAO = 'N'
                               AND NVL(P.QTPRODUZIDA,0) < NVL(P.QTPRODUZIR,0)
                               AND NVL(L.QTREQUISITADO,0) < NVL(L.QT,0)
                          GROUP BY P.NUMOP, L.NUMLOTE)
          LOOP
            -- Atualizar variáveis
            P_INTERNO.vtLOTE               := NULL;
            P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIAL;
            P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
            P_INTERNO.vtLOTE.NUMLOTE       := REGISTROS.NUMLOTE;
            -- Bloquear PCLOTE
            PRIV_BLOQUEAR_LOTE;
            -- Validar se conseguiu bloquear a PCLOTE
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Buscar o disponível do lote
            vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,REGISTROS.NUMLOTE,'I');
            -- Caso não existe disponivel para a reserva
            IF ((REGISTROS.QT > vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0))  AND
               (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
               FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
              psMSG_RETORNO := 'Erro 5 (Reserva Incluir): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                               'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Lote.........: '||CHR(9)||(REGISTROS.NUMLOTE)||CHR(13)||
                               'Necessidade..: '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                               'Operação.....: '||psOPERACAO||CHR(13)||
                               'Disponível...: '||CHR(9)||TO_CHAR(vnQTDISPONIVEL);
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            ELSE
              -- Atualizar dados
              P_INTERNO.vtLOTE.QT          := NULL;
              P_INTERNO.vtLOTE.QTEST       := NULL;
              P_INTERNO.vtLOTE.QTRESERV    := REGISTROS.QT;
              P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
              P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
              P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
              -- Administrar estoque do lote
              PRIV_ATUALIZAR_LOTE;
              -- Validando se conseguiu atualizar o lote
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Validação do disponível
            END IF;
          -- Lista dos lotes
          END LOOP;
        -- Validação do controle de lote
        END IF;
      -- Inicio - Ordem de Serviço
      WHEN psOPERACAO = 'IO' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL(SUM(A.QTDE),0) AS QT
                ,A.CODFILIALRETIRA CODFILIAL
                ,I.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCITEMSERVICO A,
                 PCORDEMSERVICO O,
                 PCORDEMSERVICOI I,
                 PCTIPOORDEMSERVICO T,
                 PCCONSUM
           WHERE O.NUMOS = I.NUMOS
             AND I.NUMOSSERVICO = A.NUMOSSERVICO
             AND O.TIPOOS = T.CODTIPO(+)
             AND O.NUMTRANSVENDAPROD IS NULL
             AND NVL(A.DEMONSTRACAO,'N') = 'N'
             AND O.NUMOS = pnIDENTIFICADOR
             AND A.CODPROD = pnCODPROD
             AND ((NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   NVL(T.GERARCONTRECEBERPRODUTO, 'N') = 'S' AND
                   O.SITUACAO IN (2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'S' AND
                   O.SITUACAO IN (1, 2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   O.SITUACAO IN (2))
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO, 'N') = 'S' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N')
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N'))
           GROUP BY A.CODFILIALRETIRA, I.CODDEPOSITO;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCORDEMSERVICOI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 6 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Consultando disponivel do produto
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'V');
        -- Apresentar erro caso a quantidade disponivel for menor
        IF ((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND
           vsPESOVARIAVEL = 'N' AND
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
           FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
          psMSG_RETORNO := 'Erro 7 (Reserva Incluir): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                           'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valida disponivel
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Inicio industria incluir requisição avulsa
      WHEN psOPERACAO = 'IA' THEN
        -- Busca quantidade e filial
        BEGIN
          SELECT NVL(PCAVULSA.QT, 0) QT
                ,PCAVULSA.CODFILIAL
                ,PCAVULSA.CODDEPOSITO
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCAVULSA
           WHERE PCAVULSA.NUMTRANSAVULSA = pnIDENTIFICADOR
             AND PCAVULSA.NUMSEQ = pnNUMSEQ
             AND PCAVULSA.CODPROD = pnCODPROD
             AND PCAVULSA.CODOPER IN ('S','P')
             AND PCAVULSA.DTCANCEL IS NULL
             AND PCAVULSA.DTBAIXA IS NULL;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCAVULSA';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 8 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE (vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Consultando disponivel do produto
        vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'V');
        -- Apresentar erro caso a quantidade disponivel for menor
        IF ((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND
           vsPESOVARIAVEL = 'N' AND
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
           FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
          psMSG_RETORNO := 'Erro 17 (Reserva Incluir): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                           'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valida disponivel
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Verifica se o produto consultado trabalha com lote
        IF (vsESTOQUEPORLOTE = 'S') THEN
          -- Lista de lotes para reserva na PCLOTE
          FOR REGISTROS IN (SELECT SUM(PCAVULSA.QT) QT
                                  ,PCAVULSA.NUMOP
                                  ,PCAVULSA.NUMLOTE
                                  ,PCAVULSA.CODPROD
                                  ,PCAVULSA.CODFILIAL
                              FROM PCAVULSA
                             WHERE PCAVULSA.NUMTRANSAVULSA = pnIDENTIFICADOR
                               AND PCAVULSA.CODPROD = pnCODPROD
                               AND SUBSTR(PCAVULSA.CODOPER,1,1) IN ('S','P')
                               AND PCAVULSA.NUMSEQ = pnNUMSEQ
                          GROUP BY PCAVULSA.CODFILIAL
                                  ,PCAVULSA.CODPROD
                                  ,PCAVULSA.NUMOP
                                  ,PCAVULSA.NUMLOTE)
          LOOP
            -- Atualizar Variáveis
            P_INTERNO.vtLOTE               := NULL;
            P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIAL;
            P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
            P_INTERNO.vtLOTE.NUMLOTE       := REGISTROS.NUMLOTE;
            -- Bloquear PCLOTE
            PRIV_BLOQUEAR_LOTE;
            -- Validar se conseguiu bloquear a PCLOTE
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Buscar o disponível do lote
            vnQTDISPONIVEL := ESTOQUE_DISPONIVEL_LOTE (vsCODFILIAL,pnCODPROD,REGISTROS.NUMLOTE,'I');
            -- Caso não existe disponivel para a reserva
            IF ((REGISTROS.QT > vnQTDISPONIVEL) OR (vnQTDISPONIVEL < 0)) AND
               (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
               FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
              psMSG_RETORNO := 'Erro 9 (Reserva Incluir): Não existe estoque disponível para realizar a reserva do lote para o ítem informado!'||CHR(13)||
                               'Identificador: '||CHR(9)||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto      : '||CHR(9)||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Lote         : '||CHR(9)||(REGISTROS.NUMLOTE)||CHR(13)||
                               'Necessidade  : '||CHR(9)||TO_CHAR(vnQT)||CHR(13)||
                               'Disponível   : '||CHR(9)||TO_CHAR(vnQTDISPONIVEL)||CHR(13)||
                               'Operação.....: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            ELSE
              -- Atualizar dados
              P_INTERNO.vtLOTE.QT          := NULL;
              P_INTERNO.vtLOTE.QTEST       := NULL;
              P_INTERNO.vtLOTE.QTRESERV    := REGISTROS.QT;
              P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
              P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
              P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
              -- Administrar estoque do lote
              PRIV_ATUALIZAR_LOTE;
              -- Validando se conseguiu atualizar o lote
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
              END IF;
            -- Validação do disponível
            END IF;
          -- Lista de lotes para reserva
          END LOOP;
        -- Validação do controle de lote
        END IF;
      --** Inicio - Requisição Depósito/Embalagens/Lote (IR/AR) **
      WHEN psOPERACAO = 'IR' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT NVL(RI.QT, 0) QT
                ,RI.CODFILIAL
                ,RI.CODDEPOSITOORIG
            INTO vnQT
                ,vsCODFILIAL
                ,P_INTERNO.CODDEPOSITO
            FROM PCREQUISICAODEPOSITO RI
           WHERE RI.CODREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD
             AND RI.NOME_TABELA = 'PCREQUISICAODEPOSITO'
             AND RI.POSICAO = 'A';
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
      P_INTERNO.NOME_TABELA := 'PCREQUISICAODEPOSITO';
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 14 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque reservado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Qualquer psOPERACAO não definida
      ELSE
        -- Consultar dados para o update no PCEST
        BEGIN
          SELECT PCPEDI.QT
                ,NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                ,PCPEDC.ORIGEMPED
                ,PCPEDC.CONDVENDA
                ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
                ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
                ,PCPEDI.CODDEPOSITO
                ,PCPEDI.TIPOENTREGA
                ,PCPEDI.ROWID
                ,PCPRODUT.TIPOMERC
            INTO vnQT
                ,vsCODFILIAL
                ,vsPOSICAO
                ,vsORIGEMPED
                ,vnCONDVENDA
                ,vsPEDIDOAVARIA -- DDMEDICA-620
                ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
                ,P_INTERNO.CODDEPOSITO
                ,P_INTERNO.TIPO_ENTREGA
                ,P_INTERNO.ROWID_REGISTRO
                ,vnTIPO_MERCADORIA
            FROM PCPEDI, PCPEDC, PCPRODUT
           WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
             AND PCPEDI.NUMPED = pnIDENTIFICADOR
             AND PCPEDI.CODPROD = PCPRODUT.CODPROD
             AND PCPEDI.CODPROD = pnCODPROD
             AND (PCPEDC.CONDVENDA <> 11 OR (PCPEDC.CONDVENDA = 11 AND NVL(PCPEDI.QT,0) > 0))
             AND PCPEDI.NUMSEQ = pnNUMSEQ;
          -- Atualizando filial do log
          P_INTERNO.NOME_TABELA := 'PCPEDI';
          P_INTERNO.CODFILIAL   := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 12 (Reserva Incluir): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Posição inválida
        IF vsPOSICAO NOT IN ('L','M') THEN
          psMSG_RETORNO := 'Erro 10 (Reserva Incluir): A posição do pedido é inválida para realizar a reserva do estoque!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Posiçao......: '||vsPOSICAO||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Condição de venda inválido
        IF vnCONDVENDA IN (4,7,14) THEN
          psMSG_RETORNO := 'Erro 11 (Reserva Incluir): O cond. Venda não é válido para realizar a reservar do estoque!'||CHR(13)||
                           'Cond. Venda..: '||TO_CHAR(vnCONDVENDA)||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Venda de Avaria - DDMEDICA-620
        IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
          -- Consultando disponivel de Avaria
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'PA');
          -- Apresentar erro caso a quantidade disponivel for menor
          IF (vnQTDISPONIVEL < vnQT) AND
             vsPESOVARIAVEL = 'N' AND
             (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
             FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
            psMSG_RETORNO := 'Erro 15 (Reserva Incluir): Não existe estoque de avaria disponível para o Pedido de Avaria!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                             'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Valida disponivel
          END IF;
          -- Inserindo informações de debug (LOG)
          P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_incluir - PED. AVARIA';
          P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
          PRIV_GERARLOG;
          RETURN 'S';
        -- Condicao: Venda de Avaria - DDMEDICA-620
        END IF;
        -- Venda de CrossDocking - DDMEDICA-620
        IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
          -- Consultando disponivel bloqueado
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'PC');
          -- Apresentar erro caso a quantidade disponivel for menor
          IF (vnQTDISPONIVEL < vnQT) AND
            vsPESOVARIAVEL = 'N' AND
             (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
             FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN
            psMSG_RETORNO := 'Erro 16 (Reserva Incluir): Não existe estoque bloqueado disponível para fazer o pedido de Crossdocking!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                             'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          -- Valida disponivel
          END IF;
          -- Inserindo informações de debug (LOG)
          P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_incluir - PED. CROSSDOCK';
          P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
          PRIV_GERARLOG;
          RETURN 'S';
        -- Condicao: Venda de CrossDocking - DDMEDICA-620
        END IF;
        -- Consultando disponivel do produto
        IF vnTIPO_MERCADORIA = 'CB' THEN
           vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'VA');
        ELSE
          vnQTDISPONIVEL := ESTOQUE_DISPONIVEL(pnCODPROD,vsCODFILIAL,'P');
        END IF;
        -- Apresentar erro caso a quantidade disponivel for menor
        IF (((vnQTDISPONIVEL < vnQT) OR (vnQTDISPONIVEL < 0)) AND (vnCONDVENDA <> 7)) AND
           vsPESOVARIAVEL = 'N' AND
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('PERMITIRESTGERNEGATIVO',vsCODFILIAL,'N') = 'N' OR
           FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VALIDARESTOQUEAUTOSERVICO','99','N') = 'S') THEN

          IF NOT((NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('CON_ACEITAVENDABALCAOESTNEG'),'N') = 'S') AND vsORIGEMPED IN ('B','R','A')) THEN
            IF (NOT vsROTINA LIKE '%998%') AND (vsROTINA NOT LIKE '%1401%') THEN
              psMSG_RETORNO := 'Erro 13 (Reserva Incluir): Não existe estoque disponível para fazer a reserva desejada!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Necessidade  : '||TO_CHAR(vnQT)||CHR(13)||
                               'Disponível   : '||TO_CHAR(vnQTDISPONIVEL);
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            -- Valida disponivel
            END IF;
          --
          END IF;
        -- Valida disponivel
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := vnQT;
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Gravar dados analiticos
        PRIV_RESERVA_ANALITICA (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,vsPOSICAO,psOPERACAO,vsCODFILIAL,vnQT,vsROTINA,psMSG_RETORNO);
        -- Validar se conseguiu atualizar reserva analitica
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
    -- Validação da OPERAÇÃO
    END CASE;
    -- Atualizar variáveis
    P_INTERNO.QTRESERV      := vnQT;
    P_INTERNO.PROCESSO      := 'RESERVAR';
    -- Movimenta estoque do depósito
    PRIV_DEP_INCLUIR;
    -- Valida se movimentação do depósito ficou correta
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva_incluir';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno será "S - Sim"
    RETURN 'S';
  -- Função
  END RESERVA_INCLUIR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Baixar reserva de estoque
  22/08/2019    Anderson Silva     DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  /************************************************************************************************************************/
  FUNCTION RESERVA_BAIXAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                          ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                          ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                          ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                          ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONDVENDAANT          PCPEDC.CONDVENDA%TYPE;
    vsPOSICAOANT            PCPEDC.POSICAO%TYPE;
    vnQTDEANT               PCMOV.QT%TYPE;
    vsCODFILIALANT          PCPEDC.CODFILIAL%TYPE;
    vsPOSICAO               PCPEDC.POSICAO%TYPE;
    vsCODFILIAL             PCPEDC.CODFILIAL%TYPE;
    vnQTDISPONIVEL          PCEST.QTRESERV%TYPE;
    vnQtdeNfPreFat          NUMBER;
    vsPEDIDOAVARIA          PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK  PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
    vsUSAWMS                PCPRODUT.USAWMS%TYPE;
    vsESTOQUEPORLOTE        PCPRODUT.ESTOQUEPORLOTE%TYPE;
    vsTIPOMERC              PCPRODUT.TIPOMERC%TYPE;
    vsPESOVARIAVEL          PCPRODUT.PESOVARIAVEL%TYPE;
    vnQTUNITCX              PCPRODUT.QTUNITCX%TYPE;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função reserva baixar';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_BAIXAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Excutar consulta do produto
    PRIV_CONS_PRODUTO(pnCODPROD,vsUSAWMS,vsESTOQUEPORLOTE,vnQTUNITCX,vsTIPOMERC,vsPESOVARIAVEL);
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    IF psOPERACAO NOT IN ('AM', 'CM', 'BA') THEN
      -- Consultar dados anteriores
      PRIV_CONS_DADOS_ANTERIORES (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,vnCONDVENDAANT,vsPOSICAOANT,vnQTDEANT,vsCODFILIALANT,psMSG_RETORNO);
      -- Verifica se deu tudo certo ao consultar dados anteriores
      IF psMSG_RETORNO <> 'OK' THEN
        PRIV_GERARLOG;
        RETURN 'N';
      END IF;
    END IF;
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    CASE
      WHEN psOPERACAO IN ('AM','CM') THEN
        BEGIN
          SELECT NVL(SUM(RI.QT), 0) QT, RC.CODFILIAL
            INTO vnQTDEANT, vsCODFILIAL
            FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
           WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
             AND RI.CODOPER = 'SM'
             AND RC.NUMPREREQUISICAO = pnIDENTIFICADOR
             AND RI.CODPROD = pnCODPROD
        GROUP BY RC.CODFILIAL;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL  := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (Reserva Baixar): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE (vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.TIPO_OPERACAO           := 'B';
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT, 0);
        -- Atualizar estoque bloqueado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        --** Inicio - Indústria Baixar (BI): Usado no apontamento final **
      WHEN psOPERACAO = 'BI' THEN
        -- Obter filial de produção
        BEGIN
          SELECT PCOPC.CODFILIAL
                ,CASE
                   WHEN NVL(PCOPI.QTRESERVALTERAR, 0) < 0 THEN
                     (NVL(PCOPI.QTRESERVALTERAR, 0) * (-1))
                 ELSE
                   NVL(PCOPI.QTRESERVALTERAR, 0)
                 END QTRESERVALTERAR
            INTO vsCODFILIAL
                ,vnQTDEANT
            FROM PCOPI
                ,PCOPC
           WHERE PCOPI.NUMOP = PCOPC.NUMOP
             AND PCOPC.NUMOP = pnIDENTIFICADOR
             AND PCOPI.CODPROD = pnCODPROD
             AND PCOPI.QTRESERVATUAL > 0
             AND PCOPI.QTNECESSIDADE > 0
             AND PCOPC.POSICAO = 'P';
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL  := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 2 (Reserva Baixar): Não foi possível consultar dados do item para baixar a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Consultar dados do estoque
        P_INTERNO.vtESTOQUE           := NULL;
        P_INTERNO.vtESTOQUE.CODFILIAL := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD   := pnCODPROD;
        PRIV_CONS_ESTOQUE_ATUAL (P_INTERNO.vtESTOQUE);
        -- Verificando reservado
        vnQTDISPONIVEL      := NVL(P_INTERNO.vtESTOQUE.QTRESERV,0);
        -- Apresentar erro caso a quantidade reservada for menor
        IF ((vnQTDISPONIVEL < vnQTDEANT) OR (vnQTDISPONIVEL < 0)) THEN
          psMSG_RETORNO := 'Erro 3 (Reserva Incluir): O estoque reservado não é suficiente para realizar a baixa!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto      : '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Necessidade  : '||TO_CHAR(vnQTDEANT)||CHR(13)||
                           'Disponível   : '||TO_CHAR(vnQTDISPONIVEL)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valida disponivel
        END IF;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE (vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT, 0);
        -- Atualizar estoque reservado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizando a ordem de producao
        BEGIN
          UPDATE PCOPI
             SET QTRESERVATUAL   = NVL(QTRESERVATUAL,0) - NVL(vnQTDEANT,0)
                ,QTRESERVALTERAR = 0
                ,QTREQUISITADO   = NVL(QTREQUISITADO,0) + NVL(vnQTDEANT,0)
           WHERE NUMOP = pnIDENTIFICADOR
             AND CODPROD = pnCODPROD
             AND QTNECESSIDADE > 0;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 4 (Reserva incluir): não foi possível atualizar a ordem de produção (PCOPI) durante a reserva (PCEST).'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
      -- Inicio industria baixar por pedido (BA)
      WHEN psOPERACAO = 'BA' THEN
        -- Busca quantidade e filial
        BEGIN
          SELECT NVL(PCAVULSA.QT,0) QT, PCAVULSA.CODFILIAL
            INTO vnQTDEANT, vsCODFILIAL
            FROM PCAVULSA
           WHERE PCAVULSA.NUMTRANSAVULSA = pnIDENTIFICADOR
             AND PCAVULSA.CODPROD = pnCODPROD
             AND PCAVULSA.NUMSEQ = pnNUMSEQ
             AND SUBSTR(PCAVULSA.CODOPER,1,1) IN ('S','P')
             AND PCAVULSA.DTCANCEL IS NULL
             AND PCAVULSA.DTBAIXA IS NULL;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 5 (Reserva Baixar): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE               := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT,0);
        -- Atualizar estoque reservado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Verifica se o produto consultado trabalha com lote
        IF (vsESTOQUEPORLOTE = 'S') THEN
          -- Lista de LOTES para atualizar reserva
          FOR REGISTROS IN (SELECT SUM(PCAVULSA.QT) QT
                                  ,PCAVULSA.CODPROD
                                  ,PCAVULSA.NUMLOTE
                                  ,PCAVULSA.NUMOP
                              FROM PCAVULSA
                             WHERE NUMTRANSAVULSA = pnIDENTIFICADOR
                               AND CODPROD = pnCODPROD
                               AND DTCANCEL IS NULL
                               AND DTBAIXA IS NULL
                               AND CODOPER IN ('S','P')
                               AND NUMSEQ = pnNUMSEQ
                          GROUP BY CODPROD, NUMLOTE, NUMOP)
          LOOP
            -- Atualizar Variáveis
            P_INTERNO.vtLOTE               := NULL;
            P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIAL;
            P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
            P_INTERNO.vtLOTE.NUMLOTE       := REGISTROS.NUMLOTE;
            -- Bloquear PCLOTE
            PRIV_BLOQUEAR_LOTE;
            -- Validar se conseguiu bloquear a PCLOTE
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Atualizar dados
            P_INTERNO.vtLOTE.QT          := NULL;
            P_INTERNO.vtLOTE.QTEST       := NULL;
            P_INTERNO.vtLOTE.QTRESERV    := REGISTROS.QT;
            P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
            P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
            P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
            -- Administrar estoque do lote
            PRIV_ATUALIZAR_LOTE;
            -- Validando se conseguiu atualizar o lote
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
          -- Lista de lotes
          END LOOP;
        -- Produto usa lote
        END IF;
      -- Inicio - Ordem serviço baixar
      WHEN psOPERACAO = 'BO' THEN
        -- Consultar itens para fazer a reserva
        BEGIN
          SELECT DISTINCT PCORDEMSERVICO.CODFILIAL --N?o usar group by pois se tiver mais de uma filial tem que dar o erro mesmo
            INTO vsCODFILIAL
            FROM PCORDEMSERVICO, PCORDEMSERVICOI, PCITEMSERVICO
           WHERE PCORDEMSERVICO.NUMOS = PCORDEMSERVICO.NUMOS
             AND PCORDEMSERVICOI.NUMOSSERVICO = PCITEMSERVICO.NUMOSSERVICO
             AND PCORDEMSERVICO.NUMOS = pnIDENTIFICADOR
             AND PCITEMSERVICO.CODPROD = pnCODPROD
             AND PCITEMSERVICO.NUMOSSERVICO = pnNUMSEQ;
          -- Atualizando filial do log
          P_INTERNO.CODFILIAL  := vsCODFILIAL;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 6 (Reserva Baixar): Não foi possível consultar dados do item para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE (vsCODFILIAL,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIAL;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT,0);
        -- Atualizar estoque reservado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      --** Inicio - Requisição Depósito/Embalagens/Lote (IR/AR) **
      WHEN psOPERACAO = 'BR' THEN
        -- Bloquear estoque reservado do item
        PRIV_BLOQUEAR_ESTOQUE(vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
        -- Atualizar variáveis
        P_INTERNO.vtESTOQUE := NULL;
        P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
        P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIALANT;
        P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
        P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT,0);
        -- Atualizar estoque reservado
        PRIV_ATUALIZAR_ESTOQUE;
        -- Validar se conseguiu atualizar o estoque
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- PEDIDO DE VENDA
      WHEN psOPERACAO IN ('BQ','BV','BP','AQ','AV','AP','CQ','CV','CP','CC','FQ') THEN
        -- Valida se é corte total
        IF psOPERACAO NOT IN ('FQ') THEN
          -- Retornar dados do pedido atual
          BEGIN
            --Validar filial e filial retira
            vsCODFILIAL := VALIDA_CODFILIAL_CEFAT(PNIDENTIFICADOR, PNCODPROD, PNNUMSEQ);
            P_INTERNO.CODFILIAL   := vsCODFILIAL;
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            --
            SELECT DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                  ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
                  ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
                  ,PCPEDI.CODDEPOSITO
                  ,PCPEDI.TIPOENTREGA
                  ,NVL(PCPEDI.NUMLOTE, '')
                  ,PCPEDI.ROWID
              INTO vsPOSICAO
                  ,vsPEDIDOAVARIA -- DDMEDICA-620
                  ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
                  ,P_INTERNO.CODDEPOSITO
                  ,P_INTERNO.TIPO_ENTREGA
                  ,P_INTERNO.NUMLOTE
                  ,P_INTERNO.ROWID_REGISTRO
              FROM PCPEDC, PCPEDI
             WHERE PCPEDC.NUMPED = PCPEDI.NUMPED
               AND PCPEDI.NUMSEQ = pnNUMSEQ
               AND PCPEDI.CODPROD = pnCODPROD
               AND PCPEDC.NUMPED = pnIDENTIFICADOR;
          EXCEPTION
            WHEN OTHERS THEN
              psMSG_RETORNO := 'Erro 7 (Reserva Baixar): Não foi possível validar dados para fazer a baixa da reserva!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                               'Operação.....: '||psOPERACAO;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
          END;
          -- Pedido de Avaria - Nao atualiza o Estoque Pendente - DDMEDICA-620
          IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
            -- Inserindo informações de debug (LOG)
            P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_baixar - PED. AVARIA';
            P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
            PRIV_GERARLOG;
            RETURN 'S';
          END IF;
          -- Pedido de CrossDocking - Nao atualiza o Estoque Pendente - DDMEDICA-620
          IF (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
            -- Inserindo informações de debug (LOG)
            P_INTERNO.INFORMACOES_LOG := P_INTERNO.PROGRAMA||' - Finalizou a função reserva_baixar - PED. CROSSDOCK';
            P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
            PRIV_GERARLOG;
            RETURN 'S';
          END IF;
        ELSE
          vsPOSICAO   := vsPOSICAOANT;
          vsCODFILIAL := vsCODFILIALANT;
        -- Validação do corte
        END IF;
        -- Caso seja uma NF de pré-faturamento,
        -- permitir baixar reserva a partir dela.
        SELECT COUNT(1)
          INTO vnQTDENFPREFAT
          FROM PCNFSAIDPREFAT C
         WHERE C.NUMPED = pnIDENTIFICADOR
           AND NOT EXISTS (SELECT 1
                             FROM PCNFSAID N
                            WHERE N.NUMTRANSVENDA = C.NUMTRANSVENDA);
        -- Atualizando o estoque
        IF (vsPOSICAOANT IN ('L', 'M') OR
           (vsPOSICAOANT = 'F' AND (vnQTDENFPREFAT = 1))) AND
           (vnCONDVENDAANT NOT IN (4, 7, 14)) THEN
          -- Locar tabela para fazer a reserva
          IF psOPERACAO NOT IN ('AQ') THEN
            -- Bloquear estoque reservado do item
            PRIV_BLOQUEAR_ESTOQUE (vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
            -- Validar se conseguiu bloquear o estoque
            IF psMSG_RETORNO <> 'OK' THEN
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
          END IF;
          -- Atualizar variáveis
          P_INTERNO.vtESTOQUE               := NULL;
          P_INTERNO.TIPO_OPERACAO           := 'B';
          P_INTERNO.vtESTOQUE.IDENTIFICADOR := pnIDENTIFICADOR;
          P_INTERNO.vtESTOQUE.CODFILIAL     := vsCODFILIALANT;
          P_INTERNO.vtESTOQUE.CODPROD       := pnCODPROD;
          P_INTERNO.vtESTOQUE.QTRESERV      := NVL(vnQTDEANT,0);
          -- Atualizar estoque reservado
          PRIV_ATUALIZAR_ESTOQUE;
          -- Validar se conseguiu atualizar o estoque
          IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
            psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Gravar dados analiticos
          PRIV_RESERVA_ANALITICA(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,vsPOSICAO,psOPERACAO,vsCODFILIAL,vnQTDEANT,vsROTINA,psMSG_RETORNO);
          IF psMSG_RETORNO <> 'OK' THEN
             PRIV_GERARLOG;
             RETURN 'N';
          END IF;

          IF (psOPERACAO IN ('BQ')) AND 
		     (P_INTERNO.NUMLOTE IS NOT NULL) AND 
			 ((vsROTINA LIKE '%PCSIS1409%') OR (vsROTINA LIKE '%PCSIS4109%')) THEN
            -- Atualizar Variáveis
            P_INTERNO.vtLOTE               := NULL;
            P_INTERNO.vtLOTE.IDENTIFICADOR := pnIDENTIFICADOR;
            P_INTERNO.vtLOTE.CODFILIAL     := vsCODFILIALANT;
            P_INTERNO.vtLOTE.CODPROD       := pnCODPROD;
            P_INTERNO.vtLOTE.NUMLOTE       := P_INTERNO.NUMLOTE;
            -- Bloquear PCLOTE
            PRIV_BLOQUEAR_LOTE;
            -- Validar se conseguiu bloquear a PCLOTE
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
            -- Atualizar dados
            P_INTERNO.vtLOTE.QT          := NULL;
            P_INTERNO.vtLOTE.QTEST       := NULL;
            P_INTERNO.vtLOTE.QTRESERV    := NVL(vnQTDEANT,0);
            P_INTERNO.vtLOTE.QTINDUSTRIA := NULL;
            P_INTERNO.vtLOTE.QTBLOQUEADA := NULL;
            P_INTERNO.vtLOTE.QTINDENIZ   := NULL;
            -- Administrar estoque do lote
            PRIV_ATUALIZAR_LOTE;
            -- Validando se conseguiu atualizar o lote
            IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
              psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
            END IF;
          -- Produto usa lote
          END IF;
        ELSE
          psMSG_RETORNO := 'Erro 8 (Reserva Baixar): Não foi possível retirar o estoque da reserva.'||CHR(13)||
                           'A posição ou tipo de venda do pedido não é válido para esta operação.'||CHR(13)||
                           'O Identificador ' ||TO_CHAR(pnIDENTIFICADOR) || ' não é valido ou !'||CHR(13)||
                           'Posição......: '||vsPOSICAOANT||CHR(13)||
                           'Tipo de venda: '||TO_CHAR(vnCONDVENDAANT)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
    -- Operação inválida
    ELSE
      psMSG_RETORNO := 'Erro 9 (Reserva Baixar): Não foi possível baixar o estoque da reserva.'||CHR(13)||
                       'O Identificador informado não é valido!'||CHR(13)||
                       'O Identificador: ' ||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.......: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da operação
    END CASE;
    -- Atualizar variáveis
    P_INTERNO.QTRESERV      := P_INTERNO.vtESTOQUE.QTRESERV;
    P_INTERNO.PROCESSO      := 'RESERVAR';
    -- Não é requisição de transferência entre depósitos
    IF P_INTERNO.TIPO_OPERACAO <> 'BR' THEN
      -- Movimenta estoque do depósito
      PRIV_DEP_BAIXAR;
    END IF;
    -- Valida se movimentação do depósito ficou correta
    IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
      psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva baixar';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Se der tudo certo o retorno cerá "S - Sim"
    RETURN 'S';
  -- Função
  END RESERVA_BAIXAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Alterar reservar de estoque da transação
  /************************************************************************************************************************/
  FUNCTION RESERVA_ALTERAR (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                           ,pnCODPROD         IN PCPEDI.CODPROD%TYPE
                           ,pnNUMSEQ          IN PCPEDI.NUMSEQ%TYPE
                           ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                           ,psMSG_RETORNO     OUT VARCHAR2
                           ,pnCODFUNC         IN PCEMPR.MATRICULA%TYPE DEFAULT 0)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONDVENDAANT      PCPEDC.CONDVENDA%TYPE;
    vnCONDVENDA         PCPEDC.CONDVENDA%TYPE;
    vsPOSICAOANT        PCPEDC.POSICAO%TYPE;
    vsPOSICAO           PCPEDC.POSICAO%TYPE;
    vnQTDEANT           PCMOV.QT%TYPE;
    vsCODFILIALANT      PCPEDC.CODFILIAL%TYPE;
    vnQTDE              PCMOV.QT%TYPE;
    vbBAIXOU            VARCHAR2(1);
    vbINCLUIU           VARCHAR2(1);
    vsTIPOOPERACAOPARAM VARCHAR2(3);
    vnCONTADOR          NUMBER:=0;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG      := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função reserva alterar';
    P_INTERNO.NOME_FUNCAO          := 'RESERVA_ALTERAR';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.NUMSEQ          := pnNUMSEQ;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Consultar dados ANTERIORES para o update no PCEST
    PRIV_CONS_DADOS_ANTERIORES (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,vnCONDVENDAANT,vsPOSICAOANT,vnQTDEANT,vsCODFILIALANT,psMSG_RETORNO);
    -- Verifica se deu tudo certo ao consultar dados anteriores
    IF psMSG_RETORNO <> 'OK' THEN
      PRIV_GERARLOG;
      RETURN 'N';
    END IF;
    /*-----------------------------------------------------
                    Consultar dados ATUAIS
    ------------------------------------------------------*/
    -- INDÚSTRIA
    CASE
      WHEN psOPERACAO = 'AI' THEN
        -- Consulta a ordem de produção
        BEGIN
          SELECT NVL(PCOPI.QTRESERVATUAL, 0) QTRESERVATUAL,
                 NVL(PCOPI.QTRESERVALTERAR, 0) QTRESERVALTERAR
            INTO vnQTDEANT
                ,vnQTDE
            FROM PCOPI, PCOPC
           WHERE PCOPI.NUMOP = PCOPC.NUMOP
             AND PCOPC.NUMOP = pnIDENTIFICADOR
             AND PCOPI.CODPROD = pnCODPROD;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 (Reserva Alterar): Não foi possível consultar dados do Identificador para alterar a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
      -- Cortes total
      WHEN psOPERACAO = 'FQ' THEN
        -- Verifica se o corte foi total
        SELECT COUNT(1)
          INTO vnCONTADOR
          FROM PCPEDI, PCPEDC
         WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
           AND PCPEDI.NUMPED = pnIDENTIFICADOR
           AND PCPEDI.CODPROD = pnCODPROD
           AND PCPEDI.NUMSEQ = pnNUMSEQ;
           --AND NVL(PCPEDI.QT,0) > 0;
        -- Caso não exista é corte TOTAL
        IF vnCONTADOR = 0 THEN
           vnQTDE      := 0;
           vsPOSICAO   := 'L';
           vnCONDVENDA := 1;
        -- Caso exista é corte PARCIAL
        ELSE
          BEGIN
            SELECT PCPEDI.QT
                  ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                  ,PCPEDC.CONDVENDA
              INTO vnQTDE, vsPOSICAO, vnCONDVENDA
              FROM PCPEDI, PCPEDC
             WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
               AND PCPEDI.NUMPED = pnIDENTIFICADOR
               AND PCPEDI.CODPROD = pnCODPROD
               AND PCPEDI.NUMSEQ = pnNUMSEQ;
               --AND NVL(PCPEDI.QT,0) > 0;
          EXCEPTION
            WHEN OTHERS THEN
              psMSG_RETORNO := 'Erro 2 (Reserva Alterar): Não foi possível consultar dados do Identificador para alterar a reserva!'||CHR(13)||
                               'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                               'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                               'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                               'Operação.....: '||psOPERACAO||CHR(13)||
                               'MSG Original.: '||SQLERRM;
              P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
              PRIV_GERARLOG;
              RETURN 'N';
          END;
        -- Corte total
        END IF;
      -- Ordem de serviço
      WHEN psOPERACAO = 'AO' THEN
        -- Consultar itens para fazer alterar reserva
        BEGIN
          SELECT NVL(SUM(A.QTDE),0) AS QT
            INTO vnQTDE
            FROM PCITEMSERVICO A,
                 PCORDEMSERVICO O,
                 PCORDEMSERVICOI I,
                 PCTIPOORDEMSERVICO T,
                 PCCONSUM
           WHERE O.NUMOS = I.NUMOS
             AND I.NUMOSSERVICO = A.NUMOSSERVICO
             AND O.TIPOOS = T.CODTIPO(+)
             AND O.NUMTRANSVENDAPROD IS NULL
             AND NVL(A.DEMONSTRACAO,'N') = 'N'
             AND O.NUMOS = pnIDENTIFICADOR
             AND A.CODPROD = pnCODPROD
             AND ((NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   NVL(T.GERARCONTRECEBERPRODUTO, 'N') = 'S' AND
                   O.SITUACAO IN (2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'N' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'S' AND
                   O.SITUACAO IN (1, 2, 4))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2))
                  OR
                  (NVL(T.OSCOMODATO,'N') = 'S' AND
                   NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'S' AND
                   O.SITUACAO IN (2))
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO, 'N') = 'S' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N')
                  OR
                  (NVL(PCCONSUM.OSRESERVANAEXECUCAO,'N') = 'N' AND
                   NVL(A.DEMONSTRACAO,'N') = 'N' AND
                   O.SITUACAO IN (1, 2) AND
                   NVL(T.GERARCONTRECEBERPRODUTO,'N') = 'N'))
           GROUP BY A.CODFILIALRETIRA;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 7 (Reserva Alterar): Não foi possível consultar dados do Identificador para alterar a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
      -- Pedidos de vendas
      WHEN psOPERACAO IN ('IN','IV','IP','BQ','BV','BP','AQ','AV','AP','CQ','CV','CP','CC','FQ') THEN
        BEGIN
          SELECT PCPEDI.QT
                ,DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) POSICAO
                ,PCPEDC.CONDVENDA
            INTO vnQTDE, vsPOSICAO, vnCONDVENDA
            FROM PCPEDI, PCPEDC
           WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
             AND PCPEDI.NUMPED = pnIDENTIFICADOR
             AND PCPEDI.CODPROD = pnCODPROD
             AND PCPEDI.NUMSEQ = pnNUMSEQ;
             --AND NVL(PCPEDI.QT,0) > 0;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 3 (Reserva Alterar): Não foi possível consultar dados do Identificador para fazer a reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                             'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
    -- Busca de dados atuais
    END CASE;
    /*-----------------------------------------------------
                    Inicio das Validações
    -----------------------------------------------------*/
    -- Alterar posição pedido de venda
    CASE
      WHEN psOPERACAO = 'AP' THEN
        -- Validar se existe mudança de posição
        IF (vnCONDVENDA NOT IN (4, 7, 14)) AND (vsPOSICAOANT IN ('L', 'M')) AND
           (vsPOSICAO IN ('P', 'B')) THEN
          -- Bloquear estoque reservado do item
          PRIV_BLOQUEAR_ESTOQUE (vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
          -- Validar se conseguiu BLOQUEAR o estoque
          IF psMSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Executar a função de baixa de reserva
          vbBAIXOU := RESERVA_BAIXAR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,psMSG_RETORNO);
          --Executar a função de incluir a reserva
          vbINCLUIU := RESERVA_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,TRUE,psOPERACAO,psMSG_RETORNO);
          -- Atualizando também a variavel de inclusão
          IF vbBAIXOU = 'S' THEN
            vbINCLUIU := 'S';
          END IF;
        -- Validação
        ELSE
          psMSG_RETORNO := 'Erro 9 (Reserva Alterar): Não foi possível alterar a reserva!'||CHR(13)||
                           'verifique o codigo de venda'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                           'Num. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                           'Cond Venda.....:'||TO_CHAR(vnCONDVENDA)||CHR(13)||
                           'Operação.....: '||psOPERACAO||CHR(13)||
                           'MSG Original.: '||SQLERRM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Indústria
      WHEN psOPERACAO = 'AI' THEN
        -- Caso a quantidade seja zero Inicio - Indústria Alterar
        IF NOT vnQTDE = 0 THEN
          -- Bloquear estoque reservado do item
          PRIV_BLOQUEAR_ESTOQUE (vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
          -- Validar se conseguiu BLOQUEAR o estoque
          IF psMSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Caso a quantidade seja menor que zero
          IF vnQTDE < 0 THEN
            -- Operação parassa a ser de baixa
            vsTIPOOPERACAOPARAM := 'BI';
            -- Baixar quantidade encontrada na reserva
            vbBAIXOU := RESERVA_BAIXAR (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,vsTIPOOPERACAOPARAM,psMSG_RETORNO);
            vbINCLUIU := 'S';
            -- Atualizar dados na ordem de produção
            UPDATE PCOPI
               SET PCOPI.QTREQUISITADO = QTREQUISITADO - (NVL(vnQTDE,0) * (-1))
             WHERE NUMOP = pnIDENTIFICADOR
               AND CODPROD = pnCODPROD;
          -- Caso quantidade maior que zero
          ELSE
            -- Operação parassa a ser de inclusão
            vsTIPOOPERACAOPARAM := 'II';
            -- Incluir quantidade encontrada na reserva
            IF vsROTINA LIKE '%998%' THEN
              vbINCLUIU := RESERVA_INCLUIR (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,vsTIPOOPERACAOPARAM,psMSG_RETORNO, pnCODFUNC);
            ELSE
              vbINCLUIU := RESERVA_INCLUIR (pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,vsTIPOOPERACAOPARAM,psMSG_RETORNO);
            END IF;
            vbBAIXOU := 'S';
            -- Atualizar dados na ordem de produção
            UPDATE PCOPI
               SET PCOPI.QTRESERVALTERAR = 0
             WHERE PCOPI.NUMOP = pnIDENTIFICADOR
               AND PCOPI.CODPROD = pnCODPROD;
          -- Quantidade
          END IF;
          -- Validar se a baixar ou inclusão foram feitas corretamento
          IF ((vbBAIXOU = 'S') AND (vbINCLUIU = 'S')) THEN
            RETURN 'S';
          ELSE
            RETURN 'N';
          END IF;
        -- Caso não tenha QTRESERVALTERAR na tabela PCOPI
        ELSE
          psMSG_RETORNO := 'Erro 4 (Reserva Alterar): Não existe reserva a ser feita ou desfeita para o item informado!'||CHR(13)||
                           'Verifique se a função e a operação executadas estão corretas'||CHR(13)||
                           'Função chamada: RESERVA_ALTERAR_PEDIDO ou RESERVA_ALTERAR'||CHR(13)||
                           'Operação......: '||vsTIPOOPERACAOPARAM;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Ordem alterar
      WHEN psOPERACAO = 'AO' THEN
        IF (vnQTDEANT <> vnQTDE) THEN
          -- Bloquear estoque reservado do item
          PRIV_BLOQUEAR_ESTOQUE (vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
          -- Validar se conseguiu BLOQUEAR o estoque
          IF psMSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          --
          vsTIPOOPERACAOPARAM := 'BO';
          -- não lança exceção para operações não encontradas
          vbBAIXOU            := RESERVA_BAIXAR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,vsTIPOOPERACAOPARAM,psMSG_RETORNO);
          vsTIPOOPERACAOPARAM := 'IO';
          -- lança exceção para operações não encontradas
          IF vsROTINA LIKE '%998%' THEN
            vbINCLUIU := RESERVA_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,vsTIPOOPERACAOPARAM,psMSG_RETORNO, pnCODFUNC);
          ELSE
            vbINCLUIU := RESERVA_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,vsTIPOOPERACAOPARAM,psMSG_RETORNO);
          END IF;
        --
        ELSE
          psMSG_RETORNO := 'Erro 5 (Reserva Alterar): Não existe reserva a ser feita ou desfeita para o item informado!'||CHR(13)||
                           'Verifique se a função e a operação executadas estão corretas'||CHR(13)||
                           'Função chamada: RESERVA_ALTERAR_PEDIDO ou RESERVA_ALTERAR'||CHR(13)||
                           'Operação......: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- PEDIDO DE VENDA
      WHEN psOPERACAO IN ('IN','IV','IP','BQ','BV','BP','AQ','AV','AP','CQ','CV','CP','CC','FQ') THEN
        IF (vnCONDVENDA NOT IN (4, 7, 14)) AND (vsPOSICAO IN ('L', 'M')) AND
           (vnQTDEANT <> vnQTDE) THEN
          -- Bloquear estoque reservado do item
          PRIV_BLOQUEAR_ESTOQUE (vsCODFILIALANT,pnCODPROD,psMSG_RETORNO);
          -- Validar se conseguiu BLOQUEAR o estoque
          IF psMSG_RETORNO <> 'OK' THEN
            PRIV_GERARLOG;
            RETURN 'N';
          END IF;
          -- Baixar o estoque reservado
          vbBAIXOU  := RESERVA_BAIXAR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,psOPERACAO,psMSG_RETORNO);
          -- Valida se é operação de corte total
          IF (psOPERACAO = 'FQ' AND vnQTDE = 0) THEN
            vbINCLUIU := 'S';
          ELSE
            IF vsROTINA LIKE '%998%' THEN
              vbINCLUIU := RESERVA_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,psOPERACAO,psMSG_RETORNO,pnCODFUNC);
            ELSE
              vbINCLUIU := RESERVA_INCLUIR(pnIDENTIFICADOR,pnCODPROD,pnNUMSEQ,FALSE,psOPERACAO,psMSG_RETORNO);
            END IF;
          END IF;
        -- Validação não atendida
        ELSE
          psMSG_RETORNO := 'Erro 6 (Reserva Alterar): Não existe reserva a ser feita ou desfeita para o item informado!'||CHR(13)||
                           'Verifique se a função e a operação executadas estão corretas'||CHR(13)||
                           'Função chamada: RESERVA_ALTERAR_PEDIDO ou RESERVA_ALTERAR'||CHR(13)||
                           'Operação......: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação
        END IF;
    -- Operação inválida
    ELSE
      psMSG_RETORNO := 'Erro 8 (Reserva Alterar): A operação informada não é válida!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13)||
                       'Núm. Seq.....: '||TO_CHAR(pnNUMSEQ)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação operação
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva alterar';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Inserindo o retorno
    IF ((vbBAIXOU = 'S') AND (vbINCLUIU = 'S')) THEN
      RETURN 'S';
    ELSE
      RETURN 'N';
    END IF;
  -- Função
  END RESERVA_ALTERAR;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Incluir reservar de estoque do pedido
  /************************************************************************************************************************/
  FUNCTION RESERVA_INCLUIR_PEDIDO (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                  ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                  ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADOR NUMBER;
    vsVALIDO   VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    vnCONTADOR                := 0;
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG      := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função reserva incluir pedido';
    P_INTERNO.NOME_FUNCAO          := 'RESERVA_INCLUIR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    /*-----------------------------------------------------
              Validando o tipo de OPERAÇÃO
    ------------------------------------------------------*/
    CASE
      -- Requisição de materia prima
      WHEN psOPERACAO = 'IM' THEN
        -- Lista de produtos
        FOR ITENS IN (SELECT DISTINCT RI.CODPROD
                        FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
                       WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
                         AND RI.NUMPREREQUISICAO = pnIDENTIFICADOR
                         AND RI.CODOPER = 'SM'
                         AND RC.SITUACAO = 'L')
        LOOP
          -- Contador de registros
          vnCONTADOR := vnCONTADOR + 1;
          -- Reservar produto
          vsVALIDO := RESERVA_INCLUIR(pnIDENTIFICADOR,ITENS.CODPROD,NULL,TRUE,psOPERACAO,psMSG_RETORNO);

      IF psMSG_RETORNO <> 'OK' THEN
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END IF;
        -- Lista produtos
        END LOOP;
        -- Indentificador valido
        IF vnCONTADOR = 0 THEN
          psMSG_RETORNO := 'Erro 1 (Reserva Incluir Ped): Não existe dados válidos para fazer a reserva!'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Valido
        END IF;
      -- Industria inclui avulsa
      WHEN psOPERACAO = 'IA' THEN
        -- Lista de produtos
        FOR ITENS IN (SELECT CODPROD, NVL(QT, 0) QT, CODOPER, NUMSEQ
                        FROM PCAVULSA
                       WHERE NUMTRANSAVULSA = pnIDENTIFICADOR
                         AND CODOPER IN ('S','P'))
        LOOP
          -- Tem registros
          vnCONTADOR := vnCONTADOR + 1;
          -- Reservar produto
          vsVALIDO := RESERVA_INCLUIR(pnIDENTIFICADOR,ITENS.CODPROD,ITENS.NUMSEQ,FALSE,psOPERACAO,psMSG_RETORNO);

      IF psMSG_RETORNO <> 'OK' THEN
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END IF;
        -- Lista de produtos
        END LOOP;
        -- Não tem produtos válidos
        IF vnCONTADOR = 0 THEN
          psMSG_RETORNO := 'Erro 2 (Reserva Incluir Ped): O Identificador não é válido para reservar estoque!'||CHR(13)||
                           'Verifique a situação e a operação do Identificador.'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Pedido de venda
      WHEN psOPERACAO IN ('IN','IV','IP','AQ','AV','AP') THEN
        -- Lista de itens para fazer reserva
        FOR ITENS IN (SELECT PCPEDI.CODPROD, PCPEDI.NUMSEQ
                        FROM PCPEDI
                            ,PCPEDC
                       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                         AND PCPEDC.NUMPED = pnIDENTIFICADOR
                         AND DECODE(NVL(PCPEDC.VENDAASSISTIDA,'N'),'S',NVL(PCPEDI.POSICAO,PCPEDC.POSICAO),PCPEDC.POSICAO) IN ('L', 'M')
                         AND PCPEDC.CONDVENDA NOT IN (4, 7, 14)
                         AND NVL(PCPEDC.DEVSIMBOLICA,'N') = 'N'
                         AND PCPEDI.QT > 0
                    ORDER BY PCPEDI.CODPROD, PCPEDI.NUMSEQ)
        LOOP
          -- Contador de registros
          vnCONTADOR := vnCONTADOR + 1;
          -- Executar a reserva do estoque item a item
          vsVALIDO := RESERVA_INCLUIR(pnIDENTIFICADOR,ITENS.CODPROD,ITENS.NUMSEQ,TRUE,psOPERACAO,psMSG_RETORNO);

      IF psMSG_RETORNO <> 'OK' THEN
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END IF;
        -- Lista de produtos
        END LOOP;
        -- Caso o pedido não seja valido
        IF vnCONTADOR = 0 THEN
          psMSG_RETORNO := 'Erro 3 (Reserva Incluir Ped): O Identificador não é válido para reservar estoque!'||CHR(13)||
                           'Verifique a posição e o tipo de venda do Identificador.'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
    -- Operação inválida
    ELSE
      psMSG_RETORNO := 'Erro 4 (Reserva Incluir Ped): A operação informada é inválida!'||CHR(13)||
                       'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                       'Operação.....: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Operação
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva incluir pedido';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Validar retornos
    RETURN vsVALIDO;
  -- Procedure
  END RESERVA_INCLUIR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Baixar reservar de estoque do pedido
  /***********************************************************************************************************************/
  FUNCTION RESERVA_BAIXAR_PEDIDO (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                 ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                 ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADOR NUMBER;
    vsVALIDO   VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    vnCONTADOR                := 0;
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG      := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função reserva baixar pedido';
    P_INTERNO.NOME_FUNCAO          := 'RESERVA_BAIXAR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    -- Validando qual é o tipo de ação que o usuário esta executando na rotina
    CASE
      WHEN psOPERACAO IN ('AM','CM') THEN
        -- Lista de itens
        FOR ITENS IN (SELECT DISTINCT RI.CODPROD
                        FROM PCPREREQMATCONSUMOI RI, PCPREREQMATCONSUMOC RC
                       WHERE RI.NUMPREREQUISICAO = RC.NUMPREREQUISICAO
                         AND RI.CODOPER = 'SM'
                         AND RI.NUMPREREQUISICAO = pnIDENTIFICADOR)
        LOOP
          -- Contardor de registros
          vnCONTADOR := vnCONTADOR + 1;
          -- Baixar a Reservar
          vsVALIDO := RESERVA_BAIXAR(pnIDENTIFICADOR,ITENS.CODPROD,NULL,psOPERACAO,psMSG_RETORNO);

      IF psMSG_RETORNO <> 'OK' THEN
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END IF;
        -- Lista de itens
        END LOOP;
        -- Validar se existe registros
        IF vnCONTADOR = 0 THEN
          -- Mensagem de erro
          psMSG_RETORNO := 'Erro 1 (Reserva Baixar Ped): O Identificador não é válido para baixa da reservar!'||CHR(13)||
                           'Verifique a situação e a operação do Identificador informado.'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Registros
        END IF;
      -- Industria inclui avulsa
      WHEN psOPERACAO = 'BA' THEN
        BEGIN
          -- Lista de itens
          FOR REGISTROS IN (SELECT CODPROD, NVL(QT, 0) QT, CODOPER, NUMSEQ
                              FROM PCAVULSA
                             WHERE NUMTRANSAVULSA = pnIDENTIFICADOR)
          LOOP
            -- Valida os dados
            IF (REGISTROS.CODOPER = 'S') OR (REGISTROS.CODOPER = 'P') THEN
              -- Contardor de registros
              vnCONTADOR := vnCONTADOR + 1;
              -- Baixar Reserva
              vsVALIDO := RESERVA_BAIXAR(pnIDENTIFICADOR,REGISTROS.CODPROD,REGISTROS.NUMSEQ,psOPERACAO,psMSG_RETORNO);

        IF psMSG_RETORNO <> 'OK' THEN
                P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 'N';
            END IF;
            -- Validar dados
            END IF;
          -- Lista de itens
          END LOOP;
        -- Erro no select
        EXCEPTION
          WHEN OTHERS THEN
            -- Mensagem de erro
            psMSG_RETORNO := 'Erro 2 (Reserva Baixar Ped): Não foi possível consultar dados do item para baixa da reserva!'||CHR(13)||
                             'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                             'Operação.....: '||psOPERACAO||CHR(13)||
                             'MSG Original.: '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END;
        -- Validar se existe registros
        IF vnCONTADOR = 0 THEN
          -- Mensagem de erro
          psMSG_RETORNO := 'Erro 3 (Reserva Baixar Ped): O Identificador não é válido para baixa da reservar!'||CHR(13)||
                           'Verifique a situação e a operação do Identificador informado.'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação
        END IF;
      -- Pedido de vendas (PCPEDC e PCPEDI)
      WHEN psOPERACAO IN ('IN','IV','IP','BQ','BV','BP','AQ','AV','AP','CQ','CV','CP','CC','FQ') THEN
        -- Lista de itens
        FOR ITENS IN (SELECT PCPEDI.NUMPED, PCPEDI.CODPROD, PCPEDI.NUMSEQ
                        FROM PCPEDI
                            ,PCPEDC
                       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                         AND PCPEDI.NUMPED = pnIDENTIFICADOR
                    ORDER BY PCPEDI.CODPROD, PCPEDI.NUMSEQ)
        LOOP
          -- Contardor de registros
          vnCONTADOR := vnCONTADOR + 1;
          -- Baixar Reserva
          vsVALIDO := RESERVA_BAIXAR(pnIDENTIFICADOR,ITENS.CODPROD,ITENS.NUMSEQ,psOPERACAO,psMSG_RETORNO);

      IF psMSG_RETORNO <> 'OK' THEN
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            PRIV_GERARLOG;
            RETURN 'N';
        END IF;
        -- Lista itens
        END LOOP;
        -- Validar se existe registros
        IF vnCONTADOR = 0 THEN
          -- Mensagem de erro
          psMSG_RETORNO := 'Erro 4 (Reserva Baixar Ped): O Identificador não é válido para baixa da reservar!'||CHR(13)||
                           'Verifique a situação e a operação do Identificador informado.'||CHR(13)||
                           'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                           'Operação.....: '||psOPERACAO;
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        -- Validação
        END IF;
    -- Operação invalida
    ELSE
      -- Mensagem de erro
      psMSG_RETORNO := 'Erro 5 (Reserva Baixar Ped): A operação informada é inválida para baixa da reservar!'||CHR(13)||
                       'Operação informada: '||psOPERACAO;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Validação da OPERACAO
    END CASE;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva baixar pedido';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Inserir retorno para a função
    RETURN vsVALIDO;
  -- Função
  END RESERVA_BAIXAR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  01/03/2017    Fernandes Brito    0                   Alterar reservar de estoque do pedido
  /***********************************************************************************************************************/
  FUNCTION RESERVA_ALTERAR_PEDIDO (pnIDENTIFICADOR   IN PCLOGPKG_ESTOQUE.IDENTIFICADOR%TYPE
                                  ,psOPERACAO        IN PCLOGPKG_ESTOQUE.TIPO_OPERACAO%TYPE
                                  ,psMSG_RETORNO     OUT VARCHAR2)
  RETURN VARCHAR2
  IS-- Declaração das variáveis internas
    vnCONTADOR NUMBER;
    vsVALIDO   VARCHAR2(1);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    vnCONTADOR                := 0;
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||'iniciou a função reserva alterar pedido';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_ALTERAR_PEDIDO';
    P_INTERNO.IDENTIFICADOR   := pnIDENTIFICADOR;
    P_INTERNO.TIPO_OPERACAO   := psOPERACAO;
    PRIV_GERARLOG;
    --Operações validas
    IF (psOPERACAO IN ('IN','BQ','AQ','CQ','FQ')) THEN
      -- Lista de produtos
      FOR ITENS IN (SELECT PCPEDI.NUMPED, PCPEDI.CODPROD, PCPEDI.NUMSEQ
                      FROM PCPEDI
                          ,PCPEDC
                     WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
                       AND PCPEDI.NUMPED = pnIDENTIFICADOR
                  ORDER BY PCPEDI.CODPROD,PCPEDI.NUMSEQ)
                       --AND NVL(PCPEDI.QT,0) > 0)
      LOOP
        -- Contador de registros
        vnCONTADOR := vnCONTADOR + 1;
        -- Alterar a reserva do item
        vsVALIDO := RESERVA_ALTERAR(ITENS.NUMPED,ITENS.CODPROD,ITENS.NUMSEQ,psOPERACAO,psMSG_RETORNO);

        IF psMSG_RETORNO <> 'OK' THEN
          P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 'N';
        END IF;
      -- Lista de produtos
      END LOOP;
      -- Indentificador valido
      IF vnCONTADOR = 0 THEN
        psMSG_RETORNO := 'Erro 1 (Reserva Alterar Ped): Não existe dados válidos para fazer a reserva!'||CHR(13)||
                         'Identificador: '||TO_CHAR(pnIDENTIFICADOR)||CHR(13)||
                         'Operação.....: '||psOPERACAO;
        P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 'N';
      -- Valido
      END IF;
    ELSE
      psMSG_RETORNO := 'Erro 2 (Reserva Alterar Ped): A opera??o informada n?o ? valida'||CHR(13)||
                       'Operação: '||psOPERACAO;
      PRIV_GERARLOG;
      RETURN 'N';
    -- Valido
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva alterar pedido';
    P_INTERNO.NOME_FUNCAO     := 'RESERVA_INCLUIR';
    PRIV_GERARLOG;
    -- Valido?
    RETURN vsVALIDO;
  -- Função
  END RESERVA_ALTERAR_PEDIDO;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  23/16/2020     Davi Bernado      0                   Criada a Função para validar a Filial do pedido
  /***********************************************************************************************************************/
  FUNCTION VALIDA_CODFILIAL_CEFAT( PNIDENTIFICADOR   IN PCPEDC.NUMPED%TYPE
                                  ,PNCODPROD         IN PCPEDI.CODPROD%TYPE
                                  ,PNNUMSEQ          IN PCPEDI.NUMSEQ%TYPE)
  RETURN VARCHAR2
  IS
    VSPOSICAOCFAT   PCPEDI.POSICAOCFAT%TYPE;
    VSCODFILIAL     PCPEDC.CODFILIAL%TYPE;
  BEGIN
    -- BUSCAR FILIAL
    BEGIN
      SELECT PCPEDI.POSICAOCFAT
            ,CASE
              WHEN FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZACENTRALFATURAMENTO','99','N') = 'S' THEN
                DECODE(PCPEDI.POSICAOCFAT
                      ,NULL, NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                      ,'AFA', NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                      ,'ERE', NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
                      ,'EVE', PCPEDC.CODFILIAL
                      ,'SRE', NULL
                      ,'SVE', NULL
                      ,'EVI', NVL(PCPEDC.CODFILIALNF, PCPEDC.CODFILIAL)
                      ,NULL)
             ELSE
               NVL(PCPEDI.CODFILIALRETIRA, PCPEDC.CODFILIAL)
             END CODFILIAL
        INTO VSPOSICAOCFAT
            ,VSCODFILIAL
        FROM PCPEDI, PCPEDC
       WHERE PCPEDI.NUMPED = PCPEDC.NUMPED
         AND PCPEDI.NUMPED = PNIDENTIFICADOR
         AND PCPEDI.CODPROD = PNCODPROD
         AND PCPEDI.NUMSEQ = NVL(PNNUMSEQ, 1);
      -- NÃO EXISTE DADOS PARA FAZER RESERVA
      IF VSCODFILIAL IS NULL THEN
        P_INTERNO.INFORMACOES_LOG := VSPOSICAOCFAT||' - NÃO EXISTEM DADOS PARA FAZER A RESERVA';
        PRIV_GERARLOG;
        RETURN NULL;
      END IF;
    EXCEPTION
      WHEN OTHERS THEN
        P_INTERNO.MSG_RETORNO := 'ERRO 1 (VALIDA_CODFILIAL_CEFAT): NÃO FOI POSSÍVEL CONSULTAR DADOS DO ITEM PARA FAZER A RESERVA!'||CHR(13)||
                                 'IDENTIFICADOR: '||TO_CHAR(PNIDENTIFICADOR)||CHR(13)||
                                 'PRODUTO......: '||TO_CHAR(PNCODPROD)||CHR(13)||
                                 'NUM. SEQ.....: '||TO_CHAR(PNNUMSEQ)||CHR(13)||
                                 'OPERAÇÃO.....: '||VSPOSICAOCFAT||CHR(13)||
                                 'MSG ORIGINAL.: '||SQLERRM;

        PRIV_GERARLOG;
        RETURN NULL;
    END;

    RETURN VSCODFILIAL;
  END VALIDA_CODFILIAL_CEFAT;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  06/05/2014     Rodrigo Santos    0                   Alteração para separar regras quanto a definição das movimentações de estoque
                                                       contábil e gerencial, estas regras passam a ser tratadas pela função "VENDAS.PRIV_DEFINIR_MOVESTOQUE"
  29/07/2014     Marcos Garcia     0.080450.2014       Ajsutado package para verificar os parametros "VOLTARESTOQUEFILIALRETIRA" e "BLOQDEVCLI"
  ************************************************************************************************************************/
  FUNCTION VENDAS_ENTRADA_PROD (pnNUMTRANSACAO            IN PCMOV.NUMTRANSENT%TYPE
                               ,pnCODPROD                 IN PCMOV.CODPROD%TYPE
                               ,psAPENAS_QTEST_QTESTGER   IN VARCHAR2
                               ,psECANCELAMENTO           IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                               ,psMSG_RETORNO             OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS          NUMBER;
    vnESTOQUE_QTEST              PCEST.QTEST%TYPE;
    vnESTOQUE_QTESTGER           PCEST.QTESTGER%TYPE;
    vnESTOQUE_QTINDENIZ          PCEST.QTINDENIZ%TYPE;
    vnESTOQUE_QTBLOQUEADA        PCEST.QTBLOQUEADA%TYPE;
    vnESTOQUE_QTRESERV           PCEST.QTRESERV%TYPE;
    vsVOLTARESTOQUEFILIALRETIRA  VARCHAR2(5);
    vsVOLTARESTOQUEFILIALVIRTUAL VARCHAR2(5);
    -- Essas variaveis são paa a ajustar a perna da versão 22 com a 23
    vsFILIALAJUSTEESTOQUE        PCFILIAL.CODIGO%TYPE;
    vnQTAJUSTEESTOQUE            PCMOV.QT%TYPE;
    vsROWIDAJUSTEESTOQUE         VARCHAR2(100);
    vnNUMTRANSVENDAAJUSTEESTOQUE PCMOV.NUMTRANSVENDA%TYPE;
    vsBLOQDEVCLI                 VARCHAR2(2);
    vsBLOQUEARENTPA              VARCHAR2(2);
    vsTIPO_TRANSFERENCIA         VARCHAR2(2);
    vnQTBLOQUEAR                 PCEST.QTBLOQUEADA%TYPE;
    vnDTMOVPRIMERIO              DATE;
    vbUTILIZOUCFAT               BOOLEAN;
    vsCODFILIAL_CFAT             PCFILIAL.CODIGO%TYPE;
    vnUTILIZOUCFAT               NUMBER;
    vnCONDVENDA                  NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;

    vnCONTADORREGISTROS       := 0;
    vnCONDVENDA               := 0;
    psMSG_RETORNO             := 'OK';
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - VENDAS_ENTRADA_PROD';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADA_PROD';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.NUMTRANSENT     := pnNUMTRANSACAO;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.CODOPER         := 'E';
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;

    -- Validar transação informada
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Vendas Entrada Prod): O numtransação informado não é valido'||CHR(13)||
                       'Identificador: '||pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    -- Notas canceladas devem movimentar estoque conforme a movimentação feita na origem
    IF psECANCELAMENTO = 'N' THEN
      -- Definir tipo de movimentação
      PRIV_DEFINIR_MOVESTOQUE;
    END IF;

    IF psECANCELAMENTO = 'S' THEN
      BEGIN
		SELECT CONDVENDA 
		  INTO vnCONDVENDA
		  FROM PCPEDC 
		 WHERE NUMPED IN (SELECT NUMPED 
							  FROM PCMOV 
							 WHERE NUMTRANSVENDA IN (SELECT PCESTCOM.NUMTRANSVENDA 
													   FROM PCESTCOM 
	  												  WHERE PCESTCOM.NUMTRANSENT = pnNUMTRANSACAO)); 
      EXCEPTION
	    WHEN OTHERS THEN
		  vnCONDVENDA := 0;
	  END;
	END IF; 

    -- Lista produtos a serem alterados
    FOR REGISTROS IN (SELECT PCMOV.CODPROD -- Dados do estoque
                            ,ESTOQUECONTABIL.CODFILIAL  CODFILIALCONTABIL
                            ,ESTOQUEGERENCIAL.CODFILIAL CODFILIALGERENCIAL
                            ,PCMOV.CODFILIAL            CODFILIALVENDA
                             -- Dados da nota fiscal
                            ,PCMOV.NUMTRANSENT
                            ,PCMOV.CODOPER
                            ,PCMOV.DESCRICAO
                            ,PCMOV.STATUS
                            ,PCMOV.NUMLOTE
                            ,PCMOV.ROWID NOTA_ROWID
                            ,CASE
                               WHEN FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('DEVOLVESIMPLESREMTV13TOTAL',PCMOV.CODFILIAL,'N') = 'S' AND PCMOV.ROTINACAD LIKE '%1332%' THEN
                                 ABS(PCMOVCOMPLE.QTRETORNOTV13)
                             ELSE
                               ABS(DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)))
                             END  NOTA_QT
                            ,CASE
                               WHEN FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('DEVOLVESIMPLESREMTV13TOTAL',PCMOV.CODFILIAL,'N') = 'S' AND PCMOV.ROTINACAD LIKE '%1332%' THEN
                                 ABS(NVL(PCMOVCOMPLE.QTRETORNOTV13,0))
                             ELSE
                               ABS(NVL(PCMOV.QTCONT, 0))
                             END NOTA_QTCONT
                             --*******************
                            ,ABS(NVL(PCMOV.QTAVARIA, 0)) NOTA_QTAVARIA
                            ,ABS(DECODE(NVL(PCMOV.QTBLOQUEADA, 0),0,NVL(PCMOV.QTAVARIA, 0), NVL(PCMOV.QTBLOQUEADA, 0))) NOTA_QTBLOQUEADA
                             ----------------------------------------------------------
                            ,NVL(PCMOV.MOVESTOQUEGERENCIAL,DECODE(PCMOV.STATUS, 'A', 'N', 'S')) MOVESTOQUEGERENCIAL
                            ,NVL(PCMOV.MOVESTOQUECONTABIL,DECODE(PCMOV.STATUS, 'B', 'N', 'S')) MOVESTOQUECONTABIL
                            ,SUBSTR(PCMOV.ROTINACAD, 6, 4) ROTINACAD
                            ,NVL(PCMOV.CODFUNCLANC, 0) CODFUNCLANC
                            ,NVL(PCMOV.CODDEVOL, 0) CODDEVOL
                            ,ABS(NVL(PCMOVCOMPLE.QTINDUSTRIA,0)) QTINDUSTRIA
                            ,NVL(PCMOV.NUMOP,0) NUMOP
                            ,PCMOV.CODDEPOSITO
                            ,PCMOV.DATAESTOQUE
                            ,PCMOV.DTMOV
                            ,PCMOV.NUMPED
                            ,PCMOV.NUMSEQ
                        FROM PCMOV,
                             PCEST ESTOQUEGERENCIAL
                            ,PCEST ESTOQUECONTABIL
                            ,PCMOVCOMPLE
                       WHERE PCMOV.CODPROD = ESTOQUEGERENCIAL.CODPROD
                         AND PCMOV.CODPROD = ESTOQUECONTABIL.CODPROD
                         AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = ESTOQUECONTABIL.CODFILIAL
                         AND NVL(PCMOV.CODFILIALRETIRA, PCMOV.CODFILIAL) = ESTOQUEGERENCIAL.CODFILIAL
                         AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+)
                         AND PCMOV.NUMTRANSENT = pnNUMTRANSACAO
                         AND (NVL(pnCODPROD, 0) = 0 or PCMOV.CODPROD = pnCODPROD)
                         AND PCMOV.CODOPER LIKE 'E%'
                         AND ((psECANCELAMENTO = 'S' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) < 0 AND (PCMOV.ROTINACAD NOT LIKE '%1122%' OR PCMOV.DATAESTOQUE is null)) OR
                              (psECANCELAMENTO = 'N' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) > 0))
                         AND NOT EXISTS(SELECT 1 FROM PCMOV P,PCMOVCOMPLE M
                                         WHERE P.ROWID = PCMOV.ROWID
                                         AND P.NUMTRANSITEM = M.NUMTRANSITEM
                                         AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('DEVOLVESIMPLESREMTV13TOTAL',
                                                                                 NVL(PCMOV.CODFILIALNF,
                                                                                 PCMOV.CODFILIAL),
                                                                                                  'N') = 'S'
                                         AND NVL(M.QTRETORNOTV13,0) = 0
                                         AND P.ROTINACAD LIKE '%1332%')
                         AND NOT(PCMOV.CODOPER IN ('EA') AND PCMOVCOMPLE.NUMINVENT IS NOT NULL AND PCMOV.STATUS = 'B')
                    ORDER BY PCMOV.CODPROD, PCMOV.NUMSEQ)
    LOOP
      --
      IF psECANCELAMENTO = 'N' THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (VENDAS_ENTRADA_PROD): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROS = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (VENDAS_ENTRADA_PROD): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
      --
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG       := 'Executando a lista de produtos';
      P_INTERNO.CODFILIAL             := REGISTROS.CODFILIALVENDA;
      P_INTERNO.CODPROD               := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Conta registros
      vnCONTADORREGISTROS := vnCONTADORREGISTROS + 1;
      -- Carregando campos estoque contábil
      
      -- Carregando campos estoque gerencial
      -- Se não for transferência, não for entrada de produção e movimentar estoque gerencial
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
        SELECT NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
          INTO vnESTOQUE_QTESTGER
          FROM PCEST
         WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
           AND PCEST.CODPROD = REGISTROS.CODPROD;
      ELSE
        vnESTOQUE_QTESTGER := 0;
      END IF;
      --
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') AND
         (REGISTROS.CODOPER NOT IN ('ET','EP','EA','EI')) THEN
        --
        SELECT GREATEST(GREATEST(NVL(PCEST.QTBLOQUEADA, 0),NVL(PCEST.QTINDENIZ, 0)), 0) ESTOQUE_QTBLOQUEADA
              ,GREATEST(NVL(PCEST.QTINDENIZ, 0), 0) ESTOQUE_QTINDENIZ
              ,NVL(PCEST.QTRESERV, 0) ESTOQUE_QTRESERV --Pedida para venda / reservada
          INTO vnESTOQUE_QTBLOQUEADA,
               vnESTOQUE_QTINDENIZ,
               vnESTOQUE_QTRESERV
          FROM PCEST
         WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
           AND PCEST.CODPROD = REGISTROS.CODPROD;
      ELSE
        vnESTOQUE_QTBLOQUEADA := 0;
        vnESTOQUE_QTINDENIZ   := 0;
        vnESTOQUE_QTRESERV    := 0;
      END IF;
      -- Calculando estoque bloqueado
      IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') AND (REGISTROS.CODOPER <> 'ET') THEN
        IF psECANCELAMENTO = 'N' THEN
          vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA + LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA, REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT),0);
        ELSE
          vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA - LEAST(GREATEST(REGISTROS.NOTA_QTBLOQUEADA,REGISTROS.NOTA_QTAVARIA),REGISTROS.NOTA_QT),0);
        END IF;
          -- solicitação: 094.057323.2014 data: 09/06/2014 não retornava bloqueado o qtavaria na 1303 quando o parametro  FIL_BLOQDEVCLI = 'N'.

        -- Calculando estoque avariado - Ajustando o estoque avariado
        vnESTOQUE_QTINDENIZ := GREATEST(LEAST(vnESTOQUE_QTINDENIZ,vnESTOQUE_QTBLOQUEADA),0);
        IF psECANCELAMENTO = 'N' THEN
          vnESTOQUE_QTINDENIZ := GREATEST(vnESTOQUE_QTINDENIZ + LEAST(REGISTROS.NOTA_QTAVARIA,vnESTOQUE_QTBLOQUEADA),0);
        ELSE
          vnESTOQUE_QTINDENIZ := GREATEST(vnESTOQUE_QTINDENIZ - LEAST(REGISTROS.NOTA_QTAVARIA,vnESTOQUE_QTBLOQUEADA),0);
        END IF;
      END IF;
      -- Buscar o tipo de transferencia
      vsTIPO_TRANSFERENCIA := PRIV_TIPO_TRANSFERENCIA(REGISTROS.CODFILIALVENDA,REGISTROS.CODFILIALGERENCIAL,REGISTROS.CODFILIALCONTABIL);
      -- Sem transferência
      CASE vsTIPO_TRANSFERENCIA
        WHEN 'N' THEN
          -- Buscar parâmetro para Bloq. Est. na devolução de cliente
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQDEVCLI',REGISTROS.CODFILIALVENDA,'N')
            INTO vsBLOQDEVCLI
            FROM DUAL;
          -- Buscar parâmetro para Bloq. Est. na devolução de cliente
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_BLOQUEARENTPA','99','N')
            INTO vsBLOQUEARENTPA
            FROM DUAL;
          -- Zerar variáveis
          vnQTBLOQUEAR := 0;
          -- Validar parâmetros de bloqueio de estoque
          IF ((REGISTROS.CODOPER IN ('ED','EN','EO')) OR (vsBLOQUEARENTPA = 'S' AND REGISTROS.CODOPER = 'EP')) THEN
            vnQTBLOQUEAR := NVL(REGISTROS.NOTA_QTBLOQUEADA, 0);
          ELSE
            vnQTBLOQUEAR := NVL(REGISTROS.NOTA_QTAVARIA, 0);
          -- Validação
          END IF;
          -- Sem transferencia entre filiais, mas bloqueando estoque em outra filial
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VOLTARESTOQUEFILIALRETIRA',REGISTROS.CODFILIALCONTABIL,'N')
            INTO vsVOLTARESTOQUEFILIALRETIRA
            FROM DUAL;
          -- Volta estoque para filia retira
          IF (vsVOLTARESTOQUEFILIALRETIRA = 'S') THEN
            -- Gerar log do bloqueio
            IF vnQTBLOQUEAR > 0 THEN
              P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
              P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
              P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALGERENCIAL;
              P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
              P_INTERNO.CODPROD         := REGISTROS.CODPROD;
              P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
              P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
              P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
              PRIV_GERARLOGBLOQUEIO;
              -- Validar retorno
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO  := P_INTERNO.MSG_RETORNO;
