                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            END IF;
          END IF;

          BEGIN
            SELECT PCMOV.CODFILIALNF,
                   PCMOV.QT,
                   PCMOV.ROWID,
                   PCMOV.NUMTRANSVENDA
              INTO vsFilialAjusteEstoque,
                   vnQtAjusteEstoque,
                   vsRowIdAjusteEstoque,
                   vnNumTransVendaAjusteEstoque
              FROM PCESTCOM, PCMOV, PCMOVCOMPLE
             WHERE PCMOV.NUMTRANSVENDA = PCESTCOM.NUMTRANSVENDA
               AND PCMOVCOMPLE.NUMTRANSITEM = PCMOV.NUMTRANSITEM
               AND PCMOV.CODPROD = REGISTROS.CODPROD
               AND PCESTCOM.NUMTRANSENT = REGISTROS.NUMTRANSENT
               AND PCMOV.STATUS = 'AB'
               AND PCMOV.MOVESTOQUECONTABIL = 'N'
               AND NVL(PCMOVCOMPLE.VERSAOREGISTRO, '0') = '0'
               AND ROWNUM = 1;
          EXCEPTION
            WHEN OTHERS THEN
              vsFILIALAJUSTEESTOQUE := NULL;
              vnQTAJUSTEESTOQUE     := 0;
              vsROWIDAJUSTEESTOQUE  := NULL;
          END;

          IF (vsFILIALAJUSTEESTOQUE IS NOT NULL) AND
             (vnQTAJUSTEESTOQUE > 0) THEN
            BEGIN
              SELECT COUNT(1)
                INTO vnNUMTRANSVENDAAJUSTEESTOQUE
                FROM PCTRANSFDEP
               WHERE PCTRANSFDEP.NUMTRANSVENDA = vnNUMTRANSVENDAAJUSTEESTOQUE
                 AND PCTRANSFDEP.CODPROD = REGISTROS.CODPROD
                 AND PCTRANSFDEP.QTTRANSF = vnQTAJUSTEESTOQUE
                 AND PCTRANSFDEP.NUMTRANSTRANSFSAIDA IS NULL;
            EXCEPTION
              WHEN OTHERS THEN
                vnNUMTRANSVENDAAJUSTEESTOQUE := 0;
            END;

            IF vnNUMTRANSVENDAAJUSTEESTOQUE > 0 THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST = CASE
                                     WHEN psECANCELAMENTO = 'N' THEN
                                       NVL(PCEST.QTEST, 0) - vnQTAJUSTEESTOQUE
                                   ELSE
                                     NVL(PCEST.QTEST, 0) + vnQTAJUSTEESTOQUE
                                   END
               WHERE PCEST.CODFILIAL = vsFILIALAJUSTEESTOQUE
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

              UPDATE PCMOV
                 SET MOVESTOQUECONTABIL = 'S'
               WHERE PCMOV.ROWID = vsROWIDAJUSTEESTOQUE;
            END IF;
          END IF;
        -- TRANSF. FILIAL VIRTUAL E RETIRA
        WHEN 'VR' THEN
          -- Consultar parâmetros na rotina 132
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VOLTARESTOQUEFILIALRETIRA',REGISTROS.CODFILIALCONTABIL,'N')
            INTO vsVOLTARESTOQUEFILIALRETIRA
            FROM DUAL;
          -- Consultar parâmetros na rotina 132
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_BLOQDEVCLI',REGISTROS.CODFILIALCONTABIL,'N')
            INTO vsBLOQDEVCLI
            FROM DUAL;
          -- Consultar parâmetros na rotina 132
          SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VOLTARESTOQUEFILIALVIRTUAL',REGISTROS.CODFILIALCONTABIL,'N')
            INTO vsVOLTARESTOQUEFILIALVIRTUAL
            FROM DUAL;
          -- Zerando variável
          vnQTBLOQUEAR := 0;
          -- Valida se bloquea estoque na devolução do cliente

          vnQTBLOQUEAR := NVL(REGISTROS.NOTA_QTBLOQUEADA, 0);

          -- Se mantem o estoque na filial virtual
          IF (vsVOLTARESTOQUEFILIALVIRTUAL = 'S') THEN
            -- Gerar log
            IF vnQTBLOQUEAR > 0 THEN
              -- Atualizar as variáveis para gerar log do bloqueio
              P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
              P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
              P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALCONTABIL;
              P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
              P_INTERNO.CODPROD         := REGISTROS.CODPROD;
              P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
              P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
              P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
              PRIV_GERARLOGBLOQUEIO;
              psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
            END IF;

            -- Atualizando o estoque gerencial
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTBLOQUEADA = CASE
                                         WHEN psECANCELAMENTO = 'N' THEN
                                           NVL(PCEST.QTBLOQUEADA, 0) +
                                           DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                  'S',
                                                  vnQTBLOQUEAR,
                                                  0)
                                       ELSE
                                         GREATEST(NVL(PCEST.QTBLOQUEADA, 0) -
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                vnQTBLOQUEAR,
                                                0), 0)
                                       END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;
            
            -- Atualizar estoque
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTINDENIZ = CASE
                                       WHEN psECANCELAMENTO = 'N' THEN
                                         NVL(PCEST.QTINDENIZ, 0) +
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                REGISTROS.NOTA_QTAVARIA,
                                                0)
                                     ELSE
                                       GREATEST(NVL(PCEST.QTINDENIZ, 0) -
                                       DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                              'S',
                                              REGISTROS.NOTA_QTAVARIA,
                                              0), 0)
                                     END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;
          -- Se volta estoque para a filial retira
          ELSIF (vsVOLTARESTOQUEFILIALRETIRA = 'S') THEN
            -- Gerar log
            IF vnQTBLOQUEAR > 0 THEN
              -- Atualizar as variáveis para gerar log do bloqueio
              P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
              P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
              P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALGERENCIAL;
              P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
              P_INTERNO.CODPROD         := REGISTROS.CODPROD;
              P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
              P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
              P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
              PRIV_GERARLOGBLOQUEIO;
              psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
            END IF;

            -- Atualizando o estoque gerencial
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTBLOQUEADA = CASE
                                         WHEN psECANCELAMENTO = 'N' THEN
                                           NVL(PCEST.QTBLOQUEADA, 0) +
                                           DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                  'S',
                                                  vnQTBLOQUEAR,
                                                  0)
                                       ELSE
                                         GREATEST(NVL(PCEST.QTBLOQUEADA, 0) -
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                vnQTBLOQUEAR,
                                                0), 0)
                                       END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
               AND PCEST.CODPROD = REGISTROS.CODPROD;
            
            -- Atualizar estoque
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTINDENIZ = CASE
                                       WHEN psECANCELAMENTO = 'N' THEN
                                         NVL(PCEST.QTINDENIZ, 0) +
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                REGISTROS.NOTA_QTAVARIA,
                                                0)
                                     ELSE
                                       GREATEST(NVL(PCEST.QTINDENIZ, 0) -
                                       DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                              'S',
                                              REGISTROS.NOTA_QTAVARIA,
                                              0), 0)
                                     END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
               AND PCEST.CODPROD = REGISTROS.CODPROD;
          -- Se volta estoque até a filial de venda
          ELSE
            --Gerar log bloquio
            IF vnQTBLOQUEAR > 0 THEN
              -- Atualizar as variáveis para gerar log do bloqueio
              P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
              P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
              P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALCONTABIL;
              P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
              P_INTERNO.CODPROD         := REGISTROS.CODPROD;
              P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
              P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
              P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
              PRIV_GERARLOGBLOQUEIO;
              -- Validar retorno
              IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                PRIV_GERARLOG;
                RETURN 0;
              END IF;
            -- Gerar log
            END IF;

            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTBLOQUEADA = CASE
                                         WHEN psECANCELAMENTO = 'N' THEN
                                           NVL(PCEST.QTBLOQUEADA, 0) +
                                           DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                  'S',
                                                  vnQTBLOQUEAR,
                                                  0)
                                       ELSE
                                         GREATEST(NVL(PCEST.QTBLOQUEADA, 0) -
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                vnQTBLOQUEAR,
                                                0), 0)
                                       END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;
            
            -- Atualizar estoque
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTINDENIZ = CASE
                                       WHEN psECANCELAMENTO = 'N' THEN
                                         NVL(PCEST.QTINDENIZ, 0) +
                                         DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                'S',
                                                REGISTROS.NOTA_QTAVARIA,
                                                0)
                                     ELSE
                                       GREATEST(NVL(PCEST.QTINDENIZ, 0) -
                                       DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                              'S',
                                              REGISTROS.NOTA_QTAVARIA,
                                              0), 0)
                                     END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;

          END IF;
          -- Contábil
          IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTEST = CASE
                                   WHEN psECANCELAMENTO = 'N' THEN
                                     NVL(PCEST.QTEST, 0) +
                                     DECODE(REGISTROS.MOVESTOQUECONTABIL,
                                            'S',
                                            REGISTROS.NOTA_QTCONT,
                                            0)
                                 ELSE
                                   NVL(PCEST.QTEST, 0) -
                                   DECODE(REGISTROS.MOVESTOQUECONTABIL,
                                          'S',
                                          REGISTROS.NOTA_QTCONT,
                                          0)
                                 END
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;

          END IF;
          -- Gerencial
          IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
            UPDATE PCEST
               SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                   PCEST.QTESTGER = CASE
                                      WHEN psECANCELAMENTO = 'N' THEN
                                        NVL(PCEST.QTESTGER, 0) +
                                        DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                               'S',
                                               REGISTROS.NOTA_QT,
                                               0)
                                    ELSE
                                      NVL(PCEST.QTESTGER, 0) -
                                      DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                             'S',
                                             REGISTROS.NOTA_QT,
                                             0)
                                    END,
           PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
             WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCEST.CODPROD = REGISTROS.CODPROD;

            IF (vsROTINA LIKE '%PCSIS1332%') OR (vsROTINA LIKE '%PCSIS1316%' AND vnCONDVENDA = 13) THEN
              --Atualiza o estoque em trânsito (HIS.00390.2016)
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

          END IF;

          IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S' AND REGISTROS.CODOPER <> 'ET') THEN
            -- Buscar valor do parâmetro
            SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VOLTARESTOQUEFILIALRETIRA',REGISTROS.CODFILIALCONTABIL,'N')
              INTO vsVOLTARESTOQUEFILIALRETIRA
              FROM DUAL;

            IF (vsVOLTARESTOQUEFILIALRETIRA = 'S') THEN
              -- Gerar log bloqueio
              IF vnQTBLOQUEAR > 0 THEN
                -- Atualizar as variáveis para gerar log do bloqueio
                P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
                P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
                P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALGERENCIAL;
                P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
                P_INTERNO.CODPROD         := REGISTROS.CODPROD;
                P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
                P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
                P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
                PRIV_GERARLOGBLOQUEIO;
                -- Validar retorno
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 0;
                END IF;
              -- Gerar log
              END IF;

              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTBLOQUEADA   = GREATEST(DECODE(psAPENAS_QTEST_QTESTGER,
                                                  'S',
                                                  PCEST.QTBLOQUEADA,
                                                  vnESTOQUE_QTBLOQUEADA), 0),
                     PCEST.QTINDENIZ     = GREATEST(DECODE(psAPENAS_QTEST_QTESTGER,
                                                  'S',
                                                  PCEST.QTINDENIZ,
                                                  vnESTOQUE_QTINDENIZ), 0)
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;              

            ELSE
              --Gerar log bloqueada
              IF vnQTBLOQUEAR > 0 THEN
                -- Atualizar as variáveis para gerar log do bloqueio
                P_INTERNO.IDENTIFICADOR   := REGISTROS.NUMTRANSENT;
                P_INTERNO.INFORMACOES_LOG := 'BLOQUEIO PELA ROTINA' || vsROTINA;
                P_INTERNO.CODFILIAL       := REGISTROS.CODFILIALCONTABIL;
                P_INTERNO.CODFUNCLANC     := REGISTROS.CODFUNCLANC;
                P_INTERNO.CODPROD         := REGISTROS.CODPROD;
                P_INTERNO.QTBLOQUEADA     := vnQTBLOQUEAR;
                P_INTERNO.CODDEVOL        := REGISTROS.CODDEVOL;
                P_INTERNO.QTINDENIZ       := REGISTROS.NOTA_QTAVARIA;
                PRIV_GERARLOGBLOQUEIO;
                -- Validar retorno
                IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
                  psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
                  PRIV_GERARLOG;
                  RETURN 0;
                END IF;
              -- Gerar log
              END IF;
              
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTBLOQUEADA   = GREATEST(DECODE(psAPENAS_QTEST_QTESTGER,
                                                  'S',
                                                  PCEST.QTBLOQUEADA,
                                                  vnESTOQUE_QTBLOQUEADA) ,0),
                     PCEST.QTINDENIZ     = GREATEST(DECODE(psAPENAS_QTEST_QTESTGER,
                                                  'S',
                                                  PCEST.QTINDENIZ,
                                                  vnESTOQUE_QTINDENIZ), 0)
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;              
            --
            END IF;
          --
          END IF;
      --
      END CASE;
      -- Se movimentar estoque contábil
      IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
        UPDATE PCMOV
           SET PCMOV.QTESTANT = vnESTOQUE_QTEST
         WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
      END IF;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizando a nota fiscal
        UPDATE PCMOV
           SET PCMOV.QTESTGERANT = vnESTOQUE_QTESTGER
         WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;

        IF REGISTROS.CODOPER = 'ET' THEN
          BEGIN
           vbUTILIZOUCFAT := FALSE;
           SELECT COUNT(1)
             INTO vnUTILIZOUCFAT
             FROM PCMOVTRANSF
            WHERE NUMPED = REGISTROS.NUMPED;

            vbUTILIZOUCFAT := (vnUTILIZOUCFAT > 0);
          EXCEPTION
            WHEN OTHERS THEN
              vbUTILIZOUCFAT := FALSE;
          END;

          IF vbUTILIZOUCFAT THEN
            vsCODFILIAL_CFAT := VALIDA_CODFILIAL_CEFAT(REGISTROS.NUMPED, REGISTROS.CODPROD, REGISTROS.NUMSEQ);
            UPDATE PCEST
               SET QTRESERV =  QTRESERV + REGISTROS.NOTA_QT
            ,DTHORAULTALTDISP =  SYSDATE
             WHERE CODFILIAL = vsCODFILIAL_CFAT
               AND CODPROD =  REGISTROS.CODPROD;
          END IF;
        END IF;

        IF vnESTOQUE_QTESTGER < 0 THEN
          UPDATE PCEST
            SET QTBLOQUEADA = LEAST(QTBLOQUEADA, GREATEST(QTESTGER))
          WHERE CODPROD = REGISTROS.CODPROD
            AND CODFILIAL = REGISTROS.CODFILIALGERENCIAL
            AND QTBLOQUEADA > QTESTGER;
        END IF;
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'B';
        ELSE
          P_INTERNO.TIPO_OPERACAO := 'I';
        END IF;
        -- Atualizar variáveis para movimentar depósito
        IF vsTIPO_TRANSFERENCIA = 'N' THEN
          IF vsVOLTARESTOQUEFILIALRETIRA = 'S' THEN
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALGERENCIAL;
          ELSE
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALVENDA;
          END IF;
        ELSIF vsTIPO_TRANSFERENCIA = 'V' THEN
          IF vsVOLTARESTOQUEFILIALVIRTUAL = 'S' THEN
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALCONTABIL;
          ELSE
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALVENDA;
          END IF;
        ELSIF vsTIPO_TRANSFERENCIA IN ('R','VR') THEN
          IF vsVOLTARESTOQUEFILIALRETIRA = 'S' THEN
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALGERENCIAL;
          ELSE
            P_INTERNO.CODFILIAL := REGISTROS.CODFILIALCONTABIL;
          END IF;
        END IF;
        -- Atualizar variáveis internas
        P_INTERNO.PROCESSO         := 'VENDER';
        P_INTERNO.ROWID_REGISTRO   := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO      := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD          := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER         := REGISTROS.NOTA_QT;
        P_INTERNO.QTBLOQUEADA      := vnQTBLOQUEAR;
        P_INTERNO.QTINDENIZ        := REGISTROS.NOTA_QTAVARIA;
        -- Administrar estoque do depósito
        IF (REGISTROS.CODOPER <> 'EI' AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S') THEN

          IF (REGISTROS.CODOPER = 'ET' AND REGISTROS.NUMPED IS NOT NULL) THEN

             SELECT PCESTOQUEDEPOSITO.CODDEPOSITO
              INTO P_INTERNO.CODDEPOSITO
              FROM PCESTOQUEDEPOSITO
             WHERE PCESTOQUEDEPOSITO.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCESTOQUEDEPOSITO.Padraovenda = 'S';

            UPDATE PCMOV
               SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
             WHERE PCMOV.CODPROD = REGISTROS.CODPROD
               AND PCMOV.ROWID = REGISTROS.NOTA_ROWID;

          END IF;

          IF REGISTROS.CODOPER = 'SV' THEN
            BEGIN
              SELECT CODDEPOSITO
                INTO P_INTERNO.CODDEPOSITO
                FROM PCESTOQUEDEPOSITO
               WHERE PADRAOAVARIA = 'S'
                 AND CODFILIAL = P_INTERNO.CODFILIAL;
            EXCEPTION
              WHEN OTHERS THEN
                P_INTERNO.CODDEPOSITO := NULL;
            END;
          END IF;

          PRIV_DEP_VENDAS_ENTRADA;

        END IF;

        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Finalizou a lista de produtos';
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
    -- Lista de produtos
    END LOOP;
    -- Marcar no cabeçalho a utilização da package
    IF vnCONTADORREGISTROS > 0 THEN
      IF (psECANCELAMENTO = 'S') THEN
      UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
    ELSE
      UPDATE PCNFENT
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'N'
         WHERE NUMTRANSENT = pnNUMTRANSACAO;
    END IF;
    -- Validando se tem registros
    ELSIF vnCONTADORREGISTROS = 0 THEN
      UPDATE PCNFENT
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSENT = pnNUMTRANSACAO;
      psMSG_RETORNO := 'Erro 4 (Vendas Entrada Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                       'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.ROTINAENTRADA   := PRIV_SOMENTENUMERO(vsROTINA);
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.ROTINAENTRADA||' finalizou a função vendas entrada prod.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADA_PROD';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADORREGISTROS;
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 5 (Vendas Entrada Prod): '||CHR(13)||
                       'Msg. original: '||SQLERRM;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 0;
  -- Função
  END VENDAS_ENTRADA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  11/09/2014     Ricardo Sousa     0                   Criado para possibilitar o recalculo de estoque por produto.
                                                       Foi alterada a função principal para ter como parametro o CODPROD e
                                                       criado este novo como sobrecarga sa função anterior para evitar impacto
                                                       com as rotinas que já usam com a assinatura anterior
  ************************************************************************************************************************/
  FUNCTION VENDAS_ENTRADA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSENT%TYPE
                          ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                          ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    CURSOR BLOQUEIA_ESTOQUE_TRNASACAO
    IS
     SELECT distinct CODPROD, CODFILIAL, CODFILIALRETIRA FROM PCMOV WHERE NUMTRANSENT = pnNUMTRANSACAO ORDER BY CODPROD;

    vnTENTATIVA NUMBER := 0;
    vnRETORNO   NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - VENDAS_ENTRADA';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;

    FOR REGISTROS IN BLOQUEIA_ESTOQUE_TRNASACAO
    LOOP
      WHILE (vnTENTATIVA < 5) LOOP
        BEGIN
          SELECT CODPROD
            INTO vnTENTATIVA
            FROM PCEST
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIAL
             FOR UPDATE;

          IF REGISTROS.CODFILIAL <> REGISTROS.CODFILIALRETIRA THEN
            SELECT CODPROD
              INTO vnTENTATIVA
              FROM PCEST
             WHERE CODPROD = REGISTROS.CODPROD
               AND CODFILIAL = REGISTROS.CODFILIALRETIRA
               FOR UPDATE;
          END IF;
          vnTENTATIVA := 5;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 - Vendas entradas: Verifique os dados informados!'||CHR(13)||
                             '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                             '2 - Os dados informados podem não ser validos!'||CHR(13)||
                             'TRANSAÇÃO: '||pnNUMTRANSACAO||' - '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            vnTENTATIVA := vnTENTATIVA + 1;
        END;
      END LOOP;
      psMSG_RETORNO := 'OK';
      vnTENTATIVA := 0;
    END LOOP;

    IF psMSG_RETORNO = 'OK' THEN
      -- Executando a função por produto
      vnRETORNO := VENDAS_ENTRADA_PROD (pnNUMTRANSACAO,0,'N',psECANCELAMENTO,psMSG_RETORNO);
      
      IF psMSG_RETORNO <> 'OK' THEN
        P_INTERNO.INFORMACOES_LOG := 'Erro 2 - Vendas entrada: Falha ao Movimentar estoque';
        P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADA';
         P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF; 

      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função reserva incluir.';
      P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADA';
      PRIV_GERARLOG;
      RETURN vnRETORNO;
    ELSE
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Erro 3 - Vendas entradas: Falha ao bloquear produtos na função';
      P_INTERNO.NOME_FUNCAO     := 'VENDAS_ENTRADAS';
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
  -- Função
  END VENDAS_ENTRADA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Rodrigo Santos    0                   Criada a função
  13/02/2014     Rodrigo Santos    0.016591.2014       Ajuste nos updates do estoque reservado para permitir
                                                       a baixa deste mesmo que fique negativo e neste caso assumir a qtde zero.
  17/02/2014     Rodrigo Santos    0                   Ajuste na movimentação de estoque contábil quando é filial virtual.
  24/02/2014     Luciano Lima      1592.018497.2014    Ajuste para incluir a validação do param. PERMITIRESTGERNEGATIVO
  06/05/2014     Rodrigo Santos    0                   Alteração para separar regras quanto a definição das movimentações de estoque
                                                       contábil e gerencial, estas regras passam a ser tratadas pela função "VENDAS.PRIV_DEFINIR_MOVESTOQUE"
  16/07/2014     Luciano Lima      3276.076952.2014    Ajuste na pkg_estoque para exibir a msg original qdo o registro estiver locado.
  22/08/2019     Anderson Silva    DDMEDICA-620        Processos de Pedido Avaria e Pedido CrossDocking - MEDICAMENTOS
  ************************************************************************************************************************/
  FUNCTION VENDAS_SAIDA_PROD (pnNUMTRANSACAO     IN PCMOV.NUMTRANSVENDA%TYPE
                             ,pnCODPROD          IN PCMOV.CODPROD%TYPE
                             ,psECANCELAMENTO    IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                             ,psMSG_RETORNO      OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnCONTADORREGISTROS          NUMBER;
    vnESTOQUE_QTEST              PCEST.QTEST%TYPE;
    vnESTOQUE_QTESTGER           PCEST.QTESTGER%TYPE;
    vnESTOQUE_QTRESERV           PCEST.QTRESERV%TYPE;
    vnDEPOSITO_QTRESERVADA       PCESTOQUEDEPOSITOPROD.QTRESERVADA%TYPE;
    vnESTOQUE_QTRESERV_ATUAL     PCEST.QTRESERV%TYPE;
    vnESTOQUE_QTBLOQUEADA        PCEST.QTBLOQUEADA%TYPE;
    vsESTOQUE_QTBLOQUEADA_ATUAL  PCEST.QTBLOQUEADA%TYPE;
    vnESTOQUE_QTINDENIZ          PCEST.QTINDENIZ%TYPE;
    vnESTOQUE_QTINDENIZ_ATUAL    PCEST.QTINDENIZ%TYPE;
    vnNFCONSIGNACAO              PCPEDC.NUMNOTACONSIG%TYPE;
    vsVOLTARESTOQUEFILIALRETIRA  VARCHAR2(1);
    vbEH_TV10                    BOOLEAN;
    vnCONDVENDA                  PCNFSAID.CONDVENDA%TYPE;
    ERRO_ESTOQUE_INSUFICIENTE    EXCEPTION;
    vnQtdeEstoquePendecia        PCEST.QTPENDENTE%TYPE;
    vsFilialAjusteEstoque        VARCHAR2(2);
    vnQtAjusteEstoque            PCEST.QTESTGER%TYPE;
    vsRowIdAjusteEstoque         VARCHAR2(100);
    vsTIPO_TRANSFERENCIA         VARCHAR2(2);
    vsTransfDep                  PCNFSAID.TRANSFDEP%TYPE;
    vsORIGEMPED                  VARCHAR2(2);
    vsPEDIDOAVARIA               PCPEDC.PEDIDOAVARIA%TYPE; -- DDMEDICA-620
    vnNUMTRANSENTCROSSDOCK       PCPEDC.NUMTRANSENTCROSSDOCK%TYPE; -- DDMEDICA-620
    vbEH_PED_AVARIA_CROSSDOCK    BOOLEAN; -- DDMEDICA-620
    vbEH_PED_AVARIA              BOOLEAN; -- DDMEDICA-1400
    vnRETORNO                    VARCHAR2(2);
    vnDTMOVPRIMERIO              DATE;
    vnCONTADORREGISTROSPCMOV     NUMBER := 0;
    vnNUMCAIXA                   PCCAIXA.NUMCAIXA%TYPE;
    vnSITUACAONFE                PCNFSAID.SITUACAONFE%TYPE := 0;
    vsCODFILIAL_CFAT             PCEST.CODFILIAL%TYPE;
    vsUTILIZOUCFAT               VARCHAR2(2);
    vnUTILIZOUCFAT               NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Iniciando variaveis
    vnCONTADORREGISTROS       := 0;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := 'OK';
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - VENDAS_SAIDA_PROD';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA_PROD';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CODOPER         := 'S';
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
	P_INTERNO.CODDEPOSITORESERVA := 0;
    PRIV_GERARLOG;

    BEGIN
      vbEH_TV10 := FALSE;
      SELECT COUNT(1)
        INTO vnCONTADORREGISTROS
        FROM PCNFSAID
       WHERE PCNFSAID.NUMTRANSVENDA = pnNUMTRANSACAO
         AND PCNFSAID.NUMTRANSVENDADEPENDENTE IS NULL
         AND PCNFSAID.CONDVENDA = 10;
      vbEH_TV10 := (vnCONTADORREGISTROS > 0);
    EXCEPTION
      WHEN OTHERS THEN
        vbEH_TV10 := FALSE;
    END;
    -- Número da nota fiscal de consignação
    BEGIN
      SELECT NVL(PCPEDC.NUMNOTACONSIG, 0)
        INTO vnNFCONSIGNACAO
        FROM PCPEDC
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO
         AND CONDVENDA = 1;
    EXCEPTION
      WHEN OTHERS THEN
        vnNFCONSIGNACAO := 0;
    END;
    -- Buscar dados pedido
    BEGIN
      SELECT NVL(PCPEDC.ORIGEMPED,'T')
            ,NVL(PCPEDC.PEDIDOAVARIA,'N') PEDIDOAVARIA -- DDMEDICA-620
            ,NVL(PCPEDC.NUMTRANSENTCROSSDOCK,0) NUMTRANSENTCROSSDOCK -- DDMEDICA-620
            ,PCPEDC.CONDVENDA
            ,PCPEDC.NUMCAIXA
        INTO vsORIGEMPED
            ,vsPEDIDOAVARIA -- DDMEDICA-620
            ,vnNUMTRANSENTCROSSDOCK -- DDMEDICA-620
            ,vnCONDVENDA
            ,vnNUMCAIXA
        FROM PCPEDC
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    EXCEPTION
      WHEN OTHERS THEN
        vsORIGEMPED            := 'T';
        vnCONDVENDA            := NULL;
        vsPEDIDOAVARIA         := 'N'; -- DDMEDICA-620
        vnNUMTRANSENTCROSSDOCK := NULL; -- DDMEDICA-620
    END;
    -- Zerando retorno
    vnCONTADORREGISTROS := 0;
    -- Validando se transação foi informada
    IF pnNUMTRANSACAO <= 0 THEN
      psMSG_RETORNO := 'Erro 1 (Vendas Saída Prod): O numtransação informado não é valido'||CHR(13)||
                       'Identificador: '||pnNUMTRANSACAO;
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
    -- Buscar situação da NFe para definir movimentação do estoque
    BEGIN
      SELECT NVL(PCNFSAID.SITUACAONFE,'0')
        INTO vnSITUACAONFE
        FROM PCNFSAID
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    EXCEPTION
      WHEN OTHERS THEN
        vnSITUACAONFE := '0';
    END;
    -- Notas canceladas devem movimentar estoque conforme a movimentação feita na origem
    IF psECANCELAMENTO = 'N' THEN
      -- Definir movimentação do estoque
      PRIV_DEFINIR_MOVESTOQUE;
    END IF;
    -- Lista de produtos
    FOR REGISTROS IN (SELECT PCMOV.CODPROD -- Dados do estoque
                            ,ESTOQUECONTABIL.CODFILIAL  CODFILIALCONTABIL
                            ,ESTOQUEGERENCIAL.CODFILIAL CODFILIALGERENCIAL
                            ,PCMOV.CODFILIAL            CODFILIALVENDA
                             -- Dados da nota fiscal
                            ,PCMOV.CODOPER
                            ,PCMOV.DESCRICAO
                            ,PCMOV.STATUS
                            ,PCMOV.ROWID NOTA_ROWID
                            ,ABS(DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0))) NOTA_QT
                            ,ABS(NVL(PCMOV.QTCONT, 0)) NOTA_QTCONT
                            ,ABS(NVL(PCMOV.QTAVARIA, 0)) NOTA_QTAVARIA
                            ,ABS(NVL(PCMOV.QTBLOQUEADA, 0)) NOTA_QTBLOQUEADA
                            ,NVL(ESTOQUEGERENCIAL.QTRESERV, 0) ESTOQUERESERVADO
                             ----------------------------------------------------------
                            ,NVL(PCMOV.MOVESTOQUEGERENCIAL,DECODE(PCMOV.STATUS, 'A', 'N', 'S')) MOVESTOQUEGERENCIAL
                            ,NVL(PCMOV.MOVESTOQUECONTABIL,DECODE(PCMOV.STATUS, 'B', 'N', 'S')) MOVESTOQUECONTABIL
                            ,NVL(PCMOV.NUMOP, 0) NUMOP
                            ,NVL(PCMOV.NUMTRANSAVULSA, 0) NUMTRANSAVULSA
                            ,PCMOV.CODDEPOSITO
                            ,PCMOV.DATAESTOQUE
                            ,PCMOV.DTMOV
                            ,PCMOV.ROTINACAD
                            ,PCMOV.NUMPED
                            ,PCMOV.NUMSEQ
                            ,PCMOV.CODFISCAL
                            ,PCMOV.CODCLI
                        FROM PCMOV,
                             PCEST ESTOQUEGERENCIAL
                            ,PCEST ESTOQUECONTABIL
                            ,PCMOVCOMPLE
                       WHERE PCMOV.CODPROD = ESTOQUEGERENCIAL.CODPROD
                         AND PCMOV.CODPROD = ESTOQUECONTABIL.CODPROD
                         AND PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+)
                         AND NVL(PCMOV.CODFILIALNF, PCMOV.CODFILIAL) = ESTOQUECONTABIL.CODFILIAL
                         AND NVL(PCMOV.CODFILIALRETIRA, PCMOV.CODFILIAL) = ESTOQUEGERENCIAL.CODFILIAL
                         AND PCMOV.NUMTRANSVENDA = pnNUMTRANSACAO
                         AND (NVL(pnCODPROD, 0) = 0 OR PCMOV.CODPROD = pnCODPROD)
                         AND ((psECANCELAMENTO = 'S' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) < 0 ) OR
                             (psECANCELAMENTO = 'N' AND DECODE(NVL(PCMOV.QTCONT, 0),0,NVL(PCMOV.QT, 0),NVL(PCMOV.QTCONT, 0)) > 0))
                         AND SUBSTR(CODOPER,1,1) IN ('S','R')                     
                         AND NOT(PCMOV.CODOPER IN ('SA') AND PCMOVCOMPLE.NUMINVENT IS NOT NULL AND PCMOV.STATUS = 'B')
                    ORDER BY PCMOV.CODPROD, PCMOV.NUMSEQ)
    LOOP
      --
      IF (psECANCELAMENTO = 'N') THEN
        -- Verificando se o transacao ja foi alterada
        IF REGISTROS.DATAESTOQUE IS NOT NULL THEN
          psMSG_RETORNO := 'Erro 2 (Vendas Saida Prod): A transação informada pode já ter movimentações de estoque, ' ||CHR(13) ||
                           'verifique se o número da transação já existe na tabela de movimentações.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;
        -- Verificando se tem datas diferentes no mesmo numtransvenda
        IF vnCONTADORREGISTROSPCMOV = 0 THEN
          vnDTMOVPRIMERIO := REGISTROS.DTMOV;
        ELSIF vnDTMOVPRIMERIO <> REGISTROS.DTMOV THEN
          psMSG_RETORNO := 'Erro 3 (Vendas Saida Prod): A transação informada já foi movimentada em outra data, ' ||CHR(13) ||
                           'verifique o número da transação e tente novamente.' ||CHR(13) ||
                           'transação: ' || TO_CHAR(pnNUMTRANSACAO);
          RETURN 0;
        END IF;

        vnCONTADORREGISTROSPCMOV := vnCONTADORREGISTROSPCMOV + 1;
      END IF;

      BEGIN
        vsUTILIZOUCFAT := 'N';

        SELECT COUNT(1)
          INTO vnUTILIZOUCFAT
          FROM PCMOVTRANSF
         WHERE NUMPED = REGISTROS.NUMPED;

        IF (vnUTILIZOUCFAT > 0) THEN
          vsUTILIZOUCFAT := 'S';
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
        vsUTILIZOUCFAT := 'N';
      END;
      -- Tipo de transferência
      vsTIPO_TRANSFERENCIA := PRIV_TIPO_TRANSFERENCIA(REGISTROS.CODFILIALVENDA,
                                                      REGISTROS.CODFILIALGERENCIAL,
                                                      REGISTROS.CODFILIALCONTABIL);
      -- Buscar parâmetros do sistema
      SELECT FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VOLTARESTOQUEFILIALRETIRA',REGISTROS.CODFILIALVENDA,'N')
        INTO vsVOLTARESTOQUEFILIALRETIRA
        FROM DUAL;
      -- Variavel para identificar se Pedido de Avaria ou CrossDocking - DDMEDICA-620
      vbEH_PED_AVARIA_CROSSDOCK := FALSE;
      IF (NVL(vsPEDIDOAVARIA,'N') = 'S') OR
         (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
        vbEH_PED_AVARIA_CROSSDOCK := TRUE;
      END IF;
      -- Variavel para identificar se Pedido de Avaria - DDMEDICA-1400
      vbEH_PED_AVARIA := FALSE;
      IF (NVL(vsPEDIDOAVARIA,'N') = 'S') THEN
        vbEH_PED_AVARIA := TRUE;
      END IF;
      -- Valida origem pedido
      P_INTERNO.CODFILIAL             := REGISTROS.CODFILIALVENDA;
      P_INTERNO.CODPROD               := REGISTROS.CODPROD;
      P_INTERNO.MOVESTOQUEGERENCIAL   := REGISTROS.MOVESTOQUEGERENCIAL;
      P_INTERNO.MOVESTOQUECONTABIL    := REGISTROS.MOVESTOQUECONTABIL;
      PRIV_GERARLOG;
      -- Validando quantidade informada
      IF (REGISTROS.NOTA_QT <= 0) THEN
        psMSG_RETORNO := 'Erro 4 (Vendas Saída Prod): Quantidade declarada na transação não pode ser menor/igual a zero.'||CHR(13)||
                         'Produto: '||TO_CHAR(REGISTROS.CODPROD)||' '||REGISTROS.DESCRICAO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
      vnContadorRegistros := vnContadorRegistros + 1;
      -- Bloquear tabela de estoque
      IF NVL(pnCODPROD, 0) > 0 THEN
        PRIV_BLOQUEAR_ESTOQUE(REGISTROS.CODFILIALCONTABIL,REGISTROS.CODPROD,psMSG_RETORNO);
        -- Validar se conseguiu bloquear o estoque
        IF psMSG_RETORNO <> 'OK' THEN
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
    END IF;
      -- Movimenta estoque Gerencial?
      IF ((REGISTROS.MOVESTOQUEGERENCIAL = 'S') OR
        (REGISTROS.MOVESTOQUEGERENCIAL = 'N' AND REGISTROS.MOVESTOQUECONTABIL = 'N' AND
        vnSITUACAONFE IN (110,205,301,302))) THEN
        -- Buscar dados do estoque atual
        SELECT NVL(PCEST.QTEST, 0) ESTOQUE_QTEST
              ,NVL(PCEST.QTESTGER, 0) ESTOQUE_QTESTGER
              ,NVL(PCEST.QTRESERV, 0) ESTOQUE_QTRESERV
              ,GREATEST(GREATEST(NVL(PCEST.QTBLOQUEADA, 0),NVL(PCEST.QTINDENIZ, 0)),0) ESTOQUE_QTBLOQUEADA
              ,GREATEST(NVL(PCEST.QTINDENIZ, 0), 0) ESTOQUE_QTINDENIZ
          INTO vnESTOQUE_QTEST
              ,vnESTOQUE_QTESTGER
              ,vnESTOQUE_QTRESERV
              ,vnESTOQUE_QTBLOQUEADA
              ,vnESTOQUE_QTINDENIZ
          FROM PCEST
         WHERE PCEST.CODFILIAL = CASE
                                   WHEN vsUTILIZOUCFAT = 'S' THEN
                                     REGISTROS.CODFILIALCONTABIL
                                 ELSE
                                   REGISTROS.CODFILIALGERENCIAL
                                 END
           AND PCEST.CODPROD = REGISTROS.CODPROD;
        -- Atualizar variáveis
        vsESTOQUE_QTBLOQUEADA_ATUAL := vnESTOQUE_QTBLOQUEADA;
        vnESTOQUE_QTINDENIZ_ATUAL   := vnESTOQUE_QTINDENIZ;
        vnESTOQUE_QTRESERV_ATUAL    := vnESTOQUE_QTRESERV;
        -- Valizar se é para baixar ou não a reserva
        IF (REGISTROS.CODOPER NOT IN('ST','SA','SI','SV','SR')
           OR (vbEH_TV10 AND (REGISTROS.ROTINACAD NOT LIKE '%PCSIS1124%'))
           OR vsUTILIZOUCFAT = 'S'
       OR vnCONDVENDA = 13)
           AND (NOT vbEH_PED_AVARIA_CROSSDOCK)
        THEN -- Pedido de Avaria e CrossDocking nao baixa a reserva - DDMEDICA-620
          -- Autosserviço?
          IF vsORIGEMPED <> 'A' THEN
            IF (REGISTROS.CODOPER = 'SP' AND REGISTROS.NUMOP = 0 AND REGISTROS.NUMTRANSAVULSA = 0) THEN
              vnESTOQUE_QTRESERV                  := GREATEST(vnESTOQUE_QTRESERV, 0);
              vnDEPOSITO_QTRESERVADA              := 0;
            ELSE
              IF (psECANCELAMENTO = 'N') THEN
                vnESTOQUE_QTRESERV     := GREATEST((vnESTOQUE_QTRESERV - REGISTROS.NOTA_QT), 0);
                vnDEPOSITO_QTRESERVADA := REGISTROS.NOTA_QT;
                -- Buscar deposito para baixa da reserva
                BEGIN
                  SELECT CODDEPOSITO
                    INTO P_INTERNO.CODDEPOSITORESERVA
                    FROM PCPEDI
                   WHERE NUMPED = REGISTROS.NUMPED
                     AND CODPROD = REGISTROS.CODPROD
                     AND NUMSEQ = REGISTROS.NUMSEQ;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    -- A movimentação não tem pedido
                    P_INTERNO.CODDEPOSITORESERVA := 0;
                END;
              END IF;
            END IF;
          -- É autosserviço!
          --ELSE
          END IF;
          --
          IF ((vsORIGEMPED = 'A') OR ((vsORIGEMPED = 'R') AND (vnNUMCAIXA > 0) and (PARAMFILIAL.OBTERCOMOBOOLEAN('RESERVAESTFRENTELOJA',REGISTROS.CODFILIALGERENCIAL,'S','N')='N'))) THEN
            -- Voltar estoque filial retira?
            IF (vsVOLTARESTOQUEFILIALRETIRA = 'S' AND psECANCELAMENTO = 'S') THEN
              -- Atualizar estoque do frente da loja
              vnRETORNO:= FRENTELOJA_ATUALIZAR_PCEST (REGISTROS.CODFILIALCONTABIL
                                                     ,REGISTROS.CODPROD
                                                     ,REGISTROS.NOTA_QT
                                                     ,'IF'
                                                     ,psMSG_RETORNO
                                                     ,pnNUMTRANSACAO);
            -- Não voltar estoque para filial retira
            ELSE
              -- Atualizar estoque do frente da loja
              vnRETORNO:= FRENTELOJA_ATUALIZAR_PCEST (REGISTROS.CODFILIALGERENCIAL
                                                     ,REGISTROS.CODPROD
                                                     ,REGISTROS.NOTA_QT
                                                     ,CASE
                                                        WHEN psECANCELAMENTO = 'N' THEN
                                                          'BF'
                                                      ELSE
                                                        'IF'
                                                      END
                                                     ,psMSG_RETORNO
                                                     ,pnNUMTRANSACAO);
            -- Voltar Est. Filial Retira
            END IF;
          -- Autosseviço
          END IF;
        -- Tipo de movimentação
        END IF;
      -- Não movimenta estoque gerencial
      ELSE
        vnESTOQUE_QTESTGER     := 0;
        vnESTOQUE_QTRESERV     := 0;
        vnDEPOSITO_QTRESERVADA := 0;
      -- Mov. gerencial
      END IF;
      -- É venda em consignação?
      IF vnNFCONSIGNACAO = 0 THEN
        -- Sem transferência
        CASE vsTIPO_TRANSFERENCIA
          WHEN 'N' THEN
            -- Transfere estoque bloqueado - Fatura estoque bloqueado e avariado em pedido de avaria - vbEH_PED_AVARIA - DDMEDICA-1400
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') AND (vsROTINA LIKE '%1124%' OR vsROTINA LIKE '%1322%'  OR vsROTINA LIKE '%1326%' OR vsROTINA LIKE '%1316%' OR vbEH_PED_AVARIA) THEN
              -- Caso tenha Qtde Avariada e não esteja cancelando
              IF (psECANCELAMENTO = 'N' AND REGISTROS.NOTA_QTAVARIA > 0) THEN
                vnESTOQUE_QTINDENIZ := GREATEST((vnESTOQUE_QTINDENIZ - REGISTROS.NOTA_QTAVARIA),0);
              -- Caso tenha Qtde Avariada e esteja cancelando
              ELSIF (psECANCELAMENTO = 'S' AND REGISTROS.NOTA_QTAVARIA > 0) THEN
                vnESTOQUE_QTINDENIZ := GREATEST((vnESTOQUE_QTINDENIZ + REGISTROS.NOTA_QTAVARIA),0);
              END IF;
              -- Caso tenha Qtde Bloqueada e não esteja cancelando
              IF (psECANCELAMENTO = 'N' AND REGISTROS.NOTA_QTBLOQUEADA > 0) THEN
                vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA - GREATEST(REGISTROS.NOTA_QTBLOQUEADA, REGISTROS.NOTA_QTAVARIA),0);
              -- Caso tenha Qtde Bloqueada e esteja cancelando
              ELSIF (psECANCELAMENTO = 'S' AND REGISTROS.NOTA_QTBLOQUEADA > 0) THEN
                vnESTOQUE_QTBLOQUEADA := GREATEST(vnESTOQUE_QTBLOQUEADA + GREATEST(REGISTROS.NOTA_QTBLOQUEADA, REGISTROS.NOTA_QTAVARIA),0);
              END IF;
              -- Calculando estoque avariado - Ajustando o estoque avariado
              -- vnESTOQUE_QTINDENIZ := GREATEST(LEAST(vnESTOQUE_QTINDENIZ,vnESTOQUE_QTBLOQUEADA),0);
              IF vnESTOQUE_QTINDENIZ > vnESTOQUE_QTBLOQUEADA THEN
                psMSG_RETORNO := 'Erro 5 (Vendas Saída Prod): A quantidade avariada ficou maior que a quantidade bloqueada.'||CHR(13)||
                                 'Reveja os dados informados e tente novamente.'||CHR(13)||
                                 'Qt. Bloq. Atual : '||vsESTOQUE_QTBLOQUEADA_ATUAL||CHR(13)||
                                 'Qt. Avaria Atual: '||vnESTOQUE_QTINDENIZ_ATUAL||CHR(13)||
                                 'Qt. Bloq. NF....: '||REGISTROS.NOTA_QTBLOQUEADA||CHR(13)||
                                 'Qt. Avaria NF...: '||REGISTROS.NOTA_QTAVARIA||CHR(13)||
                                 'Qt. Bloq. Final.: '||vnESTOQUE_QTBLOQUEADA||CHR(13)||
                                 'Qt. Avaria Final: '||vnESTOQUE_QTINDENIZ||CHR(13)||
                                 'Transação.......: '||TO_CHAR(pnNUMTRANSACAO);
              END IF;
            -- Bloqueado e indenizado
            END IF;
            -- Contábil
            IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO
                    ,PCEST.QTEST         = CASE
                                             WHEN psECANCELAMENTO = 'N' THEN
                                               NVL(PCEST.QTEST, 0) - DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QT, 0)
                                           ELSE
                                             NVL(PCEST.QTEST, 0) + DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QT, 0)
                                           END
                    ,PCEST.QTCROSSDOCK   = CASE -- DDMEDICA-1965
                                             WHEN (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
                                               CASE
                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                   NVL(PCEST.QTCROSSDOCK, 0) - NVL(REGISTROS.NOTA_QTCONT, 0)
                                               ELSE
                                                 NVL(PCEST.QTCROSSDOCK, 0) + NVL(REGISTROS.NOTA_QTCONT, 0)
                                               END
                                           ELSE
                                             PCEST.QTCROSSDOCK
                                           END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            END IF;
            -- Se mov. estoque Gerencial
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.DTULTSAIDA = TRUNC(SYSDATE),
                     PCEST.DTHORAULTSAIDA = SYSDATE,
                     PCEST.QTESTGER = CASE
                                        WHEN psECANCELAMENTO = 'N' THEN
                                          NVL(PCEST.QTESTGER, 0) -
                                          DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                 'S',
                                                 REGISTROS.NOTA_QT,
                                                 0)
                                      ELSE
                                        NVL(PCEST.QTESTGER, 0) +
                                        DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                               'S',
                                               REGISTROS.NOTA_QT,
                                               0)
                                      END
                     ---------------------------------------------------
                    ,PCEST.QTRESERV       = vnESTOQUE_QTRESERV
                    ,PCEST.QTBLOQUEADA    = GREATEST(vnESTOQUE_QTBLOQUEADA, 0)
                    ,PCEST.QTINDENIZ      = GREATEST(vnESTOQUE_QTINDENIZ, 0)
                    ,PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
                    ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
              -- Alterar deposito na filial
              P_INTERNO.CODFILIAL        := REGISTROS.CODFILIALGERENCIAL;
              P_INTERNO.CODFILIALRESERVA := REGISTROS.CODFILIALGERENCIAL;
            -- Estoques gerenciais
            END IF;
            -- Se não movimenta estoque
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND (vnCONDVENDA = 14) THEN
              --Atualiza o estoque em trânsito (HIS.00390.2016)
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                REGISTROS.NOTA_QT
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                REGISTROS.NOTA_QT
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;

            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND
               (vnSITUACAONFE IN (110,205,301,302)) THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO
                     ,PCEST.QTRESERV       = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

            --
            BEGIN
              SELECT PCMOV.CODFILIALNF, PCMOV.QT, PCMOV.ROWID
                INTO vsFilialAjusteEstoque,
                     vnQtAjusteEstoque,
                     vsRowIdAjusteEstoque
                FROM PCTRANSFDEP, PCMOV
               WHERE PCMOV.NUMTRANSVENDA = PCTRANSFDEP.NUMTRANSVENDA
                 AND PCMOV.CODPROD = PCTRANSFDEP.CODPROD --by Braga
                 AND PCTRANSFDEP.NUMTRANSTRANSFSAIDA = pnNUMTRANSACAO
                 AND PCMOV.CODPROD = REGISTROS.CODPROD
                 AND PCMOV.STATUS = 'AB'
                 AND PCMOV.MOVESTOQUECONTABIL = 'N'
                 AND ROWNUM = 1;
            --
            EXCEPTION
              WHEN OTHERS THEN
                vsFILIALAJUSTEESTOQUE := NULL;
                vnQTAJUSTEESTOQUE     := 0;
                vsROWIDAJUSTEESTOQUE  := NULL;

            END;
            --
            IF (vsFILIALAJUSTEESTOQUE IS NOT NULL) AND
               (vnQTAJUSTEESTOQUE > 0) THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST = CASE
                                     WHEN psECANCELAMENTO = 'N' THEN
                                       NVL(PCEST.QTEST, 0) - vnQTAJUSTEESTOQUE
                                   ELSE
                                     NVL(PCEST.QTEST, 0) + vnQTAJUSTEESTOQUE
                                   END
               WHERE PCEST.CODFILIAL = vsFILIALAJUSTEESTOQUE
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

              UPDATE PCMOV
                 SET MOVESTOQUECONTABIL = 'S'
               WHERE PCMOV.ROWID = vsROWIDAJUSTEESTOQUE;

            END IF;
          -- Transf. filial virtual
          WHEN 'V' THEN
            -- Contábil
            IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST         = CASE
                                             WHEN psECANCELAMENTO = 'N' THEN
                                               NVL(PCEST.QTEST, 0) -
                                               DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           ELSE
                                             NVL(PCEST.QTEST, 0) +
                                             DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           END
                   ,PCEST.QTCROSSDOCK    = CASE -- DDMEDICA-1965
                                             WHEN (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
                                               CASE
                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                   NVL(PCEST.QTCROSSDOCK, 0) - NVL(REGISTROS.NOTA_QTCONT, 0)
                                               ELSE
                                                 NVL(PCEST.QTCROSSDOCK, 0) + NVL(REGISTROS.NOTA_QTCONT, 0)
                                               END
                                           ELSE
                                             PCEST.QTCROSSDOCK
                                           END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL --Aqui o estoque contábil deve ser movimentado diretamente na filial gerencial, pois a 1419 não movimenta nada!
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;
            -- Gerencial
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.DTULTSAIDA = TRUNC(SYSDATE),
                     PCEST.DTHORAULTSAIDA = SYSDATE,
                     PCEST.QTESTGER = CASE
                                        WHEN psECANCELAMENTO = 'N' THEN
                                          NVL(PCEST.QTESTGER, 0) -
                                          DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                 'S',
                                                 REGISTROS.NOTA_QT,
                                                 0)
                                      ELSE
                                        NVL(PCEST.QTESTGER, 0) +
                                        DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                               'S',
                                               REGISTROS.NOTA_QT,
                                               0)
                                      END,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
                    ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
              ---------------------------------------------------
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
              -- Alterar deposito na filial
              P_INTERNO.CODFILIAL        := REGISTROS.CODFILIALCONTABIL;
              P_INTERNO.CODFILIALRESERVA := REGISTROS.CODFILIALGERENCIAL;
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTRESERV      = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;
            --
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND (vnCONDVENDA = 14) THEN
              --Atualiza o estoque em trânsito (HIS.00390.2016)
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                REGISTROS.NOTA_QT
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                REGISTROS.NOTA_QT
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND
               (vnSITUACAONFE IN (110,205,301,302)) THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO
                     ,PCEST.QTRESERV       = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

            SELECT COUNT(1)
              INTO vnQTDEESTOQUEPENDECIA
              FROM PCMOV, PCMOVCOMPLE
             WHERE PCMOV.NUMTRANSITEM = PCMOVCOMPLE.NUMTRANSITEM(+)
               AND NVL(PCMOVCOMPLE.VERSAOREGISTRO, '0') = '0'
               AND PCMOV.NUMTRANSVENDA IN
                   (SELECT PCPEDC.NUMTRANSACAOTRANSF
                      FROM PCPEDC
                     WHERE PCPEDC.NUMTRANSVENDA = pnNUMTRANSACAO)
               AND PCMOV.STATUS = 'A'
               AND PCMOV.CODPROD = REGISTROS.CODPROD
               AND PCMOV.MOVESTOQUECONTABIL = 'N'
               AND ROWNUM = 1;

            IF vnQTDEESTOQUEPENDECIA > 0 THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST = CASE
                                     WHEN psECANCELAMENTO = 'N' THEN
                                       NVL(PCEST.QTEST, 0) -
                                       REGISTROS.NOTA_QTCONT
                                   ELSE
                                     NVL(PCEST.QTEST, 0) +
                                     REGISTROS.NOTA_QTCONT
                                   END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALGERENCIAL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST = CASE
                                     WHEN psECANCELAMENTO = 'N' THEN
                                       NVL(PCEST.QTEST, 0) +
                                       REGISTROS.NOTA_QTCONT
                                   ELSE
                                     NVL(PCEST.QTEST, 0) -
                                     REGISTROS.NOTA_QTCONT
                                   END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;
          --TRANSF. FILIAL RETIRA
          WHEN 'R' THEN
            --CONTÁBIL
            IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST         = CASE
                                             WHEN psECANCELAMENTO = 'N' THEN
                                               NVL(PCEST.QTEST, 0) -
                                               DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           ELSE
                                             NVL(PCEST.QTEST, 0) +
                                             DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           END,
                     PCEST.QTCROSSDOCK   = CASE -- DDMEDICA-1965
                                             WHEN (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
                                               CASE
                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                   NVL(PCEST.QTCROSSDOCK, 0) - NVL(REGISTROS.NOTA_QTCONT, 0)
                                               ELSE
                                                 NVL(PCEST.QTCROSSDOCK, 0) + NVL(REGISTROS.NOTA_QTCONT, 0)
                                               END
                                           ELSE
                                             PCEST.QTCROSSDOCK
                                           END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;
            --GERENCIAL
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') THEN
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.DTULTSAIDA = TRUNC(SYSDATE),
                     PCEST.DTHORAULTSAIDA = SYSDATE,
                     PCEST.QTESTGER = CASE
                                        WHEN psECANCELAMENTO = 'N' THEN
                                          NVL(PCEST.QTESTGER, 0) -
                                          DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                 'S',
                                                 REGISTROS.NOTA_QT,
                                                 0)
                                      ELSE
                                        NVL(PCEST.QTESTGER, 0) +
                                        DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                               'S',
                                               REGISTROS.NOTA_QT,
                                               0)
                                     END,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
                    ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
              -- Alterar deposito na filial
              P_INTERNO.CODFILIAL        := REGISTROS.CODFILIALCONTABIL;
              P_INTERNO.CODFILIALRESERVA := REGISTROS.CODFILIALGERENCIAL;
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTRESERV      = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND (vnCONDVENDA = 14) THEN
              --Atualiza o estoque em trânsito (HIS.00390.2016)

              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                REGISTROS.NOTA_QT
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                REGISTROS.NOTA_QT
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;

            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND
               (vnSITUACAONFE IN (110,205,301,302)) THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO
                     ,PCEST.QTRESERV       = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;
          -- Transf. filial virtual e retira
          WHEN 'VR' THEN
            -- Contábil
            IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST         = CASE
                                             WHEN psECANCELAMENTO = 'N' THEN
                                               NVL(PCEST.QTEST, 0) -
                                               DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           ELSE
                                             NVL(PCEST.QTEST, 0) +
                                             DECODE(REGISTROS.MOVESTOQUECONTABIL, 'S', REGISTROS.NOTA_QTCONT, 0)
                                           END,
                     PCEST.QTCROSSDOCK   = CASE -- DDMEDICA-1965
                                             WHEN (NVL(vnNUMTRANSENTCROSSDOCK,0) > 0) THEN
                                               CASE
                                                 WHEN psECANCELAMENTO = 'N' THEN
                                                   NVL(PCEST.QTCROSSDOCK, 0) - NVL(REGISTROS.NOTA_QTCONT, 0)
                                               ELSE
                                                 NVL(PCEST.QTCROSSDOCK, 0) + NVL(REGISTROS.NOTA_QTCONT, 0)
                                               END
                                           ELSE
                                             PCEST.QTCROSSDOCK
                                           END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;
            -- Gerencial
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'S') AND
               ((REGISTROS.CODOPER <> 'ST') OR (vbEH_TV10)) THEN
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.DTULTSAIDA = TRUNC(SYSDATE),
                     PCEST.DTHORAULTSAIDA = SYSDATE,
                     PCEST.QTESTGER = CASE
                                        WHEN psECANCELAMENTO = 'N' THEN
                                          NVL(PCEST.QTESTGER, 0) -
                                          DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                 'S',
                                                 REGISTROS.NOTA_QT,
                                                 0)
                                      ELSE
                                        NVL(PCEST.QTESTGER, 0) +
                                        DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                               'S',
                                               REGISTROS.NOTA_QT,
                                               0)
                                      END,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                              WHEN (psECANCELAMENTO = 'S') AND
                                                   (vnCONDVENDA = 13) THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                DECODE(REGISTROS.MOVESTOQUEGERENCIAL,
                                                       'S',
                                                       REGISTROS.NOTA_QT,
                                                       0)
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
                    ,PCEST.DTHORAULTALTDISP = DECODE(REGISTROS.MOVESTOQUEGERENCIAL, 'S', SYSDATE, PCEST.DTHORAULTALTDISP)
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
              -- Alterar deposito na filial
              P_INTERNO.CODFILIAL        := REGISTROS.CODFILIALCONTABIL;
              P_INTERNO.CODFILIALRESERVA := REGISTROS.CODFILIALGERENCIAL;
              -- Atualizando o estoque gerencial
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTRESERV      = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = CASE
                                         WHEN vsUTILIZOUCFAT = 'S' THEN
                                           REGISTROS.CODFILIALCONTABIL
                                       ELSE
                                         REGISTROS.CODFILIALGERENCIAL
                                       END
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;
            --
            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND (vnCONDVENDA = 14) THEN
              --Atualiza o estoque em trânsito (HIS.00390.2016)
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO,
                     PCEST.QTTRANSITOTV13 = CASE
                                              WHEN (psECANCELAMENTO = 'N') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) -
                                                REGISTROS.NOTA_QT
                                              WHEN (psECANCELAMENTO = 'S') THEN
                                                NVL(PCEST.QTTRANSITOTV13, 0) +
                                                REGISTROS.NOTA_QT
                                            ELSE
                                              NVL(PCEST.QTTRANSITOTV13, 0)
                                            END
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
            --
            END IF;

            IF (REGISTROS.MOVESTOQUEGERENCIAL = 'N') AND
               (REGISTROS.MOVESTOQUECONTABIL = 'N') AND
               (vnSITUACAONFE IN (110,205,301,302)) THEN
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR  = pnNUMTRANSACAO
                     ,PCEST.QTRESERV       = vnESTOQUE_QTRESERV
               WHERE PCEST.CODFILIAL = REGISTROS.CODFILIALCONTABIL
                 AND PCEST.CODPROD = REGISTROS.CODPROD;

            END IF;

            --
            BEGIN
              SELECT PCMOV.CODFILIALNF, PCMOV.QT, PCMOV.ROWID
                INTO vsFilialAjusteEstoque,
                     vnQtAjusteEstoque,
                     vsRowIdAjusteEstoque
                FROM PCTRANSFDEP, PCMOV
               WHERE PCMOV.NUMTRANSVENDA = PCTRANSFDEP.NUMTRANSVENDA
                 AND PCMOV.CODPROD = PCTRANSFDEP.CODPROD --by Braga
                 AND PCTRANSFDEP.NUMTRANSTRANSFSAIDA = pnNUMTRANSACAO
                 AND PCMOV.CODPROD = REGISTROS.CODPROD
                 AND PCMOV.STATUS = 'AB'
                 AND PCMOV.MOVESTOQUECONTABIL = 'N'
                 AND ROWNUM = 1;
            --
            EXCEPTION
              WHEN OTHERS THEN
                vsFilialAjusteEstoque := NULL;
                vnQtAjusteEstoque     := 0;
                vsRowIdAjusteEstoque  := NULL;
            END;
            --
            IF (vsFilialAjusteEstoque IS NOT NULL) AND
               (vnQtAjusteEstoque > 0) THEN
              --
              UPDATE PCEST
                 SET PCEST.IDENTIFICADOR = pnNUMTRANSACAO,
                     PCEST.QTEST = CASE
                                     WHEN psECANCELAMENTO = 'N' THEN
                                       NVL(PCEST.QTEST, 0) - vnQtAjusteEstoque
                                   ELSE
                                     NVL(PCEST.QTEST, 0) + vnQtAjusteEstoque
                                   END
               WHERE PCEST.CODFILIAL = vsFilialAjusteEstoque
                 AND PCEST.CODPROD = REGISTROS.CODPROD;
              --
              UPDATE pcmov
                 SET MOVESTOQUECONTABIL = 'S'
               WHERE PCMOV.ROWID = vsRowIdAjusteEstoque;
            --
            END IF;
        --
        END CASE;
      --
      END IF;
      -- Se movimentar estoque contábil
      IF (REGISTROS.MOVESTOQUECONTABIL = 'S') THEN
        UPDATE PCMOV
           SET PCMOV.QTESTANT = NVL(vnESTOQUE_QTEST, PCMOV.QTESTANT)
         WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;
      END IF;
      -- Administrar estoque depósito
      IF REGISTROS.MOVESTOQUEGERENCIAL = 'S' THEN
        -- Atualizando a nota fiscal
        UPDATE PCMOV
           SET PCMOV.QTESTGERANT = NVL(vnESTOQUE_QTESTGER, PCMOV.QTESTGERANT)
         WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;

        IF (NVL(vnESTOQUE_QTESTGER, 0) < 0) AND (NVL(PARAMFILIAL.OBTERCOMOVARCHAR2('FIL_AUTOSERVICO',REGISTROS.CODFILIALGERENCIAL),'N') = 'N') THEN
          UPDATE PCEST
             SET QTBLOQUEADA = 0
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIALGERENCIAL
             AND QTBLOQUEADA > QTESTGER;
        ELSIF vnESTOQUE_QTBLOQUEADA < 0 THEN
          UPDATE PCEST
             SET QTBLOQUEADA = 0
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIALGERENCIAL
             AND QTBLOQUEADA < 0;
        END IF;
        -- Atualizar variável para movimentar depósito
        IF psECANCELAMENTO = 'S' THEN
          P_INTERNO.TIPO_OPERACAO := 'I';
        ELSE
          P_INTERNO.TIPO_OPERACAO := 'B';
        END IF;
        -- Atualizar variáveis internas
        P_INTERNO.PROCESSO       := 'VENDER';
        P_INTERNO.ROWID_REGISTRO := REGISTROS.NOTA_ROWID;
        P_INTERNO.CODDEPOSITO    := REGISTROS.CODDEPOSITO;
        P_INTERNO.CODPROD        := REGISTROS.CODPROD;
        P_INTERNO.QTESTGER       := REGISTROS.NOTA_QT;
        P_INTERNO.QTRESERV       := vnDEPOSITO_QTRESERVADA;
		P_INTERNO.QTINDENIZ      := REGISTROS.NOTA_QTAVARIA;
        P_INTERNO.QTBLOQUEADA    := REGISTROS.NOTA_QTBLOQUEADA;
		
        -- Administrar estoque do depósito
        IF REGISTROS.CODOPER <> 'SI' AND FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAESTOQUEDEPOSITO',P_INTERNO.CODFILIAL,'N') = 'S' THEN

          IF (REGISTROS.CODOPER = 'S' AND  vsTIPO_TRANSFERENCIA IN ('R','V','VR')) THEN

            SELECT PCESTOQUEDEPOSITO.CODDEPOSITO
              INTO P_INTERNO.CODDEPOSITO
              FROM PCESTOQUEDEPOSITO
             WHERE PCESTOQUEDEPOSITO.CODFILIAL = REGISTROS.CODFILIALCONTABIL
               AND PCESTOQUEDEPOSITO.Padraovenda = 'S';

            UPDATE PCPEDI
               SET PCPEDI.CODDEPOSITO = P_INTERNO.CODDEPOSITO
             WHERE PCPEDI.CODPROD = REGISTROS.CODPROD
               AND PCPEDI.NUMPED  = REGISTROS.NUMPED
               AND PCPEDI.NUMSEQ  = REGISTROS.NUMSEQ;

            UPDATE PCMOV
               SET PCMOV.CODDEPOSITO = P_INTERNO.CODDEPOSITO
             WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;

            P_INTERNO.CODFILIALRESERVA := REGISTROS.CODFILIALGERENCIAL;
          END IF;

          IF REGISTROS.CODOPER = 'SV' THEN
            BEGIN
              SELECT CODDEPOSITO
                INTO P_INTERNO.CODDEPOSITO
                FROM PCESTOQUEDEPOSITO
               WHERE PADRAOAVARIA = 'S'
                 AND CODFILIAL = P_INTERNO.CODFILIAL;
            EXCEPTION
              WHEN OTHERS THEN
                P_INTERNO.CODDEPOSITO := NULL;
            END;
          END IF;

          PRIV_DEP_VENDAS_SAIDA;
        END IF;

        -- Erro na administração do estoque depósito
        IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
          psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
          PRIV_GERARLOG;
          RETURN 0;
        END IF;
      -- Administração depósito
      END IF;
      -- Inserindo a data de alteração do estoque
      UPDATE PCMOV
         SET DATAESTOQUE = SYSDATE
       WHERE PCMOV.ROWID = REGISTROS.NOTA_ROWID;

      -- Movimentar o estoque de terceiro caso seja transferência TV-10.
      PRIV_VENDAS_TERCEIRO (REGISTROS.CODPROD
                           ,vbEH_TV10
                           ,psECANCELAMENTO
                           ,pnNUMTRANSACAO
                           ,REGISTROS.CODCLI
                           ,REGISTROS.CODFISCAL
                           ,REGISTROS.NOTA_QT
                           ,REGISTROS.CODFILIALVENDA);

      IF P_INTERNO.MSG_RETORNO <> 'OK' THEN
        psMSG_RETORNO := P_INTERNO.MSG_RETORNO;
        PRIV_GERARLOG;
        RETURN 0;
      END IF;
    -- Lista de produtos
    END LOOP;
    -- Gravar estoque na movimentação
    PRIV_ATUALIZAR_CUSTO (pnNUMTRANSACAO,'S');
    -- Marcar no cabeçalho a utilização da package
    IF vnCONTADORREGISTROS > 0 THEN
      IF (psECANCELAMENTO = 'S') THEN
        UPDATE PCNFSAID
           SET PCT_ESTOQUE = 'S',
           PCT_ESTOQUE_CANCELAMENTO = 'S'
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    ELSE
      UPDATE PCNFSAID
         SET PCT_ESTOQUE = 'S',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
    END IF;
    -- Validando se tem registros
    ELSIF vnCONTADORREGISTROS = 0 THEN
      UPDATE PCNFSAID
         SET PCT_ESTOQUE = 'N',
         PCT_ESTOQUE_CANCELAMENTO = 'N'
       WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      --Verificar se a PCNFSAID é oriunda de Transf. Entre Deposito 1124
      BEGIN
        SELECT NVL(TRANSFDEP, 'N')
          INTO vsTransfDep
          FROM PCNFSAID
         WHERE NUMTRANSVENDA = pnNUMTRANSACAO;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vsTransfDep := 'N';
      END;
      IF vsTransfDep = 'N' THEN
        psMSG_RETORNO := 'Erro 7 (Vendas Saída Prod): A transação repassada para a PKG_ESTOQUE não tem registros validos.'||CHR(13)||
                         'Transação: '||TO_CHAR(pnNUMTRANSACAO);
      END IF;
      PRIV_GERARLOG;
      RETURN vnCONTADORREGISTROS;
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função vendas saida prod.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA_PROD';
    PRIV_GERARLOG;
    -- Retornando valores
    RETURN vnCONTADORREGISTROS;
  EXCEPTION
    WHEN OTHERS THEN
      psMSG_RETORNO := 'Erro 8 (Vendas Saída Prod): '||CHR(13)||
                       'Msg. original: '||SQLERRM;
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN 0;
  -- Função
  END VENDAS_SAIDA_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Rodrigo Santos    0                   Criada a função
  11/09/2014     Ricardo Sousa     0                   Criado para possibilitar o recalculo de estoque por produto. Foi alterada
                                                       a função principal para ter como parametro o CODPROD e criado este novo
                                                       como sobrecarga sa função anterior para evitar impacto com as rotinas
                                                       que já usam com a assinatura anterior
  ************************************************************************************************************************/
  FUNCTION VENDAS_SAIDA (pnNUMTRANSACAO  IN PCMOV.NUMTRANSVENDA%TYPE
                        ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                        ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    CURSOR BLOQUEIA_ESTOQUE_TRNASACAO
    IS
     SELECT distinct CODPROD, CODFILIAL, CODFILIALRETIRA FROM PCMOV WHERE NUMTRANSVENDA = pnNUMTRANSACAO ORDER BY CODPROD;

    vnTENTATIVA NUMBER := 0;
    vnRETORNO   NUMBER;
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'Iniciou a função - VENDAS_SAIDA';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSACAO;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    PRIV_GERARLOG;
    -- Bloqueando o Estoque para a transação

    FOR REGISTROS IN BLOQUEIA_ESTOQUE_TRNASACAO
    LOOP
      WHILE (vnTENTATIVA < 5) LOOP
        BEGIN
          SELECT CODPROD
            INTO vnTENTATIVA
            FROM PCEST
           WHERE CODPROD = REGISTROS.CODPROD
             AND CODFILIAL = REGISTROS.CODFILIAL
             FOR UPDATE;

          IF REGISTROS.CODFILIAL <> REGISTROS.CODFILIALRETIRA THEN
            SELECT CODPROD
              INTO vnTENTATIVA
              FROM PCEST
             WHERE CODPROD = REGISTROS.CODPROD
               AND CODFILIAL = REGISTROS.CODFILIALRETIRA
               FOR UPDATE;
          END IF;
          vnTENTATIVA := 5;
        EXCEPTION
          WHEN OTHERS THEN
            psMSG_RETORNO := 'Erro 1 - Vendas saida: Verifique os dados informados!'||CHR(13)||
                             '1 - O produto pode esta em uso em outro processo. Neste caso tente mais tarde!'||CHR(13)||
                             '2 - Os dados informados podem não ser validos!'||CHR(13)||
                             'TRANSAÇÃO: '||pnNUMTRANSACAO||' - '||SQLERRM;
            P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
            vnTENTATIVA := vnTENTATIVA + 1;
        END;
      END LOOP;
      psMSG_RETORNO := 'OK';
      vnTENTATIVA := 0;
    END LOOP;
    --
    IF psMSG_RETORNO = 'OK' THEN
      vnRETORNO := VENDAS_SAIDA_PROD (pnNUMTRANSACAO,0,psECANCELAMENTO,psMSG_RETORNO);
      -- Inserindo informações de debug (LOG)
      IF psMSG_RETORNO <> 'OK' THEN
        P_INTERNO.INFORMACOES_LOG := 'Erro 2 - Vendas saida: Falha ao Movimentar estoque';
        P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA';
        PRIV_GERARLOG;
        RETURN 0;
      END IF;

      P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função vendas saida.';
      P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA';
      PRIV_GERARLOG;
      RETURN vnRETORNO;
    ELSE
      -- Inserindo informações de debug (LOG)
      P_INTERNO.INFORMACOES_LOG := 'Erro 3 - Vendas saida: Falha ao bloquear produtos na função';
      P_INTERNO.NOME_FUNCAO     := 'VENDAS_SAIDA';
      PRIV_GERARLOG;
      RETURN 0;
    END IF;
  -- Função
  END VENDAS_SAIDA;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Rodrigo Santos    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION VENDAS_MOVIMENTACAO_PROD (pnNUMTRANSENT   IN PCMOV.NUMTRANSENT%TYPE
                                    ,pnNUMTRANSVENDA IN PCMOV.NUMTRANSVENDA%TYPE
                                    ,pnCODPROD       IN PCMOV.CODPROD%TYPE
                                    ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                                    ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnResultS          NUMBER := 0;
    vsMSGRETORNO_SAIDA VARCHAR2(1000);
    vnResultE          NUMBER := 0;
    vsMSGRETORNO_ENT   VARCHAR2(1000);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função vendas movimentação prod.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_MOVIMENTACAO_PROD';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSENT;
    P_INTERNO.CODPROD         := pnCODPROD;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Validar se transações são validas
    IF (pnNUMTRANSENT > 0) AND (pnNUMTRANSVENDA > 0) THEN
      vnResultE := VENDAS_ENTRADA_PROD(pnNUMTRANSENT,
                                       pnCODPROD,
                                       'N',
                                       psECANCELAMENTO,
                                       vsMSGRETORNO_ENT);
      vnResultS := VENDAS_SAIDA_PROD(pnNUMTRANSVENDA,
                                     pnCODPROD,
                                     psECANCELAMENTO,
                                     vsMSGRETORNO_SAIDA);
    -- Mensagem de retorno
    IF (NVL(vsMSGRETORNO_ENT, 'OK') <> 'OK') AND
         (NVL(vsMSGRETORNO_SAIDA, 'OK') <> 'OK') THEN
        psMSG_RETORNO := 'Erro mov. entrada: ' || vsMSGRETORNO_ENT || CHR(13) ||
                       'Erro mov. saída: ' || vsMSGRETORNO_SAIDA;
      ELSIF (NVL(vsMSGRETORNO_ENT, 'OK') <> 'OK') THEN
        psMSG_RETORNO := 'Erro mov. entrada: ' || vsMSGRETORNO_ENT;

      ELSIF (NVL(vsMSGRETORNO_SAIDA, 'OK') <> 'OK') THEN
        psMSG_RETORNO := 'Erro mov. saída: ' || vsMSGRETORNO_SAIDA;
      END IF;
    ELSE
      psMSG_RETORNO := 'Erro 1 (Vendas Mov Prod): Não foi possível realizar a operacao!'||CHR(13)||
                       'Para este tipo de operação são obrigatórios o número de transação de venda e o número de transação de entrada!'||CHR(13)||
                       'Identificador de entrada: '||TO_CHAR(pnNUMTRANSENT)||CHR(13)||
                       'Identificador de venda: '||TO_CHAR(pnNUMTRANSVENDA)||CHR(13)||
                       'Produto......: '||TO_CHAR(pnCODPROD)||CHR(13);
      P_INTERNO.MSG_RETORNO := psMSG_RETORNO;
      PRIV_GERARLOG;
      RETURN (vnResultE + vnResultS);
    END IF;
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função vendas movimentação prod.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_MOVIMENTACAO_PROD';
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Rertono
    RETURN(vnResultE + vnResultS);
  -- Função
  END VENDAS_MOVIMENTACAO_PROD;

  /************************************************************************************************************************
  ------------------------------------------------------ Alterações -------------------------------------------------------
  Data           Autor             Solicitação         Descrição
  -------------------------------------------------------------------------------------------------------------------------
  20/04/2015     Rodrigo Santos    0                   Criada a função
  ************************************************************************************************************************/
  FUNCTION VENDAS_MOVIMENTACAO (pnNUMTRANSENT   IN PCMOV.NUMTRANSENT%TYPE
                               ,pnNUMTRANSVENDA IN PCMOV.NUMTRANSVENDA%TYPE
                               ,psECANCELAMENTO IN PCLOGPKG_ESTOQUE.CANCELAMENTO%TYPE
                               ,psMSG_RETORNO   OUT VARCHAR2)
  RETURN NUMBER
  IS-- Declaração das variáveis internas
    vnRETORNO   NUMBER(20);
  BEGIN
    -- Limpar variável P_INTERNO
    PRIV_LIMPAR_P_INTERNO;
    -- Inserindo informações de debug (LOG)
    psMSG_RETORNO             := P_INTERNO.MSG_RETORNO;
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' iniciou a função vendas movimentação.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_MOVIMENTACAO';
    P_INTERNO.IDENTIFICADOR   := pnNUMTRANSENT;
    P_INTERNO.CANCELAMENTO    := psECANCELAMENTO;
    P_INTERNO.MSG_RETORNO     := psMSG_RETORNO;
    PRIV_GERARLOG;
    -- Executar processo por produto
    vnRETORNO := VENDAS_MOVIMENTACAO_PROD(pnNUMTRANSENT,pnNUMTRANSVENDA,0,psECANCELAMENTO,psMSG_RETORNO);
    -- Inserindo informações de debug (LOG)
    P_INTERNO.INFORMACOES_LOG := 'A rotina '||P_INTERNO.PROGRAMA||' finalizou a função vendas movimentação.';
    P_INTERNO.NOME_FUNCAO     := 'VENDAS_MOVIMENTACAO';
    PRIV_GERARLOG;
    -- Inserindo retorno para a função
    RETURN vnRETORNO;
  -- Função
  END VENDAS_MOVIMENTACAO;

-- Package de estoque
END PKG_ESTOQUE;
